INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('biologia', 'bachillerato', '{1}', 'La estructura de la membrana plasmática', 'La membrana plasmática constituye la envoltura activa de toda célula y se describe mediante el modelo del mosaico fluido propuesto por Singer y Nicolson en 1972. Según este modelo, la membrana está formada por una bicapa de fosfolípidos anfipáticos, cuyas cabezas polares se orientan hacia los medios acuosos intracelular y extracelular, mientras que las colas hidrofóbicas quedan enfrentadas en el interior. Entre los fosfolípidos se intercalan moléculas de colesterol que regulan la fluidez y la permeabilidad, así como proteínas integrales y periféricas que desempeñan funciones de transporte, reconocimiento y enzimáticas. La asimetría de la membrana se manifiesta tanto en la distribución de lípidos como en la presencia de glúcidos unidos a proteínas y lípidos en la cara externa, formando el glucocálix. Esta estructura dinámica permite el transporte selectivo de sustancias, bien de forma pasiva a favor del gradiente, bien de forma activa con consumo de ATP. Además, la membrana interviene en la comunicación celular mediante receptores específicos capaces de reconocer hormonas, neurotransmisores y antígenos. Su fluidez depende de factores como la temperatura, la proporción de ácidos grasos insaturados y la concentración de colesterol, lo que explica las adaptaciones de los organismos a distintos ambientes térmicos. La correcta funcionalidad de la membrana resulta esencial para mantener la homeostasis y la integridad celular.', '[{"pregunta":"¿Quiénes propusieron el modelo del mosaico fluido?","opciones":["Watson y Crick","Singer y Nicolson","Schleiden y Schwann","Hooke y Leeuwenhoek"],"correcta":1},{"pregunta":"¿Qué función cumple el colesterol en la membrana?","opciones":["Transportar iones activamente","Regular la fluidez y permeabilidad","Sintetizar proteínas","Almacenar energía"],"correcta":1},{"pregunta":"¿Dónde se localiza el glucocálix?","opciones":["En la cara interna de la membrana","En el citoplasma","En la cara externa de la membrana","En el núcleo"],"correcta":2},{"pregunta":"¿Qué factor NO afecta a la fluidez de la membrana?","opciones":["La temperatura","Los ácidos grasos insaturados","El colesterol","El pH del núcleo"],"correcta":3}]'::jsonb),

('biologia', 'bachillerato', '{1}', 'El ciclo celular y la mitosis', 'El ciclo celular es el conjunto ordenado de acontecimientos que conducen al crecimiento de la célula y a su división en dos células hijas genéticamente idénticas. Se divide en dos grandes fases: la interfase, durante la cual la célula crece y duplica su material genético, y la fase M, que comprende la mitosis y la citocinesis. La interfase se subdivide en G1, S y G2. En G1 la célula aumenta de tamaño y sintetiza proteínas; en S tiene lugar la replicación del ADN; en G2 se prepara para la división. La mitosis propiamente dicha se organiza en profase, metafase, anafase y telofase. En profase se condensan los cromosomas y desaparece la envoltura nuclear; en metafase los cromosomas se alinean en el plano ecuatorial unidos al huso acromático; en anafase las cromátidas hermanas se separan hacia los polos; y en telofase se reconstruyen los núcleos hijos. La citocinesis divide el citoplasma completando el proceso. El ciclo está regulado por complejos formados por ciclinas y quinasas dependientes de ciclina (CDK) que controlan puntos de restricción. Alteraciones en estos mecanismos pueden conducir a proliferaciones descontroladas como las que caracterizan los procesos tumorales.', '[{"pregunta":"¿En qué fase de la interfase se replica el ADN?","opciones":["G1","S","G2","M"],"correcta":1},{"pregunta":"¿Qué ocurre durante la anafase?","opciones":["Los cromosomas se condensan","Se separan las cromátidas hermanas","Se alinean en el ecuador","Se reconstruye el núcleo"],"correcta":1},{"pregunta":"¿Qué moléculas regulan el ciclo celular?","opciones":["Ciclinas y CDK","Histonas","Ribosomas","Lisosomas"],"correcta":0},{"pregunta":"¿Qué puede provocar una desregulación del ciclo celular?","opciones":["Apoptosis programada","Proliferación tumoral","Meiosis normal","Fotosíntesis"],"correcta":1}]'::jsonb),

('biologia', 'bachillerato', '{1}', 'El metabolismo: catabolismo y anabolismo', 'El metabolismo designa el conjunto de reacciones químicas que ocurren en los seres vivos y que permiten el mantenimiento de las funciones vitales. Estas reacciones se organizan en rutas metabólicas interconectadas que se clasifican en dos grandes categorías complementarias: el catabolismo y el anabolismo. El catabolismo agrupa las reacciones de degradación de moléculas complejas en otras más sencillas, liberando energía que se almacena en forma de ATP y poder reductor como NADH o FADH2. Ejemplos característicos son la glucólisis, el ciclo de Krebs y la beta-oxidación de ácidos grasos. El anabolismo, por el contrario, consiste en la síntesis de moléculas complejas a partir de precursores sencillos, consumiendo la energía liberada en los procesos catabólicos. Entre sus rutas destacan la gluconeogénesis, la síntesis de ácidos grasos y la biosíntesis de aminoácidos. Ambas vías comparten intermediarios y están finamente reguladas mediante enzimas alostéricas y hormonas como la insulina o el glucagón. En las células eucariotas, muchos procesos catabólicos tienen lugar en las mitocondrias, mientras que otros, como la glucólisis, se desarrollan en el citosol. La respiración celular aerobia permite obtener un rendimiento energético muy superior al de la fermentación, lo que explica la ventaja evolutiva de los organismos capaces de utilizar oxígeno como aceptor final de electrones.', '[{"pregunta":"¿Qué caracteriza al catabolismo?","opciones":["Síntesis de moléculas complejas","Degradación con liberación de energía","Absorción de luz","Replicación del ADN"],"correcta":1},{"pregunta":"¿Dónde se produce principalmente la glucólisis?","opciones":["Mitocondrias","Citosol","Núcleo","Aparato de Golgi"],"correcta":1},{"pregunta":"¿Qué hormona NO regula el metabolismo de la glucosa?","opciones":["Insulina","Glucagón","Adrenalina","Melanina"],"correcta":3},{"pregunta":"¿Por qué la respiración aerobia resulta ventajosa?","opciones":["Mayor rendimiento energético","No produce CO2","Es más rápida sin enzimas","No necesita ATP"],"correcta":0}]'::jsonb),

('biologia', 'bachillerato', '{1}', 'La fotosíntesis y sus fases', 'La fotosíntesis es el proceso anabólico por el cual los organismos autótrofos transforman materia inorgánica en materia orgánica utilizando la energía de la luz. Se desarrolla en los cloroplastos de células vegetales y algas, y se divide en dos fases interdependientes: la fase luminosa y la fase oscura o ciclo de Calvin. En la fase luminosa, que tiene lugar en las membranas tilacoidales, los fotosistemas I y II absorben fotones y desencadenan una cadena de transporte electrónico que genera ATP mediante fotofosforilación y poder reductor en forma de NADPH. Además, la fotólisis del agua libera oxígeno molecular como subproducto, lo que supuso una transformación radical de la atmósfera primitiva al enriquecerla en O2. En la fase oscura, localizada en el estroma, el CO2 atmosférico se incorpora al ciclo de Calvin gracias a la enzima RuBisCO, considerada la proteína más abundante de la biosfera. A través de una serie de reacciones, el CO2 se reduce hasta formar gliceraldehído-3-fosfato, precursor de glúcidos como la glucosa. Factores como la intensidad y longitud de onda de la luz, la temperatura y la concentración de CO2 influyen en la eficiencia del proceso, siendo la fotosíntesis el motor principal de las redes tróficas y del ciclo global del carbono.', '[{"pregunta":"¿En qué orgánulo se realiza la fotosíntesis?","opciones":["Mitocondria","Cloroplasto","Núcleo","Ribosoma"],"correcta":1},{"pregunta":"¿Qué se libera en la fotólisis del agua?","opciones":["CO2","Oxígeno","Nitrógeno","Metano"],"correcta":1},{"pregunta":"¿Qué enzima fija el CO2 en el ciclo de Calvin?","opciones":["ATP sintasa","RuBisCO","Amilasa","Lipasa"],"correcta":1},{"pregunta":"¿Qué se sintetiza en la fase luminosa?","opciones":["Solo glucosa","ATP y NADPH","Aminoácidos","Ácidos grasos"],"correcta":1}]'::jsonb),

('biologia', 'bachillerato', '{1}', 'El ADN y la replicación', 'El ácido desoxirribonucleico (ADN) es la molécula portadora de la información genética en todos los seres vivos. Su estructura, descrita en 1953 por Watson y Crick, consiste en una doble hélice formada por dos cadenas antiparalelas de nucleótidos que se mantienen unidas mediante puentes de hidrógeno entre bases complementarias: adenina con timina y guanina con citosina. Cada nucleótido está compuesto por una desoxirribosa, un grupo fosfato y una base nitrogenada. La replicación del ADN es un proceso semiconservativo, como demostraron Meselson y Stahl, en el que cada hebra parental sirve de molde para la síntesis de una nueva hebra complementaria. El proceso comienza con la separación de las cadenas por la helicasa, seguida por la acción de la ADN polimerasa, que añade nucleótidos en dirección 5 prima a 3 prima. En la hebra conductora la síntesis es continua, mientras que en la retrasada se producen fragmentos de Okazaki que posteriormente son unidos por la ligasa. La fidelidad del proceso está garantizada por mecanismos de corrección enzimática que reducen notablemente la tasa de errores. Comprender la replicación ha sido clave para el desarrollo de técnicas como la PCR, esenciales en biotecnología y medicina forense.', '[{"pregunta":"¿Qué bases se emparejan en el ADN?","opciones":["A-G y C-T","A-T y G-C","A-C y G-T","U-A y G-C"],"correcta":1},{"pregunta":"¿Qué tipo de replicación presenta el ADN?","opciones":["Conservativa","Semiconservativa","Dispersiva","Aleatoria"],"correcta":1},{"pregunta":"¿Qué enzima une los fragmentos de Okazaki?","opciones":["Helicasa","Ligasa","Primasa","Topoisomerasa"],"correcta":1},{"pregunta":"¿Qué aplicación deriva del conocimiento de la replicación?","opciones":["Fotosíntesis artificial","PCR","Fermentación industrial","Destilación"],"correcta":1}]'::jsonb),

('biologia', 'bachillerato', '{1}', 'La transcripción y la traducción genética', 'La expresión de la información genética supone la transformación de la secuencia de ADN en proteínas funcionales mediante dos procesos consecutivos: la transcripción y la traducción. En la transcripción, que ocurre en el núcleo de las células eucariotas, la enzima ARN polimerasa sintetiza una molécula de ARN mensajero utilizando como molde una de las hebras del ADN. Previamente se produce el reconocimiento del promotor y, al finalizar, el ARN recién formado sufre modificaciones postranscripcionales como la adición de una caperuza en el extremo 5 prima, la cola de poli-A en el 3 prima y el corte y empalme (splicing) que elimina los intrones. El ARN maduro abandona el núcleo y se dirige a los ribosomas, donde tiene lugar la traducción. Los ribosomas leen los codones del ARN mensajero en tripletes, asignando a cada uno un aminoácido concreto mediante los ARN de transferencia, que actúan como adaptadores. El código genético es universal, degenerado y no ambiguo, características que permiten interpretar la información de manera coherente en prácticamente todos los organismos. La síntesis proteica se inicia con el codón AUG y termina en un codón de parada. Una vez sintetizada, la proteína se pliega y sufre, en ocasiones, modificaciones postraduccionales que determinan su función biológica.', '[{"pregunta":"¿Dónde ocurre la transcripción en eucariotas?","opciones":["Citoplasma","Ribosomas","Núcleo","Mitocondria"],"correcta":2},{"pregunta":"¿Qué molécula actúa como adaptador en la traducción?","opciones":["ARN mensajero","ARN de transferencia","ARN ribosómico","ADN"],"correcta":1},{"pregunta":"¿Qué proceso elimina los intrones?","opciones":["Replicación","Splicing","Fosforilación","Glucosilación"],"correcta":1},{"pregunta":"¿Con qué codón empieza habitualmente la traducción?","opciones":["UAA","AUG","UGA","GCU"],"correcta":1}]'::jsonb),

('biologia', 'bachillerato', '{1}', 'Las leyes de Mendel y la herencia', 'Las leyes de Mendel son los principios básicos de la herencia genética, deducidos en el siglo XIX por el monje Gregor Mendel a partir de sus experimentos con plantas de guisantes. Aunque en su época pasaron desapercibidas, a comienzos del siglo XX fueron redescubiertas y se convirtieron en el fundamento de la genética moderna. La primera ley, de la uniformidad, establece que al cruzar dos líneas puras para un determinado carácter se obtiene una generación filial uniforme en la que se manifiesta solamente el alelo dominante. La segunda ley, de la segregación, afirma que los alelos se separan durante la formación de los gametos, de modo que cada gameto recibe solo uno de ellos, lo que explica la reaparición del rasgo recesivo en la segunda generación. La tercera ley, de la transmisión independiente, sostiene que los caracteres hereditarios se transmiten de manera independiente entre sí cuando los genes se localizan en cromosomas distintos. La comprensión posterior del papel del ADN y de la meiosis permitió explicar el fundamento molecular de estas leyes. Sin embargo, fenómenos como el ligamiento, la dominancia incompleta o la herencia poligénica ampliaron el modelo mendeliano, demostrando que la herencia real es a menudo más compleja de lo que Mendel pudo observar.', '[{"pregunta":"¿Qué estableció Mendel en su primera ley?","opciones":["Uniformidad de la F1","Segregación de gametos","Mutaciones aleatorias","Herencia citoplasmática"],"correcta":0},{"pregunta":"¿Qué proceso biológico explica la segunda ley?","opciones":["Mitosis","Meiosis","Transcripción","Fotosíntesis"],"correcta":1},{"pregunta":"¿Cuándo se cumple la tercera ley?","opciones":["Genes ligados en el mismo cromosoma","Genes en cromosomas distintos","Siempre","Solo en bacterias"],"correcta":1},{"pregunta":"¿Qué fenómeno NO amplía el modelo mendeliano?","opciones":["Dominancia incompleta","Ligamiento","Herencia poligénica","Difusión simple"],"correcta":3}]'::jsonb),

('biologia', 'bachillerato', '{1}', 'Las mutaciones y sus consecuencias', 'Las mutaciones son cambios permanentes en la secuencia del ADN que pueden producirse de manera espontánea durante la replicación o ser inducidas por agentes mutagénicos físicos, químicos o biológicos. En función de la extensión del cambio, se clasifican en mutaciones génicas, cromosómicas y genómicas. Las génicas afectan a uno o pocos nucleótidos e incluyen sustituciones, inserciones y deleciones; algunas son silenciosas porque no alteran el aminoácido codificado, mientras que otras pueden modificar la proteína resultante, incluso de forma drástica. Las cromosómicas alteran la estructura de los cromosomas mediante duplicaciones, deleciones, inversiones o translocaciones. Las genómicas modifican el número total de cromosomas, dando lugar a aneuploidías como el síndrome de Down o a poliploidías frecuentes en plantas. Las consecuencias de una mutación dependen de la célula en que ocurra: si afecta a células somáticas, sus efectos quedan restringidos al individuo; si tiene lugar en células germinales, puede transmitirse a la descendencia. Las mutaciones constituyen la fuente primaria de variabilidad genética y, por tanto, la materia prima sobre la que actúa la selección natural. Aunque muchas son perjudiciales, otras resultan neutras o incluso beneficiosas en determinados contextos ambientales.', '[{"pregunta":"¿Qué tipo de mutación altera el número de cromosomas?","opciones":["Génica","Cromosómica","Genómica","Silenciosa"],"correcta":2},{"pregunta":"¿Qué caracteriza a una mutación silenciosa?","opciones":["Cambia el aminoácido","No altera la proteína","Elimina un cromosoma","Duplica el ADN"],"correcta":1},{"pregunta":"¿Qué mutaciones se transmiten a la descendencia?","opciones":["Somáticas","Germinales","Neutras","Inducidas"],"correcta":1},{"pregunta":"¿Qué papel tienen las mutaciones en la evolución?","opciones":["Impiden la selección natural","Son fuente de variabilidad","Solo son dañinas","No tienen efecto"],"correcta":1}]'::jsonb),

('biologia', 'bachillerato', '{1}', 'La ingeniería genética y la biotecnología', 'La ingeniería genética es el conjunto de técnicas que permiten manipular directamente el material hereditario de los organismos. Se basa en el uso de enzimas de restricción, que cortan el ADN en secuencias específicas, y de ligasas, que unen fragmentos procedentes de distintas fuentes. Con ellas pueden construirse moléculas de ADN recombinante capaces de introducir genes en células receptoras mediante vectores como plásmidos o virus modificados. Una de las aplicaciones más conocidas es la producción de proteínas humanas en microorganismos, como la insulina recombinante utilizada por personas con diabetes. En agricultura se han desarrollado plantas transgénicas resistentes a plagas, herbicidas o condiciones adversas, lo que ha generado debates sobre sus efectos en la salud y el medio ambiente. La biotecnología abarca también campos como la terapia génica, el diagnóstico molecular y el estudio de células madre, con prometedoras aplicaciones médicas. Más recientemente, técnicas como CRISPR-Cas9 han revolucionado la edición del genoma al permitir cortes precisos en lugares concretos del ADN. Estos avances plantean retos éticos y legales importantes, ya que suponen una capacidad sin precedentes para intervenir en la herencia biológica de organismos, incluidos los seres humanos.', '[{"pregunta":"¿Qué función tienen las enzimas de restricción?","opciones":["Replicar el ADN","Cortar el ADN en secuencias específicas","Sintetizar proteínas","Traducir el ARN"],"correcta":1},{"pregunta":"¿Qué producto se obtiene mediante ADN recombinante?","opciones":["Antibióticos solo","Insulina humana","Hidrógeno","Celulosa"],"correcta":1},{"pregunta":"¿Qué técnica permite edición precisa del genoma?","opciones":["PCR","Electroforesis","CRISPR-Cas9","Cromatografía"],"correcta":2},{"pregunta":"¿Qué retos plantea la ingeniería genética?","opciones":["Éticos y legales","Solo económicos","Ninguno","Solo técnicos"],"correcta":0}]'::jsonb),

('biologia', 'bachillerato', '{1}', 'Las enzimas: catalizadores biológicos', 'Las enzimas son proteínas especializadas que actúan como catalizadores de las reacciones químicas en los seres vivos, acelerando su velocidad sin consumirse en el proceso. Sin ellas, la mayoría de las reacciones biológicas ocurrirían a velocidades demasiado lentas para sostener la vida. Cada enzima reconoce de forma altamente específica uno o varios sustratos, a los que se une en una región denominada centro activo, siguiendo un modelo de ajuste inducido en el que la proteína modifica ligeramente su forma para acoplarse al sustrato. La actividad enzimática depende de factores como la temperatura, el pH, la concentración de sustrato y la presencia de inhibidores. Muchas enzimas requieren la presencia de cofactores, que pueden ser iones metálicos, o coenzimas, a menudo derivadas de vitaminas. La regulación de la actividad enzimática es clave para el funcionamiento celular: puede producirse mediante inhibición competitiva o no competitiva, regulación alostérica, modificaciones covalentes o control de la cantidad de enzima sintetizada. Alteraciones en las enzimas pueden provocar enfermedades metabólicas graves, como la fenilcetonuria o la galactosemia, lo que explica el interés en su estudio para el desarrollo de diagnósticos y tratamientos farmacológicos.', '[{"pregunta":"¿Qué son las enzimas desde el punto de vista químico?","opciones":["Lípidos","Catalizadores proteicos","Glúcidos","Ácidos nucleicos"],"correcta":1},{"pregunta":"¿Qué modelo describe la unión enzima-sustrato?","opciones":["Llave-cerradura rígido","Ajuste inducido","Difusión libre","Transporte activo"],"correcta":1},{"pregunta":"¿Qué factor NO afecta a la actividad enzimática?","opciones":["Temperatura","pH","Color del tubo","Concentración de sustrato"],"correcta":2},{"pregunta":"¿Qué enfermedad se relaciona con déficit enzimático?","opciones":["Fenilcetonuria","Gripe","Varicela","Sarampión"],"correcta":0}]'::jsonb),

('biologia', 'bachillerato', '{1}', 'Los virus: entre lo vivo y lo inerte', 'Los virus son entidades biológicas de naturaleza singular que han desafiado la definición tradicional de ser vivo. Carecen de estructura celular y están formados por un núcleo de material genético, ARN o ADN, rodeado por una cápsida proteica, y en algunos casos por una envoltura lipídica procedente de la membrana de su célula hospedadora. Son parásitos obligados, incapaces de reproducirse por sí mismos, pues necesitan infectar células vivas para utilizar su maquinaria molecular y sintetizar nuevas copias virales. El ciclo infectivo comienza con la adhesión del virus a receptores específicos de la superficie celular, continúa con la penetración del material genético, su replicación, el ensamblaje de nuevas partículas y, finalmente, su liberación, que suele destruir la célula en los ciclos líticos. Algunos virus pueden integrarse en el genoma del hospedador y permanecer latentes durante largos periodos, como ocurre en el ciclo lisogénico. Son responsables de numerosas enfermedades humanas, animales y vegetales, desde la gripe estacional hasta el sida o la covid-19. Su estudio, sin embargo, también ha aportado herramientas fundamentales para la biología molecular y para el desarrollo de vacunas, terapias génicas y vectores de modificación genética.', '[{"pregunta":"¿Qué estructura envuelve el material genético del virus?","opciones":["Pared celular","Cápsida proteica","Membrana nuclear","Cloroplasto"],"correcta":1},{"pregunta":"¿Por qué los virus son parásitos obligados?","opciones":["Tienen mitocondrias","No pueden replicarse sin una célula hospedadora","Hacen fotosíntesis","Se mueven con flagelos"],"correcta":1},{"pregunta":"¿Qué ocurre en el ciclo lisogénico?","opciones":["El virus destruye la célula inmediatamente","Se integra en el genoma del hospedador","Se dispersa por el aire","Se convierte en bacteria"],"correcta":1},{"pregunta":"¿Qué aplicación positiva tiene el estudio de virus?","opciones":["Vacunas y terapia génica","Fabricación de plásticos","Cultivo de minerales","Desalación del agua"],"correcta":0}]'::jsonb),

('biologia', 'bachillerato', '{1}', 'El sistema inmunitario y la defensa del organismo', 'El sistema inmunitario es el conjunto de órganos, tejidos y células que protegen al organismo frente a agentes patógenos y sustancias extrañas. Se compone de dos líneas principales de defensa: la inmunidad innata y la adaptativa. La inmunidad innata actúa de forma rápida e inespecífica e incluye barreras físicas como la piel y las mucosas, así como células fagocíticas como los macrófagos y los neutrófilos, capaces de reconocer patrones moleculares característicos de microorganismos. La respuesta inflamatoria, con su típico enrojecimiento, calor, hinchazón y dolor, es una de sus manifestaciones más evidentes. La inmunidad adaptativa, propia de vertebrados, se basa en linfocitos B y T que reconocen antígenos específicos y generan memoria inmunológica, lo que permite respuestas más rápidas y eficaces ante un segundo contacto con el mismo patógeno. Los linfocitos B producen anticuerpos, mientras que los T colaboran en la coordinación de la respuesta o eliminan células infectadas. Las vacunas aprovechan este principio al introducir antígenos atenuados o inactivados para estimular la generación de memoria sin provocar la enfermedad. Alteraciones del sistema inmunitario pueden dar lugar a alergias, enfermedades autoinmunes o inmunodeficiencias, con consecuencias clínicas muy diversas.', '[{"pregunta":"¿Qué caracteriza a la inmunidad innata?","opciones":["Respuesta específica y memoria","Actuación rápida e inespecífica","Solo en invertebrados","Solo produce anticuerpos"],"correcta":1},{"pregunta":"¿Qué células producen los anticuerpos?","opciones":["Linfocitos T","Linfocitos B","Eritrocitos","Plaquetas"],"correcta":1},{"pregunta":"¿En qué se basa la eficacia de las vacunas?","opciones":["Eliminar el sistema inmunitario","Crear memoria inmunológica","Destruir los anticuerpos","Reducir la inflamación"],"correcta":1},{"pregunta":"¿Qué enfermedad NO es del sistema inmunitario?","opciones":["Alergia","Esclerosis múltiple","Diabetes tipo 1","Fractura ósea"],"correcta":3}]'::jsonb),

('biologia', 'bachillerato', '{1}', 'Los ecosistemas y los flujos de energía', 'Un ecosistema es un sistema natural formado por el conjunto de seres vivos (biocenosis) que habitan un lugar determinado (biotopo) y por las interacciones que establecen entre sí y con los factores ambientales. La energía fluye a través del ecosistema de manera unidireccional, desde el Sol hasta los productores primarios, que captan la energía luminosa mediante la fotosíntesis y la transforman en materia orgánica. Los consumidores, a su vez, obtienen energía al alimentarse de otros organismos, configurándose así las cadenas y redes tróficas. La transferencia de energía entre niveles tróficos es siempre incompleta, ya que en cada escalón se pierde una parte considerable en forma de calor metabólico, lo que explica la regla aproximada del diez por ciento y la limitación del número de niveles de una cadena. A diferencia de la energía, la materia circula en ciclos biogeoquímicos cerrados que incluyen componentes atmosféricos, litosféricos e hidrosféricos. Los ecosistemas se encuentran sometidos a procesos dinámicos como la sucesión ecológica y pueden verse alterados por perturbaciones naturales o por la actividad humana. La conservación de la biodiversidad es esencial para mantener la estabilidad y la resiliencia de estos sistemas ante cambios globales.', '[{"pregunta":"¿Qué componentes forman un ecosistema?","opciones":["Solo plantas y animales","Biocenosis y biotopo","Solo seres vivos","Solo factores físicos"],"correcta":1},{"pregunta":"¿Cómo fluye la energía en un ecosistema?","opciones":["En ciclos cerrados","De forma unidireccional","En círculos","Al azar"],"correcta":1},{"pregunta":"¿Qué porcentaje aproximado de energía pasa entre niveles?","opciones":["100%","50%","10%","1%"],"correcta":2},{"pregunta":"¿Qué circula en ciclos cerrados?","opciones":["La energía","La materia","Solo el agua","Solo el calor"],"correcta":1}]'::jsonb),

('biologia', 'bachillerato', '{1}', 'La evolución y la selección natural', 'La teoría de la evolución, formulada en su versión moderna por Charles Darwin y Alfred Russel Wallace en el siglo XIX, constituye el marco explicativo central de la biología actual. Sostiene que todas las especies existentes proceden de ancestros comunes y que los cambios se producen a lo largo del tiempo mediante la actuación de diversos mecanismos. El principal es la selección natural, que favorece a los individuos mejor adaptados a su entorno, permitiéndoles sobrevivir y reproducirse con mayor éxito. Esta ventaja reproductiva incrementa la frecuencia de sus alelos en la población y, a lo largo de generaciones, conduce a cambios evolutivos. La variabilidad necesaria sobre la que actúa la selección procede de mutaciones y de la recombinación genética durante la reproducción sexual. Junto a la selección, operan otros factores como la deriva genética, especialmente importante en poblaciones pequeñas, la migración y el aislamiento reproductivo, que puede dar origen a nuevas especies. El registro fósil, la embriología comparada, la biogeografía y la biología molecular aportan pruebas convergentes del carácter evolutivo de la vida. La síntesis moderna integra la teoría darwiniana con la genética mendeliana y constituye una herramienta imprescindible para comprender la diversidad biológica y la historia de los seres vivos.', '[{"pregunta":"¿Quién propuso la teoría de la selección natural?","opciones":["Mendel","Darwin y Wallace","Lamarck","Linneo"],"correcta":1},{"pregunta":"¿De dónde procede la variabilidad sobre la que actúa la selección?","opciones":["Solo del ambiente","Mutaciones y recombinación","Solo del clima","Solo de la edad"],"correcta":1},{"pregunta":"¿Qué es la deriva genética?","opciones":["Selección dirigida","Cambio aleatorio de frecuencias alélicas","Migración masiva","Mutación inducida"],"correcta":1},{"pregunta":"¿Qué NO es prueba de la evolución?","opciones":["Registro fósil","Embriología comparada","Biología molecular","Estructura atómica"],"correcta":3}]'::jsonb),

('biologia', 'bachillerato', '{1}', 'La bioquímica de los glúcidos', 'Los glúcidos, también llamados hidratos de carbono, son biomoléculas orgánicas compuestas por carbono, hidrógeno y oxígeno, con una función fundamentalmente energética y estructural. Se clasifican según su complejidad en monosacáridos, oligosacáridos y polisacáridos. Los monosacáridos, como la glucosa o la fructosa, son azúcares sencillos solubles en agua que constituyen la unidad básica del resto de glúcidos. La glucosa, en particular, es una fuente de energía esencial para la mayoría de las células y el sustrato principal de la respiración celular. Los oligosacáridos resultan de la unión de pocas unidades de monosacáridos mediante enlaces glucosídicos; ejemplos comunes son la sacarosa, la lactosa y la maltosa. Los polisacáridos son polímeros de gran tamaño con funciones diversas: el almidón almacena energía en las plantas, el glucógeno cumple la misma función en animales y la celulosa aporta soporte estructural a las paredes vegetales. Además de estas funciones, los glúcidos participan en el reconocimiento celular al formar glucoproteínas y glucolípidos, así como en la formación del ácido desoxirribonucleico, pues la desoxirribosa es un monosacárido. Su metabolismo está finamente regulado por hormonas como la insulina, cuya alteración provoca enfermedades como la diabetes.', '[{"pregunta":"¿Cuál es la unidad básica de los glúcidos?","opciones":["Aminoácido","Monosacárido","Nucleótido","Ácido graso"],"correcta":1},{"pregunta":"¿Qué función cumple la celulosa?","opciones":["Energética","Estructural vegetal","Hormonal","Transporte de oxígeno"],"correcta":1},{"pregunta":"¿Qué tipo de enlace une monosacáridos?","opciones":["Peptídico","Glucosídico","Fosfodiéster","Disulfuro"],"correcta":1},{"pregunta":"¿Qué hormona regula la glucosa en sangre?","opciones":["Tiroxina","Insulina","Adrenalina","Melatonina"],"correcta":1}]'::jsonb),

('biologia', 'bachillerato', '{1}', 'Los lípidos y sus funciones biológicas', 'Los lípidos son un grupo heterogéneo de biomoléculas caracterizadas por su insolubilidad en agua y su solubilidad en disolventes orgánicos. Desempeñan funciones biológicas muy variadas: energéticas, estructurales, hormonales, protectoras y de reserva. Los triglicéridos, formados por glicerina y tres ácidos grasos, constituyen la principal reserva energética animal al aportar más del doble de energía por gramo que los glúcidos. Los fosfolípidos son la base estructural de las membranas celulares, gracias a su carácter anfipático que permite la formación de bicapas. Los esteroides, como el colesterol y las hormonas sexuales, derivan del núcleo esterano y participan en la regulación fisiológica y en la estabilización de las membranas. Las ceras cumplen funciones impermeabilizantes en la superficie de plantas y animales. Otros lípidos, como las vitaminas liposolubles A, D, E y K o los eicosanoides, tienen funciones reguladoras esenciales. La distinción entre ácidos grasos saturados e insaturados es relevante para la salud humana: los saturados, presentes sobre todo en grasas animales, se asocian a un mayor riesgo cardiovascular cuando se consumen en exceso, mientras que los insaturados, abundantes en aceites vegetales y pescados, tienen efectos más favorables en el perfil lipídico sanguíneo.', '[{"pregunta":"¿Qué característica define a los lípidos?","opciones":["Solubles en agua","Insolubles en agua","Siempre sólidos","Formados solo por C e H"],"correcta":1},{"pregunta":"¿Qué tipo de lípidos forman las membranas celulares?","opciones":["Ceras","Triglicéridos","Fosfolípidos","Terpenos"],"correcta":2},{"pregunta":"¿De qué núcleo derivan los esteroides?","opciones":["Glicerol","Esterano","Benceno","Purina"],"correcta":1},{"pregunta":"¿Qué vitaminas son liposolubles?","opciones":["B y C","A, D, E y K","C y B12","Solo B12"],"correcta":1}]'::jsonb),

('biologia', 'bachillerato', '{1}', 'La biodiversidad y su conservación', 'La biodiversidad o diversidad biológica es la variedad de formas de vida existentes en la Tierra a todos los niveles de organización: desde los genes hasta los ecosistemas pasando por las especies. Es el resultado de miles de millones de años de evolución y constituye uno de los patrimonios más valiosos del planeta. La biodiversidad tiene un valor intrínseco, pero también aporta servicios ecosistémicos esenciales para el ser humano, como la polinización de cultivos, la regulación del clima, la depuración del agua, la producción de oxígeno y el suministro de alimentos y medicamentos. A pesar de su importancia, se encuentra amenazada por diversos factores como la destrucción de hábitats, la contaminación, la introducción de especies invasoras, la sobreexplotación de recursos y, de manera creciente, el cambio climático. Muchos científicos consideran que estamos asistiendo a la sexta gran extinción masiva de la historia de la vida, con tasas de pérdida de especies muy superiores a las consideradas naturales. La conservación de la biodiversidad requiere políticas integradas que combinen la creación de espacios protegidos, la gestión sostenible de los recursos, la educación ambiental y la cooperación internacional. Los acuerdos globales y las estrategias regionales buscan frenar esta pérdida y avanzar hacia un desarrollo más sostenible.', '[{"pregunta":"¿A qué niveles se manifiesta la biodiversidad?","opciones":["Solo en especies","Solo en ecosistemas","Genes, especies y ecosistemas","Solo genes"],"correcta":2},{"pregunta":"¿Qué es un servicio ecosistémico?","opciones":["Un parque temático","Beneficio que los ecosistemas aportan al ser humano","Una reserva natural","Una ley ambiental"],"correcta":1},{"pregunta":"¿Cuál NO es una amenaza para la biodiversidad?","opciones":["Contaminación","Destrucción de hábitats","Cambio climático","Fotosíntesis"],"correcta":3},{"pregunta":"¿Qué se dice que vivimos actualmente?","opciones":["Sexta extinción masiva","Máxima biodiversidad","Era glacial","Época dorada"],"correcta":0}]'::jsonb);

