INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('dibujo-tecnico', 'bachillerato', '{1}', 'Los trazados fundamentales con regla y compás', 'Los trazados geométricos fundamentales constituyen la base del dibujo técnico y permiten resolver mediante regla y compás problemas como la división de segmentos, la construcción de perpendiculares y paralelas o la obtención de ángulos notables. El compás, inventado en la Antigüedad y perfeccionado a lo largo de los siglos, permite transportar distancias con precisión absoluta, mientras que la regla se limita al trazado de líneas rectas sin medir. Con estas dos herramientas pueden resolverse geométricamente numerosas construcciones, como la división de un segmento en partes iguales aplicando el teorema de Tales, o la construcción de polígonos regulares inscritos en una circunferencia. Un trazado correcto exige precisión en los centros de los arcos, elección adecuada de radios y ejecución cuidadosa de los puntos de intersección, que han de ser claramente identificables. El dibujo a lápiz requiere, además, una gradación adecuada de las líneas: líneas suaves y finas para las construcciones auxiliares y líneas más marcadas para el resultado final. El dominio de estos procedimientos resulta imprescindible antes de abordar ejercicios más complejos y permite comprender los fundamentos lógicos que sustentan las posteriores construcciones en sistemas de representación.', '[{"pregunta":"¿Qué permite hacer el compás con precisión?","opciones":["Medir ángulos","Transportar distancias","Trazar rectas sin medir","Pintar líneas"],"correcta":1},{"pregunta":"¿Qué teorema permite dividir un segmento en partes iguales?","opciones":["Pitágoras","Tales","Euclides","Herón"],"correcta":1},{"pregunta":"¿Cómo deben ser las líneas auxiliares?","opciones":["Gruesas y oscuras","Suaves y finas","Rojas","Discontinuas siempre"],"correcta":1},{"pregunta":"¿Qué se construye inscrito en una circunferencia?","opciones":["Puntos","Polígonos regulares","Curvas cónicas","Volumen"],"correcta":1}]'::jsonb),

('dibujo-tecnico', 'bachillerato', '{1}', 'Las transformaciones geométricas: traslación y giro', 'Las transformaciones geométricas son correspondencias que asocian a cada punto del plano otro punto, conservando determinadas propiedades. Las isometrías son transformaciones que mantienen las distancias y, por tanto, la forma y el tamaño de las figuras; entre ellas destacan la traslación, el giro y la simetría. La traslación desplaza todos los puntos una misma distancia en una dirección determinada, definida mediante un vector. Tras aplicarla, la figura resultante es idéntica a la original pero cambia de posición. El giro consiste en rotar los puntos respecto a un centro fijo un cierto ángulo, conservando las distancias al centro pero modificando las posiciones relativas. La simetría axial refleja los puntos respecto a una recta, mientras que la central lo hace respecto a un punto. Las homotecias y semejanzas, en cambio, no son isometrías porque modifican el tamaño de las figuras de manera proporcional, manteniendo la forma. Estas transformaciones son fundamentales no solo en matemáticas, sino también en dibujo técnico, arquitectura, diseño industrial y animación, donde se utilizan para generar composiciones simétricas, repetir motivos ornamentales o analizar la estructura de formas complejas. Su comprensión permite al dibujante tratar las figuras con flexibilidad y rigor.', '[{"pregunta":"¿Qué conservan las isometrías?","opciones":["Solo la forma","Forma y tamaño","Solo el color","Solo el área"],"correcta":1},{"pregunta":"¿Qué elemento define una traslación?","opciones":["Un ángulo","Un vector","Un punto fijo","Una recta"],"correcta":1},{"pregunta":"¿En qué transformación hay un centro de giro?","opciones":["Traslación","Giro","Homotecia","Simetría axial"],"correcta":1},{"pregunta":"¿Qué transformación NO es isometría?","opciones":["Simetría","Traslación","Homotecia","Giro"],"correcta":2}]'::jsonb),

('dibujo-tecnico', 'bachillerato', '{1}', 'Los polígonos regulares y su construcción', 'Un polígono regular es aquel cuyos lados tienen la misma longitud y cuyos ángulos interiores son iguales entre sí. Los polígonos regulares se pueden inscribir en una circunferencia, siendo su centro el punto equidistante de todos los vértices. Desde la Antigüedad, los matemáticos han estudiado los procedimientos para construirlos con regla y compás. Euclides, en sus Elementos, recogió métodos exactos para polígonos de tres, cuatro, cinco, seis y quince lados. Más tarde, el matemático alemán Carl Friedrich Gauss demostró que un polígono regular puede construirse con regla y compás solo si el número de lados es el producto de una potencia de dos y de primos de Fermat distintos. De este modo, existen polígonos cuya construcción exacta es imposible, como el heptágono, para los cuales se utilizan métodos aproximados. En dibujo técnico se distinguen dos tipos de procedimientos: los que parten del lado y los que parten de la circunferencia circunscrita. La elección del método depende de los datos del problema. Los polígonos regulares son omnipresentes en la arquitectura, la ornamentación y la naturaleza, como se aprecia en las celdillas hexagonales de los panales de abejas o en la disposición de ciertos cristales minerales.', '[{"pregunta":"¿Qué característica tienen los polígonos regulares?","opciones":["Lados y ángulos iguales","Solo lados iguales","Solo ángulos iguales","Forma irregular"],"correcta":0},{"pregunta":"¿Quién estudió las construcciones de polígonos regulares?","opciones":["Pitágoras y Tales","Euclides y Gauss","Newton","Leibniz"],"correcta":1},{"pregunta":"¿Qué polígono NO es construible exactamente con regla y compás?","opciones":["Triángulo","Hexágono","Heptágono","Cuadrado"],"correcta":2},{"pregunta":"¿Dónde encontramos hexágonos en la naturaleza?","opciones":["Plumas de aves","Panales de abejas","Escamas de peces","Flores de loto"],"correcta":1}]'::jsonb),

('dibujo-tecnico', 'bachillerato', '{1}', 'Tangencias y enlaces entre rectas y circunferencias', 'Los problemas de tangencia y enlace constituyen uno de los capítulos más característicos del dibujo técnico por su aplicación en el diseño de piezas mecánicas, carrocerías y elementos arquitectónicos. Una tangencia se produce cuando una recta y una circunferencia, o dos circunferencias, se tocan en un único punto denominado punto de tangencia. La resolución de estos ejercicios se basa en unas pocas propiedades fundamentales: el radio es perpendicular a la recta tangente en el punto de contacto, y los centros de dos circunferencias tangentes están alineados con el punto de tangencia. A partir de estas propiedades pueden deducirse los lugares geométricos utilizados para localizar los centros y radios buscados. Un enlace es una tangencia utilizada con fines estéticos o funcionales: permite unir dos curvas o una curva y una recta sin cambios bruscos, lo que evita concentraciones de tensión en piezas mecánicas y proporciona una sensación visual de continuidad. El trazado correcto exige precisión en la determinación de los puntos de tangencia y cuidado en la ejecución, ya que cualquier desviación hace que la curva final parezca interrumpida. Dominar estas construcciones es imprescindible para afrontar proyectos profesionales en ingeniería y diseño.', '[{"pregunta":"¿Qué es un punto de tangencia?","opciones":["Intersección de dos rectas","Único punto de contacto entre curva y recta","Centro de simetría","Vértice de un polígono"],"correcta":1},{"pregunta":"¿Cómo es el radio respecto a la tangente?","opciones":["Paralelo","Perpendicular","Oblicuo","Indefinido"],"correcta":1},{"pregunta":"¿Para qué sirven los enlaces?","opciones":["Unir curvas sin cambios bruscos","Pintar figuras","Medir ángulos","Cortar piezas"],"correcta":0},{"pregunta":"¿Dónde están los centros de dos circunferencias tangentes?","opciones":["En lados opuestos","Alineados con el punto de tangencia","Sin relación","Siempre coincidentes"],"correcta":1}]'::jsonb),

('dibujo-tecnico', 'bachillerato', '{1}', 'Los lugares geométricos en dibujo técnico', 'Un lugar geométrico es el conjunto de puntos del plano que cumplen una determinada condición geométrica. El concepto, aparentemente abstracto, resulta de extraordinaria utilidad en el dibujo técnico porque proporciona un método sistemático para resolver problemas en los que es necesario encontrar un punto o una serie de puntos que satisfacen varias condiciones simultáneamente. Por ejemplo, la mediatriz de un segmento es el lugar geométrico de los puntos equidistantes de sus extremos, mientras que la bisectriz de un ángulo es el lugar de los puntos equidistantes de sus lados. La circunferencia es el lugar geométrico de los puntos que distan una distancia fija de un centro, y el arco capaz es el lugar de los puntos desde los cuales un segmento se ve bajo un ángulo determinado. La intersección de dos lugares geométricos permite localizar con precisión los puntos que cumplen ambas condiciones, facilitando la resolución de ejercicios sobre tangencias, construcciones de triángulos, cuadriláteros o polígonos. Trabajar con lugares geométricos exige un razonamiento abstracto que combina la observación gráfica con el rigor lógico, lo que contribuye a desarrollar en el estudiante la capacidad para plantear problemas y elegir la estrategia más adecuada para resolverlos.', '[{"pregunta":"¿Qué es la mediatriz de un segmento?","opciones":["Recta paralela al segmento","Conjunto de puntos equidistantes de los extremos","Bisectriz de un ángulo","Circunferencia auxiliar"],"correcta":1},{"pregunta":"¿De qué es lugar geométrico la circunferencia?","opciones":["Puntos con suma constante","Puntos equidistantes a un centro","Puntos alineados","Puntos en el plano"],"correcta":1},{"pregunta":"¿Qué es el arco capaz?","opciones":["Puntos desde los que se ve un segmento bajo igual ángulo","Bisectriz de un arco","Arco máximo","Arco mínimo"],"correcta":0},{"pregunta":"¿Para qué sirve intersecar lugares geométricos?","opciones":["Encontrar puntos con varias condiciones","Dibujar volúmenes","Medir áreas","Pintar caras"],"correcta":0}]'::jsonb),

('dibujo-tecnico', 'bachillerato', '{1}', 'La proporción áurea en el arte y el diseño', 'La proporción áurea, también llamada número de oro y representada por la letra griega phi, es una relación matemática cuyo valor aproximado es 1,618. Se obtiene cuando la razón entre la longitud total de un segmento y su parte mayor es igual a la razón entre la parte mayor y la parte menor. Esta proporción ha fascinado a matemáticos, artistas y arquitectos desde la Antigüedad por asociarse a una estética equilibrada y armónica. Los griegos la utilizaron en la construcción del Partenón, y pintores renacentistas como Leonardo da Vinci o arquitectos como Le Corbusier la incorporaron a sus obras de manera consciente. El número áureo se relaciona estrechamente con la sucesión de Fibonacci, cuyas divisiones sucesivas tienden a phi a medida que se avanza en la serie. Aparece también en la naturaleza, desde la disposición de las hojas en ciertas plantas hasta la espiral de las conchas de algunos moluscos. En el dibujo técnico, el rectángulo áureo permite construir composiciones armónicas y es base para otras figuras como la espiral áurea. Aunque su uso se asocia a la belleza, conviene recordar que no se trata de una regla universal del gusto, sino de un recurso entre otros para estructurar proporciones.', '[{"pregunta":"¿Cuál es el valor aproximado del número áureo?","opciones":["1,414","1,618","2,718","3,141"],"correcta":1},{"pregunta":"¿Con qué sucesión se relaciona?","opciones":["Pell","Fibonacci","Aritmética","Geométrica"],"correcta":1},{"pregunta":"¿En qué monumento clásico aparece?","opciones":["Coliseo","Partenón","Alhambra","Pirámides"],"correcta":1},{"pregunta":"¿Es el número áureo una regla universal del gusto?","opciones":["Sí siempre","No, es un recurso entre otros","Solo en arquitectura","Solo en pintura"],"correcta":1}]'::jsonb),

('dibujo-tecnico', 'bachillerato', '{1}', 'El sistema axonométrico ortogonal', 'El sistema axonométrico ortogonal es un método de representación que permite obtener vistas tridimensionales de un objeto mediante la proyección de sus puntos sobre un plano de proyección inclinado respecto a los tres ejes del espacio. Estos ejes, perpendiculares entre sí, se designan habitualmente como X, Y y Z y, al proyectarse sobre el plano, forman un triángulo de trazas que determina la forma del sistema. Según la inclinación relativa, se distinguen tres variantes: la axonometría isométrica, en la que los ángulos entre los ejes proyectados son iguales a 120 grados y los coeficientes de reducción coinciden; la dimétrica, con dos ejes iguales y uno diferente; y la trimétrica, con los tres ejes diferentes. La axonometría isométrica es la más utilizada en dibujo técnico por su simplicidad y por la uniformidad de las medidas. Ofrece una representación clara y rápida de piezas mecánicas y construcciones arquitectónicas sencillas, aunque introduce ciertas deformaciones visuales debido a que no reproduce el efecto de perspectiva real. Para obtener resultados precisos, es necesario manejar los coeficientes de reducción, que permiten pasar de las medidas reales a las del dibujo y evitar distorsiones incorrectas de las proporciones del objeto representado.', '[{"pregunta":"¿Qué ángulos forma la isometría entre sus ejes?","opciones":["60°","90°","120°","135°"],"correcta":2},{"pregunta":"¿Qué variante tiene los tres ejes diferentes?","opciones":["Isométrica","Dimétrica","Trimétrica","Oblicua"],"correcta":2},{"pregunta":"¿Por qué es popular la axonometría isométrica?","opciones":["Es más realista que la perspectiva cónica","Simplicidad y uniformidad de medidas","Usa colores","No deforma nada"],"correcta":1},{"pregunta":"¿Qué permiten los coeficientes de reducción?","opciones":["Pasar de medidas reales a las del dibujo","Calcular áreas","Medir ángulos","Dividir segmentos"],"correcta":0}]'::jsonb),

('dibujo-tecnico', 'bachillerato', '{1}', 'La perspectiva cónica: principios generales', 'La perspectiva cónica es el sistema de representación que reproduce de manera más fiel la visión humana del espacio tridimensional, ya que se basa en las leyes ópticas del ojo. Sus fundamentos fueron desarrollados en el Renacimiento italiano por artistas y arquitectos como Filippo Brunelleschi y Leon Battista Alberti, que establecieron las reglas para representar objetos con profundidad en superficies planas. En este sistema, el observador se sitúa en un punto fijo denominado punto de vista, y las proyecciones de los elementos convergen hacia uno o varios puntos de fuga situados sobre la línea del horizonte. Dependiendo del número de puntos de fuga, se distingue entre perspectiva cónica frontal, con un único punto de fuga, y perspectiva cónica oblicua, con dos o tres puntos. Los elementos característicos del sistema incluyen el plano del cuadro, la línea de tierra y la línea del horizonte. Aunque la perspectiva cónica ofrece una imagen muy realista, introduce deformaciones que hacen que las medidas del dibujo no puedan tomarse directamente del objeto representado, lo que limita su uso en dibujo técnico profesional frente a sistemas más medibles como el diédrico. Su uso es, sin embargo, esencial en arquitectura y en representación artística.', '[{"pregunta":"¿En qué época se desarrollaron las reglas de la perspectiva cónica?","opciones":["Edad Media","Renacimiento","Neoclasicismo","Siglo XX"],"correcta":1},{"pregunta":"¿Dónde convergen las líneas en este sistema?","opciones":["En el eje central","En los puntos de fuga","En los vértices","En el plano del cuadro"],"correcta":1},{"pregunta":"¿Qué tipo de perspectiva tiene dos puntos de fuga?","opciones":["Frontal","Oblicua","Isométrica","Axonométrica"],"correcta":1},{"pregunta":"¿Por qué no se usa mucho en dibujo técnico?","opciones":["Es poco realista","Introduce deformaciones difíciles de medir","Es muy rápida","Usa colores"],"correcta":1}]'::jsonb),

('dibujo-tecnico', 'bachillerato', '{1}', 'Escalas y dimensionado en dibujo técnico', 'La escala es la relación constante entre las dimensiones del dibujo y las dimensiones reales del objeto representado. Su uso es imprescindible cuando las piezas, edificios o planos son demasiado grandes o demasiado pequeños como para dibujarse a tamaño natural sobre una hoja de papel. Se distinguen tres tipos principales: la escala natural, de relación 1:1, utilizada cuando el objeto y el dibujo coinciden en dimensiones; la escala de reducción, en la que el dibujo es menor que el objeto real, como sucede en los planos de arquitectura; y la escala de ampliación, en la que el dibujo es mayor que el objeto, como en el dibujo de piezas electrónicas minúsculas. Además de las escalas numéricas, existen las escalas gráficas, representadas mediante reglas divididas que permiten medir directamente longitudes sobre el plano sin necesidad de cálculos. El acotado consiste en indicar las dimensiones reales del objeto mediante líneas auxiliares, líneas de cota, flechas y cifras colocadas según las normas establecidas. Un buen acotado debe ser completo, preciso y no redundante, y ha de respetar las convenciones para que cualquier profesional pueda interpretar correctamente el dibujo. La combinación de escala y acotado es esencial para comunicar información técnica sin ambigüedades.', '[{"pregunta":"¿Qué es la escala natural?","opciones":["Dibujo mayor que el objeto","Dibujo 1:1","Dibujo menor","Dibujo inexistente"],"correcta":1},{"pregunta":"¿Cuándo se usa la escala de ampliación?","opciones":["Planos de edificios","Mapas","Piezas minúsculas","Paisajes"],"correcta":2},{"pregunta":"¿Qué son las escalas gráficas?","opciones":["Reglas divididas impresas en el plano","Colores","Cifras aisladas","Figuras decorativas"],"correcta":0},{"pregunta":"¿Cómo debe ser un buen acotado?","opciones":["Redundante","Completo, preciso y no redundante","Decorativo","Aproximado"],"correcta":1}]'::jsonb),

('dibujo-tecnico', 'bachillerato', '{1}', 'Vistas diédricas: alzado, planta y perfil', 'El sistema diédrico ortogonal es la base de la representación técnica y utiliza habitualmente tres vistas principales para describir un objeto: el alzado, la planta y el perfil. El alzado muestra la vista frontal del objeto, el perfil ofrece la vista lateral y la planta corresponde a la vista superior. Estas tres proyecciones, combinadas, permiten reconstruir mentalmente el volumen del objeto y proporcionan una información completa sobre sus dimensiones y formas. La disposición de las vistas en el dibujo sigue normas estrictas. En el sistema europeo, establecido por la norma ISO, el alzado se sitúa en el centro, la planta debajo y el perfil a la derecha, mientras que en el sistema americano las posiciones de planta y perfil se invierten. Es fundamental mantener la correspondencia entre vistas: los puntos de un mismo elemento deben alinearse entre alzado y planta verticalmente y entre alzado y perfil horizontalmente. Cuando una pieza presenta detalles ocultos, se representan con líneas discontinuas para distinguirlas de las visibles. Además de las tres vistas principales, pueden emplearse vistas auxiliares, secciones y cortes para mostrar partes que no son visibles desde los planos habituales, especialmente en piezas complejas de maquinaria e ingeniería.', '[{"pregunta":"¿Qué vista es la frontal?","opciones":["Alzado","Planta","Perfil","Sección"],"correcta":0},{"pregunta":"¿Qué muestra la planta?","opciones":["Vista lateral","Vista frontal","Vista superior","Vista posterior"],"correcta":2},{"pregunta":"¿Cómo se representan las aristas ocultas?","opciones":["Líneas gruesas","Líneas discontinuas","Colores","Puntos"],"correcta":1},{"pregunta":"¿Qué norma regula el sistema europeo?","opciones":["ISO","ANSI","DIN","UL"],"correcta":0}]'::jsonb),

('dibujo-tecnico', 'bachillerato', '{1}', 'Cortes y secciones en el sistema diédrico', 'En ingeniería y arquitectura es frecuente que las piezas presenten detalles interiores que no pueden apreciarse desde las vistas exteriores. Para representar estos detalles de forma clara, el dibujo técnico utiliza los cortes y las secciones, que consisten en imaginar que el objeto es atravesado por uno o varios planos, retirando una parte para dejar visible el interior. La sección representa únicamente la zona del plano que interseca al objeto, mientras que el corte muestra, además, lo que queda detrás de ese plano. Los cortes se dibujan aplicando sobre las superficies cortadas un rayado inclinado, uniforme y regular, generalmente a 45 grados, que indica que se trata de material seccionado. Existen diferentes tipos de cortes: el corte total, que atraviesa la pieza completamente; el corte por medio, que se aplica a piezas simétricas para mostrar mitad interior y mitad exterior; el corte parcial, para detallar solo una zona concreta; y los cortes por planos paralelos o concurrentes para piezas con detalles en varias direcciones. Las normas regulan la forma de indicar los planos de corte en las vistas y los símbolos que deben acompañarlos, de modo que el dibujo sea interpretable por cualquier técnico.', '[{"pregunta":"¿Para qué sirven los cortes y secciones?","opciones":["Colorear piezas","Mostrar detalles interiores","Reducir dimensiones","Doblar planos"],"correcta":1},{"pregunta":"¿Qué diferencia un corte de una sección?","opciones":["El corte muestra también lo que queda detrás","No hay diferencia","El corte es más pequeño","La sección es tridimensional"],"correcta":0},{"pregunta":"¿Cómo se marcan las superficies cortadas?","opciones":["Líneas punteadas","Rayado inclinado uniforme","Sombra","Trama de puntos"],"correcta":1},{"pregunta":"¿Qué tipo de corte se usa en piezas simétricas?","opciones":["Total","Por medio","Parcial","Concurrente"],"correcta":1}]'::jsonb),

('dibujo-tecnico', 'bachillerato', '{1}', 'El dibujo asistido por ordenador (CAD)', 'El dibujo asistido por ordenador, conocido como CAD por sus siglas en inglés, es el conjunto de tecnologías que permiten crear, modificar y analizar dibujos técnicos mediante programas informáticos. Sus orígenes se remontan a los años sesenta del siglo XX, cuando aparecieron los primeros sistemas para diseño industrial en grandes empresas. Hoy en día, el CAD es una herramienta imprescindible en ingeniería, arquitectura, diseño gráfico y ciencias aplicadas. Frente al dibujo manual, ofrece ventajas evidentes: mayor precisión, facilidad para modificar y copiar elementos, posibilidad de trabajar en dos y tres dimensiones, generación automática de vistas y cortes, y compatibilidad con otros programas de análisis como los de simulación o fabricación asistida. Los programas más extendidos permiten construir modelos paramétricos en los que cualquier cambio en una dimensión se propaga automáticamente a todas las partes del dibujo. La transición del dibujo manual al digital ha transformado profundamente la formación y el trabajo de los profesionales, pero no ha hecho desaparecer la necesidad de comprender los fundamentos geométricos, ya que el ordenador ejecuta las instrucciones que el usuario introduce. Sin una base sólida de dibujo técnico, incluso las herramientas más sofisticadas pierden buena parte de su utilidad.', '[{"pregunta":"¿Qué significan las siglas CAD?","opciones":["Control Automático Dinámico","Dibujo Asistido por Ordenador (en inglés)","Centro de Análisis y Diseño","Cálculo Acotado Digital"],"correcta":1},{"pregunta":"¿Cuándo aparecieron los primeros CAD?","opciones":["Años 20","Años 60","Años 90","Siglo XIX"],"correcta":1},{"pregunta":"¿Qué ventaja NO ofrece el CAD frente al dibujo manual?","opciones":["Precisión","Facilidad para modificar","Sustituir el pensamiento geométrico","Generar vistas automáticas"],"correcta":2},{"pregunta":"¿Qué es un modelo paramétrico?","opciones":["Dibujo a mano","Modelo que actualiza automáticamente las dimensiones","Figura estática","Imagen JPG"],"correcta":1}]'::jsonb),

('dibujo-tecnico', 'bachillerato', '{1}', 'Los poliedros regulares y su estudio', 'Los poliedros regulares son figuras tridimensionales cuyas caras son polígonos regulares iguales y en los que confluye el mismo número de caras en cada vértice. Existen únicamente cinco, los llamados sólidos platónicos, ya conocidos por los griegos: el tetraedro, con cuatro caras triangulares; el cubo o hexaedro, con seis caras cuadradas; el octaedro, con ocho caras triangulares; el dodecaedro, con doce caras pentagonales; y el icosaedro, con veinte caras triangulares. Platón los asoció simbólicamente con los elementos clásicos: fuego, tierra, aire, éter y agua respectivamente, y consideraba que reflejaban la perfección del cosmos. Desde un punto de vista matemático, cumplen la célebre fórmula de Euler, según la cual el número de vértices más el número de caras menos el número de aristas es siempre igual a dos. Los poliedros regulares aparecen en numerosos contextos: estructuras moleculares, cristales minerales, juegos de rol y diseño. En el dibujo técnico se utilizan frecuentemente como ejercicios introductorios a la representación en sistemas axonométrico, diédrico y cónico, pues su simetría facilita el aprendizaje y permite al estudiante familiarizarse con las técnicas de proyección antes de abordar figuras más complejas y menos regulares.', '[{"pregunta":"¿Cuántos poliedros regulares existen?","opciones":["Tres","Cinco","Ocho","Infinitos"],"correcta":1},{"pregunta":"¿Qué caras tiene el dodecaedro?","opciones":["Triángulos","Cuadrados","Pentágonos","Hexágonos"],"correcta":2},{"pregunta":"¿Qué establece la fórmula de Euler?","opciones":["V + C - A = 2","V - C + A = 0","V*C = A","V = C"],"correcta":0},{"pregunta":"¿Quién asoció los poliedros a los elementos clásicos?","opciones":["Aristóteles","Platón","Arquímedes","Euclides"],"correcta":1}]'::jsonb),

('dibujo-tecnico', 'bachillerato', '{1}', 'Las curvas técnicas: óvalos y ovoides', 'Además de las curvas cónicas y las espirales, el dibujo técnico utiliza otras curvas aproximadas obtenidas a partir de arcos de circunferencia. Entre ellas destacan los óvalos y los ovoides. Un óvalo es una curva cerrada, simétrica respecto a dos ejes perpendiculares, que se asemeja a una elipse pero se construye enlazando arcos de circunferencia de diferentes radios. La elipse, en cambio, es una curva matemáticamente definida por la suma constante de distancias a dos focos, por lo que no puede construirse con regla y compás de manera exacta. Cuando en el dibujo técnico es suficiente una aproximación, el óvalo ofrece una solución práctica que se construye con métodos sencillos a partir del eje mayor o menor. El ovoide, por su parte, es una curva también cerrada pero que presenta simetría respecto a un único eje, lo que le da la forma característica de un huevo. Se utiliza con frecuencia en arquitectura, diseño industrial y decoración. Tanto óvalos como ovoides son aproximaciones geométricas útiles para bocetos rápidos o para piezas donde la precisión matemática no es esencial. Su uso no sustituye a la elipse verdadera, pero permite al técnico resolver problemas cotidianos con mayor rapidez.', '[{"pregunta":"¿Cómo se construye un óvalo?","opciones":["Con arcos de circunferencia enlazados","Con línea recta","Con elipses reales","Con cónicas"],"correcta":0},{"pregunta":"¿Qué diferencia un óvalo de una elipse?","opciones":["La elipse es curva matemática real","Son iguales","El óvalo tiene focos","La elipse es cerrada"],"correcta":0},{"pregunta":"¿Cuántos ejes de simetría tiene un ovoide?","opciones":["Uno","Dos","Tres","Ninguno"],"correcta":0},{"pregunta":"¿Cuándo conviene usar un óvalo?","opciones":["Precisión absoluta","Aproximación práctica","Solo arquitectura","Solo pintura"],"correcta":1}]'::jsonb),

('dibujo-tecnico', 'bachillerato', '{1}', 'La historia del dibujo técnico', 'El dibujo técnico como disciplina formalizada es fruto de una larga evolución histórica. Sus raíces se hallan en los dibujos de los ingenieros, arquitectos y artesanos de la Antigüedad, que necesitaban representar sobre un soporte plano los edificios, mecanismos y utensilios que imaginaban construir. Los papiros egipcios contienen ya croquis acotados de proyectos constructivos, y los romanos dejaron testimonios gráficos de sus obras hidráulicas y militares. En la Edad Media, los constructores de catedrales utilizaban plantillas y trazados sobre el suelo para transferir los diseños a la piedra. El Renacimiento supuso un paso decisivo con la sistematización de la perspectiva por Brunelleschi y Alberti, y con los cuadernos de ingeniería de Leonardo da Vinci, que recogen cientos de dibujos de máquinas explicados gráficamente. En el siglo XVIII, el matemático francés Gaspard Monge desarrolló la geometría descriptiva y estableció las bases del sistema diédrico, convirtiéndolo en un método riguroso y universal. Desde entonces, el dibujo técnico ha ido incorporando nuevas herramientas, desde la reglafónda y el compás hasta los ordenadores modernos, pero conservando su misión esencial: comunicar con precisión las ideas de los técnicos para que puedan ser materializadas sin ambigüedades.', '[{"pregunta":"¿Qué civilización antigua ya usaba croquis acotados?","opciones":["Egipcia","Nórdica","Maya","Minoica"],"correcta":0},{"pregunta":"¿Quién sistematizó la geometría descriptiva?","opciones":["Leonardo","Brunelleschi","Monge","Euclides"],"correcta":2},{"pregunta":"¿Qué destacó en el Renacimiento?","opciones":["Perspectiva y cuadernos de Leonardo","Axonometría","Dibujo digital","Fotografía"],"correcta":0},{"pregunta":"¿Cuál es la misión esencial del dibujo técnico?","opciones":["Decorar","Comunicar ideas con precisión","Enseñar arte","Medir terrenos"],"correcta":1}]'::jsonb),

('dibujo-tecnico', 'bachillerato', '{1}', 'La simetría como principio compositivo', 'La simetría es uno de los principios compositivos más poderosos del dibujo técnico y artístico, y constituye un recurso esencial tanto para el análisis geométrico como para la creación de diseños equilibrados. Se puede definir como la correspondencia entre las partes de una figura respecto a un eje, un punto o un plano, de forma que los elementos situados a ambos lados mantengan la misma distancia y disposición. Según el tipo de elemento respecto al cual se establece, se habla de simetría axial, central o especular. En dibujo técnico se utiliza constantemente para simplificar trazados, ya que permite construir solo la mitad o la cuarta parte de una figura y replicar el resto mediante reflexión. En arquitectura y diseño, la simetría ha sido asociada tradicionalmente a la belleza, el orden y la solemnidad, como se aprecia en templos clásicos, iglesias renacentistas o fachadas neoclásicas. Sin embargo, muchos estilos artísticos modernos han buscado precisamente la asimetría como forma de expresión más dinámica. Además de su dimensión estética, la simetría desempeña un papel fundamental en la naturaleza, donde aparece en el cuerpo de muchos animales y plantas, en estructuras moleculares y en fenómenos físicos, conectando así la geometría con la realidad biológica y material.', '[{"pregunta":"¿Qué tipos principales de simetría existen?","opciones":["Axial, central y especular","Clara y oscura","Grande y pequeña","Libre y cerrada"],"correcta":0},{"pregunta":"¿Para qué se usa la simetría en dibujo?","opciones":["Complicar trazados","Simplificar construcciones","Solo decorar","Medir ángulos"],"correcta":1},{"pregunta":"¿Qué estilo ha buscado la asimetría?","opciones":["Neoclásico","Moderno","Renacentista","Románico"],"correcta":1},{"pregunta":"¿Dónde encontramos simetría en la naturaleza?","opciones":["Solo en plantas","En animales, plantas y moléculas","Solo en rocas","En ninguna parte"],"correcta":1}]'::jsonb),

('dibujo-tecnico', 'bachillerato', '{1}', 'El sistema acotado y su utilidad', 'El sistema acotado es un método de representación especial utilizado en topografía y cartografía para describir superficies irregulares como el relieve del terreno. Se basa en indicar junto a cada punto representado la cota o altura correspondiente, generalmente medida respecto al nivel del mar. A partir de una nube de puntos con sus cotas, se trazan las curvas de nivel, líneas imaginarias que unen puntos situados a la misma altitud. La observación de un mapa topográfico permite deducir con facilidad la forma del terreno: líneas muy próximas entre sí indican pendientes pronunciadas, mientras que líneas separadas corresponden a zonas más llanas. Las curvas de nivel cerradas representan montañas o depresiones, según la dirección de aumento o disminución de las cotas. Este sistema, desarrollado en el siglo XIX y perfeccionado con el paso del tiempo, es la base de la cartografía moderna y resulta imprescindible en la planificación de infraestructuras, el urbanismo, la geología y la gestión de riesgos naturales. La irrupción de herramientas digitales, como los modelos digitales del terreno obtenidos mediante satélites y sensores láser, ha ampliado enormemente las posibilidades de análisis, pero los principios fundamentales del sistema acotado siguen siendo los mismos desde hace más de un siglo.', '[{"pregunta":"¿Qué es una curva de nivel?","opciones":["Línea que une puntos con la misma altura","Río","Línea recta","Borde del mapa"],"correcta":0},{"pregunta":"¿Qué indican las líneas muy juntas en un mapa topográfico?","opciones":["Zonas llanas","Pendientes pronunciadas","Profundidades","Lagos"],"correcta":1},{"pregunta":"¿Dónde se usa principalmente el sistema acotado?","opciones":["Dibujo de piezas mecánicas","Topografía y cartografía","Diseño gráfico","Arquitectura de interiores"],"correcta":1},{"pregunta":"¿Qué amplió el sistema acotado recientemente?","opciones":["Modelos digitales del terreno","Reglas de madera","Papel vegetal","Tinta china"],"correcta":0}]'::jsonb);

