INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('economia', 'bachillerato', '{1}', 'La escasez y el problema económico', 'La economía es la ciencia social que estudia cómo las sociedades gestionan unos recursos que son limitados para satisfacer unas necesidades que, en la práctica, son ilimitadas. De esta tensión entre recursos escasos y deseos múltiples surge el llamado problema económico, que obliga a elegir entre alternativas y a renunciar a unas cosas para obtener otras. Toda decisión económica lleva asociado un coste de oportunidad, que es el valor de la mejor alternativa a la que se renuncia al tomar una decisión. La economía intenta responder a tres preguntas fundamentales: qué bienes y servicios producir, cómo producirlos y para quién producirlos. Las respuestas varían según el sistema económico adoptado, que puede ir desde una economía de mercado, en la que las decisiones se toman mayoritariamente a través de los precios, hasta una economía planificada, en la que es el Estado quien decide. En la práctica, la mayoría de los países combinan elementos de ambos sistemas en las llamadas economías mixtas, donde el mercado convive con la intervención pública. Reflexionar sobre estas cuestiones es el punto de partida para entender por qué los recursos se asignan de una manera determinada y cómo pueden mejorarse las decisiones a nivel individual y colectivo.', '[{"pregunta":"¿Qué es el coste de oportunidad?","opciones":["Precio de un producto","Valor de la mejor alternativa a la que se renuncia","Impuesto al consumo","Salario mínimo"],"correcta":1},{"pregunta":"¿Cuántas preguntas básicas plantea la economía?","opciones":["Dos","Tres","Cuatro","Cinco"],"correcta":1},{"pregunta":"¿Qué caracteriza a una economía mixta?","opciones":["Solo mercado","Solo Estado","Mezcla de mercado e intervención pública","Trueque puro"],"correcta":2},{"pregunta":"¿De dónde surge el problema económico?","opciones":["Recursos abundantes","Escasez frente a necesidades ilimitadas","Igualdad total","Inflación"],"correcta":1}]'::jsonb),

('economia', 'bachillerato', '{1}', 'La frontera de posibilidades de producción', 'La frontera de posibilidades de producción, abreviada como FPP, es una representación gráfica que muestra las combinaciones máximas de dos bienes que una economía puede producir con los recursos y la tecnología disponibles cuando todos sus factores están plenamente empleados. La FPP adopta generalmente una forma cóncava respecto al origen debido al principio de los costes de oportunidad crecientes: a medida que se destinan más recursos a producir un bien, los recursos adicionales que se trasladan resultan menos productivos en el nuevo uso, por lo que la cantidad del otro bien a la que se renuncia crece progresivamente. Los puntos situados sobre la curva son eficientes porque aprovechan todos los recursos disponibles, mientras que los interiores indican que existen recursos ociosos o mal utilizados. Los puntos exteriores, inalcanzables con la tecnología actual, solo pueden conseguirse si aumentan los recursos o mejora la productividad. Cuando la economía crece gracias a la inversión, la educación o el progreso tecnológico, la FPP se desplaza hacia fuera, permitiendo producir más de ambos bienes. Este modelo, aparentemente sencillo, permite entender conceptos fundamentales como la eficiencia, el coste de oportunidad, la escasez y el crecimiento económico, y es uno de los primeros instrumentos analíticos que se presentan en cualquier curso de introducción a la economía.', '[{"pregunta":"¿Qué representa la FPP?","opciones":["Precios de dos bienes","Combinaciones máximas de dos bienes con recursos dados","Impuestos","Tasa de paro"],"correcta":1},{"pregunta":"¿Qué indica un punto interior a la FPP?","opciones":["Eficiencia","Recursos ociosos","Crecimiento","Imposibilidad"],"correcta":1},{"pregunta":"¿Por qué la FPP es cóncava?","opciones":["Costes de oportunidad crecientes","Costes fijos","Tecnología infinita","Precios iguales"],"correcta":0},{"pregunta":"¿Cuándo se desplaza hacia fuera la FPP?","opciones":["Por crecimiento económico","Por recesión","Por desempleo","Por deuda pública"],"correcta":0}]'::jsonb),

('economia', 'bachillerato', '{1}', 'La elasticidad-precio de la demanda', 'La elasticidad-precio de la demanda es una medida económica que cuantifica la sensibilidad de la cantidad demandada de un bien ante cambios en su precio. Se calcula dividiendo la variación porcentual de la cantidad demandada entre la variación porcentual del precio. Si el valor absoluto del resultado es mayor que uno, la demanda es elástica: los consumidores reaccionan fuertemente a los cambios de precio. Si es menor que uno, la demanda es inelástica y las variaciones de precio apenas afectan a la cantidad consumida. Cuando es igual a uno, se habla de elasticidad unitaria. Diversos factores influyen en el grado de elasticidad de un bien. En primer lugar, la disponibilidad de sustitutos cercanos aumenta la elasticidad, pues los consumidores pueden cambiar fácilmente de producto. En segundo lugar, los bienes considerados esenciales tienden a ser inelásticos, mientras que los de lujo son más elásticos. También influyen el porcentaje de la renta que se destina al bien y el período de tiempo considerado, ya que a largo plazo los consumidores tienen más posibilidades de ajustar sus hábitos. Para las empresas, conocer la elasticidad es clave a la hora de fijar precios, ya que una subida puede incrementar los ingresos si la demanda es inelástica, pero reducirlos drásticamente si es elástica.', '[{"pregunta":"¿Qué mide la elasticidad-precio de la demanda?","opciones":["Inflación","Sensibilidad de la cantidad al precio","Coste de producción","Renta nacional"],"correcta":1},{"pregunta":"¿Qué es una demanda inelástica?","opciones":["Reacciona mucho al precio","Apenas reacciona al precio","No depende del precio","Depende del tiempo"],"correcta":1},{"pregunta":"¿Qué factor aumenta la elasticidad?","opciones":["Ser bien esencial","Tener sustitutos cercanos","Ser de primera necesidad","Bajo precio"],"correcta":1},{"pregunta":"¿Qué interesa a una empresa con demanda inelástica al subir precios?","opciones":["Aumentar ingresos","Reducir ingresos","Quebrar","Despedir"],"correcta":0}]'::jsonb),

('economia', 'bachillerato', '{1}', 'Los tipos de mercado: competencia y monopolio', 'Los mercados se clasifican según el número de empresas, la homogeneidad del producto y la facilidad de entrada y salida. En el extremo de mayor competencia se sitúa la competencia perfecta, un modelo teórico con un número muy elevado de empresas que ofrecen productos homogéneos, en el que ninguna puede influir sobre el precio y todas actúan como precio-aceptantes. En el extremo opuesto encontramos el monopolio, mercado dominado por una única empresa, que decide precio y producción con el objetivo de maximizar sus beneficios. Entre ambos extremos se encuentran situaciones intermedias: el oligopolio, con pocas empresas que dominan el mercado, frecuentemente con productos muy similares, como el mercado de las telecomunicaciones o del automóvil; y la competencia monopolística, con muchas empresas que ofrecen productos diferenciados mediante marcas, calidad o publicidad, como ocurre en la restauración o en la moda. Cada estructura de mercado produce resultados distintos en términos de eficiencia y bienestar. La competencia perfecta suele considerarse la más eficiente desde el punto de vista económico, mientras que el monopolio se asocia a precios más altos y menor producción. Por ello, los Estados suelen intervenir para limitar los monopolios y fomentar la competencia mediante leyes y organismos reguladores específicos.', '[{"pregunta":"¿Qué caracteriza a la competencia perfecta?","opciones":["Una sola empresa","Muchas empresas y productos homogéneos","Pocas empresas diferentes","Monopolio natural"],"correcta":1},{"pregunta":"¿Qué es un oligopolio?","opciones":["Mercado con una empresa","Mercado dominado por pocas empresas","Mercado con ningún vendedor","Mercado ilegal"],"correcta":1},{"pregunta":"¿Qué diferencia a la competencia monopolística?","opciones":["Producto idéntico","Productos diferenciados por marca","Pocos compradores","Cantidad fija"],"correcta":1},{"pregunta":"¿Por qué los Estados limitan los monopolios?","opciones":["Para subir precios","Para proteger a los consumidores y eficiencia","Para crear empleo público","Para eliminar impuestos"],"correcta":1}]'::jsonb),

('economia', 'bachillerato', '{1}', 'Los fallos de mercado y la intervención pública', 'Aunque el mercado es un mecanismo eficaz de asignación de recursos, no siempre produce resultados óptimos desde el punto de vista social. Los economistas denominan fallos de mercado a las situaciones en que el libre funcionamiento del mercado genera ineficiencias o desigualdades importantes. Entre los fallos más estudiados se encuentran las externalidades, que aparecen cuando una actividad económica afecta a terceros que no intervienen directamente en la transacción. La contaminación provocada por una fábrica es un ejemplo clásico de externalidad negativa, mientras que la educación básica constituye una externalidad positiva, pues genera beneficios para toda la sociedad. Otro fallo relevante es la existencia de bienes públicos, caracterizados por la no rivalidad y la no exclusión, como la defensa nacional, que no serían proporcionados adecuadamente por empresas privadas. La información asimétrica entre vendedores y compradores puede provocar también resultados ineficientes, como ocurre en el mercado de seguros o en el de automóviles usados. Ante estos fallos, los Estados intervienen mediante impuestos, subvenciones, regulación, provisión pública de servicios o creación de instituciones especializadas. La forma concreta de intervención ha sido y sigue siendo objeto de amplio debate político y académico, pues ninguna solución es perfecta y toda actuación pública tiene también sus propios costes.', '[{"pregunta":"¿Qué es un fallo de mercado?","opciones":["Una quiebra empresarial","Situación donde el mercado no asigna eficientemente","Una ley económica","Un monopolio legal"],"correcta":1},{"pregunta":"¿Qué ejemplo es una externalidad negativa?","opciones":["Educación","Contaminación","Vacunación","Transporte público"],"correcta":1},{"pregunta":"¿Qué caracteriza a los bienes públicos?","opciones":["Rivalidad alta","No rivalidad y no exclusión","Exclusión fácil","Precio alto"],"correcta":1},{"pregunta":"¿Cómo interviene el Estado ante fallos de mercado?","opciones":["Eliminando el mercado","Mediante impuestos, subvenciones y regulación","Solo con guerras","Solo con privatizaciones"],"correcta":1}]'::jsonb),

('economia', 'bachillerato', '{1}', 'El producto interior bruto y su medición', 'El producto interior bruto, conocido por sus siglas PIB, es el valor monetario total de todos los bienes y servicios finales producidos en un país durante un período determinado, generalmente un año. Es el indicador más utilizado para medir el tamaño y la evolución de una economía. Existen tres formas principales de calcularlo que, teóricamente, deben coincidir: el método de la producción, que suma el valor añadido por cada sector; el del gasto, que suma el consumo privado, la inversión, el gasto público y las exportaciones netas; y el de la renta, que suma las remuneraciones a los factores productivos. Para comparar el PIB entre años diferentes, es necesario distinguir entre PIB nominal, calculado a precios corrientes, y PIB real, que elimina el efecto de la inflación utilizando precios constantes. Cuando el PIB se divide por la población obtenemos el PIB per cápita, que ofrece una medida del nivel medio de producción por habitante. Sin embargo, el PIB presenta limitaciones importantes como indicador de bienestar: no refleja la distribución de la renta, ignora la economía sumergida, no tiene en cuenta el daño medioambiental ni actividades no remuneradas como el trabajo doméstico. Por ello, se han desarrollado indicadores complementarios como el índice de desarrollo humano o el índice de progreso social.', '[{"pregunta":"¿Qué mide el PIB?","opciones":["Solo las exportaciones","Valor de bienes y servicios finales de un país","Riqueza acumulada","Solo el gasto público"],"correcta":1},{"pregunta":"¿Qué diferencia al PIB real del nominal?","opciones":["No hay diferencia","El real elimina el efecto de la inflación","El nominal incluye exportaciones","El real solo incluye industria"],"correcta":1},{"pregunta":"¿Qué mide el PIB per cápita?","opciones":["Riqueza nacional total","Producción media por habitante","Deuda pública","Tipo de cambio"],"correcta":1},{"pregunta":"¿Qué NO refleja adecuadamente el PIB?","opciones":["Tamaño de la economía","Bienestar y distribución de la renta","Crecimiento nominal","Gasto total"],"correcta":1}]'::jsonb),

('economia', 'bachillerato', '{1}', 'La inflación y sus efectos económicos', 'La inflación es el aumento generalizado y sostenido de los precios de los bienes y servicios en una economía durante un período de tiempo. Se mide habitualmente a través del índice de precios de consumo, que registra la evolución del coste de una cesta representativa de productos adquiridos por los hogares. Cuando la tasa de inflación es moderada y estable, suele considerarse compatible con un crecimiento económico sano, pero cuando se dispara genera múltiples problemas. Los más evidentes son la pérdida de poder adquisitivo de los trabajadores cuyos salarios no se ajustan al mismo ritmo y la erosión del valor real del ahorro. También distorsiona las decisiones de inversión, ya que dificulta la comparación de precios a lo largo del tiempo. La inflación puede tener diferentes causas: un exceso de demanda frente a una oferta insuficiente, un aumento de los costes de producción, una expansión monetaria excesiva o expectativas de inflación que se retroalimentan. Los bancos centrales, como el Banco Central Europeo o la Reserva Federal, tienen entre sus principales objetivos mantener la estabilidad de precios y actúan principalmente a través de los tipos de interés. Cuando los precios caen en lugar de subir se habla de deflación, un fenómeno que puede resultar igualmente perjudicial porque suele ir asociado a estancamiento y desempleo.', '[{"pregunta":"¿Qué mide el IPC?","opciones":["Tipos de interés","Evolución del coste de una cesta de productos","Deuda pública","Exportaciones"],"correcta":1},{"pregunta":"¿A quién perjudica la inflación?","opciones":["Solo a empresas","Trabajadores sin actualización salarial y ahorradores","A nadie","Solo al Estado"],"correcta":1},{"pregunta":"¿Qué puede causar inflación?","opciones":["Solo el clima","Exceso de demanda o costes","Elecciones","Deportes"],"correcta":1},{"pregunta":"¿Qué es la deflación?","opciones":["Subida rápida de precios","Caída generalizada de precios","Aumento de impuestos","Bajada del desempleo"],"correcta":1}]'::jsonb),

('economia', 'bachillerato', '{1}', 'El desempleo y el mercado laboral', 'El desempleo es uno de los problemas económicos que más directamente afecta a las personas. Se considera desempleada a aquella persona en edad de trabajar, disponible y que busca activamente empleo pero no lo encuentra. La tasa de desempleo se calcula como el cociente entre el número de desempleados y la población activa, multiplicado por cien. Los economistas distinguen distintos tipos de desempleo según sus causas. El desempleo friccional se produce cuando las personas cambian de un trabajo a otro o incorporan nuevos trabajadores al mercado laboral. El estructural se relaciona con cambios económicos o tecnológicos que hacen obsoletas ciertas habilidades o sectores. El cíclico está asociado a las recesiones económicas y desaparece cuando la economía se recupera. El estacional depende de actividades que solo funcionan en determinadas épocas del año, como la agricultura o el turismo. El desempleo tiene efectos muy negativos tanto individuales como sociales: pérdida de ingresos, erosión de competencias, problemas de salud, incremento de la pobreza y pérdida fiscal para el Estado. Para combatirlo se aplican políticas de formación, subsidios, planes de empleo y reformas laborales, así como políticas macroeconómicas expansivas en momentos de crisis. La creación de empleo de calidad es uno de los grandes retos de las economías contemporáneas.', '[{"pregunta":"¿A quién se considera desempleado?","opciones":["Toda persona sin trabajo","Persona en edad laboral que busca empleo activamente","Estudiantes","Jubilados"],"correcta":1},{"pregunta":"¿Qué tipo de desempleo se asocia a crisis?","opciones":["Friccional","Estacional","Cíclico","Estructural"],"correcta":2},{"pregunta":"¿Qué efecto NO tiene el desempleo?","opciones":["Pérdida de ingresos","Problemas de salud","Aumento de la recaudación","Pobreza"],"correcta":2},{"pregunta":"¿Qué política combate el desempleo estructural?","opciones":["Formación y reciclaje","Bajada de intereses","Subida de precios","Impuestos al consumo"],"correcta":0}]'::jsonb),

('economia', 'bachillerato', '{1}', 'El dinero y el sistema financiero', 'El dinero es cualquier medio generalmente aceptado como pago por bienes y servicios o para el pago de deudas. Desempeña tres funciones fundamentales: sirve como medio de cambio, evitando el trueque; como unidad de cuenta, permitiendo comparar precios; y como depósito de valor, posibilitando el ahorro. A lo largo de la historia se han utilizado diversos tipos de dinero, desde conchas y metales preciosos hasta billetes y monedas, y actualmente el dinero bancario o electrónico, presente en cuentas corrientes y medios digitales. El sistema financiero es el conjunto de instituciones, mercados e instrumentos que canalizan el ahorro hacia la inversión. En él destacan los bancos, que captan depósitos y conceden préstamos, así como los mercados de valores, donde se compran y venden acciones y bonos. Los bancos centrales, como el Banco Central Europeo, supervisan el sistema y diseñan la política monetaria con el objetivo principal de mantener la estabilidad de precios. Un sistema financiero eficiente y estable es fundamental para el crecimiento económico, pues facilita la financiación de proyectos productivos, reduce el riesgo mediante la diversificación y permite a familias y empresas tomar decisiones informadas sobre el consumo, la inversión y el ahorro. Las crisis financieras demuestran la importancia de una buena regulación y supervisión.', '[{"pregunta":"¿Cuántas funciones básicas tiene el dinero?","opciones":["Una","Dos","Tres","Cuatro"],"correcta":2},{"pregunta":"¿Qué instituciones captan depósitos y conceden préstamos?","opciones":["Universidades","Bancos","Hospitales","Ayuntamientos"],"correcta":1},{"pregunta":"¿Cuál es el objetivo principal del BCE?","opciones":["Recaudar impuestos","Estabilidad de precios","Crear empleo","Gestionar la deuda"],"correcta":1},{"pregunta":"¿Qué demuestran las crisis financieras?","opciones":["Fallos de regulación y supervisión","Éxito sin límites","Nula relación con la economía","Que el dinero no importa"],"correcta":0}]'::jsonb),

('economia', 'bachillerato', '{1}', 'La política fiscal y su impacto', 'La política fiscal es el conjunto de decisiones de un gobierno sobre los ingresos y los gastos públicos con el objetivo de influir en la economía. Sus principales instrumentos son los impuestos y el gasto público, que pueden utilizarse para estabilizar el ciclo económico, redistribuir la renta o proporcionar bienes y servicios colectivos. En fases de crisis, los gobiernos pueden aplicar una política fiscal expansiva, incrementando el gasto o reduciendo los impuestos para estimular la demanda agregada y reactivar la actividad. En épocas de auge, pueden aplicar una política fiscal contractiva, aumentando impuestos o reduciendo el gasto para moderar presiones inflacionistas y contener el déficit. La política fiscal tiene efectos multiplicadores sobre la economía que han sido estudiados desde los trabajos del economista John Maynard Keynes. Sin embargo, su eficacia depende de factores como la magnitud del déficit previo, el nivel de deuda pública o la coordinación con la política monetaria. Los gobiernos deben equilibrar los objetivos de corto plazo, como la estabilización, con los de largo plazo, como la sostenibilidad de las cuentas públicas. Decisiones como la estructura del sistema impositivo o la orientación del gasto tienen consecuencias profundas sobre la equidad, la eficiencia y el crecimiento económico de un país a lo largo del tiempo.', '[{"pregunta":"¿Cuáles son los instrumentos principales de la política fiscal?","opciones":["Tipos de interés","Impuestos y gasto público","Tipos de cambio","Aranceles"],"correcta":1},{"pregunta":"¿Qué economista destacó su importancia?","opciones":["Adam Smith","Keynes","Friedman","Marx"],"correcta":1},{"pregunta":"¿Qué es una política fiscal expansiva?","opciones":["Subir impuestos","Reducir gasto","Aumentar gasto o bajar impuestos","Cerrar fronteras"],"correcta":2},{"pregunta":"¿Qué debe equilibrar un gobierno?","opciones":["Solo corto plazo","Solo largo plazo","Estabilización y sostenibilidad","Solo exportaciones"],"correcta":2}]'::jsonb),

('economia', 'bachillerato', '{1}', 'La balanza de pagos y el comercio exterior', 'La balanza de pagos es un registro contable de todas las transacciones económicas que un país realiza con el resto del mundo durante un período determinado, generalmente un año. Se divide en varias cuentas. La cuenta corriente recoge las operaciones de mercancías, servicios, rentas primarias como salarios o intereses y rentas secundarias como transferencias. La cuenta de capital incluye transferencias de capital relacionadas con inversiones y determinados activos no financieros. La cuenta financiera refleja las inversiones directas, las de cartera y otros movimientos de activos y pasivos financieros. En principio, el saldo global de la balanza de pagos debe equilibrarse, pues todo ingreso del exterior se corresponde con un pago y viceversa. Un saldo positivo en la cuenta corriente indica que el país exporta más de lo que importa, generando ahorro neto frente al exterior; un saldo negativo sugiere lo contrario y obliga a financiarse con capitales externos. El análisis de la balanza de pagos aporta información esencial sobre la competitividad, la especialización productiva y la posición financiera internacional de un país. Los desequilibrios persistentes pueden indicar problemas estructurales que requieren políticas económicas específicas para corregirlos, como reformas de productividad, ajustes en el tipo de cambio o cambios en las políticas comerciales.', '[{"pregunta":"¿Qué registra la balanza de pagos?","opciones":["Salarios internos","Transacciones con el resto del mundo","Ventas locales","Impuestos recaudados"],"correcta":1},{"pregunta":"¿Qué recoge la cuenta corriente?","opciones":["Solo mercancías","Mercancías, servicios, rentas y transferencias","Solo inversiones","Solo capital"],"correcta":1},{"pregunta":"¿Qué indica un saldo corriente positivo?","opciones":["Exporta más de lo que importa","Importa más","Endeudamiento","Depreciación"],"correcta":0},{"pregunta":"¿Qué puede requerir un desequilibrio persistente?","opciones":["Ignorarlo","Políticas económicas correctivas","Aumento del déficit","Dejar flotar todo"],"correcta":1}]'::jsonb),

('economia', 'bachillerato', '{1}', 'El crecimiento económico y el desarrollo', 'El crecimiento económico es el aumento sostenido del valor de los bienes y servicios producidos por una economía a lo largo del tiempo. Se mide habitualmente como variación porcentual del PIB real y se considera uno de los objetivos fundamentales de la política económica, aunque no el único. El crecimiento depende de factores como la acumulación de capital, el aumento de la población activa, la mejora de la educación y la innovación tecnológica. Desde los trabajos del economista Robert Solow, se sabe que el progreso técnico es la fuente principal del crecimiento a largo plazo. Sin embargo, el crecimiento económico no debe confundirse con el desarrollo, que tiene en cuenta además la distribución de la riqueza, la calidad de vida, el acceso a la educación y a la sanidad, la igualdad de género y la sostenibilidad ambiental. Indicadores como el índice de desarrollo humano de las Naciones Unidas intentan ofrecer una visión más completa del bienestar de las sociedades. En las últimas décadas, los debates se han centrado en la sostenibilidad del modelo de crecimiento actual, con propuestas como la economía circular o el decrecimiento. La búsqueda de un modelo de desarrollo sostenible que respete los límites ecológicos y permita el bienestar humano es uno de los grandes desafíos económicos del siglo XXI.', '[{"pregunta":"¿Cómo se mide el crecimiento económico?","opciones":["Por la deuda","Variación del PIB real","Impuestos recaudados","Exportaciones totales"],"correcta":1},{"pregunta":"¿Qué factor es motor principal a largo plazo?","opciones":["Capital inicial","Progreso técnico","Horas trabajadas","Deflación"],"correcta":1},{"pregunta":"¿Qué es el desarrollo?","opciones":["Solo PIB","Incluye bienestar, educación, sostenibilidad","Solo deuda","Solo PIB per cápita"],"correcta":1},{"pregunta":"¿Qué reto plantea el siglo XXI?","opciones":["Crecer sin límites","Desarrollo sostenible","Eliminar empleo","Cerrar mercados"],"correcta":1}]'::jsonb),

('economia', 'bachillerato', '{1}', 'La globalización económica', 'La globalización económica es el proceso por el cual las economías nacionales se integran cada vez más en una economía mundial mediante el aumento del comercio internacional, los flujos de capital, la transferencia de tecnología y la movilidad de personas. Aunque sus raíces pueden rastrearse en épocas anteriores, se ha acelerado desde finales del siglo XX gracias a la liberalización de los mercados, la revolución del transporte y las comunicaciones y la expansión de internet. La globalización ha permitido un crecimiento sin precedentes del comercio mundial y ha sacado a cientos de millones de personas de la pobreza, especialmente en países asiáticos. También ha facilitado la difusión de conocimiento y tecnología, reduciendo costes de producción y aumentando la variedad de bienes disponibles para los consumidores. Sin embargo, sus efectos son objeto de debate. Entre sus aspectos negativos se mencionan el aumento de la desigualdad en ciertos países, la pérdida de empleos industriales en economías desarrolladas, el incremento de la competencia desleal o los riesgos medioambientales derivados del transporte y la producción deslocalizada. Crisis financieras, pandemias y conflictos geopolíticos han mostrado las vulnerabilidades de un sistema tan interconectado, lo que ha llevado a algunos países a replantearse sus cadenas de suministro y a impulsar estrategias de relocalización productiva.', '[{"pregunta":"¿Qué es la globalización económica?","opciones":["Aislamiento de economías","Integración creciente de economías nacionales","Regreso al trueque","Fin del comercio"],"correcta":1},{"pregunta":"¿Qué factor ha impulsado la globalización?","opciones":["Nuevos aranceles","Revolución del transporte y comunicaciones","Guerras","Inflación"],"correcta":1},{"pregunta":"¿Qué efecto positivo se le atribuye?","opciones":["Crecimiento del comercio y reducción de pobreza","Aumento del analfabetismo","Más desempleo universal","Contaminación solo positiva"],"correcta":0},{"pregunta":"¿Qué debate ha surgido tras crisis y pandemias?","opciones":["Relocalización de cadenas de suministro","Abandono del ahorro","Eliminar el dinero","Cerrar bancos"],"correcta":0}]'::jsonb),

('economia', 'bachillerato', '{1}', 'El consumo responsable y la economía circular', 'El consumo responsable es un modelo de consumo basado en la reflexión sobre el impacto social, económico y ambiental de las decisiones de compra. Frente al consumismo, que prioriza la adquisición constante de bienes, el consumo responsable invita a valorar la necesidad real de los productos, su procedencia, las condiciones laborales de quienes los fabrican y su huella ecológica. Conceptos como comercio justo, productos ecológicos, ahorro energético o reducción de residuos se enmarcan en este enfoque. De forma complementaria ha surgido la economía circular, un modelo productivo que busca minimizar los residuos y el uso de recursos mediante el diseño de productos duraderos, reparables y reciclables. En lugar del modelo lineal tradicional de extraer, producir, consumir y desechar, la economía circular promueve ciclos cerrados en los que los materiales se reutilizan una y otra vez, imitando los procesos de la naturaleza. Grandes empresas y administraciones públicas están adoptando estrategias circulares para reducir costes, cumplir con la legislación medioambiental y responder a la demanda creciente de los consumidores. Estos nuevos modelos exigen cambios profundos en los procesos productivos, en los hábitos de compra y en los marcos regulatorios, y se consideran fundamentales para avanzar hacia un desarrollo económico más sostenible.', '[{"pregunta":"¿Qué promueve el consumo responsable?","opciones":["Comprar sin límites","Reflexión sobre impactos de la compra","Aumentar la publicidad","Producir más residuos"],"correcta":1},{"pregunta":"¿Qué caracteriza a la economía circular?","opciones":["Modelo lineal","Ciclos cerrados y reutilización","Desecho rápido","Exportación masiva"],"correcta":1},{"pregunta":"¿Qué concepto NO es propio del consumo responsable?","opciones":["Comercio justo","Obsolescencia programada","Productos ecológicos","Ahorro energético"],"correcta":1},{"pregunta":"¿A qué fin contribuyen ambos modelos?","opciones":["Crisis ambiental","Desarrollo sostenible","Guerras comerciales","Inflación"],"correcta":1}]'::jsonb),

('economia', 'bachillerato', '{1}', 'El papel de la empresa en la economía', 'La empresa es la unidad básica de producción en las economías modernas. Se define como una organización que combina factores productivos (recursos naturales, trabajo, capital y capacidad empresarial) con el objetivo de producir bienes o prestar servicios y obtener, en la mayoría de los casos, un beneficio. Existen muchos tipos de empresas según criterios diversos: por tamaño (microempresa, pequeña, mediana o gran empresa); por forma jurídica (autónomo, sociedad limitada, sociedad anónima, cooperativa, etc.); por sector de actividad (primario, secundario, terciario); y por su titularidad (privada, pública o mixta). Las empresas desempeñan un papel central en la generación de empleo, el crecimiento económico y la innovación. También son responsables de decisiones con implicaciones sociales y medioambientales importantes. En las últimas décadas ha ganado relevancia el concepto de responsabilidad social corporativa, según el cual las empresas no solo persiguen el beneficio económico, sino también objetivos éticos, sociales y ambientales. Iniciativas como los informes de sostenibilidad o los criterios ESG (ambientales, sociales y de gobernanza) buscan orientar las decisiones empresariales hacia el bienestar colectivo. En un entorno competitivo y globalizado, la capacidad de adaptarse, innovar y actuar con responsabilidad se ha convertido en factor clave del éxito empresarial a largo plazo.', '[{"pregunta":"¿Qué combina una empresa para producir?","opciones":["Solo capital","Factores productivos","Solo trabajo","Solo tecnología"],"correcta":1},{"pregunta":"¿Qué criterio clasifica empresas por tamaño?","opciones":["Sector","Número de trabajadores o ingresos","Color","Nombre"],"correcta":1},{"pregunta":"¿Qué significa RSC?","opciones":["Responsabilidad Social Corporativa","Régimen Social Comunitario","Registro Sindical","Red Sindical Central"],"correcta":0},{"pregunta":"¿Qué son los criterios ESG?","opciones":["Ambientales, sociales y de gobernanza","Educación y salud","Economía y servicios","Energía y sostenibilidad"],"correcta":0}]'::jsonb),

('economia', 'bachillerato', '{1}', 'La teoría del consumidor y la utilidad', 'La teoría del consumidor estudia las decisiones de gasto que toman las personas al enfrentarse a precios, rentas y preferencias diferentes. Su objetivo es explicar cómo eligen la combinación de bienes y servicios que les proporciona el mayor bienestar posible dadas sus limitaciones. Un concepto central es la utilidad, que mide la satisfacción o el placer que un consumidor obtiene al consumir un bien. Aunque es difícil medirla en términos absolutos, los economistas utilizan conceptos como la utilidad marginal, que es el incremento de utilidad derivado del consumo de una unidad adicional de un bien. La ley de la utilidad marginal decreciente afirma que, a medida que se consumen más unidades de un mismo bien, la satisfacción adicional tiende a disminuir. Esta ley explica por qué los consumidores prefieren variar su consumo y no concentrarlo en un único producto. Los consumidores también se ven limitados por su restricción presupuestaria, que establece las combinaciones posibles de bienes que pueden comprar dada su renta y los precios. El equilibrio del consumidor se alcanza cuando el cociente entre utilidad marginal y precio es el mismo para todos los bienes. Aunque es un modelo teórico, sus implicaciones son muy útiles para comprender los comportamientos observables y para diseñar políticas comerciales y sociales eficaces.', '[{"pregunta":"¿Qué es la utilidad en economía?","opciones":["Precio","Satisfacción de consumir un bien","Impuesto","Renta"],"correcta":1},{"pregunta":"¿Qué afirma la ley de utilidad marginal decreciente?","opciones":["Más consumo, más utilidad adicional","Más consumo, menos utilidad adicional","Ninguna relación","Utilidad siempre constante"],"correcta":1},{"pregunta":"¿Qué limita al consumidor?","opciones":["Solo precios","Restricción presupuestaria","Impuestos","Publicidad"],"correcta":1},{"pregunta":"¿Cuándo se alcanza el equilibrio del consumidor?","opciones":["Al maximizar gasto","Utilidad marginal por euro igualada entre bienes","Al ahorrar todo","Al gastar solo en un bien"],"correcta":1}]'::jsonb),

('economia', 'bachillerato', '{1}', 'El sistema tributario: tipos de impuestos', 'El sistema tributario es el conjunto de impuestos, tasas y contribuciones que un Estado establece para financiar el gasto público. Los impuestos son pagos obligatorios que los contribuyentes deben realizar sin recibir una contraprestación directa. Se clasifican principalmente en directos e indirectos. Los directos gravan la obtención de renta o la posesión de patrimonio, como el impuesto sobre la renta de las personas físicas o el impuesto sobre sociedades, y suelen ser progresivos, es decir, quienes tienen mayor capacidad económica pagan proporcionalmente más. Los indirectos gravan el consumo o la circulación de bienes y servicios, como el impuesto sobre el valor añadido (IVA), y suelen ser proporcionales o regresivos. Los sistemas tributarios modernos persiguen varios objetivos: recaudar recursos para financiar el gasto, redistribuir la renta entre grupos sociales, estabilizar la economía y corregir ciertos comportamientos mediante impuestos específicos sobre el tabaco, el alcohol o las emisiones contaminantes. El diseño de un sistema fiscal justo y eficiente es uno de los retos permanentes de la política económica, pues exige equilibrar los principios de equidad, eficiencia, sencillez y suficiencia recaudatoria. Los debates sobre subidas o bajadas de impuestos, progresividad o fraude fiscal son recurrentes en las sociedades democráticas contemporáneas.', '[{"pregunta":"¿Qué es un impuesto?","opciones":["Compra voluntaria","Pago obligatorio sin contraprestación directa","Donativo","Préstamo"],"correcta":1},{"pregunta":"¿Qué tipo de impuesto es el IRPF?","opciones":["Directo","Indirecto","Tasa","Contribución especial"],"correcta":0},{"pregunta":"¿Qué significa impuesto progresivo?","opciones":["Paga más quien tiene más","Todos pagan igual","Solo pagan empresas","No hay IVA"],"correcta":0},{"pregunta":"¿Qué principio NO es propio del sistema tributario?","opciones":["Equidad","Eficiencia","Opacidad","Suficiencia"],"correcta":2}]'::jsonb);

