INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('ed-fisica', 'bachillerato', '{1}', 'El sistema cardiovascular en el ejercicio', 'El sistema cardiovascular desempeña un papel fundamental durante la actividad física, pues es el encargado de transportar oxígeno, nutrientes y hormonas a los tejidos activos y de retirar los productos de desecho del metabolismo. Está compuesto por el corazón, que actúa como bomba propulsora, y por una extensa red de vasos sanguíneos que incluye arterias, capilares y venas. Cuando una persona comienza a hacer ejercicio, el sistema cardiovascular responde rápidamente: la frecuencia cardíaca aumenta, el volumen sistólico se incrementa y el gasto cardíaco puede llegar a multiplicarse por cinco o más en deportistas entrenados. La sangre se redistribuye hacia los músculos activos y, simultáneamente, disminuye su llegada a órganos menos solicitados en ese momento, como el aparato digestivo. Estas adaptaciones agudas son inmediatas, pero con el entrenamiento regular se producen también adaptaciones crónicas muy importantes: aumento del tamaño de las cavidades cardíacas, mayor eficiencia del miocardio, reducción de la frecuencia cardíaca en reposo y mejora de la capilarización muscular. Como consecuencia, el corazón de un deportista entrenado puede bombear la misma cantidad de sangre con menor esfuerzo, lo que mejora la resistencia y reduce el riesgo de enfermedades cardiovasculares, una de las principales causas de mortalidad en las sociedades sedentarias contemporáneas.', '[{"pregunta":"¿Cuál es la función principal del sistema cardiovascular en el ejercicio?","opciones":["Producir hormonas","Transportar oxígeno y nutrientes","Contraer músculos","Regular la temperatura solo"],"correcta":1},{"pregunta":"¿Qué sucede con el gasto cardíaco durante el esfuerzo?","opciones":["Disminuye","Puede multiplicarse por cinco o más","Se mantiene","Se anula"],"correcta":1},{"pregunta":"¿Qué adaptación crónica se produce con el entrenamiento?","opciones":["Aumento de la frecuencia cardíaca en reposo","Reducción de la frecuencia en reposo","Pérdida de capilares","Corazón más pequeño"],"correcta":1},{"pregunta":"¿Qué beneficio a largo plazo aporta el ejercicio regular?","opciones":["Aumenta el riesgo cardiovascular","Reduce el riesgo cardiovascular","No tiene efecto","Solo mejora la fuerza"],"correcta":1}]'::jsonb),

('ed-fisica', 'bachillerato', '{1}', 'Las cualidades físicas básicas', 'Las cualidades físicas básicas son los componentes sobre los que se construye el rendimiento físico en cualquier actividad deportiva. Tradicionalmente se distinguen cuatro: fuerza, resistencia, velocidad y flexibilidad, a las que algunos autores añaden la coordinación y el equilibrio. La fuerza es la capacidad de generar tensión contra una resistencia; puede ser máxima, explosiva o resistente, según el tipo de esfuerzo predominante. La resistencia es la capacidad de mantener un esfuerzo durante un tiempo prolongado y se divide en aeróbica, cuando el oxígeno es suficiente para las demandas musculares, y anaeróbica, cuando la intensidad supera la capacidad del metabolismo oxidativo. La velocidad es la capacidad de realizar movimientos en el menor tiempo posible y depende en gran medida del sistema nervioso y de la fuerza rápida. La flexibilidad es la capacidad de amplitud de los movimientos articulares y viene condicionada por la estructura de las articulaciones, la elasticidad de músculos y tendones, y el control neuromuscular. Cada deporte requiere una combinación específica de estas cualidades; por ejemplo, un velocista desarrolla sobre todo fuerza explosiva y velocidad, mientras que un maratoniano necesita una gran resistencia aeróbica. Un entrenamiento equilibrado y bien planificado busca desarrollar todas las cualidades básicas en función de los objetivos individuales y de las características del deportista.', '[{"pregunta":"¿Cuántas cualidades físicas básicas se distinguen tradicionalmente?","opciones":["Dos","Tres","Cuatro","Seis"],"correcta":2},{"pregunta":"¿Qué tipo de resistencia depende del oxígeno?","opciones":["Anaeróbica","Aeróbica","Explosiva","Estática"],"correcta":1},{"pregunta":"¿De qué depende principalmente la velocidad?","opciones":["Sistema digestivo","Sistema nervioso y fuerza rápida","Flexibilidad","Peso corporal"],"correcta":1},{"pregunta":"¿Qué cualidad domina en un maratoniano?","opciones":["Fuerza máxima","Resistencia aeróbica","Velocidad","Flexibilidad"],"correcta":1}]'::jsonb),

('ed-fisica', 'bachillerato', '{1}', 'Los sistemas energéticos del músculo', 'Durante el ejercicio, los músculos obtienen la energía necesaria para la contracción a partir de tres sistemas complementarios que se activan en función de la intensidad y duración del esfuerzo. El primero es el sistema de los fosfágenos o anaeróbico aláctico, que utiliza la fosfocreatina almacenada en el músculo para regenerar ATP de forma muy rápida, sin necesidad de oxígeno y sin producir ácido láctico. Este sistema proporciona energía para esfuerzos muy intensos pero de muy corta duración, inferiores a diez segundos, como un sprint o un levantamiento máximo. El segundo es el sistema glucolítico o anaeróbico láctico, que descompone la glucosa produciendo ATP y ácido láctico como subproducto. Es el sistema predominante en esfuerzos intensos que duran entre diez segundos y dos minutos, como los 400 metros en atletismo. El tercer sistema es el aeróbico, que obtiene energía mediante la oxidación de glucosa, grasas y, en menor medida, proteínas, utilizando el oxígeno transportado por la sangre. Es el sistema más eficiente y el que domina en esfuerzos prolongados como el ciclismo de fondo o la maratón. En la práctica, los tres sistemas funcionan simultáneamente, aunque con participación variable, y conocer esta distribución permite planificar el entrenamiento adecuado a cada deporte.', '[{"pregunta":"¿Qué sistema energético no necesita oxígeno ni produce lactato?","opciones":["Aeróbico","Glucolítico","Fosfágenos","Respiratorio"],"correcta":2},{"pregunta":"¿Cuánto dura aproximadamente la energía del sistema de fosfágenos?","opciones":["Menos de 10 segundos","1 minuto","10 minutos","1 hora"],"correcta":0},{"pregunta":"¿Qué se produce en el sistema glucolítico?","opciones":["ATP y ácido láctico","Solo CO2","Agua pura","Proteínas"],"correcta":0},{"pregunta":"¿Qué sistema domina en una maratón?","opciones":["Aláctico","Láctico","Aeróbico","Neumático"],"correcta":2}]'::jsonb),

('ed-fisica', 'bachillerato', '{1}', 'Nutrición del deportista', 'La alimentación del deportista debe adaptarse al tipo de actividad, a la intensidad del entrenamiento y a los objetivos de rendimiento. Una dieta equilibrada proporciona los macronutrientes y micronutrientes necesarios para mantener el rendimiento, favorecer la recuperación y prevenir lesiones. Los hidratos de carbono son la principal fuente de energía para actividades intensas y deben suponer entre el 50 y el 65 por ciento del aporte calórico total, procedentes preferentemente de alimentos como cereales integrales, frutas, verduras y legumbres. Las proteínas, entre el 12 y el 20 por ciento, son esenciales para la reparación y construcción del tejido muscular; se obtienen de carnes magras, pescados, huevos, lácteos y legumbres. Las grasas, entre el 25 y el 30 por ciento, deben procurarse a partir de aceites vegetales, frutos secos y pescado azul, priorizando las insaturadas. La hidratación es otro aspecto clave, pues durante el ejercicio se pierden grandes cantidades de agua y electrolitos por el sudor. Se recomienda beber antes, durante y después de la actividad, especialmente en ejercicios prolongados o en condiciones de calor. Una correcta distribución de las comidas a lo largo del día y un adecuado timing en torno al entrenamiento potencian los efectos del ejercicio y contribuyen al bienestar general del deportista.', '[{"pregunta":"¿Qué macronutriente es la principal fuente de energía para esfuerzos intensos?","opciones":["Proteínas","Grasas","Hidratos de carbono","Fibra"],"correcta":2},{"pregunta":"¿Qué porcentaje de proteínas se recomienda?","opciones":["5-10%","12-20%","30-40%","50-60%"],"correcta":1},{"pregunta":"¿Qué se pierde sobre todo con el sudor?","opciones":["Vitaminas liposolubles","Agua y electrolitos","Fibra","Hierro"],"correcta":1},{"pregunta":"¿Qué grasas son preferibles en la dieta deportiva?","opciones":["Saturadas","Trans","Insaturadas","Hidrogenadas"],"correcta":2}]'::jsonb),

('ed-fisica', 'bachillerato', '{1}', 'El calentamiento y sus fases', 'El calentamiento es el conjunto de ejercicios que se realizan antes de la actividad física principal para preparar al organismo física y mentalmente para el esfuerzo. Sus objetivos son aumentar la temperatura muscular y corporal, mejorar la elasticidad de los tejidos, activar el sistema cardiovascular, preparar las articulaciones y reducir el riesgo de lesiones. Un buen calentamiento debe cumplir varias fases. La primera es la fase general, en la que se realizan ejercicios aeróbicos suaves como carrera continua, salto de comba o desplazamientos variados, con el fin de elevar progresivamente la frecuencia cardíaca y la temperatura. La segunda es la fase específica, en la que se ejecutan movimientos propios del deporte o actividad que se va a practicar, involucrando los grupos musculares más implicados. La tercera, opcional, puede incluir estiramientos dinámicos, que son preferibles a los estáticos en esta fase pues no reducen el rendimiento posterior. La duración del calentamiento depende de varios factores, como la edad del deportista, la temperatura ambiente o la intensidad prevista, pero suele oscilar entre diez y veinte minutos. Un calentamiento correcto no solo previene lesiones sino que también mejora la coordinación, la atención y la disposición mental, por lo que debe considerarse parte integral y no accesoria de cualquier sesión deportiva.', '[{"pregunta":"¿Cuál es el objetivo principal del calentamiento?","opciones":["Cansar al deportista","Preparar el organismo y prevenir lesiones","Sustituir al entrenamiento","Estirar al máximo"],"correcta":1},{"pregunta":"¿Qué se hace en la fase general?","opciones":["Movimientos específicos","Actividades aeróbicas suaves","Solo estiramientos","Pruebas máximas"],"correcta":1},{"pregunta":"¿Qué tipo de estiramiento es preferible al calentar?","opciones":["Estático prolongado","Dinámico","Balístico violento","Ninguno"],"correcta":1},{"pregunta":"¿Cuánto suele durar un calentamiento?","opciones":["1 minuto","10-20 minutos","1 hora","2 horas"],"correcta":1}]'::jsonb),

('ed-fisica', 'bachillerato', '{1}', 'Fisiología del sistema respiratorio', 'El sistema respiratorio es el encargado de proporcionar al organismo el oxígeno necesario para el metabolismo celular y de eliminar el dióxido de carbono generado. Está formado por las vías respiratorias (fosas nasales, faringe, laringe, tráquea, bronquios) y los pulmones, donde se produce el intercambio de gases en unos pequeños sacos llamados alvéolos. Durante la respiración, el aire inspirado llega a los alvéolos y el oxígeno pasa a la sangre, mientras que el dióxido de carbono circula en sentido contrario y se elimina en la espiración. Durante el ejercicio, las demandas de oxígeno del músculo aumentan de forma espectacular, lo que obliga al sistema respiratorio a trabajar mucho más intensamente. La frecuencia respiratoria puede pasar de unas 12 a 15 respiraciones por minuto en reposo a más de 40 durante el esfuerzo máximo, y el volumen de aire movilizado también se multiplica. El entrenamiento regular produce adaptaciones que mejoran la eficiencia respiratoria: aumenta la capacidad pulmonar, la superficie funcional para el intercambio gaseoso y la fuerza de los músculos respiratorios. Una correcta técnica respiratoria contribuye notablemente al rendimiento y a la economía del esfuerzo, y constituye un aspecto técnico que en muchos deportes se entrena específicamente, desde la natación hasta el atletismo de fondo.', '[{"pregunta":"¿Dónde se produce el intercambio de gases?","opciones":["Bronquios","Alvéolos","Tráquea","Laringe"],"correcta":1},{"pregunta":"¿Cuánto aumenta aproximadamente la frecuencia respiratoria en ejercicio máximo?","opciones":["No cambia","Se duplica","Puede superar las 40 rpm","Se reduce a la mitad"],"correcta":2},{"pregunta":"¿Qué gas se elimina con la espiración?","opciones":["Oxígeno","Dióxido de carbono","Hidrógeno","Nitrógeno"],"correcta":1},{"pregunta":"¿Qué mejora el entrenamiento aeróbico?","opciones":["Eficiencia respiratoria","Color de la piel","Digestión","Memoria inmediata"],"correcta":0}]'::jsonb),

('ed-fisica', 'bachillerato', '{1}', 'Los principios del entrenamiento deportivo', 'El entrenamiento deportivo es un proceso planificado y sistemático cuyo objetivo es mejorar el rendimiento y la forma física del deportista. Para ser efectivo debe basarse en una serie de principios científicos que han demostrado su validez a través de la investigación y la práctica. El principio de sobrecarga establece que para producir adaptaciones es necesario aplicar cargas de trabajo superiores a las habituales, sin llegar al agotamiento excesivo. El principio de progresión afirma que esas cargas deben incrementarse de forma gradual para evitar lesiones y estancamientos. El principio de especificidad indica que las adaptaciones son específicas al tipo de ejercicio realizado, por lo que el entrenamiento debe ajustarse al objetivo perseguido. El principio de individualidad resalta que cada deportista responde de forma diferente al mismo estímulo, en función de factores genéticos, edad, nivel previo y estado de salud. El principio de reversibilidad advierte de que las mejoras desaparecen si se interrumpe el entrenamiento durante un tiempo prolongado. Finalmente, el principio de recuperación recuerda que los descansos son tan importantes como los esfuerzos, pues durante el reposo el organismo repara tejidos y consolida las mejoras. Aplicar estos principios de forma inteligente es fundamental para alcanzar el máximo potencial de cada deportista.', '[{"pregunta":"¿Qué afirma el principio de sobrecarga?","opciones":["Descansar siempre","Aplicar cargas superiores a las habituales","No cambiar nunca","Entrenar sin intensidad"],"correcta":1},{"pregunta":"¿Qué significa el principio de especificidad?","opciones":["Todos entrenan igual","Las adaptaciones son específicas al tipo de ejercicio","Hay que variar siempre","Solo se mejora fuerza"],"correcta":1},{"pregunta":"¿Qué ocurre si se interrumpe el entrenamiento?","opciones":["Las mejoras persisten siempre","Las mejoras pueden desaparecer","La forma mejora sola","Nada"],"correcta":1},{"pregunta":"¿Qué papel tiene el descanso?","opciones":["Es accesorio","Fundamental para la recuperación y adaptación","Es contraproducente","No influye"],"correcta":1}]'::jsonb),

('ed-fisica', 'bachillerato', '{1}', 'Lesiones deportivas y prevención', 'Las lesiones deportivas son alteraciones físicas que se producen como consecuencia de la práctica de una actividad física. Pueden clasificarse en agudas, cuando se generan por un traumatismo puntual como un esguince, una fractura o una rotura fibrilar, y crónicas o por sobreuso, cuando resultan de la repetición continuada de un gesto, como las tendinopatías o las fracturas por estrés. Los factores que aumentan el riesgo de lesión son múltiples: una condición física deficiente, un calentamiento insuficiente, material inadecuado, técnicas deportivas incorrectas, fatiga acumulada, desequilibrios musculares y factores externos como superficies duras o condiciones climáticas adversas. La prevención de lesiones se basa en varias estrategias complementarias. En primer lugar, un entrenamiento adecuado que respete los principios de progresión y recuperación. En segundo lugar, el uso de material específico y en buen estado. En tercer lugar, un calentamiento y vuelta a la calma correctos en cada sesión. A esto se suman ejercicios de fortalecimiento y estabilización, técnicas de movilidad articular y programas de propiocepción que mejoran el control neuromuscular. Ante una lesión aguda, el protocolo tradicional se resume en las siglas RICE: reposo, hielo, compresión y elevación. Sin embargo, en los últimos años se están desarrollando protocolos más activos que incorporan ejercicio terapéutico temprano para acelerar la recuperación.', '[{"pregunta":"¿Qué es una lesión aguda?","opciones":["Por sobreuso prolongado","Por un traumatismo puntual","Sin causa aparente","Genética"],"correcta":1},{"pregunta":"¿Qué factor NO aumenta el riesgo de lesión?","opciones":["Fatiga acumulada","Calentamiento correcto","Material inadecuado","Desequilibrios musculares"],"correcta":1},{"pregunta":"¿Qué significa RICE?","opciones":["Reposo, hielo, compresión, elevación","Ritmo, intensidad, carga, entrenamiento","Rotación, ingreso, control, equilibrio","Resistencia, intensidad, corrección, ejercicio"],"correcta":0},{"pregunta":"¿Qué técnica mejora el control neuromuscular?","opciones":["Estiramientos balísticos","Propiocepción","Levantamiento máximo","Ayuno intermitente"],"correcta":1}]'::jsonb),

('ed-fisica', 'bachillerato', '{1}', 'La planificación del entrenamiento', 'La planificación del entrenamiento es el proceso por el cual se organizan de manera lógica y sistemática los distintos componentes del preparación deportiva a lo largo del tiempo, con el objetivo de alcanzar el máximo rendimiento en un momento determinado. Se basa en el concepto de periodización, que consiste en dividir el año o la temporada en etapas o ciclos con objetivos específicos. El marco más utilizado es el propuesto originalmente por el autor soviético Matveyev, que distingue tres ciclos: el macrociclo, que corresponde a la temporada completa; los mesociclos, de varias semanas; y los microciclos, que suelen ser semanales. Dentro de cada ciclo se alternan fases de preparación general, preparación específica, competición y transición. Durante la preparación general se trabaja la condición física de base; en la específica se enfatizan las capacidades más relevantes para el deporte; en competición se mantiene y pule la forma; y en la transición se busca la recuperación activa. Existen diferentes modelos de periodización, desde el clásico hasta enfoques más recientes como el bloque o el modelo ATR. La elección depende del deporte, el calendario y el nivel del deportista. Una planificación bien estructurada es imprescindible para evitar el sobreentrenamiento, optimizar las cargas y llegar en la mejor forma posible a las competiciones más importantes.', '[{"pregunta":"¿Qué es la periodización?","opciones":["Entrenar todo igual","Dividir el año en etapas con objetivos","Descansar un mes","Correr sin parar"],"correcta":1},{"pregunta":"¿Cuál es el ciclo más largo?","opciones":["Microciclo","Mesociclo","Macrociclo","Ejercicio único"],"correcta":2},{"pregunta":"¿Qué se busca en la fase de transición?","opciones":["Competir al máximo","Recuperación activa","Iniciar preparación específica","Máxima carga"],"correcta":1},{"pregunta":"¿Qué riesgo evita una buena planificación?","opciones":["Sobreentrenamiento","Victorias","Diversión","Flexibilidad"],"correcta":0}]'::jsonb),

('ed-fisica', 'bachillerato', '{1}', 'El deporte y la salud mental', 'La práctica regular de actividad física aporta beneficios que van mucho más allá de los puramente corporales. Numerosos estudios científicos han demostrado que el ejercicio tiene un impacto significativo sobre la salud mental, reduciendo los síntomas de ansiedad, depresión y estrés, y mejorando la calidad del sueño, la autoestima y el bienestar general. Cuando nos movemos, el cerebro libera neurotransmisores como endorfinas, serotonina y dopamina, responsables de la sensación de bienestar y del conocido como subidón del corredor. Además, el ejercicio favorece la neuroplasticidad, es decir, la capacidad del cerebro para formar nuevas conexiones, y se asocia a un menor riesgo de deterioro cognitivo en edades avanzadas. En el ámbito psicológico, el deporte enseña valores como la constancia, el esfuerzo, la tolerancia a la frustración, el trabajo en equipo y la capacidad de fijarse objetivos y alcanzarlos. Los deportes colectivos fomentan además habilidades sociales y sentimiento de pertenencia. Sin embargo, el deporte puede tener también aspectos negativos cuando se vive con exigencia excesiva, con obsesión por la imagen corporal o cuando se produce adicción al ejercicio. La actividad física adaptada y moderada, integrada en un estilo de vida saludable, ofrece una de las estrategias más eficaces para prevenir problemas emocionales cada vez más frecuentes en la sociedad actual.', '[{"pregunta":"¿Qué neurotransmisores libera el ejercicio?","opciones":["Adrenalina y glucosa","Endorfinas, serotonina, dopamina","Insulina","Cortisol únicamente"],"correcta":1},{"pregunta":"¿Qué es la neuroplasticidad?","opciones":["Plástico en el cerebro","Capacidad de formar nuevas conexiones","Elasticidad muscular","Velocidad de reacción"],"correcta":1},{"pregunta":"¿Qué valor NO se asocia habitualmente al deporte?","opciones":["Constancia","Aislamiento total","Esfuerzo","Tolerancia a la frustración"],"correcta":1},{"pregunta":"¿Qué riesgo menciona el texto?","opciones":["Ser perezoso","Adicción al ejercicio","Estar sano","Dormir mejor"],"correcta":1}]'::jsonb),

('ed-fisica', 'bachillerato', '{1}', 'La historia del olimpismo moderno', 'Los Juegos Olímpicos modernos son el mayor acontecimiento deportivo del mundo y se celebran cada cuatro años, con ediciones alternas de verano e invierno. Su origen se remonta a 1896, cuando se celebraron los primeros Juegos en Atenas por iniciativa del barón francés Pierre de Coubertin, quien se inspiró en los antiguos Juegos Olímpicos celebrados en la Grecia clásica desde el año 776 antes de nuestra era. Coubertin concibió los Juegos modernos como un medio para fomentar la paz, la amistad entre pueblos y los valores educativos del deporte. Desde entonces, los Juegos han crecido de manera espectacular: aumentó el número de deportes, participantes y países involucrados, y se incorporó la participación femenina, inicialmente muy restringida. La historia olímpica refleja también los acontecimientos políticos del siglo XX: boicots en la Guerra Fría, tensiones durante los Juegos de Berlín en 1936, el atentado de Múnich en 1972, o la admisión de nuevos países tras la descolonización. El Comité Olímpico Internacional es el organismo responsable de la organización y continúa adaptando los Juegos a los nuevos tiempos, incorporando deportes como el skateboarding o el surf para atraer a nuevas generaciones. Los valores olímpicos, resumidos en la tríada excelencia, amistad y respeto, siguen siendo su seña de identidad frente a los retos del deporte contemporáneo.', '[{"pregunta":"¿Quién promovió los Juegos Olímpicos modernos?","opciones":["Napoleón","Pierre de Coubertin","Alejandro Magno","Aristóteles"],"correcta":1},{"pregunta":"¿En qué año se celebraron los primeros Juegos modernos?","opciones":["1800","1896","1924","1964"],"correcta":1},{"pregunta":"¿Cuál NO es un valor olímpico?","opciones":["Excelencia","Amistad","Respeto","Victoria a cualquier precio"],"correcta":3},{"pregunta":"¿Qué organismo organiza los Juegos?","opciones":["FIFA","COI","UEFA","ONU"],"correcta":1}]'::jsonb),

('ed-fisica', 'bachillerato', '{1}', 'El dopaje en el deporte', 'El dopaje es el uso de sustancias prohibidas o métodos ilegales para mejorar artificialmente el rendimiento deportivo. Es una de las amenazas más graves para la integridad del deporte competitivo, pues rompe el principio básico de igualdad de oportunidades entre los deportistas. Existen numerosas sustancias consideradas dopantes, entre las que destacan los esteroides anabolizantes, la hormona del crecimiento, la EPO o eritropoyetina, y algunos estimulantes. Estas sustancias pueden aumentar la masa muscular, la producción de glóbulos rojos o la resistencia, pero a costa de efectos secundarios graves para la salud: alteraciones cardiovasculares, hormonales y hepáticas, entre otras. Además del dopaje por sustancias, se han detectado prácticas como las transfusiones sanguíneas homólogas o autólogas para aumentar la capacidad de transporte de oxígeno. La lucha contra el dopaje se organiza a nivel internacional a través de la Agencia Mundial Antidopaje (WADA), creada en 1999, que coordina normativas, controles y sanciones en todo el mundo. Los controles antidopaje se realizan tanto en competición como fuera de ella, y los deportistas profesionales están obligados a informar sobre su localización para ser sometidos a pruebas aleatorias. A pesar de estos esfuerzos, el dopaje sigue siendo un problema persistente que exige la cooperación de autoridades, entrenadores, médicos y los propios deportistas.', '[{"pregunta":"¿Qué es el dopaje?","opciones":["Uso de sustancias para mejorar artificialmente el rendimiento","Entrenamiento intenso","Deporte amateur","Estiramiento"],"correcta":0},{"pregunta":"¿Qué organismo internacional lucha contra el dopaje?","opciones":["FIFA","COI","WADA","UEFA"],"correcta":2},{"pregunta":"¿Qué efecto NO tiene el dopaje?","opciones":["Daño cardiovascular","Alteraciones hormonales","Mejora duradera y segura","Problemas hepáticos"],"correcta":2},{"pregunta":"¿Cuándo se creó la WADA?","opciones":["1970","1985","1999","2010"],"correcta":2}]'::jsonb),

('ed-fisica', 'bachillerato', '{1}', 'Biomecánica del movimiento humano', 'La biomecánica es la disciplina científica que estudia las fuerzas y los movimientos que se producen en los seres vivos, aplicando los principios de la mecánica al cuerpo humano. En el ámbito deportivo permite analizar la técnica de los gestos, optimizar el rendimiento, prevenir lesiones y diseñar materiales más adecuados. Para ello utiliza herramientas como cámaras de alta velocidad, plataformas de fuerza, sensores inerciales y modelos informáticos que reconstruyen el movimiento en tres dimensiones. Los conceptos básicos de la biomecánica incluyen las palancas del cuerpo, formadas por los huesos como barras rígidas, las articulaciones como puntos de apoyo y los músculos como fuerzas motrices. Además, se analizan el centro de gravedad, el equilibrio, la cantidad de movimiento y los diferentes tipos de contracción muscular (concéntrica, excéntrica e isométrica). El estudio biomecánico ha permitido, por ejemplo, perfeccionar las técnicas de salto de altura, mejorar la pedalada en ciclismo o reducir lesiones en el tenis. También contribuye a la rehabilitación, ayudando a corregir patrones de movimiento alterados tras una lesión. Aunque es una ciencia joven, la biomecánica ha revolucionado la forma en que entendemos el cuerpo humano en acción y se ha convertido en un pilar del entrenamiento y la medicina deportiva modernos.', '[{"pregunta":"¿Qué estudia la biomecánica?","opciones":["Fuerzas y movimientos en seres vivos","Solo flexibilidad","Solo lesiones","Química muscular"],"correcta":0},{"pregunta":"¿Qué elementos forman las palancas del cuerpo?","opciones":["Sangre y linfa","Huesos, articulaciones y músculos","Ligamentos solo","Piel y grasa"],"correcta":1},{"pregunta":"¿Qué tipo de contracción NO existe?","opciones":["Concéntrica","Excéntrica","Isométrica","Aleatoria"],"correcta":3},{"pregunta":"¿En qué contribuye a la rehabilitación?","opciones":["Corregir patrones de movimiento alterados","Recetar medicamentos","Construir prótesis solo","Pintar vendajes"],"correcta":0}]'::jsonb),

('ed-fisica', 'bachillerato', '{1}', 'La actividad física en la vida diaria', 'Numerosos estudios internacionales han puesto de manifiesto los peligros del sedentarismo como factor de riesgo para la salud, equiparable en gravedad al tabaco o a la obesidad. La Organización Mundial de la Salud recomienda al menos 150 minutos semanales de actividad física moderada, o 75 minutos intensos, además de ejercicios de fortalecimiento muscular dos veces por semana. Sin embargo, en las sociedades desarrolladas cada vez más personas pasan la mayor parte del día sentadas, frente a pantallas, tanto en el trabajo como en el ocio. Para compensar esta tendencia se recomienda integrar la actividad física en las rutinas cotidianas mediante pequeños cambios: subir escaleras en lugar de usar el ascensor, desplazarse caminando o en bicicleta, realizar pausas activas durante la jornada laboral, practicar deportes o dedicar tiempo al baile o a la jardinería. Estos hábitos, aparentemente modestos, tienen un impacto acumulativo considerable sobre el gasto energético diario y sobre la salud general. Además, fomentan la autonomía, el bienestar emocional y la calidad del sueño. Las políticas públicas también juegan un papel importante mediante la construcción de carriles bici, parques, programas escolares de educación física y campañas de concienciación. La promoción de estilos de vida activos es hoy una prioridad sanitaria en la mayoría de los países del mundo.', '[{"pregunta":"¿Cuántos minutos semanales de actividad moderada recomienda la OMS?","opciones":["30","75","150","300"],"correcta":2},{"pregunta":"¿A qué se equipara el sedentarismo?","opciones":["Hacer deporte","Tabaco u obesidad","Buena alimentación","Estudiar mucho"],"correcta":1},{"pregunta":"¿Qué cambio cotidiano propone el texto?","opciones":["Ver más TV","Subir escaleras en vez del ascensor","Conducir más","Dormir siestas largas"],"correcta":1},{"pregunta":"¿Qué política pública favorece la actividad diaria?","opciones":["Más autopistas","Carriles bici y parques","Impuestos al deporte","Cerrar colegios"],"correcta":1}]'::jsonb),

('ed-fisica', 'bachillerato', '{1}', 'Los deportes de equipo y la táctica', 'Los deportes de equipo, como el fútbol, el baloncesto, el balonmano o el voleibol, son actividades en las que varios jugadores cooperan para alcanzar un objetivo común, generalmente marcar puntos o goles y evitar que el rival lo consiga. Más allá del desarrollo físico, aportan valores como la cooperación, la comunicación, el respeto a las reglas y la asunción de roles. A nivel técnico y táctico, requieren combinar habilidades individuales con el conocimiento colectivo del juego. La táctica es el conjunto de decisiones y acciones planificadas que un equipo utiliza para imponerse a su rival. Se distingue entre táctica ofensiva, cuando el equipo tiene el balón e intenta progresar y anotar, y táctica defensiva, cuando trata de impedir la progresión y la anotación rival. Cada deporte desarrolla esquemas tácticos característicos, como las formaciones en el fútbol o los sistemas de defensa en el baloncesto, que evolucionan constantemente con las ideas de entrenadores innovadores. La toma rápida de decisiones, la lectura del juego y la comunicación entre compañeros son capacidades esenciales. En la formación del deportista conviene alternar el aprendizaje técnico con situaciones reales de juego que favorezcan la comprensión táctica y la resolución de problemas, pues el deporte de equipo exige no solo saber ejecutar, sino también saber pensar dentro del juego y adaptarse a situaciones cambiantes.', '[{"pregunta":"¿Qué diferencia a los deportes de equipo?","opciones":["Se juegan siempre solos","Varios jugadores cooperan por un objetivo","No tienen reglas","Solo se practican en escuelas"],"correcta":1},{"pregunta":"¿Qué es la táctica?","opciones":["Solo técnica","Decisiones y acciones planificadas","Entrenamiento físico","Material deportivo"],"correcta":1},{"pregunta":"¿Cuándo se habla de táctica ofensiva?","opciones":["Cuando se tiene el balón","Cuando se está sin balón","En el descanso","Solo al inicio"],"correcta":0},{"pregunta":"¿Qué capacidad NO es esencial en deportes colectivos?","opciones":["Toma de decisiones","Lectura del juego","Comunicación","Egoísmo total"],"correcta":3}]'::jsonb),

('ed-fisica', 'bachillerato', '{1}', 'La postura y la ergonomía', 'La postura corporal es la posición relativa que adoptan las diferentes partes del cuerpo en cualquier momento, ya sea en movimiento o en reposo. Una postura correcta es aquella que mantiene un equilibrio estable con el menor gasto energético posible y el mínimo estrés sobre los tejidos. Desde el punto de vista anatómico, una buena postura respeta las curvaturas naturales de la columna vertebral: la lordosis cervical y lumbar, y la cifosis dorsal. Muchos problemas contemporáneos se derivan de posturas inadecuadas mantenidas durante largos períodos, como permanecer muchas horas sentado frente a un ordenador o inclinado sobre un dispositivo móvil. Estas posturas incorrectas pueden provocar dolores de espalda, contracturas, cefaleas, problemas circulatorios e incluso alteraciones digestivas o respiratorias. La ergonomía es la disciplina que estudia la adaptación del entorno de trabajo y de los objetos a las características físicas y psicológicas del ser humano con el fin de minimizar el esfuerzo y prevenir lesiones. En educación física es fundamental enseñar a los estudiantes a ser conscientes de su postura en las actividades diarias, a fortalecer la musculatura estabilizadora del tronco, a realizar pausas activas y a cuidar ergonómicamente su puesto de estudio. Estos hábitos, aprendidos desde la juventud, pueden prevenir problemas crónicos en la edad adulta.', '[{"pregunta":"¿Cómo es una buena postura?","opciones":["Con máximo gasto energético","Equilibrio con mínimo estrés tisular","Rígida y tensa","Curvada sin control"],"correcta":1},{"pregunta":"¿Qué curvaturas respeta una buena postura?","opciones":["Solo cifosis","Lordosis y cifosis naturales","Columna totalmente recta","Ninguna"],"correcta":1},{"pregunta":"¿Qué es la ergonomía?","opciones":["Adaptar el entorno al ser humano","Estudiar músculos","Diseñar calzado deportivo","Calcular calorías"],"correcta":0},{"pregunta":"¿Qué problema NO deriva de malas posturas?","opciones":["Dolores de espalda","Contracturas","Cefaleas","Aumento de la estatura"],"correcta":3}]'::jsonb),

('ed-fisica', 'bachillerato', '{1}', 'Las actividades en el medio natural', 'Las actividades en el medio natural son aquellas que se desarrollan en entornos no urbanizados como montañas, ríos, bosques o playas, aprovechando las posibilidades que ofrecen para el ejercicio físico y el contacto con la naturaleza. Incluyen disciplinas muy variadas, como el senderismo, la escalada, el piragüismo, la orientación, el ciclismo de montaña, la vela o el esquí. Estas actividades aportan beneficios específicos que las distinguen de las practicadas en instalaciones cerradas: mejoran la capacidad de adaptación a entornos cambiantes, estimulan los sentidos, fomentan la toma de decisiones y reducen el estrés gracias al contacto con la naturaleza. Desde un punto de vista educativo, permiten trabajar valores como el respeto por el medio ambiente, la cooperación, la autonomía, la responsabilidad y la superación personal. Su práctica requiere, sin embargo, una preparación adecuada: conocimiento técnico de la actividad, planificación previa, material específico, conocimiento del medio y atención a las condiciones meteorológicas. La seguridad es un aspecto crítico, pues los entornos naturales pueden presentar riesgos objetivos como cambios bruscos del tiempo, caídas o pérdidas. En los últimos años ha crecido el interés por estas actividades como alternativa saludable al ocio digital, y muchas escuelas integran excursiones, rutas y deportes al aire libre en sus programas de educación física.', '[{"pregunta":"¿Dónde se practican estas actividades?","opciones":["Solo en gimnasios","Entornos naturales como montañas y ríos","Solo en pistas","En ciudades"],"correcta":1},{"pregunta":"¿Qué beneficio específico aportan?","opciones":["Aislamiento sensorial","Contacto con la naturaleza y reducción del estrés","Más lesiones","Más rutina"],"correcta":1},{"pregunta":"¿Qué aspecto es crítico?","opciones":["El ruido","La seguridad y preparación","El maquillaje","La moda"],"correcta":1},{"pregunta":"¿Qué valor NO se suele trabajar en estas actividades?","opciones":["Respeto ambiental","Cooperación","Autonomía","Individualismo competitivo"],"correcta":3}]'::jsonb);

