INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('filosofia', 'bachillerato', '{1}', 'Los presocráticos y la búsqueda del arjé', 'Los filósofos presocráticos constituyen el primer grupo de pensadores de la historia de la filosofía occidental. Activos entre los siglos VII y V antes de nuestra era en las colonias griegas de Asia Menor e Italia, comparten el interés por encontrar una explicación racional del mundo más allá de los relatos míticos de la tradición religiosa. Su gran pregunta es la del arjé, es decir, el principio originario o la sustancia primera a partir de la cual todo lo que existe se ha generado. Tales de Mileto, considerado el iniciador, propuso que ese principio era el agua, observando su papel fundamental en todos los procesos vitales. Anaximandro, su discípulo, habló del apeirón, un principio infinito e indeterminado. Anaxímenes lo identificó con el aire, mientras que Heráclito insistió en el fuego y en la idea del cambio constante, resumida en su célebre afirmación de que no se puede bañar dos veces en el mismo río. Frente a él, Parménides defendió que el ser es único, eterno e inmutable, y que el cambio es solo una apariencia engañosa. Pitágoras aportó la idea de que los números son la clave de la realidad, mientras que Demócrito propuso los átomos como constituyentes últimos de la materia. Estas reflexiones marcan el tránsito del mito al logos y abren el camino para toda la filosofía posterior.', '[{"pregunta":"¿Qué buscaban los presocráticos?","opciones":["El arjé o principio originario","Mitos religiosos","Leyes políticas","Reglas gramaticales"],"correcta":0},{"pregunta":"¿Quién propuso el agua como principio?","opciones":["Anaxímenes","Tales de Mileto","Heráclito","Pitágoras"],"correcta":1},{"pregunta":"¿Qué defendía Parménides?","opciones":["El cambio constante","Que el ser es único e inmutable","El fuego como origen","Los átomos"],"correcta":1},{"pregunta":"¿Qué tránsito representan los presocráticos?","opciones":["Del logos al mito","Del mito al logos","De la ciencia al arte","De la religión al poder"],"correcta":1}]'::jsonb),

('filosofia', 'bachillerato', '{1}', 'Sócrates y el método mayéutico', 'Sócrates, nacido en Atenas en el siglo V antes de nuestra era, es considerado uno de los grandes maestros de la historia del pensamiento occidental, a pesar de no haber dejado obra escrita. Lo que conocemos de su filosofía procede principalmente de los diálogos de su discípulo Platón y de los testimonios de Jenofonte y Aristófanes. A diferencia de los sofistas, que cobraban por enseñar a argumentar y a ganar debates, Sócrates se presentaba como alguien que no sabía nada y que aspiraba únicamente a examinar sus propias creencias y las de sus interlocutores. Su método, conocido como mayéutica (palabra que significa arte de la partería), consistía en ayudar al otro a dar a luz las verdades que llevaba dentro mediante un diálogo basado en preguntas progresivas, que obligaban a cuestionar las opiniones recibidas. El objetivo era alcanzar definiciones universales de conceptos morales como la justicia, la valentía o la virtud. Sócrates identificaba el conocimiento con la virtud: quien conoce realmente el bien no puede dejar de hacerlo. Acusado de impiedad y de corromper a la juventud, fue condenado a muerte en el año 399 antes de nuestra era, y bebió la cicuta sin renunciar a sus principios. Su figura se convirtió en el modelo del filósofo mártir de la verdad.', '[{"pregunta":"¿En qué consiste la mayéutica?","opciones":["Imponer doctrinas","Ayudar a dar a luz verdades mediante preguntas","Contar mitos","Escribir libros"],"correcta":1},{"pregunta":"¿Qué afirmaba saber Sócrates?","opciones":["Todo","Nada","Solo matemáticas","Leyes"],"correcta":1},{"pregunta":"¿Qué identificaba con la virtud?","opciones":["La fuerza","El conocimiento","La riqueza","La elocuencia"],"correcta":1},{"pregunta":"¿Cómo murió Sócrates?","opciones":["En batalla","Bebiendo cicuta tras ser condenado","De vejez","Exiliado"],"correcta":1}]'::jsonb),

('filosofia', 'bachillerato', '{1}', 'La teoría de las Ideas de Platón', 'Platón, discípulo de Sócrates y fundador de la Academia de Atenas, desarrolló una de las teorías más influyentes de toda la filosofía: la teoría de las Ideas. Según esta doctrina, existen dos mundos claramente distinguibles: el mundo sensible, que percibimos a través de los sentidos y está en constante cambio, y el mundo inteligible, formado por las Ideas, que son realidades eternas, inmutables y perfectas. Las cosas que observamos en el mundo sensible son solo copias imperfectas o imitaciones de las Ideas correspondientes. Por ejemplo, los círculos dibujados nunca son círculos perfectos, sino aproximaciones de la Idea del Círculo. En la cúspide del mundo inteligible se encuentra la Idea del Bien, que ilumina a todas las demás y las hace inteligibles, del mismo modo que el sol permite ver los objetos en el mundo visible. Este dualismo se refleja en la famosa alegoría de la caverna, en la que Platón compara a los seres humanos ignorantes con prisioneros encadenados que solo ven sombras proyectadas en una pared. El conocimiento verdadero, la episteme, consiste en salir de la caverna mediante la razón y contemplar las Ideas. Platón defendía, además, que el alma es inmortal y que el conocimiento es una forma de reminiscencia de realidades contempladas antes del nacimiento.', '[{"pregunta":"¿Cuántos mundos distingue Platón?","opciones":["Uno","Dos","Tres","Cuatro"],"correcta":1},{"pregunta":"¿Qué ocupa la cúspide del mundo inteligible?","opciones":["Idea de belleza","Idea del Bien","Idea del mal","Idea de justicia"],"correcta":1},{"pregunta":"¿Qué ilustra la alegoría de la caverna?","opciones":["La guerra","El tránsito de la ignorancia al conocimiento","La vida política","La naturaleza"],"correcta":1},{"pregunta":"¿Cómo concibe Platón el conocimiento?","opciones":["Como invento reciente","Como reminiscencia de realidades pasadas","Como engaño","Como solo empírico"],"correcta":1}]'::jsonb),

('filosofia', 'bachillerato', '{1}', 'Aristóteles y la metafísica', 'Aristóteles, discípulo de Platón y maestro de Alejandro Magno, es una de las figuras más influyentes de la historia del pensamiento. A diferencia de su maestro, defendió que la realidad no reside en un mundo separado de Ideas, sino en los propios seres concretos que conocemos a través de los sentidos. Para él, las cosas están compuestas de materia y forma: la materia es aquello de lo que está hecho un objeto, y la forma es la estructura o esencia que lo hace ser lo que es. Esta teoría, conocida como hilemorfismo, permitió explicar el cambio sin renunciar a la existencia de una realidad estable. Aristóteles distinguió además cuatro tipos de causas que intervienen en la comprensión de cualquier fenómeno: la causa material, la formal, la eficiente y la final. La causa final, en particular, introduce una visión teleológica del mundo, pues supone que todo ser tiende hacia un fin o propósito propio. Su metafísica culmina en la idea de un Motor Inmóvil, primer principio eterno y perfecto que mueve a todas las cosas sin moverse él mismo. La obra aristotélica abarca lógica, ética, política, física, biología y poética, y durante la Edad Media y el Renacimiento se convirtió en referencia obligada para la filosofía y la teología cristianas.', '[{"pregunta":"¿Qué teoría defiende Aristóteles sobre los objetos?","opciones":["Dualismo platónico","Hilemorfismo","Atomismo","Escepticismo"],"correcta":1},{"pregunta":"¿Cuántas causas distingue?","opciones":["Dos","Tres","Cuatro","Cinco"],"correcta":2},{"pregunta":"¿Qué es la causa final?","opciones":["El material","El fin o propósito","El artesano","La forma"],"correcta":1},{"pregunta":"¿Qué es el Motor Inmóvil?","opciones":["Un mito","Primer principio eterno que mueve sin moverse","Un átomo","Una ley política"],"correcta":1}]'::jsonb),

('filosofia', 'bachillerato', '{1}', 'El estoicismo y el arte de vivir', 'El estoicismo es una corriente filosófica surgida en la Grecia helenística hacia el siglo III antes de nuestra era, fundada por Zenón de Citio y posteriormente difundida en el mundo romano por figuras como Séneca, Epicteto y el emperador Marco Aurelio. Más que una especulación abstracta, el estoicismo se concibe como un arte de vivir, una guía práctica para alcanzar la serenidad ante las adversidades de la existencia. Parte de la distinción entre lo que depende de nosotros, como nuestros pensamientos, juicios y acciones, y lo que no depende de nosotros, como la enfermedad, la muerte o las opiniones ajenas. El sabio estoico aprende a concentrarse en aquello sobre lo que tiene control, aceptando con ecuanimidad lo demás. Para ello cultiva la razón, considerada la facultad que nos vincula con el orden racional del universo, el logos. Las pasiones desordenadas son vistas como fruto de juicios erróneos y deben ser sustituidas por un estado de apatheia, que no significa indiferencia, sino ausencia de pasiones destructivas. La ética estoica propone vivir conforme a la naturaleza y practicar virtudes como la justicia, la prudencia, la templanza y la fortaleza. Su influencia ha pervivido hasta nuestros días y ha inspirado corrientes contemporáneas de desarrollo personal y psicología cognitiva.', '[{"pregunta":"¿Quién fundó el estoicismo?","opciones":["Epicuro","Zenón de Citio","Aristóteles","Platón"],"correcta":1},{"pregunta":"¿Qué distinción clave hace el estoicismo?","opciones":["Cuerpo y mente","Lo que depende de nosotros y lo que no","Ricos y pobres","Hombres y mujeres"],"correcta":1},{"pregunta":"¿Qué es la apatheia?","opciones":["Indiferencia total","Ausencia de pasiones destructivas","Odio al mundo","Pasión religiosa"],"correcta":1},{"pregunta":"¿Qué virtudes defiende?","opciones":["Solo valentía","Justicia, prudencia, templanza, fortaleza","Solo humildad","Solo riqueza"],"correcta":1}]'::jsonb),

('filosofia', 'bachillerato', '{1}', 'San Agustín y la filosofía cristiana', 'San Agustín de Hipona, obispo y teólogo del siglo IV-V, es uno de los pensadores más influyentes del cristianismo y de toda la filosofía occidental. En su juventud se interesó por el maniqueísmo y el neoplatonismo, antes de convertirse al cristianismo bajo la influencia de San Ambrosio de Milán. Sus obras principales, como las Confesiones o La Ciudad de Dios, combinan reflexión filosófica, teología y autobiografía espiritual. Uno de sus temas centrales es la relación entre la razón y la fe, que concibe como dos caminos complementarios hacia la verdad. Cree primero para poder entender, afirma, pero también entiende para creer mejor. Agustín aborda problemas clásicos como el de la naturaleza del tiempo, sobre el que afirma famosamente que sabe lo que es hasta que intenta explicarlo; el del mal, al que concibe como ausencia de bien; y el del libre albedrío, que considera esencial para que la moralidad tenga sentido. Su filosofía de la historia, expuesta en La Ciudad de Dios, divide la humanidad en dos ciudades simbólicas: la terrena, regida por el amor a uno mismo, y la celestial, regida por el amor a Dios. Su pensamiento marcó profundamente la cultura medieval y sigue siendo referencia para la reflexión teológica contemporánea.', '[{"pregunta":"¿Qué relación ve San Agustín entre razón y fe?","opciones":["Opuestas","Complementarias","Idénticas","Inútiles"],"correcta":1},{"pregunta":"¿Cómo concibe el mal?","opciones":["Como algo sustancial","Como ausencia de bien","Como creación divina","Como ilusión total"],"correcta":1},{"pregunta":"¿Qué obra divide a la humanidad en dos ciudades?","opciones":["Confesiones","La Ciudad de Dios","Suma Teológica","Apología"],"correcta":1},{"pregunta":"¿Qué sostiene sobre el libre albedrío?","opciones":["No existe","Es esencial para la moral","Es una ilusión","Solo lo tiene Dios"],"correcta":1}]'::jsonb),

('filosofia', 'bachillerato', '{1}', 'Santo Tomás de Aquino y la escolástica', 'Santo Tomás de Aquino, teólogo dominico del siglo XIII, es el máximo representante de la escolástica, corriente filosófica medieval caracterizada por el intento de armonizar la razón aristotélica con la fe cristiana. Nacido en Italia y formado en París, sus obras más importantes son la Suma Teológica y la Suma contra gentiles. Su proyecto filosófico responde al desafío planteado por la recuperación de las obras de Aristóteles a través de los filósofos árabes y judíos. Tomás sostiene que la razón y la fe, aunque diferentes, no pueden contradecirse, pues ambas provienen de Dios. Desarrolla las famosas cinco vías para demostrar racionalmente la existencia de Dios, que parten de la observación del mundo: el movimiento, la causalidad, la contingencia, los grados de perfección y el orden. Su ética distingue entre ley eterna, ley natural, ley humana y ley divina, y defiende que la razón humana puede descubrir principios morales universales presentes en la naturaleza. También aborda cuestiones políticas, reivindicando un poder civil legítimo subordinado a los fines últimos espirituales. Su obra se convirtió en la referencia oficial de la filosofía católica durante siglos y, aunque ha sido cuestionada, sigue presente en buena parte del pensamiento cristiano contemporáneo, incluida la doctrina social de la Iglesia.', '[{"pregunta":"¿A qué corriente pertenece Santo Tomás?","opciones":["Escolástica","Renacimiento","Ilustración","Positivismo"],"correcta":0},{"pregunta":"¿Qué intenta armonizar?","opciones":["Razón aristotélica y fe cristiana","Paganismo y cristianismo","Griego y latín","Ciencia y arte"],"correcta":0},{"pregunta":"¿Cuántas vías propone para demostrar a Dios?","opciones":["Tres","Cuatro","Cinco","Seis"],"correcta":2},{"pregunta":"¿Qué tipos de ley distingue?","opciones":["Solo natural","Eterna, natural, humana y divina","Civil y canónica","Penal y civil"],"correcta":1}]'::jsonb),

('filosofia', 'bachillerato', '{1}', 'Descartes y el racionalismo', 'René Descartes, filósofo y matemático francés del siglo XVII, es considerado el padre de la filosofía moderna por haber iniciado una ruptura radical con la tradición escolástica. Su objetivo era construir un saber firme y cierto, comparable al de las matemáticas, y para ello diseñó un método basado en cuatro reglas: evidencia, análisis, síntesis y enumeración. Descartes aplicó su método mediante la duda metódica, cuestionando todo aquello que pudiera ponerse en duda para encontrar un punto de partida indubitable. Dudó de los sentidos, de las verdades matemáticas, e incluso imaginó la existencia de un genio maligno que lo engañara constantemente. Pero en medio de esta duda radical descubrió que no podía dudar de que estaba dudando, de modo que debía existir al menos como sujeto pensante. Así formuló su célebre cogito, ergo sum: pienso, luego existo. A partir de esta verdad primera reconstruyó su sistema filosófico distinguiendo entre sustancia pensante y sustancia extensa, inaugurando así el dualismo cartesiano. Defendió también la existencia de Dios como garantía de la verdad y como fundamento último del conocimiento. El racionalismo cartesiano marcó profundamente la filosofía moderna y fue continuado por pensadores como Spinoza y Leibniz, que ampliaron su programa desde perspectivas distintas.', '[{"pregunta":"¿Quién inició la filosofía moderna?","opciones":["Kant","Descartes","Hume","Locke"],"correcta":1},{"pregunta":"¿Qué método usó Descartes?","opciones":["Duda metódica","Inducción empírica","Relato mítico","Escritura automática"],"correcta":0},{"pregunta":"¿Qué verdad primera encontró?","opciones":["Existe el mundo","Pienso, luego existo","Dios existe","La materia se extiende"],"correcta":1},{"pregunta":"¿Qué dualismo inauguró?","opciones":["Alma y cuerpo","Sustancia pensante y extensa","Luz y oscuridad","Razón y fe"],"correcta":1}]'::jsonb),

('filosofia', 'bachillerato', '{1}', 'El empirismo de Hume', 'David Hume, filósofo escocés del siglo XVIII, es uno de los máximos representantes del empirismo británico, corriente que defendía que todo nuestro conocimiento procede de la experiencia sensible. Su obra más conocida, el Tratado de la naturaleza humana, examina los procesos mentales humanos con un rigor que aspiraba a ser equivalente al de las ciencias naturales. Hume sostenía que las percepciones humanas son de dos tipos: impresiones, vívidas y directas, y las ideas, más débiles y derivadas de las impresiones. Todo conocimiento auténtico debe poder rastrearse hasta alguna impresión original; si no es así, se trata de una ficción. Partiendo de este principio, Hume cuestionó algunas nociones centrales del pensamiento filosófico, como la causalidad. Según él, no percibimos la causa sino únicamente una sucesión de hechos; la idea de causa es una inferencia del hábito, no una verdad demostrable. También puso en duda la existencia de un yo unificado, considerándolo un conjunto de percepciones cambiantes. Su escepticismo moderado despertó a Kant de su sueño dogmático, en palabras del propio filósofo alemán, y abrió camino a una reconsideración crítica del alcance y los límites del conocimiento humano. La obra de Hume sigue siendo imprescindible en cualquier estudio sobre epistemología y filosofía de la ciencia.', '[{"pregunta":"¿A qué corriente pertenece Hume?","opciones":["Racionalismo","Empirismo británico","Idealismo","Existencialismo"],"correcta":1},{"pregunta":"¿Qué son las impresiones?","opciones":["Ideas débiles","Percepciones vívidas y directas","Libros","Sueños"],"correcta":1},{"pregunta":"¿Qué critica Hume sobre la causalidad?","opciones":["Que es demostrable","Que es una inferencia del hábito","Que es divina","Que es innata"],"correcta":1},{"pregunta":"¿A quién despertó del sueño dogmático?","opciones":["Kant","Locke","Descartes","Nietzsche"],"correcta":0}]'::jsonb),

('filosofia', 'bachillerato', '{1}', 'Kant y el criticismo', 'Immanuel Kant, filósofo alemán del siglo XVIII, intentó superar la oposición entre racionalismo y empirismo mediante un proyecto original que denominó filosofía crítica. En su Crítica de la razón pura se preguntó por los límites y las condiciones del conocimiento humano. Sostuvo que conocer no es simplemente recibir datos del mundo exterior, sino que la mente aporta formas y categorías propias, como el espacio, el tiempo y los conceptos de sustancia o causalidad. Así, solo conocemos los fenómenos, es decir, las cosas tal como se nos aparecen, y no las cosas en sí mismas, el llamado noúmeno. Esta revolución copernicana del conocimiento, como él mismo la denominó, sostiene que el sujeto pone orden en el mundo para poder comprenderlo. En el terreno moral, expuesto en la Crítica de la razón práctica, defiende la existencia de un imperativo categórico que obliga a actuar según máximas que puedan universalizarse, respetando siempre la dignidad humana como fin y nunca como medio. La libertad, Dios y la inmortalidad del alma son, para Kant, postulados de la razón práctica, necesarios para la moralidad aunque no demostrables teóricamente. Su pensamiento influyó decisivamente en toda la filosofía posterior, desde el idealismo alemán hasta la ética contemporánea.', '[{"pregunta":"¿Qué intentó superar Kant?","opciones":["Idealismo y materialismo","Racionalismo y empirismo","Ciencia y arte","Mito y logos"],"correcta":1},{"pregunta":"¿Qué conocemos según Kant?","opciones":["La cosa en sí","Solo los fenómenos","Nada","Solo ideas innatas"],"correcta":1},{"pregunta":"¿Qué es el imperativo categórico?","opciones":["Consejo útil","Norma moral universalizable","Ley natural","Orden civil"],"correcta":1},{"pregunta":"¿Qué postulados establece?","opciones":["Materia y energía","Libertad, Dios e inmortalidad del alma","Tiempo y espacio solo","Causa y efecto"],"correcta":1}]'::jsonb),

('filosofia', 'bachillerato', '{1}', 'La ética utilitarista', 'El utilitarismo es una corriente ética desarrollada sobre todo por pensadores británicos del siglo XIX, como Jeremy Bentham y John Stuart Mill, aunque sus raíces pueden rastrearse en autores anteriores. Su principio fundamental, conocido como principio de la mayor felicidad, afirma que una acción es moralmente correcta si tiende a producir la mayor cantidad de bienestar o felicidad para el mayor número de personas. A diferencia de éticas deontológicas como la kantiana, el utilitarismo se fija en las consecuencias de los actos más que en la intención o en la norma que los guía. Bentham propuso incluso un cálculo aritmético de placeres y dolores considerando su intensidad, duración, proximidad o probabilidad. John Stuart Mill matizó esta visión distinguiendo entre placeres superiores (intelectuales y morales) e inferiores (sensoriales), sosteniendo que los primeros son cualitativamente preferibles. El utilitarismo ha sido muy influyente en la filosofía moral, política y económica moderna, pues ofrece un criterio aparentemente claro para evaluar políticas públicas y decisiones personales. Sin embargo, se le han hecho objeciones importantes: podría justificar sacrificar a unos pocos para beneficio de muchos, resulta difícil medir la felicidad con precisión, y puede no respetar derechos fundamentales. Pese a estas críticas, continúa siendo una referencia imprescindible en el debate ético actual.', '[{"pregunta":"¿Qué principio guía al utilitarismo?","opciones":["Imperativo categórico","Mayor felicidad para el mayor número","Ley natural","Destino"],"correcta":1},{"pregunta":"¿Quién propuso un cálculo de placeres?","opciones":["Kant","Bentham","Aristóteles","Hegel"],"correcta":1},{"pregunta":"¿Qué diferenció Mill?","opciones":["Bienes privados y públicos","Placeres superiores e inferiores","Leyes y normas","Mito y logos"],"correcta":1},{"pregunta":"¿Cuál es una crítica al utilitarismo?","opciones":["Puede justificar sacrificios individuales","No mide nada","Es muy religioso","Es idealista"],"correcta":0}]'::jsonb),

('filosofia', 'bachillerato', '{1}', 'Nietzsche y el cuestionamiento de los valores', 'Friedrich Nietzsche, filósofo alemán del siglo XIX, es una de las figuras más polémicas y provocadoras de la historia del pensamiento. Su obra constituye un ataque radical a los valores tradicionales de la cultura occidental, que considera fruto de una larga decadencia iniciada con Sócrates, el cristianismo y la moral de los débiles. Nietzsche acusa a esta moral de negar la vida, promover el resentimiento y privar al ser humano de su vitalidad creadora. Frente a ella propone la transvaloración de todos los valores y la figura del superhombre, un individuo que afirma la vida en toda su intensidad, crea sus propios valores y asume la responsabilidad de su existencia sin apoyarse en instancias trascendentes. Su célebre proclama Dios ha muerto no expresa alegría, sino la constatación de que en la cultura europea moderna los fundamentos tradicionales de sentido han perdido credibilidad, lo que abre a la vez una crisis y una oportunidad. Nietzsche introduce también conceptos como la voluntad de poder, el eterno retorno y el nihilismo, que busca superar mediante una afirmación radical de la vida. Su estilo aforístico y literario ha influido decisivamente en la filosofía, la literatura y el pensamiento crítico del siglo XX, aunque su recepción ha sido a menudo controvertida y objeto de interpretaciones contrapuestas.', '[{"pregunta":"¿Qué ataca Nietzsche?","opciones":["Los valores tradicionales occidentales","La ciencia moderna","Las matemáticas","Las ciudades"],"correcta":0},{"pregunta":"¿Qué significa Dios ha muerto?","opciones":["Alegría religiosa","Pérdida de credibilidad de los fundamentos tradicionales","Ateísmo jovial","Guerra santa"],"correcta":1},{"pregunta":"¿Qué figura propone como ideal?","opciones":["El monje","El superhombre","El guerrero","El rey"],"correcta":1},{"pregunta":"¿Qué concepto NO es suyo?","opciones":["Eterno retorno","Voluntad de poder","Imperativo categórico","Transvaloración"],"correcta":2}]'::jsonb),

('filosofia', 'bachillerato', '{1}', 'Lógica formal y argumentación', 'La lógica es la disciplina filosófica que estudia las formas correctas de razonamiento, es decir, las condiciones que permiten que de unas premisas se siga legítimamente una conclusión. Aristóteles fue el primero en sistematizarla en su obra Organon, donde presentó el silogismo como la estructura canónica del razonamiento deductivo. Un silogismo está compuesto por dos premisas y una conclusión que se sigue necesariamente de ellas si se respetan ciertas reglas formales. A lo largo de la historia, la lógica se ha ido desarrollando desde esquemas aristotélicos hasta llegar, en los siglos XIX y XX, a una lógica matemática de gran potencia expresiva, capaz de formalizar no solo el razonamiento tradicional sino también conceptos como los cuantificadores o las relaciones. Uno de los aspectos más importantes de la lógica contemporánea es el estudio de los argumentos informales, tan frecuentes en el debate cotidiano. Los argumentos pueden ser válidos o inválidos; los inválidos, cuando intentan convencer por caminos incorrectos, dan lugar a las llamadas falacias, como el ataque personal, el apelar a la mayoría o la falsa causa. Estudiar lógica no solo ayuda a razonar mejor, sino también a detectar manipulaciones y a desarrollar un espíritu crítico imprescindible en una sociedad democrática saturada de información y persuasión.', '[{"pregunta":"¿Quién sistematizó la lógica por primera vez?","opciones":["Platón","Aristóteles","Kant","Frege"],"correcta":1},{"pregunta":"¿Qué estructura estudió especialmente?","opciones":["El silogismo","El axioma","El verbo","La metáfora"],"correcta":0},{"pregunta":"¿Qué son las falacias?","opciones":["Demostraciones válidas","Argumentos inválidos que intentan convencer","Teoremas","Conclusiones ciertas"],"correcta":1},{"pregunta":"¿Para qué sirve la lógica hoy?","opciones":["Solo para matemáticas","Razonar mejor y detectar manipulaciones","Escribir poesía","Decorar textos"],"correcta":1}]'::jsonb),

('filosofia', 'bachillerato', '{1}', 'La filosofía política: contrato social', 'La idea de contrato social es una de las teorías políticas más influyentes de la modernidad. Intenta explicar el origen y la legitimidad del poder del Estado como el resultado de un acuerdo entre individuos que deciden abandonar un supuesto estado de naturaleza para vivir en sociedad. Thomas Hobbes, en su obra Leviatán, describe el estado de naturaleza como una situación de guerra de todos contra todos, en la que la vida humana sería solitaria, pobre, brutal y breve. Para evitarlo, los individuos renuncian a su libertad absoluta a cambio de seguridad, entregando el poder a un soberano absoluto. John Locke, por el contrario, concibe el estado de naturaleza como razonablemente pacífico, regido por la ley natural que reconoce derechos a la vida, la libertad y la propiedad. El contrato no supone una cesión total, sino la creación de un gobierno limitado encargado de proteger esos derechos. Jean-Jacques Rousseau propone una tercera versión en El contrato social, donde el pacto da lugar a una voluntad general que expresa el bien común y funda una democracia legítima. Estas teorías han influido profundamente en el constitucionalismo, las declaraciones de derechos y los sistemas políticos democráticos, y siguen sirviendo de marco para el debate sobre la legitimidad del poder y los límites del Estado.', '[{"pregunta":"¿Quién describe la guerra de todos contra todos?","opciones":["Locke","Rousseau","Hobbes","Kant"],"correcta":2},{"pregunta":"¿Qué defiende Locke del contrato?","opciones":["Gobierno absoluto","Gobierno limitado que protege derechos","Ausencia de Estado","Tiranía necesaria"],"correcta":1},{"pregunta":"¿Qué introduce Rousseau?","opciones":["El mercado","La voluntad general","La monarquía divina","El feudalismo"],"correcta":1},{"pregunta":"¿Qué influencia tuvieron estas teorías?","opciones":["Ninguna","Constitucionalismo y democracia","Religión oriental","Ciencia experimental"],"correcta":1}]'::jsonb),

('filosofia', 'bachillerato', '{1}', 'El existencialismo del siglo XX', 'El existencialismo es una corriente filosófica que cobró gran protagonismo en el siglo XX, especialmente tras las dos guerras mundiales, cuando muchos pensadores sintieron la necesidad de responder a la experiencia de la crisis, el absurdo y la responsabilidad individual. Aunque sus raíces se remontan a filósofos del siglo XIX como Soren Kierkegaard, sus figuras más conocidas son Jean-Paul Sartre, Simone de Beauvoir, Albert Camus, Martin Heidegger y Karl Jaspers. El rasgo común del existencialismo es la idea de que la existencia precede a la esencia: no hay una naturaleza humana previa que determine quiénes somos, sino que cada persona se construye a sí misma a través de sus elecciones y acciones. De ahí la importancia de conceptos como la libertad, la responsabilidad, la angustia y la autenticidad. Para Sartre, somos radicalmente libres y por eso estamos condenados a ser responsables de nuestra vida, sin poder escudarnos en excusas ni en justificaciones externas. Camus reflexiona sobre el absurdo, surgido del contraste entre nuestra demanda de sentido y el silencio del universo. Simone de Beauvoir aplicó estas ideas al análisis de la condición femenina en El segundo sexo. El existencialismo ha dejado una huella profunda en la literatura, la psicología, la ética y los debates contemporáneos sobre la identidad personal.', '[{"pregunta":"¿Qué tesis central comparte el existencialismo?","opciones":["La esencia precede a la existencia","La existencia precede a la esencia","No hay libertad","Dios determina todo"],"correcta":1},{"pregunta":"¿Quién reflexionó sobre el absurdo?","opciones":["Camus","Locke","Kant","Platón"],"correcta":0},{"pregunta":"¿Qué obra analiza la condición femenina?","opciones":["El ser y la nada","El segundo sexo","El mito de Sísifo","Ser y tiempo"],"correcta":1},{"pregunta":"¿Qué experiencia histórica impulsó al existencialismo?","opciones":["Revolución francesa","Las dos guerras mundiales","Guerra fría solo","Descolonización"],"correcta":1}]'::jsonb),

('filosofia', 'bachillerato', '{1}', 'La filosofía feminista contemporánea', 'La filosofía feminista es una corriente de pensamiento que analiza las relaciones entre los sexos y los géneros desde una perspectiva crítica, con el objetivo de desvelar y cuestionar las desigualdades estructurales entre hombres y mujeres a lo largo de la historia. Sus antecedentes pueden rastrearse en obras como Vindicación de los derechos de la mujer, de Mary Wollstonecraft, publicada a finales del siglo XVIII, o en las luchas sufragistas del siglo XIX y principios del XX por el derecho al voto femenino. En el siglo XX, pensadoras como Simone de Beauvoir, Betty Friedan, Kate Millett o Judith Butler han impulsado un análisis filosófico profundo de categorías como género, patriarcado, sexualidad, trabajo doméstico o cuidados. Una de las ideas centrales de la filosofía feminista contemporánea es la distinción entre sexo, como realidad biológica, y género, como construcción social, que permite explicar por qué los roles atribuidos a hombres y mujeres varían tanto entre culturas y épocas. Estas reflexiones han llevado a revisar no solo las instituciones sociales sino también la historia de la filosofía misma, que durante siglos ignoró sistemáticamente las voces femeninas. La filosofía feminista dialoga actualmente con muchas otras corrientes, como el poscolonialismo o la ecología política, aportando perspectivas imprescindibles para el pensamiento crítico del siglo XXI.', '[{"pregunta":"¿Qué analiza la filosofía feminista?","opciones":["Solo literatura","Las desigualdades entre sexos y géneros","Solo religión","Ninguna cuestión social"],"correcta":1},{"pregunta":"¿Qué distinción defiende?","opciones":["Cuerpo y alma","Sexo biológico y género construido","Rico y pobre","Joven y viejo"],"correcta":1},{"pregunta":"¿Quién escribió Vindicación de los derechos de la mujer?","opciones":["Beauvoir","Wollstonecraft","Butler","Friedan"],"correcta":1},{"pregunta":"¿Con qué otras corrientes dialoga actualmente?","opciones":["Poscolonialismo y ecología política","Solo escolástica","Neoplatonismo","Estoicismo"],"correcta":0}]'::jsonb),

('filosofia', 'bachillerato', '{1}', 'La bioética y los dilemas morales contemporáneos', 'La bioética es una disciplina relativamente reciente, surgida en la segunda mitad del siglo XX, que se ocupa del estudio de las cuestiones éticas planteadas por los avances de las ciencias biomédicas y biotecnológicas. Temas como el aborto, la eutanasia, la donación y trasplante de órganos, la reproducción asistida, la investigación con células madre, la manipulación genética o el final de la vida son objeto de intenso debate en las sociedades contemporáneas. La bioética busca responder a estos dilemas mediante principios reconocibles y argumentos racionales, más allá de posicionamientos ideológicos o religiosos. En este sentido, los filósofos Tom Beauchamp y James Childress propusieron un enfoque muy influyente basado en cuatro principios: autonomía, beneficencia, no maleficencia y justicia. La autonomía defiende el derecho de cada persona a decidir sobre su propio cuerpo y sus tratamientos; la beneficencia exige actuar en favor del bien del paciente; la no maleficencia obliga a evitar daños innecesarios; y la justicia busca distribuir equitativamente recursos y oportunidades. Aplicar estos principios no siempre es sencillo, porque con frecuencia entran en conflicto entre sí. Los comités de bioética de hospitales y organismos internacionales desempeñan un papel cada vez más importante en la toma de decisiones, y la bioética se ha convertido en un espacio privilegiado para el diálogo interdisciplinar entre filosofía, medicina, derecho y sociedad.', '[{"pregunta":"¿Cuándo surge la bioética?","opciones":["Siglo XVI","Siglo XIX","Segunda mitad del siglo XX","Siglo XXI"],"correcta":2},{"pregunta":"¿Quiénes propusieron los cuatro principios?","opciones":["Kant y Mill","Beauchamp y Childress","Sartre y Camus","Platón y Aristóteles"],"correcta":1},{"pregunta":"¿Cuál NO es un principio bioético?","opciones":["Autonomía","Beneficencia","Maximización del beneficio empresarial","Justicia"],"correcta":2},{"pregunta":"¿Qué papel tienen los comités de bioética?","opciones":["Decorativo","Toman parte en la toma de decisiones complejas","Solo religioso","Solo académico"],"correcta":1}]'::jsonb);

