INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('fisica', 'bachillerato', '{1}', 'La cinemática del movimiento rectilíneo', 'La cinemática es la parte de la física que estudia el movimiento de los cuerpos sin atender a sus causas. Se basa en magnitudes fundamentales como la posición, el desplazamiento, la velocidad y la aceleración, todas ellas definidas respecto a un sistema de referencia. En el movimiento rectilíneo uniforme, el objeto recorre distancias iguales en tiempos iguales y su velocidad permanece constante. La ecuación característica relaciona la posición final con la posición inicial, la velocidad y el tiempo transcurrido. Cuando la velocidad cambia de forma constante, hablamos de movimiento rectilíneo uniformemente acelerado, en el que la aceleración es constante y se pueden deducir relaciones que vinculan posición, velocidad, aceleración y tiempo. Un caso particularmente importante es la caída libre, idealización en la que un cuerpo se deja caer sobre la superficie terrestre sin resistencia del aire y experimenta una aceleración aproximadamente constante debida a la gravedad, de valor cercano a 9,8 metros por segundo al cuadrado. Galileo Galilei fue pionero en describir este tipo de movimientos mediante experimentos con planos inclinados, ya que podía estudiar así aceleraciones menores y más fáciles de medir. Desde los trabajos de Galileo, la cinemática se ha desarrollado con gran rigor y constituye la base para la formulación posterior de la dinámica y de otras ramas más avanzadas de la física.', '[{"pregunta":"¿Qué estudia la cinemática?","opciones":["Las causas del movimiento","El movimiento sin atender a sus causas","Solo fuerzas","Solo masas"],"correcta":1},{"pregunta":"¿Qué característica tiene el MRU?","opciones":["Aceleración variable","Velocidad constante","Posición fija","Sin tiempo"],"correcta":1},{"pregunta":"¿Qué es la caída libre?","opciones":["Lanzamiento con motor","Caída sin resistencia del aire con gravedad","Movimiento circular","Rebote elástico"],"correcta":1},{"pregunta":"¿Quién estudió estos movimientos con planos inclinados?","opciones":["Newton","Galileo","Einstein","Kepler"],"correcta":1}]'::jsonb),

('fisica', 'bachillerato', '{1}', 'El principio de inercia de Newton', 'El principio de inercia, conocido como primera ley de Newton, establece que todo cuerpo permanece en reposo o en movimiento rectilíneo uniforme a menos que una fuerza externa actúe sobre él. Este enunciado, aparentemente sencillo, supuso una ruptura radical con la física aristotélica, que sostenía que los cuerpos tienden naturalmente al reposo. Galileo ya había intuido el principio al estudiar objetos que se deslizaban sobre superficies cada vez más lisas, observando que tardaban más en detenerse. Isaac Newton, en sus Principia Mathematica de 1687, formalizó esta idea como ley fundamental del movimiento. La inercia expresa la resistencia de un cuerpo al cambio de su estado de movimiento, propiedad que está directamente relacionada con su masa: cuanto mayor es la masa, mayor es la inercia. Por ello, una locomotora requiere un gran esfuerzo para arrancar y para detenerse, mientras que un objeto ligero se mueve con facilidad. La primera ley también nos dice que los sistemas de referencia inerciales son aquellos en los que el principio se cumple, es decir, sistemas que no aceleran. Comprender la inercia es imprescindible para entender fenómenos cotidianos como por qué sentimos un empuje hacia adelante cuando un autobús frena bruscamente: nuestro cuerpo tiende a seguir su movimiento anterior.', '[{"pregunta":"¿Quién formalizó la primera ley?","opciones":["Galileo","Newton","Einstein","Aristóteles"],"correcta":1},{"pregunta":"¿Qué afirma la inercia?","opciones":["Los cuerpos siempre se detienen","Un cuerpo mantiene su estado si no actúa una fuerza","Todo acelera","Nada se mueve"],"correcta":1},{"pregunta":"¿Con qué se relaciona la inercia?","opciones":["Color","Masa","Volumen","Temperatura"],"correcta":1},{"pregunta":"¿Qué es un sistema inercial?","opciones":["Uno que acelera","Uno que no acelera","Uno que gira","Uno que rebota"],"correcta":1}]'::jsonb),

('fisica', 'bachillerato', '{1}', 'La segunda ley de Newton', 'La segunda ley de Newton expresa matemáticamente la relación entre la fuerza aplicada a un cuerpo, su masa y la aceleración que adquiere. Su enunciado clásico afirma que la fuerza resultante que actúa sobre un cuerpo es igual al producto de su masa por la aceleración. Esta relación se escribe de forma sintética como F = m·a, una de las ecuaciones más famosas de la física. La ley permite resolver numerosos problemas prácticos: predecir el movimiento de un proyectil, calcular la aceleración de un vehículo, entender la trayectoria de un satélite o diseñar estructuras resistentes. Una consecuencia directa es que cuanto mayor es la masa de un cuerpo, mayor es la fuerza necesaria para producir la misma aceleración. De ahí que un camión necesite un motor más potente que un coche para acelerar de igual manera. La unidad de fuerza en el Sistema Internacional es el newton, definida precisamente a partir de esta ley: un newton es la fuerza necesaria para comunicar una aceleración de un metro por segundo al cuadrado a un cuerpo de un kilogramo de masa. La segunda ley abrió la puerta al estudio sistemático de las fuerzas como causas del movimiento, y durante más de doscientos años constituyó la base de la mecánica clásica hasta los desarrollos de Einstein a principios del siglo XX.', '[{"pregunta":"¿Qué relaciona la segunda ley de Newton?","opciones":["Masa y volumen","Fuerza, masa y aceleración","Carga y campo","Temperatura y presión"],"correcta":1},{"pregunta":"¿Cuál es la ecuación clásica?","opciones":["E=mc²","F=ma","V=IR","P=VI"],"correcta":1},{"pregunta":"¿Qué unidad corresponde a la fuerza?","opciones":["Julio","Newton","Vatio","Pascal"],"correcta":1},{"pregunta":"¿Quién superó la mecánica clásica a comienzos del siglo XX?","opciones":["Newton","Einstein","Galileo","Bohr"],"correcta":1}]'::jsonb),

('fisica', 'bachillerato', '{1}', 'La tercera ley de Newton: acción y reacción', 'La tercera ley de Newton, también conocida como principio de acción y reacción, afirma que cuando un cuerpo ejerce una fuerza sobre otro, este segundo ejerce simultáneamente sobre el primero una fuerza igual en magnitud y dirección pero de sentido opuesto. Estas fuerzas no se anulan entre sí, porque actúan sobre cuerpos distintos. La ley se observa constantemente en la vida cotidiana. Cuando caminamos, por ejemplo, empujamos el suelo hacia atrás con nuestros pies, y el suelo nos empuja hacia adelante con la misma fuerza, permitiéndonos avanzar. Lo mismo ocurre cuando un cohete despega: los gases salen a gran velocidad por la parte inferior y, como reacción, el cohete es impulsado hacia arriba. Esta idea resulta sorprendentemente útil en ingeniería aeroespacial y es la base de la propulsión de aviones y naves espaciales. La tercera ley tiene consecuencias profundas en la conservación del momento lineal, magnitud que permanece constante en un sistema aislado y que resulta muy útil para analizar colisiones entre objetos. Comprender la simetría de las fuerzas ayuda a razonar correctamente sobre situaciones aparentemente paradójicas, como por qué no podemos avanzar en una superficie completamente lisa y sin fricción: sin una fuerza de reacción externa, no hay modo de impulsarse hacia adelante.', '[{"pregunta":"¿Qué afirma la tercera ley?","opciones":["Todo cuerpo se detiene","A toda acción corresponde una reacción igual y opuesta","Las masas se repelen","La energía se crea"],"correcta":1},{"pregunta":"¿Por qué no se anulan las fuerzas?","opciones":["Porque son iguales","Actúan sobre cuerpos distintos","Son imaginarias","Son muy pequeñas"],"correcta":1},{"pregunta":"¿Qué magnitud se conserva en un sistema aislado?","opciones":["Masa","Momento lineal","Temperatura","Color"],"correcta":1},{"pregunta":"¿Por qué un cohete avanza?","opciones":["Por gravedad","Porque expulsa gases y recibe reacción","Por el viento","Por combustión directa"],"correcta":1}]'::jsonb),

('fisica', 'bachillerato', '{1}', 'La gravitación universal', 'La ley de la gravitación universal, formulada por Isaac Newton en el siglo XVII, establece que todos los cuerpos del universo se atraen entre sí con una fuerza directamente proporcional al producto de sus masas e inversamente proporcional al cuadrado de la distancia que los separa. Esta fuerza es la responsable de fenómenos tan distintos como la caída de una manzana, el movimiento de los planetas alrededor del Sol o el ritmo de las mareas. La anécdota de la manzana, aunque probablemente embellecida, ilustra el momento en que Newton comprendió que la misma fuerza que hacía caer los objetos cerca de la Tierra era la que mantenía a la Luna en su órbita. Combinando sus leyes del movimiento con la ley de la gravitación, pudo explicar matemáticamente las leyes del movimiento planetario descubiertas por Johannes Kepler. La constante de gravitación universal, representada por G, tiene un valor extraordinariamente pequeño, por lo que la gravedad es despreciable entre objetos cotidianos pero se vuelve dominante en escalas astronómicas debido a las enormes masas implicadas. La teoría de la gravitación newtoniana fue considerada durante más de dos siglos como una descripción completa del universo. A comienzos del siglo XX, Albert Einstein la generalizó con su teoría de la relatividad general, que concibe la gravedad como una curvatura del espacio-tiempo provocada por la masa y la energía.', '[{"pregunta":"¿Qué factor reduce la fuerza gravitatoria al aumentar?","opciones":["La masa","La distancia al cuadrado","La temperatura","El volumen"],"correcta":1},{"pregunta":"¿Quién formuló la ley de gravitación universal?","opciones":["Kepler","Newton","Galileo","Einstein"],"correcta":1},{"pregunta":"¿Qué leyes planetarias explicó Newton?","opciones":["Las de Aristóteles","Las de Kepler","Las de Maxwell","Las de Faraday"],"correcta":1},{"pregunta":"¿Cómo concibe la gravedad la relatividad general?","opciones":["Como fluido","Como curvatura del espacio-tiempo","Como fuerza electromagnética","Como viento cósmico"],"correcta":1}]'::jsonb),

('fisica', 'bachillerato', '{1}', 'La energía cinética y potencial', 'La energía es una de las magnitudes más importantes y versátiles de la física. Puede definirse como la capacidad de un sistema para realizar un trabajo, y adopta diversas formas entre las cuales dos son fundamentales en mecánica: la energía cinética y la energía potencial. La energía cinética es la que posee un cuerpo debido a su movimiento; depende de su masa y del cuadrado de su velocidad, de manera que se multiplica por cuatro cuando la velocidad se duplica. La energía potencial, en cambio, está asociada a la posición del cuerpo dentro de un campo de fuerzas, como el gravitatorio o el elástico. En el caso gravitatorio, un objeto situado a cierta altura sobre el suelo posee energía potencial proporcional a su masa, a la altura y a la gravedad local. En los sistemas elásticos, como un muelle comprimido, la energía potencial se relaciona con la deformación elástica. El principio de conservación de la energía mecánica afirma que, en ausencia de rozamientos u otras fuerzas disipativas, la suma de energía cinética y potencial se mantiene constante a lo largo del movimiento. Este principio permite analizar de forma elegante situaciones complejas, como el movimiento de un péndulo o el de una montaña rusa, en las que la energía se transforma continuamente de un tipo a otro sin que su total cambie.', '[{"pregunta":"¿De qué depende la energía cinética?","opciones":["Masa y velocidad al cuadrado","Solo altura","Solo tiempo","Temperatura"],"correcta":0},{"pregunta":"¿Qué sucede si se duplica la velocidad?","opciones":["Energía cinética se duplica","Se multiplica por cuatro","Se reduce","No cambia"],"correcta":1},{"pregunta":"¿En qué se basa la energía potencial gravitatoria?","opciones":["Velocidad","Altura, masa y gravedad","Carga eléctrica","Presión"],"correcta":1},{"pregunta":"¿Qué afirma el principio de conservación?","opciones":["La energía siempre aumenta","La suma de cinética y potencial se mantiene sin rozamiento","La energía desaparece","No se puede medir"],"correcta":1}]'::jsonb),

('fisica', 'bachillerato', '{1}', 'La primera ley de la termodinámica', 'La termodinámica es la rama de la física que estudia las transformaciones de energía entre sistemas y su entorno, con especial atención al calor y al trabajo. Su primera ley es una formulación del principio de conservación de la energía aplicada a procesos térmicos. Afirma que la variación de la energía interna de un sistema es igual al calor absorbido menos el trabajo realizado por el sistema. En otras palabras, la energía no se crea ni se destruye; solo se transforma o se transfiere. Esta ley tiene consecuencias prácticas enormes, pues permite analizar procesos tan diversos como el funcionamiento de un motor, el calentamiento de un líquido, la refrigeración industrial o el metabolismo de un ser vivo. El calor y el trabajo son dos formas de transferencia de energía con diferencias importantes: el calor se transmite por diferencia de temperatura, mientras que el trabajo se asocia a un desplazamiento bajo la acción de una fuerza. Junto con la segunda y la tercera leyes, la primera ley constituye el núcleo de la termodinámica clásica, desarrollada en el siglo XIX a partir de los estudios de Carnot, Joule y Clausius, y aplicada con éxito en la ingeniería, la química y la biología. Comprender sus implicaciones es esencial para entender la eficiencia de cualquier transformación energética y para abordar los retos contemporáneos de la gestión sostenible de la energía.', '[{"pregunta":"¿Qué expresa la primera ley de la termodinámica?","opciones":["Conservación de la energía","Creación de energía","Destrucción de energía","Cambio de masa"],"correcta":0},{"pregunta":"¿Cómo se transmite el calor?","opciones":["Por diferencia de temperatura","Por fuerza","Por imanes","Por color"],"correcta":0},{"pregunta":"¿Quién NO es un pionero de la termodinámica?","opciones":["Carnot","Joule","Clausius","Newton"],"correcta":3},{"pregunta":"¿Qué representa W en la fórmula?","opciones":["Calor","Trabajo realizado por el sistema","Volumen","Viscosidad"],"correcta":1}]'::jsonb),

('fisica', 'bachillerato', '{1}', 'La electricidad y el circuito eléctrico', 'La electricidad es uno de los pilares de la civilización moderna y se basa en el estudio de las cargas eléctricas y su movimiento. Las cargas pueden ser positivas o negativas, y cargas del mismo signo se repelen, mientras que cargas de distinto signo se atraen, como establece la ley de Coulomb. Un circuito eléctrico es un camino cerrado por el que pueden circular electrones impulsados por una fuente de energía, como una pila o un generador. Los componentes básicos de un circuito son la fuente, los conductores, los receptores (lámparas, resistencias, motores) y los elementos de control como interruptores. La magnitud que mide el flujo de cargas es la intensidad, cuya unidad es el amperio. La diferencia de potencial o voltaje, medida en voltios, representa la energía por unidad de carga suministrada por la fuente. La relación entre voltaje, intensidad y resistencia se expresa mediante la ley de Ohm, según la cual la intensidad es directamente proporcional al voltaje e inversamente proporcional a la resistencia. Los circuitos pueden conectarse en serie o en paralelo, con consecuencias distintas sobre cómo se distribuyen voltajes e intensidades. El estudio de los circuitos es esencial para diseñar desde una simple linterna hasta un ordenador, y sus fundamentos permiten entender el funcionamiento de prácticamente toda la electrónica moderna.', '[{"pregunta":"¿Qué ley relaciona voltaje, intensidad y resistencia?","opciones":["Coulomb","Ohm","Faraday","Ampère"],"correcta":1},{"pregunta":"¿En qué unidad se mide la intensidad?","opciones":["Ohmio","Voltio","Amperio","Vatio"],"correcta":2},{"pregunta":"¿Qué elemento interrumpe el paso de la corriente?","opciones":["Pila","Interruptor","Lámpara","Cable"],"correcta":1},{"pregunta":"¿Cómo pueden conectarse los circuitos?","opciones":["Solo en serie","Solo en paralelo","En serie o paralelo","Al azar"],"correcta":2}]'::jsonb),

('fisica', 'bachillerato', '{1}', 'Las ondas: características generales', 'Una onda es una perturbación que se propaga por el espacio o por un medio material transportando energía pero sin transporte neto de materia. El ejemplo más intuitivo es una cuerda que se agita por un extremo: las partículas de la cuerda vibran en torno a sus posiciones de equilibrio, pero la perturbación se desplaza. Las ondas se clasifican según distintos criterios. Atendiendo al medio, se distingue entre ondas mecánicas, como el sonido o las ondas en el agua, que necesitan un medio material para propagarse, y ondas electromagnéticas, como la luz, que pueden viajar en el vacío. Según la relación entre la vibración y la dirección de propagación, se distingue entre ondas transversales, en las que la vibración es perpendicular al movimiento, y longitudinales, en las que coincide con la dirección de avance. Las magnitudes fundamentales que caracterizan una onda son la amplitud (valor máximo de la perturbación), la frecuencia (número de oscilaciones por segundo, medida en hercios), el período (tiempo de una oscilación completa), la longitud de onda (distancia entre dos puntos en fase) y la velocidad de propagación, relacionada con las tres anteriores. Fenómenos como la reflexión, la refracción, la interferencia o la difracción son propios del comportamiento ondulatorio y permiten identificar si una determinada perturbación tiene o no naturaleza ondulatoria.', '[{"pregunta":"¿Qué transportan las ondas?","opciones":["Materia","Energía sin transporte neto de materia","Solo sonido","Cargas eléctricas"],"correcta":1},{"pregunta":"¿Qué onda necesita un medio material?","opciones":["Electromagnética","Mecánica","Luminosa","Gravitacional"],"correcta":1},{"pregunta":"¿Cómo vibran las partículas en una onda transversal?","opciones":["En la misma dirección","Perpendicular a la propagación","No vibran","Solo rotan"],"correcta":1},{"pregunta":"¿Qué fenómeno NO es ondulatorio?","opciones":["Reflexión","Refracción","Fotosíntesis","Difracción"],"correcta":2}]'::jsonb),

('fisica', 'bachillerato', '{1}', 'La luz y la óptica geométrica', 'La luz es una forma de energía de naturaleza electromagnética que se propaga en el vacío a una velocidad aproximada de 300 000 kilómetros por segundo. Durante siglos su naturaleza fue objeto de intenso debate: algunos, como Isaac Newton, defendían una concepción corpuscular, mientras que otros, como Christiaan Huygens, proponían un modelo ondulatorio. En el siglo XIX, James Clerk Maxwell demostró que la luz es una onda electromagnética, unificando electricidad, magnetismo y óptica. Ya en el siglo XX, la mecánica cuántica reveló su dualidad onda-corpúsculo. La óptica geométrica es una aproximación útil que trata la luz como rayos rectilíneos y permite estudiar fenómenos como la reflexión y la refracción. La ley de la reflexión establece que el ángulo del rayo incidente es igual al del rayo reflejado, ambos medidos respecto a la normal. La refracción, por su parte, ocurre cuando la luz pasa de un medio a otro con distinta velocidad, y se describe mediante la ley de Snell. Estos principios permiten explicar el funcionamiento de espejos, lentes y prismas, y son la base de instrumentos ópticos como microscopios, telescopios, gafas y cámaras. Aunque la óptica geométrica no describe adecuadamente todos los fenómenos luminosos, su sencillez la hace muy útil en numerosas aplicaciones prácticas y educativas.', '[{"pregunta":"¿A qué velocidad se propaga la luz en el vacío?","opciones":["30 km/s","300 km/s","3 000 km/s","300 000 km/s"],"correcta":3},{"pregunta":"¿Quién demostró que la luz es una onda electromagnética?","opciones":["Newton","Huygens","Maxwell","Einstein"],"correcta":2},{"pregunta":"¿Qué describe la ley de Snell?","opciones":["Reflexión","Refracción","Difracción","Absorción"],"correcta":1},{"pregunta":"¿Qué es la dualidad onda-corpúsculo?","opciones":["La luz se comporta como onda y como partícula","Luz y sombra","Dos colores","Dos velocidades"],"correcta":0}]'::jsonb),

('fisica', 'bachillerato', '{1}', 'El átomo y sus modelos', 'La concepción del átomo ha cambiado radicalmente a lo largo de la historia. El término proviene del griego y significa indivisible, y fue utilizado por primera vez por los filósofos presocráticos Leucipo y Demócrito. Durante siglos, la idea permaneció olvidada hasta que John Dalton, a principios del siglo XIX, la recuperó como base de la química moderna, proponiendo que la materia está compuesta por partículas minúsculas, iguales entre sí en cada elemento. A finales del mismo siglo, el descubrimiento del electrón por J. J. Thomson demostró que el átomo no era indivisible y llevó a proponer el modelo del pudín de pasas, con una masa positiva salpicada de electrones. Ernest Rutherford, en 1911, hizo pasar partículas alfa a través de una fina lámina de oro y descubrió que la mayor parte del átomo era espacio vacío, con un núcleo denso y positivo en el centro. Niels Bohr perfeccionó este modelo introduciendo órbitas cuantizadas para los electrones, capaces de absorber y emitir energía en cantidades discretas. Finalmente, la mecánica cuántica moderna sustituyó las órbitas definidas por orbitales, regiones del espacio donde es más probable encontrar un electrón. Cada modelo ha supuesto una aproximación mejor a la realidad, mostrando cómo la ciencia avanza mediante revisión y corrección de sus ideas anteriores.', '[{"pregunta":"¿Quién propuso el modelo del pudín de pasas?","opciones":["Bohr","Thomson","Rutherford","Dalton"],"correcta":1},{"pregunta":"¿Qué descubrió Rutherford?","opciones":["El electrón","Un núcleo denso y positivo","Los quarks","La radiación cósmica"],"correcta":1},{"pregunta":"¿Qué aportó Bohr?","opciones":["Órbitas cuantizadas","Modelo continuo","Neutrones","Antimateria"],"correcta":0},{"pregunta":"¿Qué sustituye a las órbitas en la mecánica cuántica?","opciones":["Círculos","Orbitales probabilísticos","Elipses","Líneas rectas"],"correcta":1}]'::jsonb),

('fisica', 'bachillerato', '{1}', 'La tabla periódica de los elementos', 'La tabla periódica es una de las herramientas más útiles de la química. Organiza todos los elementos conocidos en función de su número atómico, es decir, del número de protones de sus átomos, y agrupa a aquellos con propiedades químicas similares. Fue concebida en 1869 por el químico ruso Dmitri Mendeléyev, quien observó regularidades entre los elementos entonces conocidos y fue capaz de predecir la existencia y las propiedades de varios elementos aún no descubiertos, como el galio y el germanio. La tabla está organizada en filas llamadas periodos y columnas llamadas grupos. Los elementos de un mismo grupo presentan configuraciones electrónicas semejantes en la capa más externa, lo que explica su parecido químico. Entre los grupos más conocidos destacan los metales alcalinos, los halógenos y los gases nobles. La tabla también permite distinguir entre metales, situados en la izquierda y el centro, y no metales, ubicados a la derecha, con una zona intermedia de semimetales o metaloides. Propiedades como la electronegatividad, el radio atómico o la energía de ionización muestran tendencias periódicas que se pueden predecir mirando la posición del elemento. Esta organización es fruto de décadas de trabajo y sigue siendo fundamental para la investigación química, el diseño de nuevos materiales y la enseñanza de las ciencias experimentales.', '[{"pregunta":"¿Por qué se organizan los elementos?","opciones":["Por color","Por número atómico","Por precio","Por letra"],"correcta":1},{"pregunta":"¿Quién concibió la tabla?","opciones":["Mendeléyev","Dalton","Lavoisier","Bohr"],"correcta":0},{"pregunta":"¿Qué son los periodos?","opciones":["Las filas","Las columnas","Los metales","Los núcleos"],"correcta":0},{"pregunta":"¿Qué grupo es conocido por su inertes?","opciones":["Metales alcalinos","Halógenos","Gases nobles","Lantánidos"],"correcta":2}]'::jsonb),

('fisica', 'bachillerato', '{1}', 'Las reacciones químicas y la estequiometría', 'Una reacción química es un proceso en el que una o varias sustancias, llamadas reactivos, se transforman en otras distintas, llamadas productos, mediante la ruptura y formación de enlaces químicos. Durante estas transformaciones, los átomos no se crean ni se destruyen, sino que se reordenan, de acuerdo con el principio de conservación de la masa enunciado por Antoine Lavoisier en el siglo XVIII. Las reacciones se representan mediante ecuaciones químicas que deben estar ajustadas, es decir, con el mismo número de átomos de cada elemento en ambos lados de la flecha. La estequiometría es la rama de la química que estudia las relaciones cuantitativas entre las sustancias que participan en una reacción, utilizando unidades como el mol, que corresponde a aproximadamente 6,022 por diez elevado a 23 partículas. A partir de una ecuación ajustada se pueden calcular cantidades de reactivos y productos, prever rendimientos y optimizar procesos industriales. Los distintos tipos de reacciones incluyen combinaciones, descomposiciones, desplazamientos y reacciones redox, en las que hay transferencia de electrones. Algunas reacciones son exotérmicas, pues liberan energía, mientras que otras son endotérmicas y requieren absorción de energía. El conocimiento de las reacciones es la base de la química aplicada, desde la producción de medicamentos hasta la obtención de energía mediante combustibles.', '[{"pregunta":"¿Qué principio enunció Lavoisier?","opciones":["Conservación de la energía","Conservación de la masa","Exclusión de Pauli","Incertidumbre"],"correcta":1},{"pregunta":"¿Qué es la estequiometría?","opciones":["Estudio de las proporciones en las reacciones","Rama de la física","Tipo de enlace","Disolvente especial"],"correcta":0},{"pregunta":"¿Qué es un mol?","opciones":["Unidad de masa","Aproximadamente 6,022·10^23 partículas","Medida de volumen","Tipo de átomo"],"correcta":1},{"pregunta":"¿Qué tipo de reacción libera energía?","opciones":["Endotérmica","Exotérmica","Neutra","Redox siempre"],"correcta":1}]'::jsonb),

('fisica', 'bachillerato', '{1}', 'Los estados de agregación de la materia', 'La materia se presenta habitualmente en tres estados de agregación: sólido, líquido y gaseoso, a los que puede añadirse el plasma, común en las estrellas pero raro en la Tierra. En el estado sólido, las partículas están fuertemente unidas y ordenadas en posiciones fijas, lo que da a los sólidos forma y volumen propios. En el estado líquido, las fuerzas de cohesión son menores: las partículas están próximas pero pueden desplazarse unas respecto a otras, por lo que los líquidos adoptan la forma del recipiente pero conservan su volumen. En el estado gaseoso, las partículas se mueven con gran libertad, ocupando todo el volumen disponible. Los cambios entre estos estados se denominan cambios de estado y se producen por variaciones de temperatura o presión: fusión, solidificación, vaporización, condensación, sublimación y deposición. Estos procesos ocurren a temperaturas características para cada sustancia, como el punto de fusión del hielo a cero grados centígrados al nivel del mar. La teoría cinético-molecular explica estas observaciones asumiendo que la temperatura es una medida de la energía cinética media de las partículas y que las fuerzas intermoleculares determinan la cohesión del sistema. Esta comprensión permite entender numerosos fenómenos cotidianos, desde la formación de rocío hasta la destilación del alcohol o el funcionamiento de los refrigeradores y aires acondicionados modernos.', '[{"pregunta":"¿Cuántos estados de agregación son habituales en la Tierra?","opciones":["Dos","Tres","Cuatro","Cinco"],"correcta":1},{"pregunta":"¿Qué conserva un líquido?","opciones":["Forma y volumen","Volumen pero no forma","Ni forma ni volumen","Solo forma"],"correcta":1},{"pregunta":"¿Cómo se llama el paso de sólido a gas directamente?","opciones":["Fusión","Condensación","Sublimación","Evaporación"],"correcta":2},{"pregunta":"¿Qué representa la temperatura según la teoría cinética?","opciones":["Color","Energía cinética media","Densidad","Forma"],"correcta":1}]'::jsonb),

('fisica', 'bachillerato', '{1}', 'Las disoluciones y su concentración', 'Una disolución es una mezcla homogénea de dos o más sustancias en la que una de ellas, llamada soluto, se encuentra dispersa uniformemente en otra, llamada disolvente, en proporción generalmente mucho mayor. Las disoluciones son ubicuas: desde el aire que respiramos, mezcla de gases con predominio del nitrógeno, hasta el agua de mar, rica en sales disueltas, o la aleación metálica que forma una moneda. La concentración indica la cantidad de soluto presente en una determinada cantidad de disolución y puede expresarse de varias formas, como el porcentaje en masa, la molaridad (moles de soluto por litro de disolución), la molalidad (moles por kilogramo de disolvente) o la fracción molar. El conocimiento de la concentración es esencial en química analítica, farmacia, industria alimentaria y medicina, donde pequeñas variaciones pueden tener grandes consecuencias. La solubilidad de una sustancia en un disolvente depende de factores como la temperatura, la presión (especialmente en el caso de gases) y la naturaleza química de ambos. Existen disoluciones insaturadas, saturadas y sobresaturadas según la relación entre la cantidad disuelta y la máxima posible en esas condiciones. La comprensión de las disoluciones es también clave para entender fenómenos naturales como la lluvia ácida, la contaminación de aguas o los procesos metabólicos que tienen lugar en los seres vivos.', '[{"pregunta":"¿Qué es el soluto?","opciones":["El componente mayoritario","La sustancia dispersada en menor proporción","El recipiente","La temperatura"],"correcta":1},{"pregunta":"¿Qué unidad es la molaridad?","opciones":["Mol/kg","Mol/L","g/mL","kg/L"],"correcta":1},{"pregunta":"¿Qué factor NO afecta a la solubilidad?","opciones":["Temperatura","Presión","Naturaleza química","Color del vaso"],"correcta":3},{"pregunta":"¿Qué tipo de disolución tiene más soluto del habitual?","opciones":["Insaturada","Saturada","Sobresaturada","Vacía"],"correcta":2}]'::jsonb),

('fisica', 'bachillerato', '{1}', 'El magnetismo y el electromagnetismo', 'El magnetismo es una propiedad de la materia conocida desde la Antigüedad, cuando se observó que ciertos minerales, como la magnetita, atraían el hierro. Durante siglos permaneció como una curiosidad, pero el estudio científico moderno comenzó con William Gilbert en el siglo XVI. El gran salto llegó a principios del siglo XIX, cuando Hans Christian Oersted observó que una corriente eléctrica desviaba la aguja de una brújula, demostrando la conexión entre electricidad y magnetismo. A partir de ahí, físicos como André-Marie Ampère, Michael Faraday y James Clerk Maxwell desarrollaron el electromagnetismo, unificando ambos fenómenos en un marco teórico común. Faraday descubrió que un campo magnético variable induce una corriente eléctrica en un conductor cercano, principio que está en la base de la producción masiva de electricidad en generadores y turbinas. Maxwell formuló las ecuaciones que describen completamente los campos eléctricos y magnéticos, prediciendo incluso la existencia de las ondas electromagnéticas, que fueron confirmadas experimentalmente por Heinrich Hertz. Esta unificación es uno de los logros más importantes de la física clásica y sigue siendo fundamental para tecnologías actuales como las comunicaciones inalámbricas, los motores eléctricos o la resonancia magnética médica. El magnetismo, que parecía una rareza, se ha convertido en pieza clave del mundo moderno.', '[{"pregunta":"¿Quién observó la desviación de la brújula por una corriente?","opciones":["Faraday","Oersted","Ampère","Maxwell"],"correcta":1},{"pregunta":"¿Qué descubrió Faraday?","opciones":["Inducción electromagnética","La electrólisis","El electrón","El neutrón"],"correcta":0},{"pregunta":"¿Quién formuló las ecuaciones unificadoras?","opciones":["Hertz","Maxwell","Thomson","Bohr"],"correcta":1},{"pregunta":"¿Qué tecnología NO deriva del electromagnetismo?","opciones":["Motores eléctricos","Resonancia magnética","Resistencia a fricción pura","Comunicaciones inalámbricas"],"correcta":2}]'::jsonb),

('fisica', 'bachillerato', '{1}', 'La física moderna: breve introducción', 'La física moderna se desarrolla a partir de los primeros años del siglo XX como respuesta a fenómenos que la física clásica no podía explicar. Entre sus dos grandes pilares están la teoría de la relatividad de Albert Einstein y la mecánica cuántica. La relatividad especial, publicada en 1905, revoluciona los conceptos de espacio, tiempo y masa: el tiempo y la longitud dependen del observador, y la masa puede convertirse en energía según la famosa ecuación E = mc². La relatividad general, de 1915, redefine la gravedad como curvatura del espacio-tiempo, con consecuencias comprobadas en fenómenos astronómicos como la desviación de la luz por el Sol o la dilatación temporal. La mecánica cuántica, por su parte, nace del estudio de los fenómenos atómicos y subatómicos. Max Planck propuso en 1900 que la energía se emite en paquetes discretos llamados cuantos. Posteriormente, Einstein, Bohr, Heisenberg, Schrödinger y otros desarrollaron un marco teórico que describe la realidad en términos probabilísticos, con principios tan contraintuitivos como el de incertidumbre, que limita la precisión con que se pueden conocer a la vez la posición y el momento de una partícula. La física moderna ha hecho posibles tecnologías como el láser, la electrónica de semiconductores o la energía nuclear, transformando profundamente nuestra vida cotidiana.', '[{"pregunta":"¿Qué ecuación relaciona masa y energía?","opciones":["F=ma","E=mc²","V=IR","P=VI"],"correcta":1},{"pregunta":"¿Qué redefine la relatividad general?","opciones":["La luz","La gravedad como curvatura del espacio-tiempo","El electromagnetismo","La masa atómica"],"correcta":1},{"pregunta":"¿Qué principio limita la precisión simultánea en mecánica cuántica?","opciones":["Inercia","Incertidumbre","Exclusión","Correspondencia"],"correcta":1},{"pregunta":"¿Qué tecnología NO deriva de la física moderna?","opciones":["Láser","Semiconductores","Energía nuclear","Palanca simple"],"correcta":3}]'::jsonb);

