INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('frances', 'bachillerato', '{1}', 'La gastronomie française', 'La gastronomie française est mondialement connue et représente un véritable art de vivre. Depuis 2010, elle figure au patrimoine culturel immatériel de l''humanité reconnu par l''UNESCO, une distinction qui souligne son importance culturelle et sociale. Chaque région possède ses spécialités: la bouillabaisse à Marseille, la choucroute en Alsace, la ratatouille en Provence, les crêpes en Bretagne et, bien sûr, les fromages, dont on compte plus de trois cents variétés différentes. Le vin accompagne traditionnellement les repas et joue un rôle central dans la culture française, avec des régions réputées comme Bordeaux, la Bourgogne, la Champagne ou la Vallée du Rhône. Le pain, notamment la baguette, est un autre symbole national. Les repas en France sont souvent longs et se composent de plusieurs plats: entrée, plat principal, fromage et dessert. La convivialité autour de la table est considérée comme essentielle et rassemble familles et amis. La formation des chefs cuisiniers est prestigieuse, et les écoles françaises attirent des étudiants du monde entier. De grands chefs comme Auguste Escoffier ou Paul Bocuse ont révolutionné la cuisine classique et contemporaine. Aujourd''hui, malgré la concurrence d''autres gastronomies, la cuisine française reste une référence incontournable dans le monde.', '[{"pregunta":"Depuis quand la gastronomie française est au patrimoine UNESCO?","opciones":["1990","2000","2010","2020"],"correcta":2},{"pregunta":"Combien de fromages compte-t-on en France?","opciones":["Plus de cent","Plus de deux cents","Plus de trois cents","Plus de mille"],"correcta":2},{"pregunta":"Quel chef a révolutionné la cuisine?","opciones":["Victor Hugo","Paul Bocuse","Napoléon","Louis XIV"],"correcta":1},{"pregunta":"Que symbolise la table en France?","opciones":["La solitude","La convivialité","Le travail","Le sport"],"correcta":1}]'::jsonb),

('frances', 'bachillerato', '{1}', 'Molière et le théâtre classique', 'Molière, de son vrai nom Jean-Baptiste Poquelin, est l''un des plus grands dramaturges de la littérature française. Né à Paris en 1622, il abandonne jeune une carrière bourgeoise pour se consacrer au théâtre, art alors peu considéré. Après avoir parcouru les provinces avec sa troupe pendant plusieurs années, il revient à Paris et obtient la protection du roi Louis XIV. Il devient rapidement célèbre grâce à ses comédies qui critiquent avec humour les travers de la société de son époque. Ses pièces les plus connues sont Tartuffe, qui dénonce l''hypocrisie religieuse, Le Misanthrope, qui analyse l''homme face à la société, L''Avare, qui caricature l''obsession de l''argent, Le Bourgeois gentilhomme et Le Malade imaginaire. Molière ne se contente pas d''écrire: il joue lui-même dans ses pièces, dirige sa troupe et collabore avec des musiciens comme Lully pour créer la comédie-ballet. Son style mêle comique, observation fine des mœurs et réflexion sur la nature humaine. Il meurt en 1673, juste après avoir joué Le Malade imaginaire, ce qui renforce la dimension légendaire de son destin d''homme de théâtre. Aujourd''hui encore, la langue française est parfois surnommée la langue de Molière, témoignage de son influence durable sur la culture française et sur les arts de la scène.', '[{"pregunta":"Quel est le vrai nom de Molière?","opciones":["Jean Racine","Jean-Baptiste Poquelin","Pierre Corneille","Louis de Funès"],"correcta":1},{"pregunta":"Quel roi protégeait Molière?","opciones":["Louis XIII","Louis XIV","Louis XV","Louis XVI"],"correcta":1},{"pregunta":"Quelle pièce dénonce l''hypocrisie religieuse?","opciones":["L''Avare","Tartuffe","Le Misanthrope","Dom Juan"],"correcta":1},{"pregunta":"Comment appelle-t-on parfois la langue française?","opciones":["Langue de Molière","Langue d''Hugo","Langue de Voltaire","Langue de Zola"],"correcta":0}]'::jsonb),

('frances', 'bachillerato', '{1}', 'Paris, ville lumière', 'Paris, surnommée la ville lumière, est la capitale de la France et l''une des villes les plus visitées au monde. Elle doit son surnom à son rôle pionnier dans l''éclairage public au XVIIe siècle et au rayonnement intellectuel qu''elle exerce depuis l''époque des Lumières. Traversée par la Seine, Paris est divisée en vingt arrondissements qui s''enroulent en spirale à partir du centre historique. La ville regorge de monuments célèbres: la Tour Eiffel, construite par Gustave Eiffel pour l''Exposition universelle de 1889 et devenue le symbole international de la France; la cathédrale Notre-Dame, chef-d''œuvre gothique commencé au XIIe siècle; le musée du Louvre, ancien palais royal transformé en l''un des plus grands musées du monde; et l''Arc de Triomphe, dressé à la gloire des armées napoléoniennes. Paris est aussi un centre universitaire, artistique et culturel d''importance mondiale. Ses quartiers, comme Montmartre, le Marais ou Saint-Germain-des-Prés, ont attiré au fil des siècles des écrivains, des peintres et des philosophes venus du monde entier. La mode, la gastronomie, le cinéma et la littérature y trouvent un écho particulier. Malgré les défis modernes, liés à la circulation, au tourisme massif ou à la rénovation urbaine, Paris continue d''incarner une certaine idée de l''élégance et de la création artistique.', '[{"pregunta":"Pourquoi Paris est appelée ville lumière?","opciones":["À cause de ses feux d''artifice","Pour son rôle dans l''éclairage public et les Lumières","Elle a beaucoup de lampes","Il y fait toujours soleil"],"correcta":1},{"pregunta":"Qui a construit la Tour Eiffel?","opciones":["Victor Hugo","Gustave Eiffel","Napoléon","Louis XIV"],"correcta":1},{"pregunta":"Combien d''arrondissements compte Paris?","opciones":["Dix","Quinze","Vingt","Trente"],"correcta":2},{"pregunta":"Quel fleuve traverse Paris?","opciones":["La Loire","La Seine","Le Rhône","La Garonne"],"correcta":1}]'::jsonb),

('frances', 'bachillerato', '{1}', 'La francophonie dans le monde', 'La francophonie désigne l''ensemble des peuples et des pays qui ont le français en commun, soit comme langue maternelle, soit comme langue officielle ou d''usage. On estime aujourd''hui à environ trois cents millions le nombre de locuteurs francophones dans le monde, répartis sur les cinq continents. Le français n''est pas seulement parlé en France, mais aussi en Belgique, en Suisse, au Québec (Canada), en Afrique subsaharienne et du Nord, à Madagascar, en Haïti, au Liban, dans certaines îles du Pacifique et dans de nombreux autres territoires. L''Organisation internationale de la francophonie, créée en 1970, réunit plus de quatre-vingts États et gouvernements qui coopèrent sur des questions linguistiques, culturelles, éducatives et politiques. Le français est également l''une des six langues officielles de l''ONU et l''une des langues de travail de nombreuses institutions internationales. La francophonie est aussi un espace culturel vivant qui inclut la musique, la littérature et le cinéma. De grands écrivains francophones non français, comme Léopold Sédar Senghor, Aimé Césaire ou Assia Djebar, ont enrichi la langue française avec leurs univers propres. Défendre la francophonie signifie promouvoir la diversité culturelle et linguistique face à la domination de l''anglais, tout en encourageant le dialogue entre des peuples très différents qui partagent un même outil de communication.', '[{"pregunta":"Combien de locuteurs francophones dans le monde?","opciones":["Environ 100 millions","Environ 200 millions","Environ 300 millions","Environ 500 millions"],"correcta":2},{"pregunta":"Quand a été créée l''OIF?","opciones":["1945","1960","1970","1990"],"correcta":2},{"pregunta":"Le français est une langue officielle de quelle organisation?","opciones":["ONU","FIFA","OTAN","BCE"],"correcta":0},{"pregunta":"Quel écrivain n''est pas francophone non français?","opciones":["Senghor","Césaire","Djebar","Zola"],"correcta":3}]'::jsonb),

('frances', 'bachillerato', '{1}', 'Le cinéma français', 'Le cinéma français est considéré comme l''un des plus importants au monde sur le plan artistique et historique. Il est né à la fin du XIXe siècle avec les frères Lumière, qui organisent à Paris, en décembre 1895, la première projection publique et payante de films, ce qui en fait l''un des actes de naissance du septième art. Au cours du XXe siècle, le cinéma français a développé des genres et des courants très variés. Dans les années 1930, le réalisme poétique, représenté par des cinéastes comme Jean Renoir ou Marcel Carné, offre des portraits sensibles de la société. Après la Seconde Guerre mondiale apparaît la célèbre Nouvelle Vague, un mouvement emmené par François Truffaut, Jean-Luc Godard, Éric Rohmer ou Agnès Varda, qui rompt avec les conventions du cinéma commercial et privilégie les tournages en extérieur, les acteurs peu connus et les thèmes de la vie quotidienne. Le cinéma français contemporain continue d''explorer des histoires originales et variées, et bénéficie d''un soutien public important à travers des aides à la production et au festival de Cannes, l''un des plus prestigieux au monde. Chaque année, de nombreux films français sont présentés dans des festivals internationaux, et certains remportent des prix importants. Le cinéma reste un moyen d''expression privilégié pour parler de la société française et francophone.', '[{"pregunta":"Qui organisa la première projection en 1895?","opciones":["Les frères Grimm","Les frères Lumière","Les frères Renoir","Les frères Dardenne"],"correcta":1},{"pregunta":"Quel mouvement apparaît après 1945?","opciones":["Le Naturalisme","La Nouvelle Vague","Le Dadaïsme","Le Surréalisme"],"correcta":1},{"pregunta":"Quel festival français est célèbre dans le monde?","opciones":["Berlin","Venise","Cannes","Toronto"],"correcta":2},{"pregunta":"Quelle réalisatrice est mentionnée?","opciones":["Agnès Varda","Marion Cotillard","Juliette Binoche","Catherine Deneuve"],"correcta":0}]'::jsonb),

('frances', 'bachillerato', '{1}', 'Le système éducatif en France', 'Le système éducatif français est reconnu pour son organisation centralisée et la place qu''il accorde à l''école publique, laïque et gratuite. L''école est obligatoire pour tous les enfants de trois à seize ans. Le parcours commence par l''école maternelle, qui accueille les enfants de trois à six ans. Suit l''école élémentaire, de six à onze ans, où l''on apprend à lire, écrire et compter. Ensuite, les élèves intègrent le collège, de onze à quinze ans, où ils étudient pendant quatre ans et obtiennent à la fin le diplôme national du brevet. Après le collège, ils choisissent entre le lycée général, le lycée technologique et le lycée professionnel. À la fin du lycée, ils passent le baccalauréat, examen national créé par Napoléon en 1808, nécessaire pour accéder à l''enseignement supérieur. Les études supérieures se déroulent principalement à l''université, aux grandes écoles (comme Sciences Po ou Polytechnique) ou en formations courtes. Le français bénéficie d''un statut privilégié dans toute l''éducation, et les langues étrangères, notamment l''anglais et l''espagnol, sont étudiées dès le primaire. Le système éducatif français fait régulièrement l''objet de réformes et de débats, surtout en ce qui concerne l''égalité des chances, la réussite des élèves issus de milieux défavorisés et l''adaptation aux nouvelles technologies numériques.', '[{"pregunta":"À quel âge l''école devient obligatoire?","opciones":["À 3 ans","À 6 ans","À 7 ans","À 10 ans"],"correcta":0},{"pregunta":"Qui a créé le baccalauréat?","opciones":["Louis XIV","Napoléon","De Gaulle","Mitterrand"],"correcta":1},{"pregunta":"Combien d''années dure le collège?","opciones":["Deux","Trois","Quatre","Cinq"],"correcta":2},{"pregunta":"Quel diplôme obtient-on à la fin du collège?","opciones":["Baccalauréat","Brevet","Licence","Master"],"correcta":1}]'::jsonb),

('frances', 'bachillerato', '{1}', 'Victor Hugo, écrivain engagé', 'Victor Hugo (1802-1885) est l''une des figures les plus importantes de la littérature française. Poète, romancier, dramaturge et homme politique, il a profondément marqué le XIXe siècle. Dès son jeune âge, il publie des poèmes qui lui valent une reconnaissance rapide. Il devient ensuite le chef de file du mouvement romantique français, qui revendique plus de liberté dans la création artistique et remet en cause les règles du classicisme. Sa bataille autour de la pièce Hernani, en 1830, symbolise cette révolution littéraire. Hugo s''est également illustré dans le roman avec des œuvres comme Notre-Dame de Paris et Les Misérables, un immense roman qui raconte la vie de personnages issus des classes populaires et dénonce l''injustice sociale. En politique, il défend la liberté, l''éducation gratuite, l''abolition de la peine de mort et le suffrage universel. Opposé au coup d''État de Louis-Napoléon Bonaparte en 1851, il vit en exil pendant près de vingt ans à Jersey puis à Guernesey. De retour en France après la chute du Second Empire, il est accueilli en héros républicain. À sa mort, en 1885, des funérailles nationales sont organisées et plus de deux millions de personnes l''accompagnent au Panthéon. Son œuvre immense continue d''inspirer les lecteurs et les artistes dans le monde entier.', '[{"pregunta":"De quel mouvement Hugo était-il le chef?","opciones":["Classicisme","Romantisme","Naturalisme","Surréalisme"],"correcta":1},{"pregunta":"Quel roman raconte l''injustice sociale?","opciones":["Notre-Dame de Paris","Les Misérables","Hernani","Les Contemplations"],"correcta":1},{"pregunta":"Pourquoi Hugo a-t-il vécu en exil?","opciones":["Raisons économiques","Opposition au coup d''État de 1851","Maladie","Études"],"correcta":1},{"pregunta":"Combien de personnes ont suivi ses funérailles?","opciones":["Cent mille","Cinq cent mille","Un million","Plus de deux millions"],"correcta":3}]'::jsonb),

('frances', 'bachillerato', '{1}', 'L''impressionnisme et la peinture', 'L''impressionnisme est un mouvement artistique né en France dans la seconde moitié du XIXe siècle et qui a profondément transformé la peinture occidentale. Le terme lui-même vient d''un tableau de Claude Monet intitulé Impression, soleil levant, présenté lors d''une exposition parisienne en 1874. Au départ, ce nom est employé de façon moqueuse par un critique d''art, mais il est vite revendiqué par les peintres eux-mêmes. Les impressionnistes, comme Monet, Renoir, Degas, Pissarro, Sisley ou Berthe Morisot, cherchent à capter les effets changeants de la lumière et des couleurs dans la nature. Ils sortent de leurs ateliers pour peindre en plein air, avec des touches rapides et colorées qui donnent un aspect vibrant et vivant à leurs toiles. Ils s''intéressent à la vie moderne, aux paysages urbains, aux bords de Seine, aux jardins et aux scènes quotidiennes. Les sujets traditionnels comme les scènes mythologiques ou religieuses sont abandonnés au profit d''instantanés du monde contemporain. À leurs débuts, les impressionnistes sont rejetés par l''Académie et les critiques officiels. Peu à peu, leur œuvre est reconnue et devient l''une des plus appréciées de l''histoire de l''art. Aujourd''hui, de nombreux musées, comme le musée d''Orsay à Paris, conservent une importante collection de chefs-d''œuvre impressionnistes qui attirent chaque année des millions de visiteurs.', '[{"pregunta":"D''où vient le nom impressionnisme?","opciones":["D''un livre","D''un tableau de Monet","D''une région","D''une chanson"],"correcta":1},{"pregunta":"Où peignent les impressionnistes principalement?","opciones":["En atelier seulement","En plein air","Dans des caves","Sous terre"],"correcta":1},{"pregunta":"Quel peintre n''appartient pas au mouvement?","opciones":["Monet","Renoir","Picasso","Degas"],"correcta":2},{"pregunta":"Quel musée parisien conserve leurs œuvres?","opciones":["Louvre","Orsay","Pompidou","Rodin"],"correcta":1}]'::jsonb),

('frances', 'bachillerato', '{1}', 'Le climat et le changement climatique', 'Le changement climatique est l''un des défis les plus importants auxquels l''humanité doit faire face au XXIe siècle. Depuis la révolution industrielle, les activités humaines, notamment la combustion des énergies fossiles (charbon, pétrole, gaz), ont provoqué une augmentation significative des gaz à effet de serre dans l''atmosphère, en particulier le dioxyde de carbone. Ces gaz retiennent la chaleur du soleil près de la surface terrestre et provoquent une hausse globale des températures. Les conséquences sont nombreuses et déjà visibles: fonte des glaciers et des calottes polaires, montée du niveau des mers, phénomènes météorologiques extrêmes plus fréquents, perte de biodiversité, sécheresses, inondations et migrations forcées. Les scientifiques du GIEC, le groupe d''experts intergouvernemental sur l''évolution du climat, alertent depuis des années sur la gravité de la situation et sur la nécessité d''agir rapidement. Les accords internationaux, comme ceux de Paris signés en 2015, cherchent à limiter la hausse des températures à moins de deux degrés par rapport à l''ère préindustrielle. Pour y parvenir, il est nécessaire de développer les énergies renouvelables, de réduire la consommation et de modifier en profondeur les modes de production et de transport. Les citoyens peuvent aussi participer par leurs choix quotidiens, comme privilégier les transports collectifs, réduire les déchets ou consommer de manière responsable.', '[{"pregunta":"Quel gaz est responsable principalement du réchauffement?","opciones":["Oxygène","Dioxyde de carbone","Azote","Hélium"],"correcta":1},{"pregunta":"Où ont été signés les accords de 2015?","opciones":["Berlin","Paris","Madrid","Tokyo"],"correcta":1},{"pregunta":"Quel organisme scientifique alerte sur le climat?","opciones":["GIEC","ONU","UNESCO","OMS"],"correcta":0},{"pregunta":"Quelle conséquence NE découle PAS du changement climatique?","opciones":["Fonte des glaciers","Montée des mers","Augmentation de la biodiversité","Phénomènes extrêmes"],"correcta":2}]'::jsonb),

('frances', 'bachillerato', '{1}', 'La Révolution française de 1789', 'La Révolution française, qui commence en 1789, est l''un des événements les plus importants de l''histoire mondiale. Elle marque la fin de l''Ancien Régime, fondé sur la monarchie absolue et les privilèges de la noblesse et du clergé, et ouvre la voie à une société nouvelle fondée sur l''égalité des citoyens devant la loi. Les causes de la Révolution sont multiples: une crise économique grave, de mauvaises récoltes, des impôts injustes et l''influence des idées des philosophes des Lumières, qui critiquaient l''injustice et défendaient la raison, la liberté et les droits de l''homme. Le 14 juillet 1789, le peuple parisien prend d''assaut la prison de la Bastille, symbole de l''arbitraire royal. Peu après, l''Assemblée constituante adopte la Déclaration des droits de l''homme et du citoyen, qui affirme que les hommes naissent libres et égaux en droits. La Révolution connaît ensuite plusieurs phases: monarchie constitutionnelle, République, Terreur, Directoire. Le roi Louis XVI, jugé pour trahison, est guillotiné en 1793. Bien que le pays traverse des années très violentes, la Révolution laisse un héritage durable: la devise liberté, égalité, fraternité, le suffrage (d''abord limité), la laïcité et l''idée que le pouvoir doit émaner du peuple. Cet héritage continue d''inspirer les mouvements démocratiques dans le monde.', '[{"pregunta":"En quelle année commence la Révolution?","opciones":["1776","1789","1815","1848"],"correcta":1},{"pregunta":"Que s''est-il passé le 14 juillet 1789?","opciones":["Couronnement","Prise de la Bastille","Exécution du roi","Bataille de Waterloo"],"correcta":1},{"pregunta":"Quel roi a été guillotiné?","opciones":["Louis XIV","Louis XV","Louis XVI","Louis XVIII"],"correcta":2},{"pregunta":"Quelle devise laisse la Révolution?","opciones":["Liberté, égalité, fraternité","Travail, famille, patrie","Union, progrès","Un pour tous"],"correcta":0}]'::jsonb),

('frances', 'bachillerato', '{1}', 'Les jeunes et les réseaux sociaux', 'Les jeunes d''aujourd''hui grandissent dans un monde dominé par les réseaux sociaux. Des plateformes comme Instagram, TikTok, Snapchat ou YouTube font partie de leur vie quotidienne et influencent leurs relations, leur image de soi et leurs modes d''information. D''un côté, ces outils présentent de nombreux avantages: ils permettent de rester en contact avec les amis et la famille, de s''exprimer, de partager des passions et de découvrir des cultures du monde entier. Ils offrent aussi des possibilités pour apprendre, pour s''organiser collectivement et parfois même pour trouver un emploi ou développer une activité. De l''autre côté, leur usage excessif peut avoir des conséquences négatives. Les études récentes montrent une augmentation de l''anxiété, du stress et des troubles du sommeil chez les adolescents fortement exposés aux écrans. Le harcèlement en ligne, les fausses informations et la pression liée à l''image que l''on renvoie sont d''autres risques importants. Les algorithmes qui choisissent les contenus affichés peuvent également renforcer certaines opinions ou créer des bulles de filtres. Face à ces défis, les familles, les écoles et les pouvoirs publics cherchent à promouvoir un usage plus réfléchi et responsable. Apprendre à gérer son temps, à vérifier les sources et à protéger sa vie privée devient une compétence essentielle pour les jeunes générations.', '[{"pregunta":"Quel est un avantage des réseaux sociaux selon le texte?","opciones":["Moins de contacts","Rester en contact et partager","Plus de solitude","Moins d''info"],"correcta":1},{"pregunta":"Quelle conséquence négative est mentionnée?","opciones":["Meilleure mémoire","Anxiété et troubles du sommeil","Confiance totale","Moins de stress"],"correcta":1},{"pregunta":"Qu''est-ce qu''une bulle de filtres?","opciones":["Une technique photo","Un effet des algorithmes","Un jeu vidéo","Un outil de cuisine"],"correcta":1},{"pregunta":"Que faut-il apprendre à faire selon le texte?","opciones":["Ignorer tout","Vérifier les sources","Croire tout","Éviter le numérique"],"correcta":1}]'::jsonb),

('frances', 'bachillerato', '{1}', 'La mode et la haute couture', 'La France est depuis longtemps considérée comme la capitale mondiale de la mode. Paris accueille deux fois par an la Fashion Week, où les plus grands couturiers présentent leurs nouvelles collections devant un public international composé de journalistes, de célébrités et de professionnels du secteur. La haute couture est une appellation strictement réglementée par la Fédération française de la couture: seules quelques maisons, comme Chanel, Dior, Givenchy ou Jean Paul Gaultier, ont le droit de l''utiliser. La haute couture se distingue du prêt-à-porter par la fabrication artisanale, sur mesure, avec des tissus précieux et des heures de travail manuel extraordinaires. Chaque pièce est pratiquement unique. La mode française ne se limite cependant pas à l''élite: elle a une grande influence sur le prêt-à-porter accessible au grand public. De grands noms comme Coco Chanel ont révolutionné la mode au XXe siècle en inventant la petite robe noire et en libérant le corps féminin des vêtements contraignants. Yves Saint Laurent a également bousculé les codes en proposant des smokings pour femmes. Aujourd''hui, la mode française affronte de nouveaux défis, notamment la nécessité de devenir plus durable et respectueuse de l''environnement. De nombreuses marques mettent désormais l''accent sur des matériaux écologiques et sur des conditions de production éthiques.', '[{"pregunta":"Combien de fois par an a lieu la Fashion Week à Paris?","opciones":["Une fois","Deux fois","Quatre fois","Jamais"],"correcta":1},{"pregunta":"Qui a inventé la petite robe noire?","opciones":["Dior","Coco Chanel","YSL","Gaultier"],"correcta":1},{"pregunta":"Qu''est-ce qui distingue la haute couture?","opciones":["Fabrication industrielle","Fabrication artisanale sur mesure","Vente en supermarché","Matières synthétiques"],"correcta":1},{"pregunta":"Quel défi moderne affronte la mode française?","opciones":["Être plus chère","Être plus durable","Être plus cachée","Être plus rapide"],"correcta":1}]'::jsonb),

('frances', 'bachillerato', '{1}', 'Le patrimoine et les châteaux de la Loire', 'La vallée de la Loire est l''une des régions les plus célèbres et les plus visitées de France, notamment pour ses nombreux châteaux magnifiques qui jalonnent son cours. Inscrite au patrimoine mondial de l''UNESCO depuis 2000, cette région combine la beauté des paysages, la richesse architecturale et une longue histoire. La plupart des châteaux ont été construits ou transformés entre le XVe et le XVIIe siècle, à une époque où les rois de France séjournaient souvent dans la région. Parmi les plus connus, on trouve Chambord, commandé par François Ier et remarquable pour sa taille, son célèbre escalier à double révolution attribué à Léonard de Vinci et son toit orné de tourelles. Chenonceau, appelé le château des dames, enjambe le Cher grâce à une galerie spectaculaire et est lié aux noms de Catherine de Médicis et Diane de Poitiers. Amboise, Blois, Villandry et Azay-le-Rideau complètent cette liste impressionnante. Chaque château possède sa propre personnalité et raconte une partie de l''histoire de la France. La visite de la vallée de la Loire est aussi l''occasion de découvrir une gastronomie raffinée, des vins réputés et des jardins d''une grande beauté. Chaque année, des millions de touristes parcourent la région, contribuant à la conservation du patrimoine et à l''économie locale.', '[{"pregunta":"Depuis quand la vallée est au patrimoine mondial?","opciones":["1980","1990","2000","2010"],"correcta":2},{"pregunta":"Qui a commandé Chambord?","opciones":["Louis XIV","François Ier","Napoléon","Henri IV"],"correcta":1},{"pregunta":"À qui est attribué l''escalier à double révolution?","opciones":["Michel-Ange","Léonard de Vinci","Raphaël","Donatello"],"correcta":1},{"pregunta":"Comment surnomme-t-on Chenonceau?","opciones":["Château du roi","Château des dames","Château rouge","Château noir"],"correcta":1}]'::jsonb),

('frances', 'bachillerato', '{1}', 'La chanson française', 'La chanson française occupe une place très particulière dans la culture du pays. Depuis le Moyen Âge, les chanteurs et troubadours ont accompagné la vie sociale et politique. Mais c''est surtout au XXe siècle que la chanson française acquiert un statut artistique majeur. Dans les années 1930 et 1940, Édith Piaf devient une icône mondiale avec des titres comme La Vie en rose ou Non, je ne regrette rien. Après la guerre, une nouvelle génération d''auteurs-compositeurs donne naissance à ce qu''on appelle parfois la chanson à texte, c''est-à-dire des chansons où les paroles comptent autant, voire plus, que la musique. Georges Brassens, Jacques Brel (belge d''origine), Léo Ferré, Charles Aznavour ou Barbara en sont les figures emblématiques. Leurs chansons parlent d''amour, de politique, de la vie quotidienne et de questions philosophiques, avec une grande qualité littéraire. Dans les années 1960 et 1970, Serge Gainsbourg renouvelle profondément la chanson en mélangeant les styles et en osant des sujets audacieux. Aujourd''hui, la scène française est très diverse: rap, pop, électro, chanson indie, et de nombreux artistes rencontrent le succès en dehors de la francophonie. La chanson française continue de jouer un rôle important dans la transmission de la langue et des valeurs culturelles à travers les générations et les frontières.', '[{"pregunta":"Qui est une icône mondiale des années 30-40?","opciones":["Barbara","Édith Piaf","Céline Dion","Mireille Mathieu"],"correcta":1},{"pregunta":"Qu''est-ce que la chanson à texte?","opciones":["Des chansons sans paroles","Des chansons où les paroles importent beaucoup","De la musique instrumentale","Des chansons en anglais"],"correcta":1},{"pregunta":"Quel artiste n''appartient pas à la chanson à texte?","opciones":["Brassens","Brel","Ferré","Einstein"],"correcta":3},{"pregunta":"Quel style moderne existe aussi aujourd''hui?","opciones":["Uniquement rock","Rap, pop, électro","Opéra seulement","Chants grégoriens"],"correcta":1}]'::jsonb),

('frances', 'bachillerato', '{1}', 'Les sports en France', 'Le sport occupe une place importante dans la société française. De nombreux sports sont pratiqués régulièrement, aussi bien à un niveau professionnel que dans les clubs amateurs ou en loisir. Le football est sans doute le sport le plus populaire, avec des clubs renommés comme le Paris Saint-Germain, l''Olympique de Marseille ou l''Olympique lyonnais. L''équipe de France, championne du monde en 1998 et 2018, est une grande source de fierté nationale. Le rugby est très apprécié, surtout dans le sud-ouest du pays, avec un Tournoi des Six Nations disputé chaque année contre les équipes britanniques, l''Irlande et l''Italie. Le cyclisme est également profondément enraciné dans la culture française grâce au Tour de France, course mythique créée en 1903, qui traverse chaque été tout le pays. Le tennis est aussi très suivi, notamment avec le tournoi de Roland-Garros, l''un des quatre tournois du Grand Chelem. La France compte également de nombreux champions dans des disciplines comme le judo, le handball ou l''escrime. En 2024, Paris a accueilli les Jeux Olympiques d''été, exactement cent ans après les Jeux de Paris 1924, ce qui a été l''occasion de mettre en avant l''histoire sportive du pays et de moderniser de nombreuses installations. Le sport est ainsi à la fois un divertissement, un enjeu de santé et un outil d''intégration sociale.', '[{"pregunta":"En quelles années la France a été championne du monde?","opciones":["1990 et 2010","1998 et 2018","2002 et 2014","2006 et 2022"],"correcta":1},{"pregunta":"Quand fut créé le Tour de France?","opciones":["1903","1920","1950","1970"],"correcta":0},{"pregunta":"Quel tournoi de tennis est français?","opciones":["Wimbledon","Roland-Garros","US Open","Open d''Australie"],"correcta":1},{"pregunta":"Quand Paris a-t-elle accueilli les JO d''été récemment?","opciones":["2008","2016","2024","2028"],"correcta":2}]'::jsonb),

('frances', 'bachillerato', '{1}', 'La laïcité en France', 'La laïcité est un principe fondamental de la République française, qui signifie la séparation entre les institutions publiques et les religions. Elle garantit à la fois la liberté de conscience et l''égalité des citoyens devant la loi, quelles que soient leurs croyances. La laïcité est le fruit d''une longue histoire, marquée notamment par la loi du 9 décembre 1905 concernant la séparation des Églises et de l''État. Cette loi met fin au régime concordataire instauré par Napoléon et établit que la République ne reconnaît, ne salarie ni ne subventionne aucun culte. Depuis, l''État français est neutre sur le plan religieux, tout en garantissant à chacun la liberté de pratiquer la religion de son choix dans le respect des lois communes. Dans l''école publique, les signes religieux ostensibles sont interdits depuis 2004 pour les élèves. Le principe de laïcité fait parfois l''objet de débats passionnés, notamment concernant la place des religions dans l''espace public et l''intégration des minorités. Les défenseurs de la laïcité insistent sur son rôle protecteur: elle permet aux citoyens de vivre ensemble dans le respect mutuel et indépendamment de leurs convictions. Les critiques estiment parfois qu''elle est appliquée de manière trop rigide. Dans tous les cas, la laïcité reste l''un des piliers les plus discutés et les plus importants de l''identité républicaine française.', '[{"pregunta":"Quelle année est celle de la loi de séparation?","opciones":["1789","1870","1905","1946"],"correcta":2},{"pregunta":"Que signifie la laïcité?","opciones":["Religion d''État","Séparation institutions publiques/religions","Interdiction du culte","Obligation de pratique"],"correcta":1},{"pregunta":"Quand a-t-on interdit les signes ostensibles à l''école publique?","opciones":["1989","2004","2015","2020"],"correcta":1},{"pregunta":"Que garantit la laïcité aux citoyens?","opciones":["Une religion","Liberté de conscience et égalité","Un salaire","Un logement"],"correcta":1}]'::jsonb),

('frances', 'bachillerato', '{1}', 'La bande dessinée, le neuvième art', 'La bande dessinée occupe une place privilégiée en France et en Belgique francophone, où elle est parfois appelée le neuvième art. Elle bénéficie d''une reconnaissance culturelle comparable à celle de la littérature ou du cinéma. Parmi les personnages les plus célèbres figurent Astérix et Obélix, créés par René Goscinny et Albert Uderzo en 1959, qui racontent de manière humoristique les aventures de deux Gaulois luttant contre l''occupation romaine. Tintin, né sous la plume du dessinateur belge Hergé dès 1929, a également traversé les générations et est traduit dans des dizaines de langues. Lucky Luke, Les Schtroumpfs ou Gaston Lagaffe complètent ce patrimoine classique. La bande dessinée française ne se limite pas aux histoires pour enfants. Elle traite de sujets très variés: histoire, science-fiction, politique, société, aventures personnelles. Des auteurs comme Marjane Satrapi avec Persepolis, Joann Sfar ou Riad Sattouf ont apporté une dimension autobiographique et engagée au genre. Le festival international de la bande dessinée d''Angoulême, qui a lieu chaque année depuis 1974, est devenu un événement majeur dont les prix sont très prestigieux. Aujourd''hui, la bande dessinée évolue avec le numérique et touche un public toujours plus large. Elle est enseignée dans des écoles spécialisées et occupe une place importante dans les bibliothèques et les librairies françaises.', '[{"pregunta":"Comment appelle-t-on parfois la BD en France?","opciones":["Le septième art","Le neuvième art","Le dixième art","Le onzième art"],"correcta":1},{"pregunta":"Qui a créé Astérix?","opciones":["Hergé","Goscinny et Uderzo","Sempé","Franquin"],"correcta":1},{"pregunta":"Qui est l''auteur de Tintin?","opciones":["Hergé","Uderzo","Morris","Peyo"],"correcta":0},{"pregunta":"Où a lieu le festival de BD?","opciones":["Paris","Lyon","Angoulême","Marseille"],"correcta":2}]'::jsonb);

