INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('historia-mundo', 'bachillerato', '{1}', 'El Antiguo Régimen y la sociedad estamental', 'El Antiguo Régimen es la expresión con la que los revolucionarios franceses designaron el sistema social, político y económico predominante en Europa antes de 1789. Se caracterizaba por la existencia de una monarquía absoluta en la que el rey concentraba todos los poderes y afirmaba gobernar por derecho divino. La sociedad estaba dividida en tres estamentos claramente diferenciados: la nobleza, que poseía tierras y privilegios fiscales y jurídicos; el clero, que desempeñaba un papel religioso pero también económico, poseyendo vastas propiedades y cobrando el diezmo; y el tercer estado, al que pertenecía la inmensa mayoría de la población, compuesta por campesinos, artesanos, comerciantes y, en las ciudades, una burguesía cada vez más pujante. El sistema económico era predominantemente agrario y señorial, con relaciones de dependencia heredadas del feudalismo medieval, aunque las ciudades comenzaban a desarrollar actividades mercantiles y manufactureras. Las ideas de los pensadores ilustrados, como Voltaire, Rousseau o Montesquieu, cuestionaron los fundamentos del Antiguo Régimen al reivindicar la razón, la libertad, la tolerancia y la separación de poderes. Las crisis económicas y la creciente desigualdad, unidas a la influencia de estas ideas y al ejemplo de la independencia estadounidense, prepararon el terreno para las revoluciones que transformarían Europa desde finales del siglo XVIII y a lo largo del XIX.', '[{"pregunta":"¿Qué caracterizaba a la monarquía del Antiguo Régimen?","opciones":["Monarquía constitucional","Monarquía absoluta","República","Oligarquía"],"correcta":1},{"pregunta":"¿Cuántos estamentos había?","opciones":["Dos","Tres","Cuatro","Cinco"],"correcta":1},{"pregunta":"¿Qué estamento no tenía privilegios?","opciones":["Nobleza","Clero","Tercer estado","Realeza"],"correcta":2},{"pregunta":"¿Qué pensador ilustrado defendió la separación de poderes?","opciones":["Voltaire","Rousseau","Montesquieu","Diderot"],"correcta":2}]'::jsonb),

('historia-mundo', 'bachillerato', '{1}', 'La Ilustración y sus ideas', 'La Ilustración es un movimiento cultural e intelectual que se desarrolla en Europa principalmente durante el siglo XVIII, aunque sus raíces pueden rastrearse en las revoluciones científicas del siglo XVII. Su rasgo más característico es la confianza en la razón como instrumento capaz de mejorar el conocimiento, las instituciones y la vida humana. Frente a la tradición, la autoridad religiosa y la superstición, los ilustrados proponen el pensamiento crítico, la tolerancia, el progreso y la educación. Filósofos como Voltaire defienden la libertad de expresión y la crítica al fanatismo; Montesquieu analiza las leyes y propone la división de poderes como garantía de libertad política; Rousseau reflexiona sobre la desigualdad y el contrato social entre los ciudadanos; y Diderot dirige la monumental Enciclopedia, que pretende recopilar y difundir el conjunto del saber humano. La Ilustración también tiene consecuencias políticas en el llamado despotismo ilustrado, ejemplificado en monarcas como Federico II de Prusia o Carlos III de España, que aplicaron reformas inspiradas en las ideas ilustradas manteniendo, sin embargo, el poder absoluto. El lema todo para el pueblo, pero sin el pueblo resume con ironía su espíritu. La Ilustración preparó el camino a las revoluciones liberales y a los movimientos democráticos posteriores, y sigue influyendo en los valores que sustentan las sociedades contemporáneas.', '[{"pregunta":"¿Qué instrumento central propone la Ilustración?","opciones":["La fe","La razón","La tradición","La fuerza"],"correcta":1},{"pregunta":"¿Quién dirigió la Enciclopedia?","opciones":["Voltaire","Rousseau","Diderot","Kant"],"correcta":2},{"pregunta":"¿Qué era el despotismo ilustrado?","opciones":["Monarcas absolutos con reformas ilustradas","Democracias","Repúblicas","Tiranías militares"],"correcta":0},{"pregunta":"¿Qué proponía Montesquieu?","opciones":["Monarquía absoluta","División de poderes","Revolución armada","Religión de Estado"],"correcta":1}]'::jsonb),

('historia-mundo', 'bachillerato', '{1}', 'La independencia de Estados Unidos', 'La independencia de los Estados Unidos de América es uno de los acontecimientos más importantes de la historia moderna, ya que supuso la primera ruptura colonial exitosa frente a una potencia europea y la creación de una república basada en los principios ilustrados. Las trece colonias británicas de Norteamérica comenzaron a enfrentarse con la metrópoli a mediados del siglo XVIII por cuestiones económicas y fiscales. Los colonos se opusieron especialmente a los impuestos impuestos por el Parlamento británico sin su representación, resumidos en el famoso lema no hay impuestos sin representación. Los enfrentamientos aumentaron con episodios como el Motín del té de Boston en 1773. En 1776 se proclamó la Declaración de Independencia, redactada principalmente por Thomas Jefferson, que afirmaba que todos los hombres son creados iguales y tienen derechos inalienables a la vida, la libertad y la búsqueda de la felicidad. La guerra que siguió fue larga y difícil, pero los colonos, apoyados por Francia y España, lograron la victoria definitiva en Yorktown en 1781. En 1783, el Tratado de Versalles reconoció oficialmente la independencia. Pocos años después, en 1787, se redactó la Constitución de los Estados Unidos, que establecía un sistema federal con separación de poderes, una de las primeras en el mundo. La nueva nación se convirtió en un modelo para posteriores procesos revolucionarios en Europa y América Latina.', '[{"pregunta":"¿Cuántas colonias británicas había en Norteamérica?","opciones":["Diez","Trece","Quince","Veinte"],"correcta":1},{"pregunta":"¿Quién redactó principalmente la Declaración?","opciones":["Washington","Jefferson","Franklin","Adams"],"correcta":1},{"pregunta":"¿Qué año se proclamó la Declaración?","opciones":["1773","1776","1781","1787"],"correcta":1},{"pregunta":"¿Qué países apoyaron a los colonos?","opciones":["Francia y España","Rusia","Alemania","Italia"],"correcta":0}]'::jsonb),

('historia-mundo', 'bachillerato', '{1}', 'Napoleón Bonaparte y el Imperio', 'Napoleón Bonaparte es una de las figuras más influyentes de la historia moderna. Nacido en Córcega en 1769, destacó como oficial durante la Revolución Francesa gracias a sus victorias militares. En 1799 dio un golpe de Estado, el 18 de brumario, que puso fin al Directorio e instauró el Consulado, en el que asumió progresivamente todos los poderes. En 1804 se coronó emperador de los franceses en la catedral de Notre-Dame, en presencia del papa Pío VII. Durante su mandato impulsó importantes reformas que modernizaron Francia, como el Código Civil de 1804, que garantizaba la igualdad ante la ley y el derecho de propiedad, la reorganización de la administración, la creación del Banco de Francia y una profunda reforma educativa. En política exterior, Napoleón buscó imponer la hegemonía francesa en Europa mediante una serie de guerras victoriosas contra las principales potencias. Llegó a controlar gran parte del continente, imponiendo sus reformas en los territorios ocupados. Sin embargo, su ambición le llevó a enfrentarse con casi todas las monarquías europeas, y su desastrosa campaña de Rusia en 1812 marcó el inicio de su caída. Tras varias derrotas, fue finalmente vencido en Waterloo en 1815 y exiliado a la isla de Santa Elena, donde murió en 1821. Su legado político y jurídico perdura en gran parte de Europa y América.', '[{"pregunta":"¿Dónde nació Napoleón?","opciones":["París","Córcega","Italia","Nápoles"],"correcta":1},{"pregunta":"¿En qué año se proclamó emperador?","opciones":["1799","1804","1812","1815"],"correcta":1},{"pregunta":"¿Qué campaña inició su caída?","opciones":["Egipto","España","Rusia","Prusia"],"correcta":2},{"pregunta":"¿Dónde fue derrotado definitivamente?","opciones":["Austerlitz","Waterloo","Trafalgar","Leipzig"],"correcta":1}]'::jsonb),

('historia-mundo', 'bachillerato', '{1}', 'Las revoluciones liberales del siglo XIX', 'El siglo XIX europeo fue un periodo de intensas transformaciones políticas, marcado por las llamadas revoluciones liberales. Tras la derrota de Napoleón en 1815, el Congreso de Viena intentó restaurar el orden del Antiguo Régimen mediante un sistema conservador basado en la legitimidad dinástica, el intervencionismo y el equilibrio entre potencias. Sin embargo, las ideas liberales y nacionalistas, difundidas por la Revolución Francesa y el Imperio napoleónico, no desaparecieron, y a lo largo del siglo se produjeron varias oleadas revolucionarias. La primera, en 1820, afectó a España, Portugal, Italia y Grecia. La segunda, en 1830, tuvo especial impacto en Francia, donde la monarquía de los Borbones fue sustituida por la de Luis Felipe de Orleans, más moderada. También en Bélgica, que se independizó de los Países Bajos. La tercera gran oleada, conocida como la primavera de los pueblos de 1848, se extendió por casi todo el continente y combinó reclamaciones liberales, democráticas, sociales y nacionalistas. Aunque la mayoría de estas revoluciones fueron sofocadas, sus efectos a largo plazo fueron profundos: el progresivo reconocimiento de las constituciones, la ampliación del sufragio, la abolición de privilegios feudales y la consolidación de los estados-nación europeos. Las ideologías liberales, nacionalistas, socialistas y democráticas, nacidas o consolidadas en este periodo, marcaron de forma decisiva el futuro del continente.', '[{"pregunta":"¿Qué buscó restaurar el Congreso de Viena?","opciones":["La República","El orden del Antiguo Régimen","El Imperio napoleónico","La democracia"],"correcta":1},{"pregunta":"¿Qué ocurrió en 1830 en Francia?","opciones":["Llega Napoleón III","Sustitución de los Borbones por Luis Felipe","Fin de Luis XIV","Primera República"],"correcta":1},{"pregunta":"¿Cómo se conoce la oleada de 1848?","opciones":["Guerra de Crimea","Primavera de los pueblos","Reconquista","Comuna"],"correcta":1},{"pregunta":"¿Qué consecuencia a largo plazo tuvieron?","opciones":["Ampliación del sufragio y constituciones","Retroceso del liberalismo","Fin de los parlamentos","Solo fracasos"],"correcta":0}]'::jsonb),

('historia-mundo', 'bachillerato', '{1}', 'La Revolución Industrial y sus consecuencias', 'La Revolución Industrial es el proceso histórico por el cual las sociedades europeas, especialmente Gran Bretaña a finales del siglo XVIII, pasaron de una economía agraria y artesanal a otra dominada por la industria y la máquina. Su origen se sitúa en el Reino Unido gracias a una combinación de factores favorables: abundancia de carbón y hierro, disponibilidad de capital, red comercial marítima, mano de obra liberada por los cambios agrarios y clima social e institucional propicio a la innovación. La invención de la máquina de vapor por James Watt en 1769 impulsó la mecanización textil y posteriormente los transportes con el ferrocarril y los barcos a vapor. La industria del algodón, del hierro y del carbón encabezó el despegue. Las consecuencias sociales fueron profundas: aparición de una nueva clase obrera, crecimiento de las ciudades, miseria en los barrios industriales, nuevas relaciones laborales basadas en el salario, y aparición de fenómenos como el trabajo infantil o las extensas jornadas laborales. Frente a estas condiciones surgieron los primeros movimientos obreros, el ludismo y después los sindicatos y partidos socialistas. La segunda Revolución Industrial, a partir de 1870, añadió nuevos sectores como la química, el acero, la electricidad y el petróleo, y se extendió a otros países como Alemania, Estados Unidos o Japón, transformando definitivamente la economía mundial.', '[{"pregunta":"¿Dónde comenzó la Revolución Industrial?","opciones":["Francia","Reino Unido","Alemania","Estados Unidos"],"correcta":1},{"pregunta":"¿Quién inventó una versión importante de la máquina de vapor?","opciones":["Edison","James Watt","Newton","Faraday"],"correcta":1},{"pregunta":"¿Qué fenómeno social NO surge con ella?","opciones":["Clase obrera","Ludismo","Sindicatos","Feudalismo"],"correcta":3},{"pregunta":"¿Qué sectores destacan en la segunda revolución?","opciones":["Solo textil","Química, acero, electricidad, petróleo","Solo agricultura","Solo carbón"],"correcta":1}]'::jsonb),

('historia-mundo', 'bachillerato', '{1}', 'El movimiento obrero y el marxismo', 'El desarrollo de la industrialización trajo consigo el nacimiento de una nueva clase social, el proletariado industrial, sometido a duras condiciones de trabajo y salarios bajos. Frente a estas desigualdades, desde principios del siglo XIX comenzaron a surgir diversas formas de protesta y organización obrera. Las primeras reacciones fueron espontáneas, como el ludismo, en el que los obreros destruían las máquinas a las que culpaban del desempleo. Pronto aparecieron formas más organizadas, como las sociedades de socorro mutuo, los primeros sindicatos y los movimientos de reivindicación política, entre ellos el cartismo británico, que pedía el sufragio universal y reformas democráticas. En el plano intelectual, Karl Marx y Friedrich Engels, en el Manifiesto Comunista de 1848, propusieron una interpretación materialista de la historia según la cual las sociedades estaban divididas por conflictos entre clases, y anunciaron que la lucha del proletariado conduciría a la superación del capitalismo mediante una revolución social. Su pensamiento, desarrollado en obras como El Capital, tuvo una enorme influencia en el movimiento obrero mundial. A lo largo del siglo XIX y comienzos del XX surgieron partidos socialistas y organizaciones internacionales, como la Primera y la Segunda Internacional. También aparecieron corrientes alternativas, como el anarquismo defendido por Bakunin, que rechazaba cualquier forma de Estado. La pluralidad del movimiento obrero marcaría la política del siglo XX.', '[{"pregunta":"¿Qué hacían los obreros en el ludismo?","opciones":["Sufragio universal","Destruían máquinas","Escribían libros","Iban al parlamento"],"correcta":1},{"pregunta":"¿Quiénes escribieron el Manifiesto Comunista?","opciones":["Marx y Engels","Bakunin y Proudhon","Saint-Simon y Fourier","Lenin y Trotski"],"correcta":0},{"pregunta":"¿Qué interpretación de la historia propusieron?","opciones":["Idealista","Materialista","Religiosa","Naturalista"],"correcta":1},{"pregunta":"¿Quién defendió el anarquismo?","opciones":["Marx","Engels","Bakunin","Lenin"],"correcta":2}]'::jsonb),

('historia-mundo', 'bachillerato', '{1}', 'Los nacionalismos del siglo XIX', 'El nacionalismo es una de las fuerzas políticas e ideológicas más influyentes del siglo XIX. Parte de la idea de que las personas con una misma lengua, cultura, historia o tradiciones forman una nación y tienen derecho a disponer de un Estado propio. Sus raíces se encuentran en la Revolución Francesa y la experiencia napoleónica, que difundieron el principio de soberanía nacional por toda Europa. A lo largo del siglo XIX, los nacionalismos desempeñaron un papel decisivo en dos grandes procesos: las unificaciones y las independencias. Entre las unificaciones más importantes destacan la de Italia, conseguida gracias a la diplomacia de Cavour, la acción militar de Garibaldi y el papel del reino de Piamonte-Cerdeña, culminada en 1861 con el reino de Italia; y la de Alemania, liderada por el canciller prusiano Otto von Bismarck a través de una serie de guerras victoriosas, que concluyó con la proclamación del Imperio alemán en 1871. En paralelo, en Europa oriental y en los Balcanes, pueblos sometidos a imperios multinacionales como el austrohúngaro o el otomano reivindicaron su independencia. En América Latina, los procesos de independencia frente a España y Portugal, llevados a cabo por figuras como Bolívar o San Martín, también tuvieron una fuerte componente nacional. El nacionalismo sería una de las causas profundas de los conflictos del siglo XX.', '[{"pregunta":"¿Qué defiende el nacionalismo?","opciones":["Imperios absolutos","Que cada nación tenga un Estado propio","Elisir la religión","Volver al feudalismo"],"correcta":1},{"pregunta":"¿Quién lideró la unificación alemana?","opciones":["Garibaldi","Bismarck","Cavour","Napoleón III"],"correcta":1},{"pregunta":"¿Cuándo se proclamó el reino de Italia?","opciones":["1848","1861","1871","1890"],"correcta":1},{"pregunta":"¿Qué figuras lideraron las independencias americanas?","opciones":["Bolívar y San Martín","Garibaldi y Cavour","Bismarck y Mazzini","Metternich y Talleyrand"],"correcta":0}]'::jsonb),

('historia-mundo', 'bachillerato', '{1}', 'El imperialismo y el reparto colonial', 'El imperialismo es el proceso por el cual las potencias europeas, y posteriormente Estados Unidos y Japón, extendieron su dominio político y económico sobre vastas regiones del mundo en las últimas décadas del siglo XIX y principios del XX. Sus causas son múltiples. En el plano económico, la Segunda Revolución Industrial demandaba nuevos mercados, materias primas y posibilidades de inversión. En el plano político, el imperialismo se asociaba a la búsqueda de prestigio internacional y al reforzamiento de la posición de las potencias. A ello se sumaban justificaciones ideológicas, como la supuesta misión civilizadora de Europa, la superioridad racial y el evangelismo religioso. África fue el continente más afectado por el imperialismo. La Conferencia de Berlín de 1884-1885 repartió el continente entre las potencias europeas con criterios arbitrarios, sin tener en cuenta las realidades étnicas ni culturales. Solo Etiopía y Liberia mantuvieron su independencia. En Asia, las potencias se repartieron influencia sobre India, Indochina, China y otras regiones. El imperialismo tuvo consecuencias profundas y duraderas: transformó economías enteras, impuso lenguas y culturas europeas, generó resistencias y sublevaciones y creó las bases de los conflictos descolonizadores del siglo XX. También contribuyó a aumentar la rivalidad entre las grandes potencias, uno de los factores que llevaron a la Primera Guerra Mundial.', '[{"pregunta":"¿Qué conferencia repartió África?","opciones":["Berlín","Viena","Versalles","Yalta"],"correcta":0},{"pregunta":"¿Qué causa económica tenía el imperialismo?","opciones":["Búsqueda de mercados y materias primas","Exceso de población","Falta de religión","Guerras civiles"],"correcta":0},{"pregunta":"¿Qué países africanos mantuvieron su independencia?","opciones":["Egipto y Sudán","Etiopía y Liberia","Kenia y Tanzania","Ghana y Nigeria"],"correcta":1},{"pregunta":"¿A qué conflicto contribuyó el imperialismo?","opciones":["Guerra civil española","Primera Guerra Mundial","Guerra Fría","Guerra de Corea"],"correcta":1}]'::jsonb),

('historia-mundo', 'bachillerato', '{1}', 'La Primera Guerra Mundial', 'La Primera Guerra Mundial, también conocida como la Gran Guerra, tuvo lugar entre 1914 y 1918 y fue el primer conflicto bélico global de la historia. Sus causas son complejas e incluyen las rivalidades imperiales, los nacionalismos, la carrera armamentística, el sistema de alianzas entre las potencias y las tensiones en los Balcanes. El detonante fue el asesinato en Sarajevo del archiduque austrohúngaro Francisco Fernando el 28 de junio de 1914, que desencadenó una cadena de declaraciones de guerra. Los bandos enfrentados fueron la Triple Entente, formada inicialmente por Francia, Reino Unido y Rusia, a los que se sumaron Italia en 1915 y Estados Unidos en 1917; y las Potencias Centrales, encabezadas por Alemania y Austria-Hungría junto al Imperio otomano y Bulgaria. La guerra se caracterizó por el uso masivo de nuevas armas, como ametralladoras, artillería de largo alcance, gases venenosos, tanques y aviones, que causaron millones de bajas. En el frente occidental, las tropas permanecieron atrincheradas durante años en una guerra de desgaste. La entrada de Estados Unidos y el agotamiento económico de las Potencias Centrales determinaron la victoria aliada. El Tratado de Versalles, firmado en 1919, impuso duras condiciones a Alemania y reorganizó el mapa europeo, sentando sin embargo las semillas de futuros conflictos. La guerra provocó alrededor de nueve millones de muertes militares y transformó profundamente la sociedad del siglo XX.', '[{"pregunta":"¿Cuándo tuvo lugar la Gran Guerra?","opciones":["1905-1910","1914-1918","1920-1925","1939-1945"],"correcta":1},{"pregunta":"¿Quién fue asesinado en Sarajevo?","opciones":["Francisco José","Francisco Fernando","Guillermo II","Nicolás II"],"correcta":1},{"pregunta":"¿Qué bando ganó la guerra?","opciones":["Potencias Centrales","Triple Entente (Aliados)","URSS","Imperio otomano"],"correcta":1},{"pregunta":"¿Qué tratado la cerró?","opciones":["Tratado de Versalles","Tratado de Trianón","Tratado de París","Tratado de Saint-Germain"],"correcta":0}]'::jsonb),

('historia-mundo', 'bachillerato', '{1}', 'La Revolución rusa de 1917', 'La Revolución rusa de 1917 es uno de los acontecimientos más influyentes del siglo XX. Se desarrolló en dos fases principales en el contexto de la Primera Guerra Mundial, que había provocado enormes sufrimientos y un profundo malestar social en Rusia. En febrero (según el calendario juliano entonces vigente) estalló una revolución popular que obligó al zar Nicolás II a abdicar, poniendo fin a varios siglos de monarquía zarista. Se formó un gobierno provisional de orientación liberal que, sin embargo, cometió el error de continuar en la guerra, lo que aumentó el descontento. Paralelamente se consolidaron los soviets, consejos elegidos por obreros y soldados, que disputaban el poder al gobierno. En octubre (noviembre en el calendario actual), los bolcheviques liderados por Vladímir Lenin protagonizaron una segunda revolución que derrocó al gobierno provisional y estableció el primer Estado socialista del mundo. Las primeras medidas incluyeron la salida de la guerra mediante el Tratado de Brest-Litovsk, la nacionalización de tierras y la abolición de los privilegios aristocráticos. A continuación se produjo una cruenta guerra civil entre los bolcheviques y sus adversarios, que terminó con la victoria de los primeros. En 1922 se proclamó la Unión de Repúblicas Socialistas Soviéticas (URSS), que durante todo el siglo XX sería una de las grandes potencias mundiales y un modelo alternativo al capitalismo occidental.', '[{"pregunta":"¿Quién fue obligado a abdicar en febrero de 1917?","opciones":["Lenin","Stalin","Zar Nicolás II","Kerensky"],"correcta":2},{"pregunta":"¿Quién lideró a los bolcheviques?","opciones":["Stalin","Trotski","Lenin","Rasputín"],"correcta":2},{"pregunta":"¿Cuándo se fundó la URSS?","opciones":["1917","1918","1922","1924"],"correcta":2},{"pregunta":"¿Qué tratado sacó a Rusia de la guerra?","opciones":["Versalles","Brest-Litovsk","Rapallo","Saint-Germain"],"correcta":1}]'::jsonb),

('historia-mundo', 'bachillerato', '{1}', 'El crack de 1929 y la Gran Depresión', 'El crack bursátil de octubre de 1929 supuso el inicio de la Gran Depresión, la crisis económica más grave del capitalismo moderno. A lo largo de los años veinte, Estados Unidos había vivido un periodo de prosperidad conocido como los felices años veinte, caracterizado por el auge del consumo, la especulación bursátil y el optimismo económico. Sin embargo, tras esa aparente prosperidad se ocultaban graves desequilibrios: sobreproducción industrial y agrícola, concentración excesiva de la riqueza, endeudamiento y especulación desmedida en la Bolsa. El jueves negro, 24 de octubre de 1929, se produjo el hundimiento de la Bolsa de Nueva York, con pérdidas que arrastraron a empresas, bancos y ahorradores. La crisis se propagó rápidamente al resto de la economía estadounidense: quiebras empresariales, despidos masivos, caída del consumo y cierre de bancos. El desempleo alcanzó cifras inéditas y gran parte de la población se vio sumida en la pobreza. La crisis se extendió pronto al resto del mundo debido a la interdependencia económica y a la retirada de capitales estadounidenses. La recuperación solo comenzó con las políticas del New Deal aplicadas por el presidente Franklin Delano Roosevelt a partir de 1933, basadas en un mayor intervencionismo del Estado, obras públicas y regulación financiera. La Gran Depresión marcó un cambio de rumbo en las políticas económicas del siglo XX y contribuyó al ascenso de los totalitarismos en Europa.', '[{"pregunta":"¿En qué año empezó el crack?","opciones":["1918","1929","1933","1939"],"correcta":1},{"pregunta":"¿Cómo se llaman los años 20 en Estados Unidos?","opciones":["Años de plomo","Felices años veinte","Años dorados","Años de crisis"],"correcta":1},{"pregunta":"¿Quién aplicó el New Deal?","opciones":["Hoover","Roosevelt","Wilson","Truman"],"correcta":1},{"pregunta":"¿A qué contribuyó la crisis en Europa?","opciones":["Ascenso de los totalitarismos","Estabilidad democrática","Fin de las guerras","Descolonización inmediata"],"correcta":0}]'::jsonb),

('historia-mundo', 'bachillerato', '{1}', 'El fascismo italiano y el nazismo alemán', 'El fascismo italiano y el nazismo alemán son dos regímenes totalitarios surgidos en Europa durante el período de entreguerras, en un contexto marcado por la crisis económica, la inestabilidad política y el miedo al comunismo. El fascismo fue fundado por Benito Mussolini, quien llegó al poder en Italia en 1922 tras la llamada Marcha sobre Roma. Su ideología combinaba nacionalismo exacerbado, rechazo del liberalismo y del comunismo, exaltación del Estado, culto al líder y glorificación de la violencia. En pocos años, Mussolini estableció un régimen dictatorial de partido único. El nacionalsocialismo alemán, liderado por Adolf Hitler, tomó el poder en Alemania en 1933 tras el hundimiento de la República de Weimar, muy afectada por la crisis del 29 y por el resentimiento provocado por el Tratado de Versalles. El nazismo añadió al modelo fascista un antisemitismo extremo, la teoría de la raza aria superior y la idea de un espacio vital que justificaba la expansión territorial. Ambos regímenes suprimieron los derechos y libertades, persiguieron a sus oponentes, controlaron la educación y los medios de comunicación y prepararon a sus países para la guerra. Su política agresiva fue uno de los factores que llevó al estallido de la Segunda Guerra Mundial, durante la cual perpetraron crímenes masivos, entre ellos el Holocausto, que causó la muerte de millones de judíos, gitanos y otros grupos perseguidos.', '[{"pregunta":"¿Quién fundó el fascismo italiano?","opciones":["Hitler","Mussolini","Franco","Stalin"],"correcta":1},{"pregunta":"¿Cuándo llegó Mussolini al poder?","opciones":["1918","1922","1929","1933"],"correcta":1},{"pregunta":"¿Qué añadió el nazismo al fascismo?","opciones":["Antisemitismo extremo y racismo ario","Monarquía","Pacifismo","Republicanismo"],"correcta":0},{"pregunta":"¿Qué acontecimiento antes ayudó a Hitler?","opciones":["Revolución rusa","Crisis de 1929","Conferencia de Yalta","Tratado de Roma"],"correcta":1}]'::jsonb),

('historia-mundo', 'bachillerato', '{1}', 'La Segunda Guerra Mundial', 'La Segunda Guerra Mundial, que se extendió entre 1939 y 1945, fue el conflicto más devastador de la historia humana, con unos sesenta millones de muertos y consecuencias profundas en todas las áreas de la vida. Sus causas incluyen el revanchismo alemán por el Tratado de Versalles, el fracaso de la Sociedad de Naciones, la política expansionista del nazismo, el fascismo italiano y la militarización de Japón. La guerra comenzó con la invasión alemana de Polonia el 1 de septiembre de 1939, a la que siguió la declaración de guerra de Francia y Reino Unido. Durante los primeros años, Alemania logró una rápida expansión por Europa, ocupando países como Dinamarca, Noruega, Bélgica, Francia y los Balcanes. La guerra se extendió globalmente con el ataque japonés a Pearl Harbor en 1941, que provocó la entrada de Estados Unidos en el conflicto, y con la invasión alemana de la Unión Soviética en la llamada Operación Barbarroja. El conflicto tuvo escenarios en Europa, África, Asia y el Pacífico. A partir de 1942 el curso de la guerra cambió: la derrota alemana en Stalingrado, el desembarco aliado en Normandía en 1944 y la ofensiva soviética desde el este sellaron el destino de la Alemania nazi, que se rindió en mayo de 1945. En agosto del mismo año, el lanzamiento de las bombas atómicas sobre Hiroshima y Nagasaki precipitó la rendición japonesa. La guerra dejó Europa devastada y abrió una nueva era marcada por la Guerra Fría.', '[{"pregunta":"¿Cuándo empezó la Segunda Guerra Mundial?","opciones":["1936","1939","1941","1945"],"correcta":1},{"pregunta":"¿Qué provocó la entrada de EE UU en la guerra?","opciones":["Pearl Harbor","Stalingrado","Versalles","Yalta"],"correcta":0},{"pregunta":"¿Dónde desembarcaron los aliados en 1944?","opciones":["Sicilia","Normandía","Berlín","Creta"],"correcta":1},{"pregunta":"¿Qué ciudades fueron bombardeadas con armas atómicas?","opciones":["Tokio y Osaka","Hiroshima y Nagasaki","Berlín y Múnich","Londres y París"],"correcta":1}]'::jsonb),

('historia-mundo', 'bachillerato', '{1}', 'La Guerra Fría y el mundo bipolar', 'Tras el fin de la Segunda Guerra Mundial, el mundo quedó dividido en dos grandes bloques liderados por Estados Unidos y la Unión Soviética, las dos superpotencias vencedoras. Este enfrentamiento, conocido como Guerra Fría, no dio lugar a un conflicto armado directo entre ambas potencias, pero generó una tensión constante que se manifestó en la carrera armamentística, la carrera espacial, guerras locales y bloqueos diplomáticos. Europa quedó dividida por el llamado telón de acero, con una Europa occidental vinculada a Estados Unidos y una oriental controlada por la URSS. La creación de la OTAN en 1949 y la del Pacto de Varsovia en 1955 formalizaron las alianzas militares enfrentadas. Las principales crisis de la Guerra Fría incluyen el bloqueo de Berlín en 1948, la guerra de Corea (1950-1953), la crisis de los misiles de Cuba en 1962 (que estuvo a punto de provocar una guerra nuclear), la guerra de Vietnam (1955-1975) y la invasión soviética de Afganistán en 1979. Paralelamente, los bloques competían por atraer a nuevos países en el llamado Tercer Mundo. La Guerra Fría terminó a finales de los años ochenta con la caída del Muro de Berlín en 1989 y el posterior colapso de la Unión Soviética en 1991, lo que marcó el inicio de una nueva etapa de la historia mundial con Estados Unidos como única superpotencia.', '[{"pregunta":"¿Qué dos potencias lideraron la Guerra Fría?","opciones":["EE UU y China","EE UU y URSS","URSS y Alemania","China y Japón"],"correcta":1},{"pregunta":"¿Qué alianza creó Occidente en 1949?","opciones":["Pacto de Varsovia","OTAN","ONU","CEE"],"correcta":1},{"pregunta":"¿Qué crisis casi provocó una guerra nuclear?","opciones":["Corea","Berlín","Misiles de Cuba","Vietnam"],"correcta":2},{"pregunta":"¿Cuándo cayó el Muro de Berlín?","opciones":["1985","1989","1991","1993"],"correcta":1}]'::jsonb),

('historia-mundo', 'bachillerato', '{1}', 'La descolonización en el siglo XX', 'La descolonización es el proceso por el que los pueblos sometidos a dominio colonial alcanzaron su independencia a lo largo del siglo XX, especialmente tras la Segunda Guerra Mundial. La guerra había debilitado a las potencias coloniales europeas, mientras que la expansión de las ideas nacionalistas, la creación de la ONU y el apoyo de Estados Unidos y la Unión Soviética facilitaron los procesos emancipadores. En Asia, uno de los primeros casos fue la India, que obtuvo la independencia de Reino Unido en 1947 tras décadas de lucha encabezadas por líderes como Mahatma Gandhi y Jawaharlal Nehru. La partición dio lugar a dos Estados, India y Pakistán, con graves conflictos derivados. En Indochina, la guerra contra Francia terminó con la derrota francesa y la división de Vietnam. En África, la descolonización se aceleró en los años sesenta, la llamada década africana, cuando numerosos países accedieron a la independencia, a menudo tras guerras violentas, como en Argelia. En algunos casos, la descolonización fue pacífica; en otros, generó largos conflictos armados. Las nuevas naciones se enfrentaron a desafíos enormes: fronteras artificiales heredadas del colonialismo, dependencia económica, inestabilidad política y luchas étnicas. Muchas se agruparon en el llamado Movimiento de Países No Alineados, que buscaba una tercera vía frente a la división Este-Oeste de la Guerra Fría. La descolonización transformó profundamente el mapa y el equilibrio político del mundo contemporáneo.', '[{"pregunta":"¿Quién lideró la independencia india?","opciones":["Mandela","Gandhi","Ho Chi Minh","Mao"],"correcta":1},{"pregunta":"¿Cuándo obtuvo India su independencia?","opciones":["1945","1947","1956","1960"],"correcta":1},{"pregunta":"¿Cómo se conoce la década de descolonización africana?","opciones":["Década africana","Década dorada","Década perdida","Década blanca"],"correcta":0},{"pregunta":"¿Qué movimiento buscaba una tercera vía?","opciones":["OTAN","No Alineados","Pacto de Varsovia","CEE"],"correcta":1}]'::jsonb),

('historia-mundo', 'bachillerato', '{1}', 'La construcción de la Unión Europea', 'La construcción de la Unión Europea es uno de los procesos más originales e importantes del siglo XX y principios del XXI. Tras dos guerras mundiales devastadoras, varios líderes europeos, entre ellos Robert Schuman, Jean Monnet, Konrad Adenauer y Alcide De Gasperi, promovieron la idea de una integración pacífica de los países del continente para evitar nuevos conflictos. El primer paso fue la creación en 1951 de la Comunidad Europea del Carbón y del Acero (CECA) por Francia, Alemania, Italia, Bélgica, Países Bajos y Luxemburgo. En 1957, los mismos países firmaron los Tratados de Roma, que dieron origen a la Comunidad Económica Europea (CEE) y a Euratom, con el objetivo de crear un mercado común. En las décadas siguientes se sumaron nuevos países y se ampliaron las competencias comunes. El Tratado de Maastricht, firmado en 1992, estableció la Unión Europea propiamente dicha, creando una ciudadanía europea, una política exterior común y sentando las bases del euro, la moneda única adoptada oficialmente en 2002 por la mayoría de sus miembros. La UE ha seguido creciendo hasta contar con más de veinticinco Estados, sobre todo tras la ampliación al este de 2004. Su historia también ha estado marcada por crisis, como la financiera de 2008, la del euro o la salida del Reino Unido (Brexit). Pese a las dificultades, la UE representa un modelo de integración económica, política y social sin precedentes.', '[{"pregunta":"¿Qué organización se creó en 1951?","opciones":["CECA","CEE","UE","EFTA"],"correcta":0},{"pregunta":"¿Qué tratado crea la UE en 1992?","opciones":["Lisboa","Roma","Maastricht","Niza"],"correcta":2},{"pregunta":"¿Cuándo entró el euro en circulación general?","opciones":["1992","1999","2002","2007"],"correcta":2},{"pregunta":"¿Qué se llamó Brexit?","opciones":["Entrada de Reino Unido","Salida de Reino Unido","Entrada de Bulgaria","Salida de Grecia"],"correcta":1}]'::jsonb);

