INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('latin', 'bachillerato', '{1}', 'La fundación de Roma', 'La fundación de Roma es uno de los episodios más conocidos de la mitología y la historia antigua. Según la tradición, Roma fue fundada por Rómulo y Remo, hermanos gemelos de origen divino, hijos del dios Marte y de Rea Silvia, princesa de la ciudad de Alba Longa. La leyenda cuenta que, nada más nacer, fueron abandonados en las orillas del río Tíber por orden de un tío usurpador, pero sobrevivieron gracias a una loba que los amamantó y a un pastor llamado Fáustulo, que los crio junto a su esposa. Al alcanzar la edad adulta, los dos hermanos decidieron fundar una ciudad en las colinas donde habían sido rescatados. Sin embargo, surgió una disputa sobre quién debía reinar y dar nombre a la nueva ciudad. Tras consultar a los dioses mediante el vuelo de las aves, Rómulo mató a su hermano en un episodio trágico y se convirtió en el primer rey de Roma. La tradición fija la fecha de la fundación en el año 753 antes de nuestra era. La arqueología ha demostrado que efectivamente existieron asentamientos en las colinas romanas desde una época muy antigua, lo que no significa que la leyenda deba tomarse al pie de la letra. El mito sirvió a los romanos para legitimar su origen divino y su destino imperial, y continúa formando parte del imaginario cultural europeo.', '[{"pregunta":"¿Quiénes fundaron Roma según la leyenda?","opciones":["Eneas y Anquises","Rómulo y Remo","Numa y Anco","Tarquinio y Servio"],"correcta":1},{"pregunta":"¿Qué animal amamantó a los gemelos?","opciones":["Un águila","Una loba","Una osa","Una cabra"],"correcta":1},{"pregunta":"¿En qué año se fija la fundación tradicional?","opciones":["509 a. C.","753 a. C.","27 a. C.","476 d. C."],"correcta":1},{"pregunta":"¿Cómo se llama el dios padre de los gemelos?","opciones":["Júpiter","Marte","Apolo","Mercurio"],"correcta":1}]'::jsonb),

('latin', 'bachillerato', '{1}', 'La familia romana y la patria potestas', 'La familia romana era una institución central en la vida social y jurídica de Roma. Su estructura y funcionamiento diferían notablemente de la familia actual. El cabeza de familia, el pater familias, poseía una autoridad absoluta sobre todos los miembros de la casa, conocida como patria potestas. Esta autoridad se extendía a la esposa, los hijos, los descendientes por línea masculina, los esclavos y los bienes materiales. El pater familias podía tomar decisiones sobre matrimonios, herencias, ventas y, en teoría, incluso sobre la vida de sus hijos, aunque este derecho extremo prácticamente no se utilizaba en la práctica cotidiana. Las mujeres casadas, en la forma más antigua del matrimonio, pasaban a estar bajo la autoridad del marido; con el tiempo, sin embargo, se desarrollaron formas de matrimonio en las que la esposa mantenía cierta independencia jurídica, especialmente en la gestión de su dote. Los niños recibían la educación familiar en los primeros años y, más tarde, los varones de familias acomodadas asistían a escuelas donde aprendían lectura, escritura y conocimientos necesarios para la vida pública. El matrimonio romano era, ante todo, una institución social y legal orientada a la continuación de la familia y de la ciudadanía. Las celebraciones matrimoniales incluían rituales específicos y la transmisión simbólica de la esposa a la casa del marido, donde asumía nuevas responsabilidades domésticas y religiosas.', '[{"pregunta":"¿Quién era el cabeza de la familia romana?","opciones":["Mater familias","Pater familias","Princeps","Senator"],"correcta":1},{"pregunta":"¿Qué era la patria potestas?","opciones":["Un impuesto","La autoridad absoluta del pater","Una ley militar","Una ceremonia religiosa"],"correcta":1},{"pregunta":"¿Qué aprendían los niños varones en las escuelas?","opciones":["Solo música","Lectura, escritura y vida pública","Solo danza","Agricultura"],"correcta":1},{"pregunta":"¿Qué mantenía la esposa en formas más modernas del matrimonio?","opciones":["Esclavos","Cierta independencia jurídica","Un ejército","Un templo"],"correcta":1}]'::jsonb),

('latin', 'bachillerato', '{1}', 'El sistema de declinaciones del latín', 'Una de las particularidades del latín es su carácter flexivo, es decir, que las palabras cambian su terminación para indicar la función que desempeñan dentro de la oración. Este sistema se conoce como declinación, y afecta principalmente a los sustantivos, adjetivos y pronombres. El latín cuenta con cinco declinaciones, cada una con un conjunto característico de terminaciones. Además, los sustantivos y adjetivos presentan seis casos principales: nominativo, para el sujeto; vocativo, para la llamada; acusativo, para el complemento directo; genitivo, para el complemento del nombre; dativo, para el complemento indirecto; y ablativo, para numerosas funciones circunstanciales. Cada caso tiene formas distintas en singular y en plural, lo que hace que la misma palabra pueda tener más de diez formas diferentes. Aunque a primera vista este sistema resulte complicado, tiene la ventaja de permitir una gran flexibilidad en el orden de las palabras. En latín clásico, el orden de los elementos en la frase no es fijo y puede variar por razones de énfasis o estilo sin alterar el significado básico, porque las desinencias indican claramente la función de cada palabra. Comprender las declinaciones es esencial para leer textos latinos originales y para entender la evolución de muchas lenguas romances, como el español, el francés, el italiano o el portugués, que conservan huellas importantes de este sistema gramatical.', '[{"pregunta":"¿Cuántas declinaciones tiene el latín?","opciones":["Tres","Cuatro","Cinco","Seis"],"correcta":2},{"pregunta":"¿Para qué sirve el nominativo?","opciones":["Complemento directo","Sujeto","Circunstancial","Complemento del nombre"],"correcta":1},{"pregunta":"¿Qué ventaja aporta la declinación?","opciones":["Fija el orden de palabras","Permite flexibilidad en el orden","Obliga a usar artículos","Elimina los verbos"],"correcta":1},{"pregunta":"¿Qué lenguas conservan huellas del sistema latino?","opciones":["Lenguas romances","Lenguas semíticas","Lenguas árabes","Lenguas turcas"],"correcta":0}]'::jsonb),

('latin', 'bachillerato', '{1}', 'Julio César y la Guerra de las Galias', 'Julio César es una de las figuras más célebres de la historia romana. Nacido en el año 100 antes de nuestra era en una familia patricia, combinó una destacada carrera política con una brillante actuación militar. Uno de los episodios más importantes de su vida fue la Guerra de las Galias, que dirigió entre los años 58 y 51 a. C. y que él mismo narró en su obra De Bello Gallico, escrita en un latín elegante y sobrio. Durante estos años, César sometió a la actual Francia, Bélgica, partes de los Países Bajos, Suiza y Alemania, enfrentándose a numerosas tribus galas y germanas. Su victoria decisiva sobre el caudillo galo Vercingétorix en la batalla de Alesia, en el 52 a. C., puso fin a la resistencia organizada y consolidó el dominio romano en la Galia. La conquista tuvo consecuencias profundas, pues incorporó a Roma un vasto territorio que acabaría romanizándose en lo lingüístico, cultural y administrativo. La obra de César, además de un relato histórico, era también una herramienta de propaganda política, destinada a mostrar sus méritos ante el Senado y el pueblo romano. Al regresar a Italia, las tensiones políticas estallaron en una guerra civil que César terminó ganando, convirtiéndose en dictador perpetuo poco antes de su asesinato en los idus de marzo del 44 a. C.', '[{"pregunta":"¿En qué obra narró César la Guerra de las Galias?","opciones":["Eneida","De Bello Gallico","Historia Romana","Metamorfosis"],"correcta":1},{"pregunta":"¿Contra quién venció César en Alesia?","opciones":["Aníbal","Vercingétorix","Pirro","Mitrídates"],"correcta":1},{"pregunta":"¿Cuándo fue asesinado César?","opciones":["58 a. C.","52 a. C.","44 a. C.","27 a. C."],"correcta":2},{"pregunta":"¿Qué proceso cultural se produjo tras la conquista?","opciones":["Islamización","Romanización","Helenización","Germanización"],"correcta":1}]'::jsonb),

('latin', 'bachillerato', '{1}', 'Virgilio y la Eneida', 'Publio Virgilio Marón, conocido simplemente como Virgilio, es uno de los más grandes poetas de Roma y de toda la literatura europea. Nacido en el año 70 antes de nuestra era cerca de Mantua, en el norte de Italia, desarrolló su obra durante el reinado del emperador Augusto, en una época de renovación cultural y política tras las guerras civiles. Su obra más famosa es la Eneida, un poema épico en doce libros que narra las aventuras del héroe troyano Eneas, superviviente de la caída de Troya, en su viaje hacia Italia para fundar el pueblo del que surgirán los romanos. Inspirada en los poemas homéricos, la Eneida tiene sin embargo un carácter propio: no se limita a relatar hazañas, sino que ofrece una reflexión profunda sobre el destino, el deber, la piedad y la fundación de Roma como ciudad elegida por los dioses. El personaje de Eneas encarna las virtudes romanas ideales, especialmente la pietas, es decir, el respeto a los dioses, a la familia y a la patria. Virgilio escribió también obras anteriores, como las Bucólicas, poemas pastorales, y las Geórgicas, dedicadas a la agricultura y a la vida rural. Su poesía influyó enormemente en la literatura posterior y Dante, en la Edad Media, lo eligió como guía en la Divina Comedia, demostrando el prestigio del que gozaba muchos siglos después.', '[{"pregunta":"¿Quién es el protagonista de la Eneida?","opciones":["Ulises","Aquiles","Eneas","Héctor"],"correcta":2},{"pregunta":"¿Cuántos libros tiene la Eneida?","opciones":["Ocho","Diez","Doce","Veinticuatro"],"correcta":2},{"pregunta":"¿Qué virtud romana encarna Eneas?","opciones":["Clementia","Pietas","Fortitudo","Virtus militaris"],"correcta":1},{"pregunta":"¿Qué poeta medieval eligió a Virgilio como guía?","opciones":["Petrarca","Dante","Boccaccio","Chaucer"],"correcta":1}]'::jsonb),

('latin', 'bachillerato', '{1}', 'La vida cotidiana en Roma', 'La vida cotidiana de los romanos ha sido reconstruida por los historiadores gracias a los numerosos textos, inscripciones y restos arqueológicos conservados, especialmente en ciudades como Pompeya y Herculano, sepultadas por la erupción del Vesubio en el año 79 de nuestra era. Los romanos acomodados vivían en domus, casas urbanas con un patio central llamado atrio y, en muchas ocasiones, un jardín interior rodeado de columnas conocido como peristilo. Los más humildes habitaban en insulae, edificios de varios pisos con condiciones muy desiguales: las plantas bajas podían ser cómodas, pero las superiores eran pequeñas, carecían de agua corriente y estaban expuestas a incendios. La jornada comenzaba temprano: los ciudadanos acudían al trabajo, a los templos o a los tribunales, y a mediados de la mañana disfrutaban de un breve descanso. El tiempo libre giraba en torno a las termas, los baños públicos donde se combinaba el cuidado del cuerpo con la vida social; al circo, donde se celebraban carreras de carros; y a los anfiteatros, donde los gladiadores luchaban en combates que atraían a grandes multitudes. La dieta romana era variada y estaba basada en el pan, el vino, el aceite de oliva, las legumbres, las verduras y, en menor medida, la carne. Los romanos concedían gran importancia a los banquetes, especialmente entre las clases sociales acomodadas, como ocasiones para conversar, cerrar negocios o exhibir riqueza.', '[{"pregunta":"¿Cómo se llamaba la casa urbana romana?","opciones":["Villa","Domus","Insula","Forum"],"correcta":1},{"pregunta":"¿Qué eran las insulae?","opciones":["Templos","Casas señoriales","Edificios de varios pisos","Almacenes"],"correcta":2},{"pregunta":"¿Dónde se hacían carreras de carros?","opciones":["Anfiteatro","Circo","Foro","Templo"],"correcta":1},{"pregunta":"¿Qué ciudades fueron sepultadas por el Vesubio?","opciones":["Roma y Ostia","Pompeya y Herculano","Pisa y Florencia","Atenas y Corinto"],"correcta":1}]'::jsonb),

('latin', 'bachillerato', '{1}', 'La religión romana y sus dioses', 'La religión romana tradicional era politeísta y tenía un carácter marcadamente práctico y ritual. Los romanos rendían culto a numerosos dioses, muchos de los cuales se asimilaron a divinidades griegas tras los contactos con el mundo helénico. Entre los más importantes estaban Júpiter, equivalente al Zeus griego y protector del Estado; Juno, su esposa, protectora de las mujeres y del matrimonio; Marte, dios de la guerra, especialmente importante para Roma por su relación con el mito fundacional; Minerva, diosa de la sabiduría y las artes; Venus, diosa del amor; Mercurio, dios del comercio y los viajes; y Vesta, diosa del hogar, a cuyo servicio estaban las sacerdotisas vestales. Junto a estos grandes dioses, cada familia veneraba a sus propios dioses domésticos, los lares y penates, y a los manes, espíritus de los antepasados. Los rituales religiosos estaban regulados por colegios sacerdotales como los pontífices, los augures y los arúspices. El emperador, a partir de Augusto, acabó siendo objeto de culto también, lo que reforzaba la unidad política del Imperio. A partir del siglo I, el cristianismo comenzó a extenderse lentamente por el mundo romano, enfrentándose a persecuciones hasta que, en el siglo IV, el emperador Constantino lo declaró lícito y Teodosio lo convirtió en religión oficial del Imperio. La religión romana sobrevivió, sin embargo, en numerosas tradiciones culturales posteriores.', '[{"pregunta":"¿Cómo se llamaba la esposa de Júpiter?","opciones":["Atenea","Juno","Venus","Minerva"],"correcta":1},{"pregunta":"¿Qué dios protegía el hogar?","opciones":["Marte","Vesta","Mercurio","Neptuno"],"correcta":1},{"pregunta":"¿Quién convirtió el cristianismo en religión oficial?","opciones":["Augusto","Constantino","Nerón","Teodosio"],"correcta":3},{"pregunta":"¿Qué eran los lares?","opciones":["Pescadores","Dioses domésticos","Esclavos","Sacerdotes"],"correcta":1}]'::jsonb),

('latin', 'bachillerato', '{1}', 'El latín y su evolución hacia las lenguas romances', 'El latín es una lengua indoeuropea originaria del Lacio, región de la actual Italia central, que se fue extendiendo con la expansión de Roma por todo el Mediterráneo y gran parte de Europa. En la época clásica existían dos registros principales: el latín literario o cultivado, usado por los grandes autores como Cicerón o Virgilio, y el latín vulgar, hablado por la mayoría de la población en la vida cotidiana. Este latín vulgar, más sencillo y flexible, fue el que sirvió de base a la formación de las llamadas lenguas romances tras la caída del Imperio romano de Occidente en el siglo V de nuestra era. Con el paso de los siglos, las variedades habladas en las distintas provincias evolucionaron de forma cada vez más independiente, hasta dar lugar a lenguas hoy tan distintas como el español, el francés, el italiano, el portugués, el rumano, el catalán o el occitano. Cada una conservó elementos básicos del latín y, al mismo tiempo, incorporó influencias de las lenguas anteriores habladas en cada zona y de las que llegaron con invasiones o contactos posteriores. El latín clásico continuó siendo durante siglos la lengua de la cultura, la religión, la ciencia y el derecho en Europa, y aún hoy sigue presente en muchos términos técnicos, jurídicos, médicos y académicos que utilizamos en nuestro día a día.', '[{"pregunta":"¿Qué latín dio origen a las lenguas romances?","opciones":["Clásico","Vulgar","Arcaico","Eclesiástico"],"correcta":1},{"pregunta":"¿En qué región surgió el latín?","opciones":["Nápoles","Lacio","Sicilia","Galia"],"correcta":1},{"pregunta":"¿Qué lengua NO es romance?","opciones":["Español","Francés","Rumano","Alemán"],"correcta":3},{"pregunta":"¿Qué ámbitos siguió dominando el latín durante siglos?","opciones":["Deporte","Cultura, religión, ciencia, derecho","Cocina","Transporte"],"correcta":1}]'::jsonb),

('latin', 'bachillerato', '{1}', 'El teatro romano: Plauto y Terencio', 'El teatro romano tiene sus raíces en diversas tradiciones: las ceremonias religiosas latinas, las influencias etruscas y, sobre todo, el teatro griego, con el que los romanos entraron en contacto a través de las colonias helénicas del sur de Italia. Los dos autores más importantes de la comedia latina son Plauto y Terencio, ambos del siglo II antes de nuestra era. Plauto, nacido en Umbría, compuso numerosas obras de las que se conservan veintiuna completas. Sus comedias, inspiradas en modelos griegos pero muy adaptadas al público romano, destacan por su ritmo ágil, sus enredos ingeniosos, sus personajes típicos (el esclavo astuto, el viejo avaro, el joven enamorado) y un humor vivo y popular. Títulos como Aulularia o Miles Gloriosus influyeron en el teatro europeo posterior, incluido Molière. Terencio, de origen africano y vinculado a círculos aristocráticos romanos, escribió obras más elegantes y sutiles, con un latín de gran belleza. Sus comedias, como Andria o El eunuco, trataban temas familiares y morales con un estilo refinado que los hizo modelo de buen latín durante siglos. Aunque ambos autores compartían la estructura de la comedia nueva griega, cada uno aportó su propio estilo. El teatro latino no se limitó a la comedia: también existían la tragedia y las llamadas atelanas, farsas populares, pero fueron Plauto y Terencio quienes dejaron la huella más duradera.', '[{"pregunta":"¿Cuáles son los dos grandes autores cómicos?","opciones":["Horacio y Ovidio","Virgilio y César","Plauto y Terencio","Séneca y Tácito"],"correcta":2},{"pregunta":"¿Qué caracteriza las obras de Plauto?","opciones":["Tono trágico","Ritmo ágil y humor popular","Estilo sobrio","Ausencia de enredos"],"correcta":1},{"pregunta":"¿Qué estilo tenía Terencio?","opciones":["Rústico","Refinado y elegante","Cómico popular","Religioso"],"correcta":1},{"pregunta":"¿Qué autor europeo fue influido por Plauto?","opciones":["Molière","Shakespeare","Voltaire","Cervantes"],"correcta":0}]'::jsonb),

('latin', 'bachillerato', '{1}', 'Cicerón y la oratoria', 'Marco Tulio Cicerón, nacido en el año 106 antes de nuestra era, es considerado el mayor orador de Roma y uno de los más grandes de toda la historia. Proveniente de una familia ecuestre y no aristocrática, logró escalar por sus propios méritos hasta los más altos cargos de la República, llegando a ocupar el consulado en el año 63 a. C. Durante su consulado desbarató la conjuración de Catilina, acontecimiento que narró en sus célebres Catilinarias, discursos que se conservan como modelo de elocuencia y argumentación. Cicerón dominaba todos los géneros oratorios: forense, deliberativo y epidíctico. En sus discursos judiciales defendía o acusaba con rigor y estilo; en los políticos intervenía en los debates del Senado; y en los epidícticos elogiaba a personajes o ideas. Pero su importancia va más allá de la oratoria. Fue también un gran filósofo que, escribiendo en latín, tradujo y adaptó el pensamiento griego para el público romano en obras como De Officiis, De Republica o Tusculanas, convirtiéndose en el principal transmisor de la filosofía antigua al mundo latino. Además, dejó una abundante correspondencia privada, con cientos de cartas en las que se revelan tanto los acontecimientos políticos como sus sentimientos personales. Asesinado en el año 43 a. C. por orden de Marco Antonio, su influencia sobre la prosa latina y sobre el pensamiento occidental ha sido inmensa.', '[{"pregunta":"¿En qué año fue cónsul Cicerón?","opciones":["100 a. C.","63 a. C.","43 a. C.","27 a. C."],"correcta":1},{"pregunta":"¿Qué conjuración desbarató?","opciones":["La de Catilina","La de César","La de Espartaco","La de Sertorio"],"correcta":0},{"pregunta":"¿Qué género tratan sus cartas?","opciones":["Epistolar privado","Épico","Lírico","Didáctico"],"correcta":0},{"pregunta":"¿Quién ordenó su asesinato?","opciones":["Augusto","Pompeyo","Marco Antonio","Bruto"],"correcta":2}]'::jsonb),

('latin', 'bachillerato', '{1}', 'Ovidio y las Metamorfosis', 'Publio Ovidio Nasón, conocido como Ovidio, es uno de los poetas latinos más leídos e influyentes de la historia. Nacido en el año 43 antes de nuestra era en una familia acomodada del centro de Italia, recibió una esmerada educación en retórica antes de dedicarse por completo a la poesía. Su obra cumbre es las Metamorfosis, un extenso poema en quince libros que recorre más de doscientas cincuenta leyendas mitológicas griegas y romanas, unidas por el tema común de la transformación. Ovidio narra con gracia, ironía y habilidad cómo dioses, héroes y mortales cambian de forma, convirtiéndose en plantas, animales, piedras o constelaciones, a menudo como resultado del amor, la venganza o la compasión. Las Metamorfosis han sido una inagotable fuente de inspiración para la literatura, el arte y la música desde el Renacimiento hasta nuestros días. Ovidio escribió también otras obras muy populares, como los Amores, el Arte de amar y los Fastos. Su vida dio un giro inesperado cuando, en el año 8 de nuestra era, el emperador Augusto lo desterró a Tomis, una ciudad fría y remota en la orilla del Mar Negro, por razones que nunca se aclararon del todo. Desde allí escribió las Tristes y las Pónticas, llenas de nostalgia. Murió en el exilio sin haber recibido el perdón imperial, pero su obra le aseguró la inmortalidad literaria.', '[{"pregunta":"¿Cuántos libros tienen las Metamorfosis?","opciones":["Diez","Doce","Quince","Veinte"],"correcta":2},{"pregunta":"¿Qué tema común une el poema?","opciones":["Guerra","Transformación","Agricultura","Política"],"correcta":1},{"pregunta":"¿Quién desterró a Ovidio?","opciones":["César","Augusto","Nerón","Tiberio"],"correcta":1},{"pregunta":"¿Qué obras escribió en el exilio?","opciones":["Amores y Fastos","Tristes y Pónticas","Metamorfosis","Eneida"],"correcta":1}]'::jsonb),

('latin', 'bachillerato', '{1}', 'La mitología romana y los mitos fundacionales', 'La mitología romana está estrechamente ligada a la griega, de la que tomó prestados numerosos dioses, héroes y relatos, adaptándolos a sus propias tradiciones. Sin embargo, los romanos también poseían mitos específicos relacionados con el origen de su ciudad y con los valores que querían transmitir a los ciudadanos. Entre los más conocidos destaca el de Eneas, héroe troyano superviviente de la caída de Troya, que tras un largo viaje llegó al Lacio y se convirtió en antepasado de los reyes de Alba Longa y, por tanto, de Rómulo. Este mito fue celebrado por Virgilio en la Eneida y tenía una clara función política, pues vinculaba el origen de Roma con el prestigioso mundo homérico. Otro relato emblemático es el de las vírgenes vestales y el fuego sagrado que debían mantener siempre encendido; las que lo dejaban apagar o rompían su voto de castidad eran severamente castigadas. También son célebres los mitos del rapto de las sabinas, que según la tradición dio origen a la fusión de latinos y sabinos en los primeros tiempos de Roma, o el episodio de Lucrecia, cuyo ultraje condujo a la caída de la monarquía y al establecimiento de la República. Estos relatos no se entendían solo como historias, sino como lecciones morales y políticas destinadas a reforzar la cohesión, el patriotismo y las virtudes romanas entre la ciudadanía.', '[{"pregunta":"¿De qué héroe desciende según la leyenda Roma?","opciones":["Ulises","Eneas","Héctor","Aquiles"],"correcta":1},{"pregunta":"¿Qué debían mantener las vestales?","opciones":["Un jardín","El fuego sagrado","Los escudos","Las monedas"],"correcta":1},{"pregunta":"¿Qué episodio llevó a la caída de la monarquía?","opciones":["Rapto de sabinas","Ultraje de Lucrecia","Guerra de Troya","Incendio del templo"],"correcta":1},{"pregunta":"¿Qué función tenían estos mitos?","opciones":["Solo entretener","Transmitir valores y cohesión","Enseñar idiomas","Calendario agrícola"],"correcta":1}]'::jsonb),

('latin', 'bachillerato', '{1}', 'El ejército romano y sus legiones', 'El ejército romano fue uno de los factores más importantes del éxito y la expansión del Imperio. Su unidad básica era la legión, una formación militar perfectamente organizada que, en su época clásica, contaba con aproximadamente cinco mil soldados, en su mayoría infantes. Las legiones se dividían en cohortes, manípulos y centurias, con una estricta jerarquía de oficiales encabezada por el legado y los centuriones. Los legionarios eran soldados profesionales, ciudadanos romanos que firmaban un contrato de servicio por veinte o veinticinco años y recibían un salario, una parte de botín y, al licenciarse, tierras y, a menudo, la ciudadanía para ellos o para sus familiares. El entrenamiento era duro y constante: marchas con pesada carga, prácticas de armas, construcción de campamentos y disciplina estricta. Junto a las legiones operaban las tropas auxiliares, reclutadas entre los pueblos no ciudadanos, que incluían caballería, arqueros y unidades ligeras. La flota romana completaba el dispositivo militar, patrullando el Mediterráneo, que los romanos llamaban Mare Nostrum, nuestro mar. La eficacia del ejército se basaba no solo en su tecnología y disciplina, sino también en su capacidad de ingeniería: los romanos construían caminos, puentes, fortificaciones y máquinas de asedio con asombrosa rapidez. Gracias a este ejército, Roma pudo conquistar y mantener durante siglos un inmenso territorio que se extendía desde Britania hasta el Oriente Próximo.', '[{"pregunta":"¿Cuántos soldados tenía aproximadamente una legión clásica?","opciones":["1 000","5 000","20 000","100 000"],"correcta":1},{"pregunta":"¿Qué recibían al licenciarse los legionarios?","opciones":["Solo un abrazo","Tierras y a veces ciudadanía","Templos","Una corona"],"correcta":1},{"pregunta":"¿Cómo llamaban al Mediterráneo?","opciones":["Mare Roma","Mare Nostrum","Mare Latinum","Mare Internum"],"correcta":1},{"pregunta":"¿Qué tropas complementaban las legiones?","opciones":["Gladiadores","Tropas auxiliares","Piratas","Vestales"],"correcta":1}]'::jsonb),

('latin', 'bachillerato', '{1}', 'El derecho romano y su legado', 'El derecho romano es uno de los legados más duraderos de Roma y constituye la base de la mayoría de los sistemas jurídicos de Europa continental y de muchos países de América Latina. A lo largo de los siglos, los romanos desarrollaron un conjunto de normas y principios cada vez más sofisticados para regular las relaciones entre personas, la propiedad, los contratos, las obligaciones y las herencias, así como la organización del Estado. Una obra fundamental fue la Ley de las Doce Tablas, redactada en el siglo V antes de nuestra era, considerada la primera codificación escrita del derecho romano. Con el tiempo, juristas profesionales elaboraron interpretaciones, opiniones y comentarios que enriquecieron enormemente el sistema. Durante el Imperio, figuras como Gayo, Papiniano o Ulpiano alcanzaron gran prestigio. El momento culminante llegó en el siglo VI de nuestra era, cuando el emperador Justiniano promovió una gran compilación conocida como Corpus Iuris Civilis, que recogía leyes, opiniones de juristas y manuales de enseñanza. Esta obra monumental influyó decisivamente en el derecho medieval y moderno, especialmente a partir de su redescubrimiento en el siglo XI en las universidades italianas. Conceptos y términos romanos como contrato, obligación, derecho, ley, justicia o culpa siguen vivos en el lenguaje jurídico cotidiano y forman parte de la cultura compartida de muchas sociedades contemporáneas.', '[{"pregunta":"¿Qué fue la Ley de las Doce Tablas?","opciones":["Un mito","La primera codificación escrita","Un templo","Un ejército"],"correcta":1},{"pregunta":"¿Quién ordenó el Corpus Iuris Civilis?","opciones":["Augusto","Trajano","Justiniano","Constantino"],"correcta":2},{"pregunta":"¿Qué jurista NO es romano?","opciones":["Gayo","Papiniano","Ulpiano","Sócrates"],"correcta":3},{"pregunta":"¿Dónde se redescubrió el derecho romano?","opciones":["China","Universidades italianas","Egipto","África occidental"],"correcta":1}]'::jsonb),

('latin', 'bachillerato', '{1}', 'Las calzadas romanas y el comercio', 'Las calzadas romanas son uno de los elementos más visibles y admirables del legado de Roma. Los romanos construyeron una red impresionante de caminos que conectaba las principales ciudades del Imperio, desde Britania hasta el Oriente Próximo y desde el Rin hasta el norte de África. Se calcula que, en su máxima extensión, la red superaba los ochenta mil kilómetros. Las calzadas se construían con técnicas muy avanzadas: se excavaba un lecho firme, se añadían varias capas de gravilla y piedra, y se remataban con grandes losas bien encajadas. Muchas de ellas podían soportar durante siglos el tránsito de carros, legiones y viajeros. Las calzadas facilitaban enormemente el desplazamiento del ejército, pero también el comercio, el envío de cartas mediante el cursus publicus y el contacto entre culturas diferentes. A lo largo de las calzadas existían mansiones y mutationes, lugares donde los viajeros podían descansar y cambiar de caballos. Puentes, túneles y hitos kilométricos completaban el sistema. Las calzadas contribuyeron a unificar el inmenso Imperio y a integrar económicamente regiones muy distantes, permitiendo el intercambio de productos como el trigo, el vino, el aceite, los metales, los tejidos y los esclavos. Muchos caminos actuales en Europa siguen trazados romanos originales, prueba palpable de la calidad y la importancia de una infraestructura concebida hace más de dos mil años.', '[{"pregunta":"¿Cuántos kilómetros alcanzaba la red?","opciones":["8 000","30 000","50 000","Más de 80 000"],"correcta":3},{"pregunta":"¿Qué era el cursus publicus?","opciones":["Un templo","Un servicio de mensajería oficial","Un tribunal","Un mercado"],"correcta":1},{"pregunta":"¿Qué papel tenían las mansiones?","opciones":["Fortalezas","Lugares de descanso y relevo","Templos","Bibliotecas"],"correcta":1},{"pregunta":"¿Qué beneficios aportaron las calzadas?","opciones":["Solo militares","Militares, comerciales y culturales","Solo religiosos","Solo deportivos"],"correcta":1}]'::jsonb),

('latin', 'bachillerato', '{1}', 'Séneca y el estoicismo romano', 'Lucio Anneo Séneca, nacido en Córdoba hacia el año 4 antes de nuestra era, es uno de los filósofos más importantes del estoicismo romano. Fue orador, dramaturgo, hombre de Estado y autor de numerosas obras en prosa que han llegado hasta nosotros. Su vida estuvo estrechamente vinculada a los emperadores de la dinastía Julio-Claudia. Fue preceptor del joven Nerón y, durante los primeros años de su gobierno, ejerció una considerable influencia política. Con el paso del tiempo, sin embargo, se distanció del emperador hasta que, acusado de conspirar contra él, recibió en el año 65 de nuestra era la orden de suicidarse, que ejecutó con estoica serenidad. En sus Cartas a Lucilio, Séneca expone con estilo claro y elegante una filosofía práctica orientada a enseñar a vivir con virtud, sobrellevar las adversidades y aceptar la propia mortalidad. Insistía en la importancia del examen de conciencia diario, la moderación, la autosuficiencia y el control de las pasiones. Su pensamiento se presentaba como una guía útil para cualquier persona, no solo para filósofos profesionales. Séneca también escribió tragedias, que influyeron en el teatro europeo posterior, y tratados sobre temas como la ira, la clemencia o la brevedad de la vida. Sus obras se convirtieron en lectura obligada en el Renacimiento y siguen siendo relevantes para quienes buscan reflexionar sobre cómo vivir en tiempos de incertidumbre.', '[{"pregunta":"¿Dónde nació Séneca?","opciones":["Roma","Córdoba","Nápoles","Atenas"],"correcta":1},{"pregunta":"¿De qué emperador fue preceptor?","opciones":["Augusto","Tiberio","Nerón","Claudio"],"correcta":2},{"pregunta":"¿A qué escuela filosófica pertenece?","opciones":["Epicureísmo","Estoicismo","Platonismo","Cinismo"],"correcta":1},{"pregunta":"¿Cómo murió Séneca?","opciones":["En batalla","Suicidio forzado","De viejo","En naufragio"],"correcta":1}]'::jsonb),

('latin', 'bachillerato', '{1}', 'Las inscripciones latinas y la epigrafía', 'Las inscripciones latinas, estudiadas por la disciplina llamada epigrafía, son una fuente fundamental para conocer el mundo romano más allá de lo que cuentan los textos literarios. Los romanos grababan inscripciones sobre piedra, metal y otros soportes con motivos muy diversos: dedicatorias a dioses, epitafios funerarios, honores a magistrados y benefactores, edictos imperiales, listas de soldados, inventarios o simples grafitos en las paredes. Gracias a estas inscripciones conocemos nombres, cargos, oficios, relaciones familiares y creencias de personas que, de otro modo, habrían quedado en el anonimato. Los epitafios son especialmente valiosos, pues recogen información sobre la edad al morir, la profesión, los sentimientos de los seres queridos y las ideas romanas sobre la muerte. Los grafitos conservados en Pompeya aportan, además, un retrato vivísimo de la vida cotidiana: mensajes de amor, anuncios comerciales, declaraciones políticas, insultos o simples dibujos. La epigrafía ayuda también a fechar edificios, seguir carreras militares y políticas, reconstruir estructuras administrativas y comprender el uso del latín en las distintas provincias. Los filólogos y arqueólogos actuales colaboran para preservar, interpretar y editar las inscripciones, que aparecen por miles en todo el antiguo territorio del Imperio. Su estudio exige conocer bien el latín y las convenciones epigráficas, pero ofrece a cambio una ventana única para acercarse a la vida real de quienes habitaron Roma y sus provincias.', '[{"pregunta":"¿Qué disciplina estudia las inscripciones?","opciones":["Paleografía","Epigrafía","Numismática","Filatelia"],"correcta":1},{"pregunta":"¿En qué se grababan las inscripciones?","opciones":["Solo papel","Piedra y metal, entre otros","Hielo","Tela"],"correcta":1},{"pregunta":"¿Qué son los epitafios?","opciones":["Edictos","Inscripciones funerarias","Cartas privadas","Discursos"],"correcta":1},{"pregunta":"¿Qué ciudad destaca por sus grafitos?","opciones":["Roma","Pompeya","Atenas","Mérida"],"correcta":1}]'::jsonb);

