INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('lengua', 'bachillerato', '{1}', 'La literatura medieval: el mester de juglaría', 'La literatura medieval española tiene sus primeras grandes manifestaciones en la poesía épica, que se difundía oralmente gracias a los juglares, poetas errantes que recitaban cantares en plazas y castillos acompañándose de instrumentos musicales. Este tipo de poesía, conocido como mester de juglaría, se caracterizaba por su estilo directo, realista y adaptado al gusto del público. Su obra cumbre es el Cantar de mio Cid, compuesto hacia el año 1200, que narra con verosimilitud las aventuras del caballero castellano Rodrigo Díaz de Vivar tras ser desterrado por el rey Alfonso VI. El poema se divide en tres cantares: el del destierro, el de las bodas de las hijas del Cid y el de la afrenta de Corpes. A diferencia de otras epopeyas europeas, el Cantar de mio Cid destaca por su sobriedad, su fidelidad histórica aproximada y la humanidad de su protagonista, que aparece como un caballero leal, padre de familia y defensor de la justicia. Junto al mester de juglaría se desarrolló el mester de clerecía, poesía culta escrita por clérigos con finalidad moral y didáctica. Autores como Gonzalo de Berceo, con sus Milagros de Nuestra Señora, o el Arcipreste de Hita, con el Libro de buen amor, aportaron al panorama medieval una literatura que combinaba influencia religiosa, humor y observación de la sociedad de la época.', '[{"pregunta":"¿Qué caracteriza al mester de juglaría?","opciones":["Estilo culto y escrito","Difusión oral por juglares","Carácter religioso","Rima consonante perfecta"],"correcta":1},{"pregunta":"¿Cuántos cantares tiene el Cantar de mio Cid?","opciones":["Dos","Tres","Cuatro","Cinco"],"correcta":1},{"pregunta":"¿Quién escribió los Milagros de Nuestra Señora?","opciones":["Berceo","Arcipreste de Hita","Juan Ruiz","Manrique"],"correcta":0},{"pregunta":"¿Qué virtud destaca en el Cid literario?","opciones":["Soberbia","Lealtad","Codicia","Avaricia"],"correcta":1}]'::jsonb),

('lengua', 'bachillerato', '{1}', 'Jorge Manrique y las Coplas a la muerte de su padre', 'Jorge Manrique, poeta del siglo XV, es autor de una de las obras más célebres de la literatura española: las Coplas a la muerte de su padre, escritas tras el fallecimiento de don Rodrigo Manrique, maestre de la Orden de Santiago. Compuesta hacia 1476, la obra está formada por cuarenta coplas de pie quebrado, estrofas en las que alternan versos octosílabos con otros más cortos de cuatro sílabas, creando un ritmo característico. El poema reflexiona sobre temas universales como la brevedad de la vida, la fugacidad de las glorias humanas y la inevitabilidad de la muerte. Manrique retoma la tradición medieval del ubi sunt, pregunta retórica sobre dónde están los personajes famosos del pasado, para mostrar que la fama y los bienes terrenales pasan rápidamente. Frente a esa visión, el autor propone tres tipos de vida: la vida terrena, efímera y llena de peligros; la vida de la fama, que sobrevive en el recuerdo de los demás; y la vida eterna, alcanzable mediante la virtud y la fe. El padre del poeta aparece como modelo ejemplar de caballero cristiano, cuya aceptación serena de la muerte confirma su virtud. La belleza del poema reside tanto en sus imágenes, como la del río que simboliza la vida humana que desemboca en el mar de la muerte, como en la profundidad filosófica y religiosa de su meditación.', '[{"pregunta":"¿Cuántas coplas tiene el poema?","opciones":["Veinte","Treinta","Cuarenta","Cincuenta"],"correcta":2},{"pregunta":"¿Qué tipo de estrofa usa Manrique?","opciones":["Soneto","Copla de pie quebrado","Décima","Terceto"],"correcta":1},{"pregunta":"¿Qué tres tipos de vida propone?","opciones":["Niñez, juventud, vejez","Terrena, fama, eterna","Rico, pobre, medio","Guerrero, sacerdote, rey"],"correcta":1},{"pregunta":"¿Con qué se compara la vida humana?","opciones":["Con una montaña","Con un río","Con un árbol","Con una torre"],"correcta":1}]'::jsonb),

('lengua', 'bachillerato', '{1}', 'La Celestina de Fernando de Rojas', 'La Celestina, publicada a finales del siglo XV por Fernando de Rojas, es una de las obras más importantes de la literatura española y marca un momento de transición entre la Edad Media y el Renacimiento. Su título completo es Tragicomedia de Calisto y Melibea, y mezcla diálogos teatrales con una compleja trama narrativa. La obra cuenta la historia del amor apasionado entre dos jóvenes nobles, Calisto y Melibea, que se encuentran gracias a la intermediación de Celestina, una vieja alcahueta astuta y manipuladora. Con la ayuda de Celestina, los amantes viven un intenso romance que terminará de forma trágica: Celestina muere asesinada por la ambición, los criados son ejecutados, Calisto fallece al caer de una escalera y Melibea, desolada, se suicida. A través de estos acontecimientos, Rojas presenta una visión crítica y amarga de la sociedad de su tiempo. Los personajes son complejos y llenos de matices psicológicos, algo poco habitual en la literatura anterior. El lenguaje mezcla niveles cultos y populares, con refranes, expresiones coloquiales y un rico vocabulario. Se discute si la obra debe considerarse novela dialogada o drama para leer, pero en cualquier caso su influencia en la literatura posterior es enorme. Su mirada sobre el amor, el deseo, la avaricia y la muerte anticipa muchos de los temas del humanismo renacentista y la observa con pesimismo y lucidez notables.', '[{"pregunta":"¿Quién escribió La Celestina?","opciones":["Manrique","Fernando de Rojas","Cervantes","Quevedo"],"correcta":1},{"pregunta":"¿Qué papel tiene Celestina?","opciones":["Heroína","Alcahueta intermediaria","Reina","Monja"],"correcta":1},{"pregunta":"¿Cómo mueren los amantes?","opciones":["Calisto cae y Melibea se suicida","En batalla","De viejos","En naufragio"],"correcta":0},{"pregunta":"¿Qué movimiento anuncia la obra?","opciones":["Romanticismo","Humanismo renacentista","Ilustración","Barroco"],"correcta":1}]'::jsonb),

('lengua', 'bachillerato', '{1}', 'Garcilaso de la Vega y el Renacimiento', 'Garcilaso de la Vega, poeta y soldado del siglo XVI, es una de las figuras más importantes del Renacimiento español. Nacido en Toledo hacia 1501 en una familia noble, combinó su carrera literaria con una intensa actividad militar al servicio del emperador Carlos V. Murió joven, en 1536, a causa de las heridas recibidas en un asalto militar en el sur de Francia. Pese a la brevedad de su vida y a que no publicó él mismo sus poemas, que aparecieron póstumamente, su obra tuvo un impacto decisivo en la poesía española. Junto con Juan Boscán, introdujo en castellano formas y temas procedentes de la lírica italiana renacentista, como el soneto, la lira, el tercero encadenado y la octava real, y un modelo poético basado en la claridad, la elegancia y la naturalidad. Los temas de Garcilaso giran en torno al amor, la naturaleza, la melancolía y la fugacidad de la vida, siguiendo el ideal renacentista del carpe diem. Sus poemas amorosos, inspirados en su pasión por Isabel Freyre, rezuman una mezcla de ternura, tristeza y aceptación del destino. Su influencia llega hasta los grandes poetas del Siglo de Oro, como Fray Luis de León o San Juan de la Cruz, y más allá, hasta los poetas del siglo XX que siguieron admirando la musicalidad y la hondura de sus versos. Garcilaso representa como nadie el ideal renacentista del perfecto cortesano, hombre de armas y de letras.', '[{"pregunta":"¿Con quién introdujo las formas italianas?","opciones":["Manrique","Boscán","Manrique","Quevedo"],"correcta":1},{"pregunta":"¿Qué estrofa NO es italiana?","opciones":["Soneto","Lira","Octava real","Copla de pie quebrado"],"correcta":3},{"pregunta":"¿A qué emperador sirvió?","opciones":["Felipe II","Carlos V","Felipe IV","Carlos III"],"correcta":1},{"pregunta":"¿Qué ideal refleja su poesía?","opciones":["Solo guerra","Perfecto cortesano, armas y letras","Vida monástica","Vida campesina"],"correcta":1}]'::jsonb),

('lengua', 'bachillerato', '{1}', 'La novela picaresca y el Lazarillo', 'El Lazarillo de Tormes, publicado anónimamente en 1554, es la obra que inaugura el género de la novela picaresca, una de las aportaciones más originales de la literatura española. La novela narra en primera persona las aventuras de Lázaro, un muchacho de humilde origen que, para sobrevivir, sirve a diversos amos, cada uno de los cuales representa un tipo social y moral concreto: un ciego astuto y cruel, un clérigo avaro, un escudero arruinado pero orgulloso, un buldero engañoso, entre otros. Con un estilo claro, irónico y realista, el autor anónimo dibuja una sociedad española hipócrita y desigual, donde la pobreza obliga a los más débiles a buscar en el ingenio y en el engaño un medio para no morir de hambre. Lázaro, al final, consigue una estabilidad muy discutible que se basa en el silencio frente a una situación moralmente dudosa. La originalidad del Lazarillo reside en varios aspectos: el punto de vista autobiográfico, la evolución psicológica del protagonista, el lenguaje vivo y el realismo social. La obra tuvo un enorme éxito y sirvió de modelo a otras novelas picarescas posteriores, como el Guzmán de Alfarache de Mateo Alemán o el Buscón de Quevedo. La picaresca se convirtió así en una especie de reverso crítico del idealismo de las novelas de caballerías y pastoriles, ofreciendo una visión descarnada de la realidad.', '[{"pregunta":"¿Cuándo se publicó el Lazarillo?","opciones":["1492","1554","1605","1681"],"correcta":1},{"pregunta":"¿En qué persona se narra?","opciones":["Tercera","Primera","Segunda","Plural"],"correcta":1},{"pregunta":"¿Qué género inaugura?","opciones":["Pastoril","Picaresca","Caballerías","Cortesana"],"correcta":1},{"pregunta":"¿Qué autor NO escribió picaresca?","opciones":["Mateo Alemán","Quevedo","Cervantes (estrictamente)","Anónimo del Lazarillo"],"correcta":2}]'::jsonb),

('lengua', 'bachillerato', '{1}', 'Miguel de Cervantes y Don Quijote', 'Miguel de Cervantes Saavedra (1547-1616) es el autor de Don Quijote de la Mancha, considerada la primera novela moderna y una de las obras maestras de la literatura universal. La primera parte se publicó en 1605, y la segunda en 1615, pocos meses antes de la muerte del autor. La novela narra las aventuras de un hidalgo manchego que, enloquecido por la lectura de libros de caballerías, decide convertirse en caballero andante con el nombre de don Quijote y salir al mundo a deshacer entuertos y ayudar a los desvalidos. Le acompaña su fiel escudero Sancho Panza, un campesino práctico y socarrón que ofrece un contraste permanente con el idealismo del protagonista. A lo largo de sus viajes, los dos personajes protagonizan numerosas aventuras que combinan parodia, humor, crítica social y reflexión filosófica. Con una estructura abierta, personajes llenos de matices, juegos narrativos muy complejos y un lenguaje de enorme riqueza, Cervantes revolucionó el género novelesco. Más que burlarse del ideal caballeresco, la obra reflexiona sobre la tensión entre ideales y realidad, entre locura y cordura, entre libertad personal y normas sociales. Cervantes también escribió novelas ejemplares, poesía y teatro, pero es el Quijote lo que le asegura un lugar eterno en la literatura. Traducida a numerosas lenguas, la novela ha influido en autores de todo el mundo y sigue siendo un clásico insuperable.', '[{"pregunta":"¿Cuándo se publicó la primera parte del Quijote?","opciones":["1554","1605","1615","1681"],"correcta":1},{"pregunta":"¿Cómo se llama el escudero?","opciones":["Sansón","Sancho Panza","Ginés","Cardenio"],"correcta":1},{"pregunta":"¿Qué género parodia el Quijote?","opciones":["Pastoril","Picaresca","Novelas de caballerías","Sonetos"],"correcta":2},{"pregunta":"¿Qué aporta Cervantes a la novela?","opciones":["Género teatral","La primera novela moderna","La epopeya antigua","La tragedia griega"],"correcta":1}]'::jsonb),

('lengua', 'bachillerato', '{1}', 'Lope de Vega y el teatro del Siglo de Oro', 'Lope de Vega (1562-1635), uno de los autores más prolíficos de la literatura mundial, fue el creador del modelo de la comedia nueva, que transformó el teatro español del siglo XVII. En su Arte nuevo de hacer comedias, publicado en 1609, Lope explica las reglas de su fórmula dramática, que rompía con los preceptos clásicos y se adaptaba al gusto del público. Sus principales rasgos son: la mezcla de lo trágico y lo cómico, la división en tres actos (exposición, nudo y desenlace), el uso de diferentes tipos de versos según las situaciones, la ruptura de las unidades clásicas de tiempo y lugar, la aparición del personaje del gracioso y una atención especial a temas como el honor, el amor y la lealtad al rey. Lope escribió, según sus propios cálculos, más de mil quinientas comedias, de las cuales se conservan varios cientos. Entre sus obras más famosas se encuentran Fuenteovejuna, basada en una sublevación popular contra un comendador abusivo; Peribáñez y el comendador de Ocaña; El caballero de Olmedo y El perro del hortelano. Sus comedias mezclan personajes de distintas clases sociales, presentan una visión viva de la sociedad y expresan valores como la dignidad personal frente a los abusos. Junto a Lope, otros grandes dramaturgos como Tirso de Molina y Calderón de la Barca desarrollaron y enriquecieron esta fórmula, que convirtió el teatro español en uno de los más destacados de Europa.', '[{"pregunta":"¿Quién escribió el Arte nuevo de hacer comedias?","opciones":["Calderón","Lope de Vega","Tirso","Cervantes"],"correcta":1},{"pregunta":"¿En cuántos actos se divide la comedia nueva?","opciones":["Dos","Tres","Cuatro","Cinco"],"correcta":1},{"pregunta":"¿Qué obra trata un levantamiento popular?","opciones":["Fuenteovejuna","La vida es sueño","El burlador de Sevilla","El alcalde de Zalamea"],"correcta":0},{"pregunta":"¿Qué personaje típico introduce?","opciones":["El gracioso","El monje","El capitán","El sabio"],"correcta":0}]'::jsonb),

('lengua', 'bachillerato', '{1}', 'Quevedo y Góngora: culteranismo y conceptismo', 'Luis de Góngora (1561-1627) y Francisco de Quevedo (1580-1645) representan las dos grandes tendencias estéticas del Barroco español: el culteranismo y el conceptismo. El culteranismo, del que Góngora es máximo exponente, busca una belleza extrema del lenguaje a través del uso de cultismos, latinismos sintácticos, metáforas audaces, referencias mitológicas y una gran complejidad formal. Sus obras más famosas son las Soledades y la Fábula de Polifemo y Galatea, auténticos monumentos poéticos cuya lectura exige un esfuerzo considerable, pero que ofrecen imágenes de extraordinaria belleza. El conceptismo, cuyo principal representante es Quevedo, se centra en el juego conceptual: busca sorprender al lector mediante asociaciones ingeniosas, antítesis, dobles sentidos, paradojas y un lenguaje denso pero directo. Quevedo es autor de sonetos amorosos y metafísicos, poesía satírica, prosa moral como los Sueños y novelas como El Buscón. La rivalidad entre Góngora y Quevedo fue legendaria y se manifestó en múltiples poemas satíricos en los que se burlaban uno del otro con ingenio despiadado. Aunque tradicionalmente se presentan como corrientes opuestas, culteranismo y conceptismo comparten el gusto barroco por la dificultad, la originalidad y el virtuosismo del lenguaje. Ambos reflejan, cada uno a su manera, la visión pesimista y a la vez deslumbrante del Barroco, marcado por la crisis política, económica y religiosa del siglo XVII español.', '[{"pregunta":"¿Qué autor representa el culteranismo?","opciones":["Quevedo","Góngora","Calderón","Lope"],"correcta":1},{"pregunta":"¿Qué obra escribió Góngora?","opciones":["El Buscón","Los Sueños","Soledades","Fuenteovejuna"],"correcta":2},{"pregunta":"¿Qué caracteriza al conceptismo?","opciones":["Metáforas pastorales","Juego conceptual e ingenio","Religiosidad medieval","Épica heroica"],"correcta":1},{"pregunta":"¿Qué siglo fue el gran momento del Barroco español?","opciones":["XV","XVI","XVII","XVIII"],"correcta":2}]'::jsonb),

('lengua', 'bachillerato', '{1}', 'La morfología: clases de palabras', 'La morfología es la rama de la lingüística que estudia la estructura interna de las palabras y sus categorías gramaticales. Cada palabra puede analizarse en partes más pequeñas llamadas morfemas, que son las unidades mínimas con significado. Se distinguen los morfemas léxicos, que aportan el significado básico, y los morfemas gramaticales, que indican género, número, tiempo, modo, persona o función sintáctica. Las palabras se agrupan en clases o categorías según su forma y función: sustantivos, adjetivos, verbos, adverbios, pronombres, determinantes, preposiciones, conjunciones e interjecciones. Los sustantivos nombran personas, animales, objetos o ideas; los adjetivos expresan cualidades; los verbos indican acciones o estados; los adverbios modifican al verbo, al adjetivo o a otro adverbio; los pronombres sustituyen o hacen referencia a un sustantivo; los determinantes acompañan al sustantivo y lo concretan; las preposiciones y conjunciones establecen relaciones entre palabras o frases; y las interjecciones expresan emociones o llamadas. Además, las palabras pueden formarse mediante diferentes procedimientos: derivación, por el uso de prefijos o sufijos; composición, uniendo dos o más lexemas; o parasíntesis, que combina derivación y composición. Conocer bien la morfología es fundamental para comprender el funcionamiento de la lengua, mejorar la expresión escrita y hablar con precisión, ya que permite identificar errores y elegir las formas más adecuadas en cada contexto comunicativo.', '[{"pregunta":"¿Qué es un morfema?","opciones":["Un sonido","Unidad mínima con significado","Una frase","Una letra"],"correcta":1},{"pregunta":"¿Qué clase de palabra expresa cualidades?","opciones":["Verbo","Adjetivo","Adverbio","Preposición"],"correcta":1},{"pregunta":"¿Qué proceso une dos lexemas?","opciones":["Derivación","Composición","Flexión","Abreviación"],"correcta":1},{"pregunta":"¿Qué modifica un adverbio?","opciones":["Solo al sustantivo","Al verbo, adjetivo u otro adverbio","Solo a preposiciones","A sí mismo"],"correcta":1}]'::jsonb),

('lengua', 'bachillerato', '{1}', 'La sintaxis de la oración compuesta', 'La oración compuesta es aquella que está formada por dos o más proposiciones que se relacionan entre sí para formar una unidad comunicativa. Según el tipo de relación que establezcan, las oraciones compuestas pueden clasificarse en coordinadas, yuxtapuestas y subordinadas. Las coordinadas son las que unen dos o más proposiciones del mismo nivel sintáctico mediante nexos, como las copulativas (y, e, ni), las adversativas (pero, sin embargo), las disyuntivas (o, u), las distributivas (bien... bien) y las explicativas (es decir, o sea). Las yuxtapuestas se unen sin nexos, separadas por signos de puntuación como comas o punto y coma. Las subordinadas, en cambio, contienen una proposición principal y al menos una secundaria que depende de la primera y cumple una función gramatical. Dentro de las subordinadas se distinguen las sustantivas, que funcionan como un sustantivo; las adjetivas o de relativo, que modifican a un sustantivo como un adjetivo; y las adverbiales, que funcionan como un adverbio y pueden expresar tiempo, lugar, modo, causa, finalidad, condición, concesión, consecuencia o comparación. El análisis sintáctico de una oración compuesta exige identificar las distintas proposiciones, sus nexos y las relaciones que establecen entre ellas. Dominar la sintaxis es esencial no solo para el estudio de la lengua, sino también para la producción de textos claros, correctos y coherentes, especialmente en los registros escritos.', '[{"pregunta":"¿Qué son las oraciones yuxtapuestas?","opciones":["Unidas por nexos","Unidas sin nexos y separadas por signos","Subordinadas","Solo interrogativas"],"correcta":1},{"pregunta":"¿Qué tipo de nexo es pero?","opciones":["Copulativo","Adversativo","Disyuntivo","Distributivo"],"correcta":1},{"pregunta":"¿Qué función tiene una subordinada adjetiva?","opciones":["Sustantivo","Adjetivo que modifica a un sustantivo","Verbo","Adverbio"],"correcta":1},{"pregunta":"¿Qué expresan las subordinadas adverbiales?","opciones":["Solo causa","Tiempo, lugar, modo, causa, etc.","Solo lugar","Solo negación"],"correcta":1}]'::jsonb),

('lengua', 'bachillerato', '{1}', 'La variación lingüística del español', 'El español es una lengua hablada por más de quinientos millones de personas en todo el mundo, lo que la convierte en la segunda lengua más hablada como lengua materna, después del chino mandarín. A pesar de su unidad esencial, el español presenta una importante variación lingüística, que puede clasificarse en diatópica (geográfica), diastrática (social) y diafásica (de registro o estilo). La variación geográfica se refiere a las diferencias entre los distintos países y regiones donde se habla español, que incluyen España, buena parte de Hispanoamérica y otros territorios. Cada zona tiene peculiaridades de pronunciación, vocabulario y gramática; por ejemplo, el voseo en Argentina y otros países, el seseo en gran parte de América y sur de España, o el uso de ciertas palabras propias de cada región. La variación social se relaciona con el nivel cultural, la profesión o la edad de los hablantes y da lugar a distintas formas de expresarse, desde el habla popular hasta el lenguaje culto. La variación de registro depende de la situación comunicativa: una conversación informal no usa los mismos recursos que un discurso formal o un texto académico. La Real Academia Española, junto con las demás academias de la lengua en América, trabaja para garantizar la unidad básica del idioma al tiempo que respeta su rica diversidad, favoreciendo una comunicación eficaz entre hablantes de diferentes regiones del mundo hispánico.', '[{"pregunta":"¿Cuántos hablantes tiene el español aproximadamente?","opciones":["100 millones","200 millones","Más de 500 millones","Mil millones"],"correcta":2},{"pregunta":"¿Qué tipo de variación es el voseo?","opciones":["Social","Diatópica (geográfica)","De registro","Histórica"],"correcta":1},{"pregunta":"¿Qué es la variación diafásica?","opciones":["Por región","Por situación comunicativa","Por edad","Por clase social"],"correcta":1},{"pregunta":"¿Qué institución regula el español?","opciones":["ONU","RAE junto a academias americanas","Instituto Cervantes solo","UNESCO"],"correcta":1}]'::jsonb),

('lengua', 'bachillerato', '{1}', 'Los géneros literarios', 'Los géneros literarios son categorías o grupos en los que se clasifican las obras de la literatura según sus características formales y temáticas. La división tradicional, heredada del mundo clásico, distingue tres grandes géneros: la lírica, la épica y la dramática. La lírica reúne las obras que expresan sentimientos, emociones o reflexiones del autor en verso, con una gran presencia del yo poético; abarca subgéneros como la oda, la elegía, el soneto o la égloga. La épica, que en la literatura moderna se ha transformado sobre todo en la narrativa, incluye obras en las que un narrador cuenta hechos reales o ficticios que les suceden a unos personajes; sus principales subgéneros son la epopeya, el cantar de gesta, el romance, la novela y el cuento. La dramática comprende las obras escritas para ser representadas en un escenario, en las que los personajes actúan y hablan directamente; sus subgéneros clásicos son la tragedia, la comedia y el drama. A estos tres grandes géneros se añade a veces un cuarto, el didáctico o ensayístico, formado por obras que pretenden enseñar o reflexionar sobre un tema. Los géneros no son categorías rígidas: en la práctica literaria existen muchas obras que mezclan rasgos de distintos géneros, y a lo largo de la historia han aparecido nuevas formas híbridas, como la novela lírica, el microrrelato, el teatro de calle o la poesía visual, que enriquecen el panorama literario.', '[{"pregunta":"¿Cuáles son los tres géneros tradicionales?","opciones":["Lírica, épica, dramática","Narrativa, ensayo, crítica","Poema, cuento, ensayo","Canción, prosa, teatro"],"correcta":0},{"pregunta":"¿Qué expresa la lírica?","opciones":["Solo diálogos","Sentimientos y reflexiones","Solo relatos épicos","Instrucciones"],"correcta":1},{"pregunta":"¿Qué género incluye la novela?","opciones":["Lírica","Épica/Narrativa","Dramática","Didáctica"],"correcta":1},{"pregunta":"¿Qué género se añade a veces como cuarto?","opciones":["Didáctico o ensayístico","Gastronómico","Científico estricto","Técnico-artístico"],"correcta":0}]'::jsonb),

('lengua', 'bachillerato', '{1}', 'La comunicación y sus elementos', 'La comunicación es el proceso por el que se transmite información entre un emisor y un receptor mediante un código común, y es una de las actividades más fundamentales de la vida humana. En su análisis más clásico, formulado por el lingüista Roman Jakobson, intervienen seis elementos principales: el emisor, que produce el mensaje; el receptor, que lo interpreta; el mensaje, que es el contenido que se transmite; el código, sistema de signos compartido (como una lengua); el canal, medio físico por el que circula la información (voz, papel, pantalla); y el contexto o referente, realidad a la que se refiere el mensaje. A cada uno de estos elementos, Jakobson asoció una función concreta del lenguaje: la función emotiva, centrada en el emisor; la conativa o apelativa, orientada al receptor; la poética, que pone el acento en la forma del mensaje; la metalingüística, que reflexiona sobre el propio código; la fática, que mantiene o inicia el contacto; y la referencial, que describe la realidad. Aunque en cada acto comunicativo suelen coexistir varias funciones, una predomina sobre las demás. Comprender los elementos y las funciones de la comunicación permite analizar con más detalle los textos, identificar sus intenciones, mejorar las propias producciones y ser conscientes de la enorme variedad de situaciones comunicativas en las que participamos cada día, desde una simple conversación hasta un discurso institucional o un mensaje publicitario.', '[{"pregunta":"¿Quién formuló las funciones del lenguaje?","opciones":["Saussure","Jakobson","Chomsky","Hjelmslev"],"correcta":1},{"pregunta":"¿Cuántos elementos principales hay?","opciones":["Cuatro","Cinco","Seis","Siete"],"correcta":2},{"pregunta":"¿Qué función se centra en la forma del mensaje?","opciones":["Emotiva","Poética","Referencial","Fática"],"correcta":1},{"pregunta":"¿Qué función mantiene el contacto?","opciones":["Fática","Emotiva","Conativa","Metalingüística"],"correcta":0}]'::jsonb),

('lengua', 'bachillerato', '{1}', 'Los textos argumentativos', 'Un texto argumentativo es aquel cuyo propósito es defender una opinión, una idea o una tesis mediante razones, pruebas y ejemplos. Se encuentra en ámbitos muy variados, como el periodismo, la publicidad, la ciencia, la política o la vida cotidiana, y su dominio es esencial para participar activamente en la vida pública y democrática. La estructura típica de un texto argumentativo incluye tres partes: introducción, donde se presenta el tema y la tesis; desarrollo o argumentación, donde se exponen los argumentos que sustentan la tesis; y conclusión, en la que se resumen las ideas principales y se refuerza la opinión defendida. Existen varios tipos de argumentos: los basados en hechos y datos, los apoyados en la experiencia personal, los fundamentados en la autoridad (citas de expertos o fuentes reconocidas), los analógicos (comparaciones) y los emotivos, que buscan conmover al lector. Un buen texto argumentativo combina varios tipos de argumentos de forma coherente, anticipa las posibles objeciones y las rebate, y utiliza un lenguaje preciso, claro y adecuado al destinatario. Es importante distinguir entre argumentar y manipular: mientras el primero busca convencer mediante razones, la segunda intenta persuadir ocultando información o apelando a los sentimientos sin fundamento. Saber leer críticamente textos argumentativos y producirlos con rigor es una de las competencias más valiosas en el mundo contemporáneo, donde la información circula con gran rapidez y no siempre con veracidad.', '[{"pregunta":"¿Cuál es el propósito de un texto argumentativo?","opciones":["Describir un paisaje","Defender una tesis con razones","Contar un cuento","Dar instrucciones"],"correcta":1},{"pregunta":"¿Cuántas partes básicas tiene su estructura?","opciones":["Dos","Tres","Cuatro","Cinco"],"correcta":1},{"pregunta":"¿Qué tipo de argumento usa citas de expertos?","opciones":["Analógico","De autoridad","Emotivo","De experiencia"],"correcta":1},{"pregunta":"¿Qué diferencia argumentar de manipular?","opciones":["Ninguna","Argumentar usa razones; manipular engaña","Argumentar es más rápido","Manipular es más eficaz"],"correcta":1}]'::jsonb),

('lengua', 'bachillerato', '{1}', 'El ensayo como género literario', 'El ensayo es un género literario en prosa en el que un autor expone y analiza con libertad un tema de cualquier ámbito: filosófico, literario, histórico, científico, político o cotidiano. A diferencia del tratado académico, el ensayo no pretende agotar el tema ni seguir un método riguroso, sino aportar una reflexión personal que busca interesar y convencer al lector. Se caracteriza por la combinación de rigor intelectual y estilo literario, por la presencia del yo del autor, por su carácter subjetivo y abierto y, a menudo, por una cierta belleza formal. El género fue inaugurado a finales del siglo XVI por el francés Michel de Montaigne, quien publicó sus Essais en 1580. En español, importantes figuras del ensayo moderno incluyen a Miguel de Unamuno, José Ortega y Gasset y María Zambrano, cuyas obras influyeron decisivamente en el pensamiento en lengua española del siglo XX. El ensayo permite abordar cualquier tema con la máxima flexibilidad formal y es especialmente valioso para desarrollar el pensamiento crítico. En el periodismo contemporáneo, el ensayo breve se manifiesta en los artículos de opinión, las columnas y los editoriales, que contribuyen al debate público sobre cuestiones de actualidad. Leer y escribir ensayos fomenta la capacidad de argumentar, de conectar ideas de ámbitos distintos y de formular una visión personal sobre los problemas del mundo contemporáneo.', '[{"pregunta":"¿Quién inauguró el ensayo moderno?","opciones":["Unamuno","Montaigne","Ortega","Zambrano"],"correcta":1},{"pregunta":"¿Qué caracteriza al ensayo?","opciones":["Método científico estricto","Reflexión personal con estilo literario","Narración épica","Discurso cerrado"],"correcta":1},{"pregunta":"¿Cuándo publicó Montaigne sus Essais?","opciones":["1492","1580","1650","1700"],"correcta":1},{"pregunta":"¿Dónde se manifiesta el ensayo breve actualmente?","opciones":["En novelas","En artículos de opinión","En tragedias","En epopeyas"],"correcta":1}]'::jsonb),

('lengua', 'bachillerato', '{1}', 'La literatura del Romanticismo español', 'El Romanticismo es un movimiento literario, artístico e ideológico que se desarrolló en Europa durante la primera mitad del siglo XIX. En España cobró fuerza especialmente a partir de 1833, con el regreso de los exiliados liberales tras la muerte de Fernando VII, y se caracterizó por una exaltación del yo, la búsqueda de la libertad, la valoración de la naturaleza, la fascinación por el pasado histórico y por temas como el amor apasionado, la muerte y la rebeldía. Los románticos rompieron con las reglas neoclásicas y defendieron la originalidad y el genio individual. En poesía destacan figuras como José de Espronceda, autor de La canción del pirata y del poema narrativo El estudiante de Salamanca, y Gustavo Adolfo Bécquer, cuyas Rimas siguen siendo una referencia del intimismo lírico. En prosa, destacan las Leyendas del propio Bécquer, que recrean un mundo misterioso y legendario, y los artículos de Mariano José de Larra, que con espíritu crítico y satírico analizaban la sociedad española con lucidez y desencanto. En el teatro sobresale Don Juan Tenorio de José Zorrilla, que ofrece una versión propia del mito del seductor impenitente. El Romanticismo español tuvo un carácter más tardío que el europeo y a menudo se mezcla con rasgos costumbristas. Su influencia, sin embargo, fue decisiva en la evolución literaria y preparó el terreno para el realismo y el simbolismo de la segunda mitad del siglo XIX.', '[{"pregunta":"¿Qué tipo de poesía escribió Espronceda?","opciones":["Neoclásica","Romántica","Barroca","Renacentista"],"correcta":1},{"pregunta":"¿Quién escribió las Rimas?","opciones":["Espronceda","Bécquer","Larra","Zorrilla"],"correcta":1},{"pregunta":"¿Qué obra teatral destaca de Zorrilla?","opciones":["Don Álvaro","Don Juan Tenorio","La fuerza del sino","El trovador"],"correcta":1},{"pregunta":"¿Qué caracteriza al Romanticismo?","opciones":["Reglas rígidas","Exaltación del yo y libertad","Realismo social","Análisis científico"],"correcta":1}]'::jsonb),

('lengua', 'bachillerato', '{1}', 'La Generación del 98', 'La llamada Generación del 98 es un grupo de escritores españoles que alcanzó su madurez a finales del siglo XIX y comienzos del XX, marcado por la profunda crisis provocada por la pérdida de Cuba, Puerto Rico y Filipinas en 1898, últimas colonias del antiguo imperio español. Estos autores compartieron la preocupación por España, su historia, su paisaje, su alma colectiva y su futuro, y se caracterizaron por una actitud reflexiva, crítica y a menudo pesimista. Miguel de Unamuno, el más filosófico del grupo, escribió novelas como Niebla y San Manuel Bueno, mártir, y ensayos como Del sentimiento trágico de la vida, en los que aborda las grandes cuestiones existenciales. Pío Baroja, con su estilo directo y espontáneo, publicó numerosas novelas como El árbol de la ciencia. José Martínez Ruiz, conocido como Azorín, destacó por su prosa cuidada y su sensibilidad descriptiva en obras como La ruta de don Quijote. Antonio Machado aportó, sobre todo, su poesía, marcada por un profundo sentido del tiempo, del paisaje castellano y de la reflexión moral, en libros como Campos de Castilla. Valle-Inclán, aunque difícilmente clasificable, compartió algunas inquietudes del grupo y creó su propio estilo con el esperpento, ejemplo de renovación teatral. La Generación del 98 ofreció una visión innovadora y crítica de España que sigue influyendo en la cultura española contemporánea.', '[{"pregunta":"¿Qué suceso da nombre a la generación?","opciones":["La pérdida de las últimas colonias en 1898","La Revolución francesa","La Guerra Civil","La guerra mundial"],"correcta":0},{"pregunta":"¿Quién escribió Niebla?","opciones":["Baroja","Unamuno","Azorín","Machado"],"correcta":1},{"pregunta":"¿Cuál es la obra más famosa de Machado?","opciones":["Campos de Castilla","El árbol de la ciencia","Luces de bohemia","Niebla"],"correcta":0},{"pregunta":"¿Qué estilo creó Valle-Inclán?","opciones":["Esperpento","Noucentismo","Modernismo","Krausismo"],"correcta":0}]'::jsonb);

