INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('literatura-universal', 'bachillerato', '{1}', 'La epopeya de Gilgamesh', 'La epopeya de Gilgamesh, escrita en tablillas de arcilla en torno al segundo milenio antes de nuestra era, es considerada una de las obras literarias más antiguas que se conocen. Procede de la antigua Mesopotamia y cuenta las aventuras del rey Gilgamesh de Uruk, un personaje semihistórico que gobernó hacia el año 2700 a. C. Al comienzo del poema, Gilgamesh es un rey poderoso pero orgulloso y tiránico. Los dioses envían a Enkidu, un hombre salvaje criado en la estepa, para que se enfrente a él. Tras un combate memorable, los dos se hacen amigos inseparables y emprenden juntos grandes hazañas, como la derrota del monstruo Humbaba en el bosque de cedros. Sin embargo, la muerte de Enkidu por voluntad divina sume a Gilgamesh en un profundo dolor y lo lleva a emprender una búsqueda de la inmortalidad. Encuentra al sabio Utnapishtim, único superviviente humano de un diluvio universal, quien le revela que los dioses han reservado la vida eterna solo para unos pocos y le propone una prueba que Gilgamesh no logra superar. El héroe regresa a Uruk aceptando finalmente su condición mortal, consciente de que la verdadera inmortalidad reside en las obras duraderas y en el recuerdo. La epopeya combina mito, aventura y profunda reflexión sobre la amistad, el sentido de la vida y la inevitabilidad de la muerte.', '[{"pregunta":"¿De qué antigua región procede la epopeya?","opciones":["Egipto","Mesopotamia","Grecia","India"],"correcta":1},{"pregunta":"¿Quién es el amigo de Gilgamesh?","opciones":["Aquiles","Enkidu","Ulises","Hércules"],"correcta":1},{"pregunta":"¿Qué busca Gilgamesh tras la muerte de su amigo?","opciones":["Riquezas","Inmortalidad","Un reino nuevo","Una esposa"],"correcta":1},{"pregunta":"¿Dónde reside la verdadera inmortalidad según el poema?","opciones":["En los templos","En las obras duraderas y el recuerdo","En la magia","En las estrellas"],"correcta":1}]'::jsonb),

('literatura-universal', 'bachillerato', '{1}', 'Homero y la Ilíada', 'La Ilíada, atribuida al poeta griego Homero, es una de las obras fundamentales de la literatura occidental, compuesta probablemente hacia el siglo VIII antes de nuestra era. Narra unos cincuenta días del décimo y último año de la guerra de Troya, conflicto legendario en el que una coalición de ciudades griegas sitió la ciudad de Ilión, la Troya de la Edad del Bronce, para recuperar a Helena, raptada por el príncipe Paris. El tema central del poema es la cólera de Aquiles, el mejor guerrero griego, ofendido por el rey Agamenón, quien le arrebata una prisionera. Aquiles se retira del combate y su ausencia provoca graves pérdidas a los griegos. Solo cuando su amigo íntimo Patroclo es muerto por Héctor, hijo del rey troyano Príamo, Aquiles regresa al campo de batalla, sediento de venganza, y mata a Héctor en combate singular. El poema concluye con el episodio conmovedor en el que Príamo, en secreto y suplicando, logra recuperar el cuerpo de su hijo para darle sepultura. La Ilíada no solo cuenta una guerra: reflexiona sobre la gloria y la mortalidad, el honor y la amistad, el destino y la compasión. Sus héroes y sus versos han inspirado a escritores, filósofos y artistas durante casi tres milenios, y su influencia sigue presente en la cultura literaria moderna.', '[{"pregunta":"¿Cuál es el tema central de la Ilíada?","opciones":["El viaje de Ulises","La cólera de Aquiles","La fundación de Roma","La guerra con Persia"],"correcta":1},{"pregunta":"¿Quién mata a Patroclo?","opciones":["Aquiles","Agamenón","Héctor","París"],"correcta":2},{"pregunta":"¿Qué hace Príamo al final?","opciones":["Huye","Recupera el cuerpo de su hijo","Mata a Aquiles","Ataca de noche"],"correcta":1},{"pregunta":"¿En qué siglo se compuso aproximadamente?","opciones":["Siglo XII a. C.","Siglo VIII a. C.","Siglo V a. C.","Siglo I d. C."],"correcta":1}]'::jsonb),

('literatura-universal', 'bachillerato', '{1}', 'La tragedia griega: Sófocles', 'La tragedia griega es uno de los géneros literarios más importantes del mundo clásico. Nacida en la Atenas del siglo V antes de nuestra era en el contexto de las fiestas dedicadas al dios Dioniso, sus principales autores fueron Esquilo, Sófocles y Eurípides. Sófocles (496-406 a. C.), considerado por muchos el más perfecto de los tres, escribió unas ciento veinte obras, de las cuales solo siete se conservan completas. Sus piezas más famosas son Edipo rey, Antígona y Electra, que siguen siendo representadas y estudiadas hoy en día. Edipo rey cuenta la tragedia del rey de Tebas que, sin saberlo, ha cumplido la profecía según la cual mataría a su padre y se casaría con su madre; cuando descubre la verdad, se ciega a sí mismo y se exilia. Antígona plantea un conflicto entre las leyes divinas y las humanas: la joven Antígona decide enterrar a su hermano Polinices contra la prohibición del rey Creonte, aceptando las consecuencias fatales de su decisión. Las tragedias de Sófocles destacan por la profundidad psicológica de sus personajes, por la perfección de la construcción dramática y por la capacidad de plantear problemas éticos universales. Sus temas, como el destino, la culpa, el poder, la justicia y la dignidad humana, siguen interpelando al espectador contemporáneo y han influido en la filosofía, la literatura y el pensamiento moderno, desde Hegel hasta el psicoanálisis de Freud.', '[{"pregunta":"¿A qué dios se dedicaban las fiestas de la tragedia?","opciones":["Apolo","Dioniso","Zeus","Hades"],"correcta":1},{"pregunta":"¿Qué obra plantea leyes humanas contra divinas?","opciones":["Edipo rey","Antígona","Medea","Las troyanas"],"correcta":1},{"pregunta":"¿Qué descubre Edipo al final?","opciones":["Que es rico","Que mató a su padre y se casó con su madre","Que es dios","Que es un extranjero"],"correcta":1},{"pregunta":"¿Cuántos autores trágicos principales destacan?","opciones":["Uno","Dos","Tres","Cuatro"],"correcta":2}]'::jsonb),

('literatura-universal', 'bachillerato', '{1}', 'La Divina Comedia de Dante', 'La Divina Comedia, escrita por el poeta florentino Dante Alighieri entre 1307 y 1321, es una de las obras cumbres de la literatura universal y una síntesis magistral del pensamiento medieval cristiano. Está compuesta en italiano vulgar, lo cual supuso una decisión innovadora en una época en la que el latín dominaba la literatura culta. El poema narra un viaje imaginario de Dante por los tres reinos del más allá: el Infierno, el Purgatorio y el Paraíso. Cada uno corresponde a una cántica y está formado por treinta y tres cantos, más un canto inicial, lo que suma cien cantos en total. Los versos están organizados en tercetos encadenados, estrofa inventada para esta obra. En el Infierno, Dante es guiado por el poeta latino Virgilio a través de los nueve círculos en los que se castigan los distintos pecados. En el Purgatorio, el mismo guía le acompaña por las terrazas donde las almas se purifican. Finalmente, en el Paraíso, es Beatrice, la mujer amada por Dante en su juventud, quien lo conduce por las esferas celestiales hasta la contemplación de Dios. La obra es a la vez una aventura alegórica, una reflexión teológica, un comentario político y una celebración del amor y de la poesía. Su riqueza simbólica, su construcción rigurosa y su belleza han hecho de la Divina Comedia una de las obras más influyentes de toda la literatura europea.', '[{"pregunta":"¿Qué tres reinos recorre Dante?","opciones":["Tierra, cielo, mar","Infierno, Purgatorio, Paraíso","Norte, sur, este","Pasado, presente, futuro"],"correcta":1},{"pregunta":"¿Quién guía a Dante en el Infierno?","opciones":["Beatrice","Virgilio","Homero","San Francisco"],"correcta":1},{"pregunta":"¿Cuántos cantos tiene en total?","opciones":["Cincuenta","Ochenta","Cien","Ciento veinte"],"correcta":2},{"pregunta":"¿En qué lengua escribió Dante?","opciones":["Latín","Italiano vulgar","Francés","Griego"],"correcta":1}]'::jsonb),

('literatura-universal', 'bachillerato', '{1}', 'Shakespeare y el teatro isabelino', 'William Shakespeare (1564-1616) es considerado el más grande dramaturgo en lengua inglesa y uno de los mayores escritores de todos los tiempos. Su obra, escrita principalmente durante el reinado de Isabel I y los primeros años de Jacobo I, abarca unas treinta y ocho piezas teatrales, divididas en comedias, tragedias, dramas históricos y tragicomedias, además de ciento cincuenta y cuatro sonetos y algunos poemas narrativos. Entre sus tragedias más célebres figuran Hamlet, que explora la duda, la venganza y los límites de la acción humana; Macbeth, que estudia la ambición y la culpa; El rey Lear, sobre la locura y la caída del poder; y Otelo, centrada en los celos y la manipulación. Entre las comedias destacan El sueño de una noche de verano, Mucho ruido y pocas nueces o Como gustéis, llenas de enredos amorosos, humor y personajes memorables. Sus dramas históricos, como Ricardo III o Enrique V, ofrecen retratos vivos de la historia inglesa medieval. Shakespeare creó personajes psicológicamente complejos, enriqueció la lengua inglesa con expresiones e imágenes, y mostró una extraordinaria capacidad para reflejar la condición humana en todas sus facetas. Sus obras se representan continuamente en todo el mundo y han sido traducidas a numerosos idiomas. La influencia de Shakespeare es tal que muchos lo consideran el padre del teatro moderno occidental y una figura imprescindible para comprender el desarrollo posterior de la literatura europea.', '[{"pregunta":"¿Durante qué reinado comenzó a escribir Shakespeare?","opciones":["Enrique VIII","Isabel I","Carlos I","Victoria"],"correcta":1},{"pregunta":"¿Qué tragedia trata sobre los celos?","opciones":["Hamlet","Macbeth","Otelo","Lear"],"correcta":2},{"pregunta":"¿Cuántos sonetos escribió?","opciones":["Cien","Ciento cincuenta y cuatro","Doscientos","Cincuenta"],"correcta":1},{"pregunta":"¿Qué explora Macbeth?","opciones":["Los celos","La ambición y la culpa","La duda","La traición amorosa"],"correcta":1}]'::jsonb),

('literatura-universal', 'bachillerato', '{1}', 'Goethe y Fausto', 'Johann Wolfgang von Goethe (1749-1832) es la figura más importante de la literatura alemana y uno de los grandes autores europeos. Su vida longeva abarcó una época de enormes transformaciones históricas, desde la Ilustración hasta el inicio del Romanticismo, y su obra refleja esa riqueza de influencias. Goethe escribió poesía, novela, teatro y ensayos, y su producción abarca desde la famosa novela epistolar Las penas del joven Werther, que causó un impacto extraordinario en toda Europa, hasta el complejísimo poema dramático Fausto, obra a la que dedicó prácticamente toda su vida. Fausto cuenta la historia de un sabio desencantado que, harto del conocimiento librario, pacta con Mefistófeles, representante del diablo, la entrega de su alma a cambio de experimentar la totalidad de la vida. A lo largo de las dos partes del poema, Fausto vive amores, viajes, éxitos y fracasos, y se enfrenta a las grandes cuestiones morales y metafísicas de la existencia humana. La primera parte, publicada en 1808, es más conocida por el drama amoroso con Margarita, una joven destruida por la pasión. La segunda parte, publicada póstumamente, es una obra de extraordinaria complejidad simbólica en la que Fausto busca un sentido último a su vida. La obra se ha convertido en símbolo del espíritu humano que aspira al conocimiento y la libertad, aunque ello implique riesgos y caídas.', '[{"pregunta":"¿Qué autor escribió Fausto?","opciones":["Schiller","Goethe","Heine","Hölderlin"],"correcta":1},{"pregunta":"¿Con quién pacta Fausto?","opciones":["Dios","Mefistófeles","Un rey","Un ángel"],"correcta":1},{"pregunta":"¿Cuál es la novela juvenil famosa de Goethe?","opciones":["Los hermanos Karamázov","Las penas del joven Werther","Don Carlos","Frankenstein"],"correcta":1},{"pregunta":"¿Cuándo se publicó la primera parte de Fausto?","opciones":["1774","1808","1832","1850"],"correcta":1}]'::jsonb),

('literatura-universal', 'bachillerato', '{1}', 'El Romanticismo europeo', 'El Romanticismo es un movimiento artístico y literario que se extendió por Europa durante la primera mitad del siglo XIX y que supuso una profunda reacción contra el racionalismo de la Ilustración y las rígidas reglas del Neoclasicismo. Los románticos defendían la primacía del sentimiento, la imaginación, la libertad creativa y la originalidad del genio individual. Amaban la naturaleza, sobre todo en sus manifestaciones más grandiosas o solitarias; se interesaban por el pasado medieval, las leyendas, la historia y el folclore de los distintos pueblos; y abordaban temas como el amor apasionado, la muerte, la rebeldía o la melancolía. En Inglaterra, autores como William Wordsworth, Samuel Taylor Coleridge, Lord Byron, Percy Bysshe Shelley y John Keats renovaron la poesía con obras que combinaban sensibilidad personal y experiencia íntima con la naturaleza. En Alemania, los hermanos Schlegel, Novalis, Hölderlin y el propio Goethe contribuyeron al movimiento. En Francia, Victor Hugo, Alexandre Dumas o Alfred de Musset llevaron el Romanticismo al teatro, la novela y la poesía, y en Italia, Alessandro Manzoni publicó Los novios, una de las grandes novelas históricas del siglo. El Romanticismo tuvo también una dimensión política importante, pues se vinculó a los movimientos liberales y nacionalistas de la época. Aunque como corriente específica fue relativamente breve, su influencia ha marcado profundamente la sensibilidad moderna.', '[{"pregunta":"¿Contra qué reaccionó el Romanticismo?","opciones":["Contra el Renacimiento","Contra el Neoclasicismo y la Ilustración","Contra el Barroco","Contra la Edad Media"],"correcta":1},{"pregunta":"¿Qué defendían los románticos?","opciones":["Reglas rígidas","Sentimiento, imaginación, libertad","Geometría","Orden militar"],"correcta":1},{"pregunta":"¿Quién escribió Los novios?","opciones":["Dumas","Hugo","Manzoni","Byron"],"correcta":2},{"pregunta":"¿Con qué movimientos políticos se vinculó?","opciones":["Absolutismo","Liberalismo y nacionalismo","Anarquismo","Conservadurismo clerical"],"correcta":1}]'::jsonb),

('literatura-universal', 'bachillerato', '{1}', 'La novela realista del siglo XIX', 'La segunda mitad del siglo XIX vio el triunfo de la novela realista, un género que aspiraba a representar con fidelidad la sociedad contemporánea, sus clases, costumbres y conflictos. El Realismo surgió como reacción al idealismo romántico y se apoyó en un estudio minucioso de la realidad, con técnicas cercanas a las de un naturalista que observa los hechos. Sus grandes cultivadores en Francia fueron Honoré de Balzac, autor de la ambiciosa Comedia humana, una serie de casi cien novelas que retratan la sociedad francesa post-revolucionaria; Gustave Flaubert, cuya Madame Bovary revolucionó el arte narrativo con su prosa depurada y su análisis psicológico; y Émile Zola, quien radicalizó el realismo en el naturalismo con obras como Germinal. En Inglaterra, Charles Dickens denunció las desigualdades sociales en novelas como Oliver Twist, David Copperfield o Tiempos difíciles, mientras George Eliot aportó obras de gran profundidad psicológica como Middlemarch. En Rusia, los grandes maestros realistas fueron Fiódor Dostoievski, autor de Crimen y castigo y Los hermanos Karamázov, novelas que exploran la psique humana y los dilemas morales, y León Tolstói, autor de Guerra y paz y Ana Karénina, impresionantes por su amplitud y humanidad. En España sobresalieron Benito Pérez Galdós con sus Episodios Nacionales y Leopoldo Alas Clarín con La Regenta. La novela realista se convirtió en la forma literaria más influyente del siglo XIX.', '[{"pregunta":"¿Qué obra es de Flaubert?","opciones":["Comedia humana","Madame Bovary","Germinal","Middlemarch"],"correcta":1},{"pregunta":"¿Quién escribió Crimen y castigo?","opciones":["Tolstói","Dostoievski","Gogol","Chéjov"],"correcta":1},{"pregunta":"¿A qué movimiento radicalizó Zola el realismo?","opciones":["Simbolismo","Naturalismo","Romanticismo","Impresionismo"],"correcta":1},{"pregunta":"¿Qué autor escribió La Regenta?","opciones":["Galdós","Clarín","Baroja","Valera"],"correcta":1}]'::jsonb),

('literatura-universal', 'bachillerato', '{1}', 'Dostoievski y la psicología literaria', 'Fiódor Dostoievski (1821-1881) es uno de los mayores novelistas de la literatura universal. Su vida estuvo marcada por experiencias difíciles: la prisión en Siberia por motivos políticos, la adicción al juego, problemas económicos y la epilepsia. Todas esas vivencias alimentaron su mirada profunda sobre el ser humano. Sus novelas más importantes son Crimen y castigo, El idiota, Los demonios y Los hermanos Karamázov. En Crimen y castigo, el joven Raskólnikov comete un asesinato justificándolo con una teoría sobre la superioridad de ciertos individuos, pero el remordimiento y el encuentro con la piadosa Sonia lo conducen a la confesión y al camino de la redención. En Los hermanos Karamázov, Dostoievski aborda la existencia de Dios, el libre albedrío y el sufrimiento humano mediante un complicado drama familiar. La profundidad psicológica de los personajes, su capacidad para mostrar las contradicciones internas, los debates morales y las preguntas religiosas han hecho de su obra una referencia imprescindible para el pensamiento moderno. Dostoievski anticipó muchos temas del existencialismo y del psicoanálisis, e influyó en autores como Kafka, Camus, Faulkner o Coetzee. Sus novelas no son solo relatos: son auténticas exploraciones del alma humana, abiertas a las grandes preguntas sobre el bien, el mal, la libertad y la fe. Leerlo supone adentrarse en un territorio literario donde la intriga narrativa se une a una reflexión filosófica de enorme alcance.', '[{"pregunta":"¿Qué novela cuenta la historia de Raskólnikov?","opciones":["El idiota","Crimen y castigo","Los demonios","Karamázov"],"correcta":1},{"pregunta":"¿Qué experiencia biográfica le marcó?","opciones":["Viaje a América","Prisión en Siberia","Vida monástica","Estudios en París"],"correcta":1},{"pregunta":"¿Qué aspecto destaca en su literatura?","opciones":["Humor ligero","Profundidad psicológica","Folletín amoroso","Descripción geográfica"],"correcta":1},{"pregunta":"¿A qué corriente del siglo XX influyó?","opciones":["Romanticismo","Existencialismo","Parnasianismo","Culteranismo"],"correcta":1}]'::jsonb),

('literatura-universal', 'bachillerato', '{1}', 'El simbolismo y la poesía moderna', 'El simbolismo es un movimiento literario, sobre todo poético, que surgió en Francia a finales del siglo XIX y que marca el inicio de la poesía moderna. Reaccionó contra el realismo y el naturalismo, que pretendían representar la realidad exterior con precisión, proponiendo en cambio una poesía que buscara sugerir sensaciones, estados de ánimo y correspondencias ocultas entre los objetos del mundo. Los poetas simbolistas consideraban que la realidad más profunda no era visible a los sentidos y que solo la intuición poética podía insinuarla a través de símbolos, imágenes evocadoras y musicalidad. Charles Baudelaire, con Las flores del mal (1857), es considerado el precursor del movimiento, al explorar nuevos territorios de la sensibilidad y expresar la complejidad del mundo moderno. Paul Verlaine defendió una poesía de la música y la sugerencia. Arthur Rimbaud, con obras como Iluminaciones y Una temporada en el infierno, llevó la búsqueda a extremos de intensidad antes de abandonar para siempre la literatura a los veinte años. Stéphane Mallarmé perfeccionó una poesía extremadamente depurada y hermética. El simbolismo influyó en poetas de toda Europa y América, desde Rubén Darío y Antonio Machado hasta Rilke, Yeats y Paul Valéry. También preparó el terreno para las vanguardias del siglo XX, que llevarían la renovación poética a nuevas e inesperadas fronteras.', '[{"pregunta":"¿Dónde surgió el simbolismo?","opciones":["Alemania","Francia","Italia","Inglaterra"],"correcta":1},{"pregunta":"¿Quién es el precursor del movimiento?","opciones":["Mallarmé","Verlaine","Baudelaire","Rimbaud"],"correcta":2},{"pregunta":"¿Qué obra de Rimbaud destaca?","opciones":["Las flores del mal","Iluminaciones","Un golpe de dados","Odas"],"correcta":1},{"pregunta":"¿Qué quería sugerir la poesía simbolista?","opciones":["Solo la realidad exterior","Sensaciones y correspondencias ocultas","Hechos históricos","Datos científicos"],"correcta":1}]'::jsonb),

('literatura-universal', 'bachillerato', '{1}', 'Kafka y el realismo existencial', 'Franz Kafka (1883-1924) es uno de los escritores más influyentes del siglo XX. Nacido en Praga, en el seno de una familia judía de habla alemana, vivió atormentado por una relación difícil con su padre, por sus problemas de salud y por sus dudas existenciales, todo lo cual marcó profundamente su obra. Kafka publicó muy poco en vida y pidió a su amigo Max Brod que destruyera sus manuscritos tras su muerte, algo que Brod afortunadamente no hizo. Gracias a esa decisión, podemos leer hoy obras como La metamorfosis, El proceso, El castillo o El desaparecido. En La metamorfosis, el comerciante Gregor Samsa se despierta una mañana transformado en un insecto gigante, y su familia, tras un intento inicial de cuidarlo, acaba por rechazarlo y desentendiéndose de su suerte. En El proceso, Josef K. es detenido y juzgado por un crimen que nunca le es revelado, en un laberinto burocrático inabarcable. Estas obras, aparentemente absurdas, se han convertido en símbolos de la alienación, la burocracia deshumanizada y la angustia existencial del hombre moderno. El adjetivo kafkiano entró en el lenguaje común para describir situaciones absurdas, opresivas o incomprensibles. Kafka combinó un estilo sobrio y preciso con imágenes surrealistas y una atmósfera inquietante que anticipa muchos temas del existencialismo, el absurdo y la literatura del siglo XX en general.', '[{"pregunta":"¿En qué ciudad nació Kafka?","opciones":["Viena","Praga","Berlín","Budapest"],"correcta":1},{"pregunta":"¿Qué le pasa a Gregor Samsa?","opciones":["Hereda un imperio","Se transforma en un insecto","Se enamora","Gana el Nobel"],"correcta":1},{"pregunta":"¿A quién pidió destruir sus obras?","opciones":["Su padre","Max Brod","Kafka nunca","Una amante"],"correcta":1},{"pregunta":"¿Qué significa kafkiano?","opciones":["Romántico","Absurdo y opresivo","Humorístico","Patriótico"],"correcta":1}]'::jsonb),

('literatura-universal', 'bachillerato', '{1}', 'El boom de la literatura hispanoamericana', 'El llamado boom de la literatura hispanoamericana designa el fenómeno editorial y crítico que, entre los años sesenta y setenta del siglo XX, llevó a la atención del público internacional a una generación de novelistas latinoamericanos extraordinariamente creativos. Autores como Gabriel García Márquez, Julio Cortázar, Mario Vargas Llosa, Carlos Fuentes, José Donoso y Juan Rulfo renovaron profundamente el género con novelas que combinaban técnicas narrativas experimentales, profundidad psicológica, compromiso político, humor y una imaginación desbordante. Una de las obras más emblemáticas del período es Cien años de soledad, publicada por García Márquez en 1967. La novela narra la saga de la familia Buendía y la historia del pueblo imaginario de Macondo a lo largo de varias generaciones, fusionando lo real y lo maravilloso en un estilo conocido como realismo mágico. Otros títulos destacados son Rayuela de Cortázar, La ciudad y los perros de Vargas Llosa, La región más transparente de Fuentes y Pedro Páramo de Rulfo. El boom supuso el reconocimiento mundial de una literatura hispanoamericana plenamente madura y a la altura de las grandes tradiciones europeas. Sus autores ganaron numerosos premios, entre ellos el Nobel de Literatura (García Márquez en 1982, Vargas Llosa en 2010). Su influencia continúa viva en los escritores contemporáneos en lengua española, y sus obras son lectura habitual en escuelas y universidades de todo el mundo.', '[{"pregunta":"¿Cuándo se publicó Cien años de soledad?","opciones":["1950","1967","1982","1995"],"correcta":1},{"pregunta":"¿Qué estilo popularizó García Márquez?","opciones":["Naturalismo","Realismo mágico","Surrealismo","Nouveau roman"],"correcta":1},{"pregunta":"¿Qué autor NO es del boom?","opciones":["Cortázar","Vargas Llosa","Neruda","Fuentes"],"correcta":2},{"pregunta":"¿Qué premio ganó García Márquez?","opciones":["Cervantes","Nobel","Príncipe de Asturias","Booker"],"correcta":1}]'::jsonb),

('literatura-universal', 'bachillerato', '{1}', 'Jane Austen y la novela de costumbres', 'Jane Austen (1775-1817) es una de las más grandes novelistas inglesas, famosa por su aguda observación de la vida social y por su estilo irónico y elegante. Nacida en una familia rural acomodada, vivió casi toda su vida en el campo inglés y nunca se casó. Su obra se compone de seis novelas principales: Sentido y sensibilidad, Orgullo y prejuicio, Mansfield Park, Emma, Persuasión y La abadía de Northanger. Aunque publicadas inicialmente de forma anónima, sus libros obtuvieron cierto éxito ya en vida de la autora y alcanzaron una fama creciente a lo largo de los siglos XIX y XX. Los temas centrales de Austen son el amor, el matrimonio, la educación, las relaciones de clase y la vida cotidiana de la pequeña aristocracia rural de su época. Sus heroínas, como Elizabeth Bennet en Orgullo y prejuicio, son mujeres inteligentes, independientes y con un fuerte sentido moral, capaces de desafiar con sutileza las convenciones sociales. El estilo de Austen combina la ironía fina con un análisis psicológico extraordinario, revelando con precisión los pensamientos y las contradicciones de sus personajes. Sus novelas, aparentemente limitadas en escenario y argumento, ofrecen en realidad una de las visiones más completas y lúcidas de la sociedad inglesa del principio del siglo XIX. Hoy en día son lectura obligada y sus adaptaciones cinematográficas, teatrales y televisivas siguen atrayendo a públicos de todo el mundo.', '[{"pregunta":"¿Cuántas novelas principales escribió?","opciones":["Tres","Cuatro","Cinco","Seis"],"correcta":3},{"pregunta":"¿Cuál es la heroína de Orgullo y prejuicio?","opciones":["Emma","Elizabeth Bennet","Fanny","Anne"],"correcta":1},{"pregunta":"¿Qué estilo caracteriza a Austen?","opciones":["Dramático","Ironía y análisis psicológico","Épico","Oscuro"],"correcta":1},{"pregunta":"¿Dónde se desarrollan sus tramas?","opciones":["En la corte","En el campo inglés","En Londres industrial","En el extranjero"],"correcta":1}]'::jsonb),

('literatura-universal', 'bachillerato', '{1}', 'La poesía de Walt Whitman', 'Walt Whitman (1819-1892) es considerado uno de los más grandes poetas de la literatura estadounidense y uno de los precursores de la poesía moderna en todo el mundo. Su obra maestra, Hojas de hierba, fue publicada por primera vez en 1855 y revisada y ampliada por el propio poeta hasta su muerte. Whitman rompió con las convenciones métricas de la tradición inglesa al adoptar un verso libre, amplio y musical, capaz de acoger toda la riqueza y variedad de la experiencia humana. Sus temas son amplios: la celebración del individuo, la fraternidad entre los hombres, el amor, la naturaleza, la democracia, el trabajo y la muerte. Whitman se presenta en sus poemas como portavoz del pueblo americano y cantor de la vida en todas sus manifestaciones, sin distinciones sociales, geográficas o morales. Su célebre poema Canto a mí mismo es una larga meditación lírica en la que el yo poético se identifica con todos los seres y con todos los elementos del cosmos. La influencia de Whitman ha sido enorme en la poesía posterior. Poetas como Fernando Pessoa, Pablo Neruda, Federico García Lorca, Allen Ginsberg o Jorge Luis Borges reconocieron su huella. Hoy, Hojas de hierba sigue siendo considerada un hito en la historia de la poesía, por su capacidad para unir emoción, pensamiento y exaltación de la vida en un lenguaje fluido y libre que prefigura mucho de lo que vendría después.', '[{"pregunta":"¿Cómo se llama la obra maestra de Whitman?","opciones":["Canto nocturno","Hojas de hierba","Cantares","Crepúsculos"],"correcta":1},{"pregunta":"¿Qué tipo de verso usa?","opciones":["Soneto","Verso libre","Alejandrino","Endecasílabo clásico"],"correcta":1},{"pregunta":"¿Qué celebra principalmente su poesía?","opciones":["Solo el dolor","La vida y la democracia","La guerra","La soledad rural"],"correcta":1},{"pregunta":"¿A qué poetas influyó?","opciones":["Neruda, Pessoa, Lorca","Solo estadounidenses","Solo europeos","A ninguno"],"correcta":0}]'::jsonb),

('literatura-universal', 'bachillerato', '{1}', 'Virginia Woolf y la literatura modernista', 'Virginia Woolf (1882-1941) es una de las figuras más importantes del modernismo literario en lengua inglesa. Nacida en Londres, formó parte del llamado círculo de Bloomsbury, un grupo de intelectuales y artistas que defendía la libertad creativa, la crítica a las convenciones victorianas y la exploración de nuevas formas de expresión. Sus novelas más conocidas son La señora Dalloway, Al faro, Orlando y Las olas. Woolf experimentó con la técnica del monólogo interior o corriente de la conciencia, que permite al lector acceder a los pensamientos, recuerdos y sensaciones de los personajes de una manera fluida y aparentemente desordenada, pero muy cercana a cómo trabaja la mente humana. Esta técnica la comparte con autores como James Joyce o William Faulkner, con quienes Woolf formó parte de la renovación modernista de la novela. Más allá de sus novelas, Virginia Woolf es también autora de ensayos fundamentales como Una habitación propia, en el que reivindica las condiciones materiales y culturales necesarias para que las mujeres puedan escribir y participar plenamente en la vida intelectual. Este texto se ha convertido en uno de los clásicos del pensamiento feminista moderno. Víctima de problemas de salud mental, se suicidó en 1941. Su obra sigue siendo esencial tanto por sus innovaciones narrativas como por su reflexión sobre el lugar de la mujer en la literatura y en la sociedad.', '[{"pregunta":"¿Con qué círculo se asociaba Woolf?","opciones":["Bloomsbury","Jena","Madrid","Boston"],"correcta":0},{"pregunta":"¿Qué técnica utilizó?","opciones":["Romance","Monólogo interior","Soneto","Epistolar"],"correcta":1},{"pregunta":"¿Qué ensayo feminista escribió?","opciones":["Una habitación propia","El segundo sexo","La mística femenina","Teoría queer"],"correcta":0},{"pregunta":"¿Con qué otros autores comparte el modernismo?","opciones":["Joyce y Faulkner","Dickens y Austen","Balzac y Zola","Dostoievski y Tolstói"],"correcta":0}]'::jsonb),

('literatura-universal', 'bachillerato', '{1}', 'La literatura distópica del siglo XX', 'A lo largo del siglo XX, uno de los géneros más influyentes ha sido la literatura distópica, que presenta sociedades imaginarias en las que los ideales utópicos de progreso, justicia o felicidad han degenerado en pesadillas autoritarias. Tres obras destacan especialmente. Un mundo feliz, publicada por Aldous Huxley en 1932, describe una sociedad futura en la que los seres humanos son producidos en laboratorios, clasificados por castas y mantenidos en estado de felicidad artificial gracias al consumo, la tecnología y una droga llamada soma. La novela critica el exceso de control tecnológico y la renuncia a la libertad a cambio de comodidad. 1984, de George Orwell, publicada en 1949, imagina un régimen totalitario dirigido por el Gran Hermano que vigila cada aspecto de la vida privada, manipula el lenguaje y la historia, y persigue cualquier forma de disidencia. La novela ha dado origen a expresiones y conceptos como doblepensar, neolengua y Gran Hermano que hoy forman parte del lenguaje común para referirse a la vigilancia y la manipulación. Finalmente, El cuento de la criada, de Margaret Atwood (1985), imagina una teocracia patriarcal en la que las mujeres son reducidas a funciones reproductivas. Las distopías funcionan como advertencias sobre los peligros que acechan a las sociedades modernas y nos invitan a valorar y defender la libertad, los derechos individuales y la capacidad crítica frente a toda forma de autoritarismo.', '[{"pregunta":"¿Quién escribió Un mundo feliz?","opciones":["Orwell","Huxley","Atwood","Bradbury"],"correcta":1},{"pregunta":"¿Qué expresión popularizó 1984?","opciones":["Gran Hermano","Torre oscura","Matrix","Fahrenheit"],"correcta":0},{"pregunta":"¿Qué tipo de sociedad describe Atwood?","opciones":["Teocracia patriarcal","Anarquía pacífica","Democracia plena","Imperio pagano"],"correcta":0},{"pregunta":"¿Qué función tiene la distopía?","opciones":["Divertir solamente","Advertir sobre peligros reales","Vender tecnología","Describir el pasado"],"correcta":1}]'::jsonb),

('literatura-universal', 'bachillerato', '{1}', 'La poesía y el haiku japonés', 'El haiku es una forma breve de poesía japonesa que ha ejercido una influencia profunda en la literatura mundial, especialmente desde finales del siglo XIX. Consta de tres versos con una estructura tradicional de cinco, siete y cinco sílabas, y suele evocar un momento concreto, una imagen del mundo natural o una sensación fugaz. Su aparente sencillez esconde una enorme exigencia: en muy pocas palabras debe concentrar una visión aguda y sugerente. El haiku tiene sus raíces en formas poéticas japonesas más antiguas, como el haikai no renga, y alcanzó su madurez con el poeta Matsuo Bashō en el siglo XVII, autor de haikus célebres y también de prosas poéticas como Sendas de Oku. Otros grandes maestros del haiku fueron Yosa Buson, Kobayashi Issa y, más modernamente, Masaoka Shiki, quien contribuyó a renovar el género y darle su forma actual. Las características esenciales del haiku son la concisión, la atención al presente, la presencia de una referencia a la naturaleza y la ausencia de juicio moral explícito. Cuando los occidentales conocieron el haiku a través de las traducciones de finales del siglo XIX y principios del XX, numerosos poetas lo incorporaron a sus propias tradiciones, desde los imaginistas angloamericanos como Ezra Pound hasta poetas en lengua española. Hoy, el haiku se escribe en muchos idiomas y sigue siendo una forma privilegiada para capturar instantes de belleza y reflexión.', '[{"pregunta":"¿Cuántos versos tiene un haiku?","opciones":["Dos","Tres","Cuatro","Cinco"],"correcta":1},{"pregunta":"¿Cuál es la estructura silábica tradicional?","opciones":["5-5-5","5-7-5","7-7-7","3-5-3"],"correcta":1},{"pregunta":"¿Quién fue un gran maestro del siglo XVII?","opciones":["Bashō","Shiki","Pound","Tagore"],"correcta":0},{"pregunta":"¿Qué elemento suele aparecer en un haiku?","opciones":["Guerras","Naturaleza y estaciones","Política","Publicidad"],"correcta":1}]'::jsonb);

