INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('matematicas', 'bachillerato', '{1}', 'Los números reales y sus propiedades', 'Los números reales forman uno de los conjuntos más importantes de las matemáticas y constituyen el marco en el que se desarrolla una buena parte del análisis y el cálculo. Se designan con la letra R y comprenden tanto los números racionales, como las fracciones y los decimales finitos o periódicos, como los irracionales, cuya expresión decimal es infinita y no periódica, como ocurre con el número pi, el número e o la raíz cuadrada de 2. Los números reales pueden representarse gráficamente sobre una recta, la llamada recta real, donde a cada punto le corresponde un número y a cada número un punto. Las operaciones fundamentales (suma, resta, multiplicación, división) cumplen una serie de propiedades algebraicas esenciales, como la conmutativa, la asociativa y la distributiva. Los reales se pueden ordenar gracias a la relación menor que, lo que permite hablar de intervalos y de valor absoluto. La construcción rigurosa del conjunto de los números reales se atribuye a matemáticos del siglo XIX, como Dedekind y Cantor, que ofrecieron distintos métodos para definirlos a partir de los racionales. Comprender las propiedades de los reales es fundamental no solo para el bachillerato, sino también para cualquier rama de la ciencia y la ingeniería, pues gran parte de los fenómenos físicos y económicos se modelan mediante funciones cuyas variables toman valores en este conjunto.', '[{"pregunta":"¿Con qué letra se designa el conjunto de los reales?","opciones":["N","Z","Q","R"],"correcta":3},{"pregunta":"¿Qué tipo de número es pi?","opciones":["Natural","Entero","Irracional","Racional"],"correcta":2},{"pregunta":"¿Qué propiedad cumple la suma y la multiplicación?","opciones":["Solo conmutativa","Conmutativa, asociativa, distributiva","Solo asociativa","Ninguna"],"correcta":1},{"pregunta":"¿Quiénes formalizaron los reales en el siglo XIX?","opciones":["Newton y Leibniz","Dedekind y Cantor","Euclides","Pitágoras"],"correcta":1}]'::jsonb),

('matematicas', 'bachillerato', '{1}', 'Las ecuaciones de segundo grado', 'Las ecuaciones de segundo grado, también conocidas como cuadráticas, son aquellas que pueden expresarse en la forma ax² + bx + c = 0, donde a, b y c son números reales y a es distinto de cero. Resolverlas significa encontrar los valores de x que la hacen cierta, a los que se llama soluciones o raíces. La fórmula general para obtenerlas, x = (-b ± √(b² - 4ac)) / (2a), es una de las más conocidas de las matemáticas escolares y permite resolver cualquier ecuación cuadrática. El término dentro de la raíz, b² - 4ac, recibe el nombre de discriminante y ofrece información importante: si es positivo, la ecuación tiene dos soluciones reales distintas; si es cero, una solución doble; y si es negativo, no tiene soluciones reales, aunque sí dos complejas conjugadas. Las ecuaciones cuadráticas aparecen constantemente en problemas prácticos: al calcular áreas, estudiar movimientos con aceleración constante, optimizar funciones económicas o modelar fenómenos físicos. Además, la gráfica de la función y = ax² + bx + c es una parábola, cuyo eje y vértice pueden determinarse a partir de los coeficientes. Comprender bien la ecuación cuadrática es esencial no solo por sí misma, sino como paso previo para el estudio de ecuaciones de mayor grado y para el trabajo con funciones en el análisis matemático posterior.', '[{"pregunta":"¿Qué forma tiene una ecuación de segundo grado?","opciones":["ax+b=0","ax²+bx+c=0","ax³+bx+c=0","a^x=b"],"correcta":1},{"pregunta":"¿Cómo se llama b²-4ac?","opciones":["Raíz","Discriminante","Coeficiente","Potencia"],"correcta":1},{"pregunta":"¿Qué indica si el discriminante es negativo?","opciones":["Dos reales","Una real doble","Sin soluciones reales","Solo una real"],"correcta":2},{"pregunta":"¿Qué gráfica tiene la función cuadrática?","opciones":["Recta","Parábola","Hipérbola","Elipse"],"correcta":1}]'::jsonb),

('matematicas', 'bachillerato', '{1}', 'Las funciones y su representación', 'En matemáticas, una función es una regla que asigna a cada elemento de un conjunto, llamado dominio, un único elemento de otro conjunto, llamado codominio. Las funciones son una de las herramientas más poderosas para describir las relaciones entre magnitudes y constituyen el núcleo del análisis matemático moderno. Se pueden expresar de varias formas: mediante una fórmula, una tabla, un gráfico o incluso una descripción verbal. Algunas de las funciones más importantes son las lineales, cuya gráfica es una recta y que expresan proporciones directas; las cuadráticas, con gráfica parabólica; las polinómicas, que incluyen las anteriores y otras más complejas; las exponenciales, que modelan crecimientos o decrecimientos rápidos; las logarítmicas, inversas de las exponenciales; y las trigonométricas, como el seno, el coseno y la tangente, que describen fenómenos periódicos. Al estudiar una función interesa analizar su dominio, su recorrido, su continuidad, sus puntos de corte, su monotonía (intervalos donde crece o decrece), sus máximos y mínimos, su simetría, su comportamiento asintótico y, en niveles superiores, su derivabilidad e integrabilidad. La representación gráfica es una herramienta fundamental que permite visualizar de un vistazo muchas de estas propiedades. Dominar las funciones es esencial para la física, la economía, la biología y cualquier disciplina que pretenda modelar con rigor los fenómenos del mundo real.', '[{"pregunta":"¿Qué es una función matemática?","opciones":["Regla que asigna a cada x un único y","Una lista","Un dibujo aleatorio","Un número par"],"correcta":0},{"pregunta":"¿Qué función es periódica?","opciones":["Lineal","Trigonométrica","Polinómica","Exponencial"],"correcta":1},{"pregunta":"¿Qué es el dominio?","opciones":["Valores de y","Valores de x permitidos","Pendiente","Ordenada"],"correcta":1},{"pregunta":"¿Qué propiedad NO se estudia habitualmente?","opciones":["Monotonía","Máximos y mínimos","Color","Simetría"],"correcta":2}]'::jsonb),

('matematicas', 'bachillerato', '{1}', 'La trigonometría y los triángulos', 'La trigonometría es la rama de las matemáticas que estudia las relaciones entre los ángulos y los lados de los triángulos. Su nombre procede del griego y significa literalmente medida de los triángulos. Las razones trigonométricas fundamentales, definidas inicialmente para triángulos rectángulos, son el seno, el coseno y la tangente de un ángulo, junto con sus inversas cosecante, secante y cotangente. Estas razones se extienden posteriormente a cualquier ángulo mediante el círculo goniométrico unitario, donde el seno y el coseno se interpretan como coordenadas de un punto sobre la circunferencia. Las fórmulas fundamentales de la trigonometría, como la identidad pitagórica sen² x + cos² x = 1, permiten relacionar las diferentes razones y resolver problemas de cálculo. Para los triángulos no rectángulos existen dos teoremas clave: el teorema del seno, que relaciona cada lado con el seno del ángulo opuesto, y el teorema del coseno, que generaliza el teorema de Pitágoras. La trigonometría tiene aplicaciones prácticas enormes en topografía, astronomía, ingeniería, navegación, acústica y, en general, en cualquier situación en la que sea necesario calcular distancias, alturas o ángulos a partir de otros datos. Su desarrollo histórico es muy antiguo, pues ya matemáticos griegos como Hiparco y Tolomeo, y más tarde astrónomos árabes e indios, sistematizaron sus principales resultados, que llegaron a Europa gracias a las traducciones medievales.', '[{"pregunta":"¿Qué estudia la trigonometría?","opciones":["Integrales","Ángulos y lados de triángulos","Grafos","Probabilidad"],"correcta":1},{"pregunta":"¿Qué teorema generaliza el de Pitágoras?","opciones":["Seno","Coseno","Tales","Thales"],"correcta":1},{"pregunta":"¿Qué vale sen² x + cos² x?","opciones":["0","1","x","2"],"correcta":1},{"pregunta":"¿Qué aplicación NO se menciona?","opciones":["Topografía","Astronomía","Genética","Navegación"],"correcta":2}]'::jsonb),

('matematicas', 'bachillerato', '{1}', 'Los vectores en el plano', 'Los vectores son objetos matemáticos que tienen a la vez magnitud (módulo), dirección y sentido, y se representan gráficamente mediante flechas. Se utilizan intensivamente en matemáticas, física e ingeniería para describir magnitudes vectoriales como fuerzas, velocidades o aceleraciones, que no quedan completamente definidas con un solo número. En el plano, un vector queda determinado por sus dos componentes cartesianas, que indican cuánto avanza en horizontal y cuánto en vertical. Con las componentes es sencillo realizar operaciones: sumar vectores equivale a sumar componente a componente; multiplicarlos por un escalar equivale a multiplicar cada componente por ese número. El módulo de un vector se obtiene aplicando el teorema de Pitágoras a sus componentes. Entre las operaciones más importantes destaca el producto escalar, que asocia a dos vectores un número y que permite calcular el ángulo que forman o estudiar su perpendicularidad. En geometría analítica, los vectores permiten escribir ecuaciones de rectas y estudiar sus posiciones relativas con mucha comodidad. En física, sirven para describir con rigor cualquier magnitud que involucre dirección, desde los campos gravitatorios hasta las fuerzas sobre un cuerpo. Dominar los vectores es fundamental no solo para el bachillerato, sino también para seguir estudios universitarios en ciencias e ingeniería, donde aparecen constantemente como lenguaje común para expresar problemas geométricos y físicos.', '[{"pregunta":"¿Qué propiedad NO caracteriza a un vector?","opciones":["Módulo","Dirección","Color","Sentido"],"correcta":2},{"pregunta":"¿Cómo se suman dos vectores en componentes?","opciones":["Multiplicando","Componente a componente","Restando ángulos","Dividiendo"],"correcta":1},{"pregunta":"¿Qué permite calcular el producto escalar?","opciones":["Área","Ángulo entre vectores","Volumen","Radio"],"correcta":1},{"pregunta":"¿Qué teorema permite hallar el módulo?","opciones":["Tales","Pitágoras","Euler","Fermat"],"correcta":1}]'::jsonb),

('matematicas', 'bachillerato', '{1}', 'Las derivadas y sus aplicaciones', 'La derivada es uno de los conceptos más importantes del cálculo diferencial y mide, en términos intuitivos, la rapidez con la que una función cambia respecto a su variable independiente. En términos geométricos, la derivada de una función en un punto equivale a la pendiente de la recta tangente a la gráfica de la función en ese punto. Su definición rigurosa se basa en el concepto de límite: la derivada es el límite del cociente incremental cuando el incremento de la variable tiende a cero. Existen reglas prácticas para derivar cualquier función habitual: la derivada de una suma es la suma de derivadas, la derivada de una constante es cero, y hay fórmulas específicas para las potencias, los logaritmos, las exponenciales y las funciones trigonométricas. La derivada se utiliza para estudiar el comportamiento de las funciones: permite determinar sus intervalos de crecimiento y decrecimiento, localizar máximos y mínimos, analizar la concavidad y la convexidad y obtener las ecuaciones de las rectas tangentes y normales. Más allá de la geometría, las derivadas tienen aplicaciones prácticas muy diversas: en física, la derivada de la posición respecto al tiempo es la velocidad, y la de la velocidad es la aceleración; en economía, permite estudiar los ingresos marginales y optimizar beneficios; en biología y otras ciencias, sirve para modelar procesos de cambio. La derivada, junto con la integral, es el corazón del cálculo infinitesimal desarrollado por Newton y Leibniz en el siglo XVII.', '[{"pregunta":"¿Qué mide una derivada?","opciones":["La rapidez de cambio de una función","Área","Volumen","Longitud"],"correcta":0},{"pregunta":"¿Qué representa geométricamente?","opciones":["Pendiente de la tangente","Perímetro","Ancho","Radio"],"correcta":0},{"pregunta":"¿Qué es la derivada de la posición?","opciones":["Masa","Velocidad","Energía","Densidad"],"correcta":1},{"pregunta":"¿Quiénes desarrollaron el cálculo?","opciones":["Euclides y Tales","Newton y Leibniz","Gauss y Euler","Fermat y Pascal"],"correcta":1}]'::jsonb),

('matematicas', 'bachillerato', '{1}', 'Las matrices y su utilidad', 'Una matriz es una tabla rectangular de números organizada en filas y columnas que se utiliza como una herramienta matemática de gran versatilidad. Cada número de la matriz se llama elemento o entrada y suele indicarse con dos subíndices que señalan su posición: el primero para la fila y el segundo para la columna. Las matrices se pueden sumar, restar y multiplicar bajo ciertas condiciones. La suma y la resta exigen que las matrices tengan las mismas dimensiones, y se realizan elemento a elemento. La multiplicación, en cambio, requiere que el número de columnas de la primera coincida con el número de filas de la segunda, y sigue una regla especial que combina filas con columnas. Las matrices permiten representar y resolver sistemas de ecuaciones lineales de manera compacta, y son imprescindibles en áreas como el álgebra lineal, la geometría, la estadística, la informática y la economía. Un concepto asociado muy importante es el determinante, un número que se calcula a partir de una matriz cuadrada y que aporta información sobre sus propiedades, como por ejemplo si tiene inversa o no. Los sistemas de ecuaciones lineales se pueden resolver de forma elegante mediante matrices y sus determinantes, gracias al método de Gauss o a la regla de Cramer. Aunque a primera vista puedan parecer abstractas, las matrices aparecen por todas partes en las aplicaciones modernas, desde los gráficos por ordenador hasta los algoritmos de inteligencia artificial.', '[{"pregunta":"¿Qué es una matriz?","opciones":["Una tabla rectangular de números","Una curva","Un vector único","Un polinomio"],"correcta":0},{"pregunta":"¿Qué condición exige multiplicar dos matrices?","opciones":["Misma dimensión","Columnas de la primera = filas de la segunda","Ser cuadradas","Tener inverso"],"correcta":1},{"pregunta":"¿Qué es el determinante?","opciones":["Una fila","Un número asociado a una matriz cuadrada","Una columna","El doble del elemento"],"correcta":1},{"pregunta":"¿Qué método permite resolver sistemas?","opciones":["Gauss o Cramer","Euler","Lagrange","Ruffini"],"correcta":0}]'::jsonb),

('matematicas', 'bachillerato', '{1}', 'La probabilidad y sus fundamentos', 'La probabilidad es la rama de las matemáticas que estudia los fenómenos aleatorios, es decir, aquellos cuyos resultados no se pueden predecir con certeza pero sí con cierta regularidad a la hora de repetirlos muchas veces. Su origen se remonta al siglo XVII, cuando matemáticos como Pascal y Fermat analizaron problemas relacionados con juegos de azar, pero hoy se aplica a campos tan diversos como la física, la biología, las ciencias sociales, la economía o la informática. El experimento aleatorio es cualquier proceso cuyo resultado depende del azar, y el conjunto de todos los resultados posibles se llama espacio muestral. Un suceso es un subconjunto del espacio muestral, y su probabilidad es un número entre cero y uno que mide la posibilidad de que ocurra: cero indica imposibilidad y uno, certeza. La llamada regla de Laplace permite calcular la probabilidad de un suceso en experimentos con resultados equiprobables como el cociente entre los casos favorables y los casos posibles. Cuando los sucesos no son equiprobables, se utilizan otras técnicas, como las frecuencias relativas, los árboles de probabilidad o las distribuciones. El estudio de la probabilidad es esencial para la estadística inferencial, la toma de decisiones en condiciones de incertidumbre y el diseño de algoritmos. En el mundo actual, lleno de datos y de predicciones, dominar las ideas básicas de la probabilidad es fundamental para entender la información que recibimos y para actuar con criterio.', '[{"pregunta":"¿Entre qué valores está una probabilidad?","opciones":["0 y 10","0 y 1","-1 y 1","1 y 100"],"correcta":1},{"pregunta":"¿Qué matemáticos estudiaron juegos de azar en el s. XVII?","opciones":["Euler y Gauss","Pascal y Fermat","Newton y Leibniz","Tales y Pitágoras"],"correcta":1},{"pregunta":"¿Qué indica la regla de Laplace?","opciones":["Casos favorables entre casos posibles","Suma de probabilidades","Integral del suceso","Media de sucesos"],"correcta":0},{"pregunta":"¿Qué es el espacio muestral?","opciones":["El suceso imposible","Conjunto de resultados posibles","La media","La moda"],"correcta":1}]'::jsonb),

('matematicas', 'bachillerato', '{1}', 'La estadística descriptiva', 'La estadística descriptiva es la parte de la estadística que se dedica a recoger, organizar, presentar y resumir conjuntos de datos con el objetivo de describir sus principales características. Al estudiar un conjunto de datos, el primer paso suele ser organizar la información en tablas de frecuencias o en gráficos apropiados, como histogramas, diagramas de barras, circulares o de caja. A continuación, se calculan las llamadas medidas de centralización, que indican dónde se concentran los datos: la media aritmética, la mediana (valor central) y la moda (valor más repetido). Cada una tiene ventajas e inconvenientes, por lo que es útil conocerlas todas. También se calculan las medidas de dispersión, que informan sobre cómo se alejan los datos de la media: el rango, la varianza y la desviación típica son las más importantes. Una desviación típica grande indica que los datos están muy dispersos; pequeña, que se agrupan cerca de la media. Cuando se comparan dos grupos de datos, las medidas relativas, como el coeficiente de variación, son muy útiles. La estadística descriptiva es el paso previo a cualquier análisis más profundo y permite detectar patrones, comparar grupos y resumir información de grandes cantidades de datos. Es una herramienta imprescindible en la ciencia, la medicina, la economía, la sociología, el marketing y, en general, en cualquier ámbito que trabaje con información cuantitativa.', '[{"pregunta":"¿Qué es la moda en estadística?","opciones":["El valor más repetido","El valor central","La media","La suma"],"correcta":0},{"pregunta":"¿Qué mide la desviación típica?","opciones":["Tendencia central","Dispersión","Moda","Mediana"],"correcta":1},{"pregunta":"¿Qué gráfico NO es típico de la estadística?","opciones":["Histograma","Diagrama de barras","Diagrama circular","Tabla periódica"],"correcta":3},{"pregunta":"¿Qué indica una desviación típica grande?","opciones":["Datos dispersos","Datos agrupados","Mediana alta","Moda única"],"correcta":0}]'::jsonb),

('matematicas', 'bachillerato', '{1}', 'Los límites y la continuidad', 'El concepto de límite es uno de los pilares del cálculo y del análisis matemático. De forma intuitiva, el límite de una función f(x) cuando x se aproxima a un cierto valor a es el valor al que tiende f(x) a medida que x se acerca a a sin llegar a tocarlo. Formalmente, la definición rigurosa utiliza la famosa noción epsilon-delta, introducida en el siglo XIX por el matemático francés Cauchy y perfeccionada por Weierstrass, que se sirve de pequeñas distancias para capturar la idea de aproximación. Los límites son una herramienta para estudiar el comportamiento de funciones cerca de puntos especiales, como los puntos de discontinuidad, los puntos donde no están definidas o los valores en los que tienden al infinito. A partir del concepto de límite se define la continuidad de una función: una función es continua en un punto si el límite en ese punto coincide con su valor. Existen distintos tipos de discontinuidades: evitables, cuando pueden repararse redefiniendo la función; de salto finito, cuando los límites laterales son distintos; y asintóticas, cuando los límites laterales tienden al infinito. Muchos teoremas importantes del cálculo, como el de Bolzano, el de Weierstrass o el del valor intermedio, exigen que la función sea continua en un intervalo. Dominar los conceptos de límite y continuidad es fundamental para abordar con rigor el cálculo diferencial e integral.', '[{"pregunta":"¿Qué mide un límite?","opciones":["El comportamiento al aproximarse a un valor","La integral","La derivada","El área exacta"],"correcta":0},{"pregunta":"¿Quién formalizó la noción epsilon-delta?","opciones":["Newton","Cauchy y Weierstrass","Euclides","Arquímedes"],"correcta":1},{"pregunta":"¿Cuándo es continua una función en un punto?","opciones":["Si el límite coincide con el valor","Siempre","Nunca","Solo si es lineal"],"correcta":0},{"pregunta":"¿Qué teorema NO depende de la continuidad?","opciones":["Bolzano","Valor intermedio","Weierstrass","Pitágoras"],"correcta":3}]'::jsonb),

('matematicas', 'bachillerato', '{1}', 'Las sucesiones y las progresiones', 'Una sucesión es un conjunto ordenado de números en el que cada elemento ocupa una posición determinada. Los términos de una sucesión se numeran mediante subíndices: el primer término, el segundo, el tercero, etc. Algunas sucesiones tienen reglas de formación especialmente sencillas y útiles, y reciben el nombre de progresiones. Una progresión aritmética es aquella en la que cada término se obtiene sumando al anterior una cantidad fija llamada diferencia. Por ejemplo, 3, 7, 11, 15, 19 es una progresión aritmética de diferencia 4. Una progresión geométrica, en cambio, es aquella en la que cada término se obtiene multiplicando el anterior por un número fijo llamado razón. Por ejemplo, 2, 6, 18, 54 es una progresión geométrica de razón 3. Existen fórmulas muy útiles para calcular el término general y la suma de los primeros n términos de estas progresiones. El estudio de las progresiones no es solo teórico: se utiliza en matemática financiera para calcular intereses simples y compuestos, en biología para modelar crecimientos poblacionales, en física para estudiar fenómenos periódicos y en muchas otras aplicaciones. Además, el concepto de sucesión es el primer paso hacia ideas más avanzadas como el límite de una sucesión y la suma de series infinitas, que son la base del análisis matemático moderno.', '[{"pregunta":"¿Qué es una progresión aritmética?","opciones":["Cada término se suma una cantidad fija","Cada término se multiplica","Es aleatoria","Es cuadrática"],"correcta":0},{"pregunta":"¿Qué es la razón de una geométrica?","opciones":["Diferencia fija","Factor multiplicativo fijo","Primer término","Suma total"],"correcta":1},{"pregunta":"¿En qué se aplica al interés compuesto?","opciones":["Progresión geométrica","Progresión aritmética","Progresión alterna","Ninguna"],"correcta":0},{"pregunta":"¿Qué concepto generaliza la idea de sucesión?","opciones":["Serie infinita","Matriz","Polinomio","Conjunto"],"correcta":0}]'::jsonb),

('matematicas', 'bachillerato', '{1}', 'Los logaritmos y su origen', 'Los logaritmos fueron inventados a principios del siglo XVII por el matemático escocés John Napier con el objetivo de facilitar cálculos complicados, especialmente los relacionados con la astronomía, la navegación y la trigonometría. La idea fundamental es convertir multiplicaciones y divisiones en sumas y restas, mucho más sencillas de realizar manualmente. Dado un número positivo b distinto de 1, llamado base, el logaritmo de un número x en esa base es el exponente al que hay que elevar b para obtener x. Los logaritmos más usados son el decimal, de base 10, y el natural, de base e, un número irracional cuyo valor aproximado es 2,718 y que aparece con frecuencia en el análisis matemático. Las propiedades fundamentales de los logaritmos permiten transformar el producto en suma, el cociente en resta y la potencia en producto, lo que explica su enorme utilidad antes de la aparición de las calculadoras electrónicas. Durante siglos, las tablas de logaritmos fueron indispensables para cualquier calculista profesional, y dieron lugar a instrumentos como la regla de cálculo, que los utilizaba mecánicamente. Hoy, los logaritmos siguen siendo conceptos fundamentales en muchas áreas: escalas logarítmicas como la de Richter o la del pH, cálculo de intereses continuos, teoría de la información o análisis de algoritmos en informática. Su invención supuso una revolución comparable a la de la notación posicional o a la introducción del cero.', '[{"pregunta":"¿Quién inventó los logaritmos?","opciones":["Napier","Newton","Euler","Gauss"],"correcta":0},{"pregunta":"¿Qué base tiene el logaritmo natural?","opciones":["10","2","e","100"],"correcta":2},{"pregunta":"¿Qué transforma el logaritmo en las operaciones?","opciones":["Producto en suma","Suma en producto","Resta en cociente","Nada"],"correcta":0},{"pregunta":"¿Qué escala es logarítmica?","opciones":["Richter","Celsius","Metros","Pesos"],"correcta":0}]'::jsonb),

('matematicas', 'bachillerato', '{1}', 'La geometría analítica del plano', 'La geometría analítica es la rama de las matemáticas que combina la geometría con el álgebra mediante la introducción de coordenadas. Su creación, atribuida principalmente a René Descartes en el siglo XVII, supuso una auténtica revolución al permitir expresar figuras geométricas como ecuaciones y, a la inversa, interpretar las ecuaciones como figuras. En el plano, cada punto se identifica por un par de coordenadas (x, y), y las rectas, las circunferencias, las parábolas, las elipses y las hipérbolas pueden describirse mediante ecuaciones sencillas. Por ejemplo, la ecuación general de la recta se escribe como y = mx + n, donde m es la pendiente y n la ordenada en el origen. La circunferencia con centro en el punto (a, b) y radio r tiene por ecuación (x - a)² + (y - b)² = r². Las llamadas cónicas, como la elipse, la parábola y la hipérbola, son curvas que surgen al cortar un cono con un plano y pueden expresarse también mediante ecuaciones cuadráticas. La geometría analítica ha sido fundamental para el desarrollo del cálculo diferencial e integral y para la física, la astronomía o la ingeniería. Permite resolver problemas geométricos con herramientas algebraicas, lo que a menudo resulta mucho más cómodo que el razonamiento puramente visual, y ofrece además una base natural para pasar a la geometría del espacio en tres o más dimensiones.', '[{"pregunta":"¿Quién es considerado el creador de la geometría analítica?","opciones":["Euclides","Descartes","Pitágoras","Riemann"],"correcta":1},{"pregunta":"¿Qué representa m en y=mx+n?","opciones":["Pendiente","Ordenada en el origen","Radio","Ángulo"],"correcta":0},{"pregunta":"¿Qué curva NO es cónica?","opciones":["Parábola","Elipse","Hipérbola","Parábola gaussiana"],"correcta":3},{"pregunta":"¿Qué aporta la geometría analítica?","opciones":["Usar álgebra para resolver geometría","Eliminar ecuaciones","Solo calcular áreas","Suprimir el cálculo"],"correcta":0}]'::jsonb),

('matematicas', 'bachillerato', '{1}', 'Las distribuciones de probabilidad', 'Las distribuciones de probabilidad son modelos matemáticos que describen cómo se distribuyen los valores posibles de una variable aleatoria y qué probabilidad tiene cada uno de ellos. Se clasifican en dos grandes grupos. Las distribuciones discretas corresponden a variables que solo pueden tomar un número finito o numerable de valores, como el número de caras al lanzar varias monedas; ejemplos habituales son la distribución binomial, la de Poisson y la uniforme discreta. Las distribuciones continuas, en cambio, describen variables que pueden tomar cualquier valor dentro de un intervalo real, como las alturas de las personas o los tiempos de llegada; el ejemplo más importante es la distribución normal o campana de Gauss, caracterizada por su forma simétrica y su aparición en multitud de fenómenos naturales. La distribución normal queda completamente determinada por dos parámetros, la media y la desviación típica, y cumple propiedades fundamentales como la famosa regla del 68-95-99,7, según la cual aproximadamente ese porcentaje de los datos se sitúa dentro de una, dos o tres desviaciones típicas de la media. Las distribuciones de probabilidad son la base de la estadística inferencial, pues permiten calcular intervalos de confianza, realizar contrastes de hipótesis y tomar decisiones a partir de datos muestrales. Se utilizan ampliamente en medicina, economía, física, ingeniería o ciencias sociales para modelar fenómenos con cierto grado de incertidumbre y obtener predicciones razonadas.', '[{"pregunta":"¿Cómo se clasifican principalmente?","opciones":["Discretas y continuas","Pares e impares","Naturales y reales","Rectas y curvas"],"correcta":0},{"pregunta":"¿Cuál es la distribución continua más famosa?","opciones":["Binomial","Normal o gaussiana","Poisson","Uniforme"],"correcta":1},{"pregunta":"¿Qué parámetros definen la normal?","opciones":["Media y desviación típica","Moda y rango","Mínimo y máximo","Suma y resta"],"correcta":0},{"pregunta":"¿Qué porcentaje hay dentro de 2 desviaciones?","opciones":["50%","68%","95%","99,7%"],"correcta":2}]'::jsonb),

('matematicas', 'bachillerato', '{1}', 'Los números complejos', 'Los números complejos surgieron en el siglo XVI para resolver ciertas ecuaciones cuadráticas y cúbicas cuyas soluciones no podían obtenerse con los números reales. Un número complejo se escribe en la forma a + bi, donde a y b son números reales e i es la llamada unidad imaginaria, definida como aquella cuyo cuadrado es igual a menos uno. El número a recibe el nombre de parte real y b el de parte imaginaria. Los números reales son un caso particular de los complejos, aquellos en los que la parte imaginaria es cero. Las operaciones con números complejos siguen reglas análogas a las de los reales, pero teniendo en cuenta que i² = -1. Cada número complejo tiene un conjugado, que cambia el signo de la parte imaginaria, y un módulo, que representa su distancia al origen en el llamado plano complejo o plano de Argand. La representación geométrica de los complejos permite visualizarlos como puntos o vectores en un plano. Además de la forma binómica, los complejos pueden expresarse en forma polar y en forma exponencial mediante la célebre fórmula de Euler, e^(iθ) = cos θ + i sen θ, una de las más bellas de las matemáticas. Los números complejos son herramientas indispensables en muchas áreas, como la electrónica, la física cuántica, el tratamiento de señales o la teoría de funciones.', '[{"pregunta":"¿Cuánto vale i²?","opciones":["1","0","-1","2"],"correcta":2},{"pregunta":"¿Cómo se llama el plano de los complejos?","opciones":["De Gauss","De Argand","De Hilbert","De Descartes"],"correcta":1},{"pregunta":"¿Qué famosa fórmula relaciona e, i, π?","opciones":["Euler","Riemann","Cauchy","Dirac"],"correcta":0},{"pregunta":"¿En qué no se aplican los complejos?","opciones":["Física cuántica","Electrónica","Tratamiento de señales","Ortografía"],"correcta":3}]'::jsonb),

('matematicas', 'bachillerato', '{1}', 'La combinatoria y el conteo', 'La combinatoria es la rama de las matemáticas que se ocupa de contar, ordenar y agrupar elementos de conjuntos finitos. Es una herramienta fundamental para la probabilidad y para numerosas aplicaciones en informática, estadística y ciencias experimentales. Las tres técnicas básicas de la combinatoria son las variaciones, las permutaciones y las combinaciones. Las variaciones cuentan el número de formas en que se pueden elegir y ordenar r elementos de un conjunto de n, es decir, importa el orden de elección. Las permutaciones son un caso particular de las variaciones en las que se eligen todos los elementos del conjunto, de manera que cuentan el número de formas distintas de ordenarlos. Las combinaciones, en cambio, cuentan el número de formas en que se pueden elegir r elementos de un conjunto de n sin que importe el orden. Existen fórmulas explícitas para cada una de estas operaciones en términos de factoriales. Un problema clásico de combinatoria es el del cálculo del número de posibles quinielas o loterías, el número de formas en que se pueden colocar libros en una estantería o el número de comités posibles que pueden formarse dentro de un grupo. Además de sus aplicaciones prácticas, la combinatoria da lugar a resultados hermosos como el triángulo de Pascal, el binomio de Newton y las identidades combinatorias, que conectan áreas diversas de las matemáticas.', '[{"pregunta":"¿Qué estudia la combinatoria?","opciones":["Contar y ordenar elementos finitos","Medir ángulos","Integrar funciones","Resolver ecuaciones"],"correcta":0},{"pregunta":"¿Cuál importa el orden?","opciones":["Combinaciones","Variaciones","Conjuntos","Relaciones"],"correcta":1},{"pregunta":"¿Qué es una permutación?","opciones":["Ordenación de todos los elementos","Subconjunto","Suma","Distancia"],"correcta":0},{"pregunta":"¿Qué triángulo célebre pertenece a la combinatoria?","opciones":["Triángulo de Euler","Triángulo de Pascal","Triángulo equilátero","Triángulo órfico"],"correcta":1}]'::jsonb),

('matematicas', 'bachillerato', '{1}', 'La historia de las matemáticas', 'La historia de las matemáticas es una de las aventuras intelectuales más largas y ricas de la humanidad. Sus primeras manifestaciones aparecen en civilizaciones antiguas como la egipcia, la babilónica, la china o la india, donde ya se desarrollaron sistemas de numeración, técnicas de medida y métodos para resolver problemas prácticos de agrimensura, comercio y astronomía. La matemática como disciplina teórica, sin embargo, alcanzó su primer gran momento en Grecia, con figuras como Tales, Pitágoras, Euclides y Arquímedes, quienes sistematizaron la geometría y dieron los primeros pasos hacia el razonamiento deductivo. Durante la Edad Media, los matemáticos árabes realizaron aportaciones fundamentales, entre las que destacan el álgebra, nombrada así a partir del libro del persa al-Juarismi, y la difusión del sistema de numeración decimal con origen indio, que llegó a Europa gracias a ellos. El Renacimiento y la revolución científica del siglo XVII dieron lugar a avances como el cálculo infinitesimal de Newton y Leibniz, la geometría analítica de Descartes o la teoría de probabilidades de Pascal y Fermat. En los siglos XIX y XX se produjeron grandes cambios, con la aparición de las geometrías no euclidianas, la teoría de conjuntos de Cantor, la lógica matemática y nuevas ramas como la topología o la teoría de la computación. Las matemáticas actuales abarcan incontables áreas y siguen siendo una herramienta indispensable para comprender el mundo natural, tecnológico y social.', '[{"pregunta":"¿En qué civilización antigua se sistematizó la geometría?","opciones":["Babilónica","China","Grecia","Azteca"],"correcta":2},{"pregunta":"¿De dónde viene la palabra álgebra?","opciones":["Griego","Latín","Libro de al-Juarismi","Egipto"],"correcta":2},{"pregunta":"¿Quiénes desarrollaron el cálculo?","opciones":["Newton y Leibniz","Euler y Gauss","Tales y Pitágoras","Cantor y Hilbert"],"correcta":0},{"pregunta":"¿Qué teoría creó Cantor?","opciones":["De la relatividad","De conjuntos","De la evolución","Cuántica"],"correcta":1}]'::jsonb);

