INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('programacion', 'bachillerato', '{1}', 'Los lenguajes de programación', 'Un lenguaje de programación es un sistema formal diseñado para comunicar instrucciones a una máquina, normalmente un ordenador, con el fin de que realice tareas concretas. Existen miles de lenguajes de programación, cada uno diseñado con distintos objetivos y filosofías. Los lenguajes se clasifican según su nivel de abstracción y su paradigma. Los lenguajes de bajo nivel, como el ensamblador, están muy próximos al lenguaje máquina y permiten un control detallado del hardware, aunque son difíciles de escribir y mantener. Los de alto nivel, como Python, Java, C# o JavaScript, ofrecen una sintaxis mucho más cercana al lenguaje humano, lo que facilita el trabajo de los programadores. Según su paradigma, los lenguajes pueden ser imperativos, orientados a objetos, funcionales, lógicos o declarativos, entre otros. La elección del lenguaje depende del tipo de proyecto: Python es popular en ciencia de datos y educación, JavaScript domina el desarrollo web, C y C++ se usan en sistemas que requieren alto rendimiento, y Java y C# son habituales en aplicaciones empresariales y móviles. Todos los lenguajes comparten una serie de elementos comunes: variables, estructuras de control, funciones, tipos de datos y bibliotecas. Aprender un primer lenguaje facilita enormemente el aprendizaje de los demás, porque permite desarrollar una forma de pensar algorítmica que trasciende la sintaxis concreta y se mantiene útil durante toda la carrera de un programador.', '[{"pregunta":"¿Qué es un lenguaje de programación?","opciones":["Un idioma humano","Un sistema formal para dar instrucciones a una máquina","Un tipo de teclado","Un archivo de texto"],"correcta":1},{"pregunta":"¿Qué lenguaje es de bajo nivel?","opciones":["Python","JavaScript","Ensamblador","Java"],"correcta":2},{"pregunta":"¿Qué lenguaje domina la web?","opciones":["Python","JavaScript","C++","COBOL"],"correcta":1},{"pregunta":"¿Qué es común a todos los lenguajes?","opciones":["Mismos nombres","Variables, estructuras de control, funciones","Mismo precio","Mismo autor"],"correcta":1}]'::jsonb),

('programacion', 'bachillerato', '{1}', 'Variables y tipos de datos', 'Las variables son uno de los conceptos fundamentales de la programación. Pueden considerarse como contenedores en los que se almacena un valor que puede cambiar durante la ejecución de un programa. Cada variable tiene un nombre, que sirve para identificarla, y un tipo, que determina qué clase de valores puede contener y qué operaciones se pueden hacer con ella. Los tipos de datos básicos más habituales son los enteros, para números sin decimales; los reales o de coma flotante, para números con decimales; los booleanos, que solo pueden tomar los valores verdadero o falso; los caracteres, que representan letras o símbolos individuales; y las cadenas de texto, que son secuencias de caracteres. Además de los tipos primitivos, los lenguajes modernos ofrecen tipos compuestos como las listas, los arrays, las tuplas, los conjuntos, los diccionarios o las estructuras definidas por el programador. Algunos lenguajes son fuertemente tipados, como Java o C#, y obligan a declarar el tipo de cada variable; otros son débilmente o dinámicamente tipados, como Python o JavaScript, y deducen el tipo a partir del valor asignado. Cada enfoque tiene ventajas e inconvenientes en términos de seguridad, flexibilidad y rendimiento. Elegir el tipo adecuado para cada variable es una decisión importante porque influye en la claridad, la eficiencia y la fiabilidad del programa resultante.', '[{"pregunta":"¿Qué es una variable?","opciones":["Un comentario","Un contenedor con nombre y tipo","Un nombre fijo","Un número"],"correcta":1},{"pregunta":"¿Qué tipo admite solo verdadero o falso?","opciones":["Entero","Real","Booleano","Cadena"],"correcta":2},{"pregunta":"¿Qué lenguaje es dinámicamente tipado?","opciones":["Java","C#","Python","Rust"],"correcta":2},{"pregunta":"¿Por qué importa el tipo?","opciones":["Decorativo","Afecta a operaciones y fiabilidad","No importa","Solo afecta al color"],"correcta":1}]'::jsonb),

('programacion', 'bachillerato', '{1}', 'Las estructuras de control', 'Las estructuras de control son las construcciones del lenguaje que permiten al programador alterar el orden en que se ejecutan las instrucciones, adaptando la lógica del programa a distintas situaciones. Existen tres tipos fundamentales de estructuras de control: las secuenciales, las condicionales y las repetitivas. La secuencia significa que las instrucciones se ejecutan una detrás de otra en el orden en que aparecen. Las estructuras condicionales permiten tomar decisiones: la más común es if, que ejecuta un bloque de código solo si una condición es verdadera, y puede ampliarse con else o con ramas adicionales como else if o switch. Las estructuras repetitivas o bucles permiten ejecutar un bloque de código varias veces. Las más utilizadas son el bucle for, que normalmente se emplea cuando se conoce de antemano el número de iteraciones, y el bucle while, que se utiliza cuando la repetición depende de una condición que puede o no cumplirse. Además, existen variantes como do-while o foreach, adaptadas a situaciones concretas. Las estructuras de control se pueden combinar y anidar entre sí para resolver problemas complejos. La comprensión de estas construcciones es uno de los primeros pasos esenciales en el aprendizaje de cualquier lenguaje de programación y determina en gran medida la calidad y la legibilidad del código que se produce.', '[{"pregunta":"¿Cuántos tipos fundamentales de estructuras de control hay?","opciones":["Dos","Tres","Cuatro","Cinco"],"correcta":1},{"pregunta":"¿Qué hace un if?","opciones":["Repite siempre","Ejecuta un bloque si la condición es cierta","Asigna valores","Declara variables"],"correcta":1},{"pregunta":"¿Cuándo conviene un bucle for?","opciones":["Cuando no se sabe el número de iteraciones","Cuando se conoce el número de iteraciones","Nunca","Solo en Java"],"correcta":1},{"pregunta":"¿Pueden anidarse las estructuras de control?","opciones":["No","Sí","Solo en Python","Solo en C++"],"correcta":1}]'::jsonb),

('programacion', 'bachillerato', '{1}', 'Los algoritmos y la resolución de problemas', 'Un algoritmo es una secuencia finita y ordenada de pasos precisos que permite resolver un problema o llevar a cabo una tarea. El término, que procede del matemático persa al-Juarismi, es anterior a los ordenadores y se ha utilizado desde hace siglos en las matemáticas. En informática, los algoritmos son el corazón del diseño de cualquier programa: antes de escribir código, un buen programador debe pensar en cómo resolver el problema paso a paso. Un algoritmo debe ser claro, preciso, finito y correcto. Para describirlo se utilizan herramientas como los pseudocódigos, que usan un lenguaje parecido al natural pero estructurado, o los diagramas de flujo, que representan visualmente las decisiones y los pasos. Los algoritmos se clasifican según distintos criterios: por ejemplo, pueden ser deterministas o probabilísticos, iterativos o recursivos, exactos o aproximados. Existen algoritmos famosos como los de ordenación (burbuja, inserción, quicksort, mergesort), los de búsqueda (lineal, binaria), los de grafos (Dijkstra, A*) o los criptográficos. La eficiencia de un algoritmo es un aspecto crucial y se mide habitualmente con la notación O grande, que describe cómo crece el tiempo o la memoria necesarios cuando aumenta el tamaño de la entrada. Comprender los algoritmos no solo sirve para programar mejor, sino también para razonar con orden sobre cualquier tipo de problema.', '[{"pregunta":"¿De qué palabra deriva algoritmo?","opciones":["Algoritmia","Al-Juarismi","Alquimia","Álgebra"],"correcta":1},{"pregunta":"¿Qué debe ser un algoritmo?","opciones":["Eterno","Claro, preciso, finito y correcto","Aleatorio","Opcional"],"correcta":1},{"pregunta":"¿Qué notación mide la eficiencia?","opciones":["Notación pi","Notación O grande","Notación musical","Notación científica"],"correcta":1},{"pregunta":"¿Qué algoritmo es de búsqueda?","opciones":["Burbuja","Binaria","Quicksort","Mergesort"],"correcta":1}]'::jsonb),

('programacion', 'bachillerato', '{1}', 'La programación orientada a objetos', 'La programación orientada a objetos (POO) es uno de los paradigmas más importantes en la informática contemporánea. En lugar de organizar un programa únicamente como una secuencia de instrucciones, la POO lo estructura en torno a entidades llamadas objetos, que combinan datos (atributos) y comportamientos (métodos). Los objetos se crean a partir de clases, que son plantillas o moldes que definen qué atributos y qué métodos tendrán los objetos que se creen a partir de ellas. Los cuatro pilares fundamentales de la POO son la encapsulación, la herencia, el polimorfismo y la abstracción. La encapsulación consiste en ocultar los detalles internos de un objeto y exponer solo lo necesario mediante una interfaz pública, lo que favorece la seguridad y la mantenibilidad. La herencia permite que una clase (hija) herede atributos y métodos de otra (padre), facilitando la reutilización del código. El polimorfismo permite que diferentes clases utilicen los mismos nombres de métodos con comportamientos distintos. La abstracción invita a centrarse en lo esencial de cada entidad, ignorando los detalles irrelevantes. Lenguajes como Java, Python, C#, C++ y Ruby adoptan este paradigma, aunque con matices distintos. La POO ha tenido un enorme éxito para desarrollar aplicaciones complejas gracias a que permite modelar el mundo de forma natural y colaborativa, aunque en ciertas situaciones otros paradigmas pueden resultar más adecuados.', '[{"pregunta":"¿En torno a qué se organiza la POO?","opciones":["Variables","Objetos","Funciones puras","Archivos"],"correcta":1},{"pregunta":"¿Cuáles son los 4 pilares de la POO?","opciones":["Encapsulación, herencia, polimorfismo, abstracción","Suma, resta, multiplicación, división","Texto, imagen, audio, vídeo","Crear, leer, actualizar, borrar"],"correcta":0},{"pregunta":"¿Qué permite la herencia?","opciones":["Reutilizar atributos y métodos","Borrar clases","Impedir el acceso","Cambiar el sistema operativo"],"correcta":0},{"pregunta":"¿Qué lenguaje es orientado a objetos?","opciones":["Java","Ensamblador","HTML","CSS"],"correcta":0}]'::jsonb),

('programacion', 'bachillerato', '{1}', 'Las bases de datos relacionales', 'Las bases de datos relacionales son sistemas de almacenamiento de información estructurada en tablas compuestas por filas y columnas. Cada fila representa un registro y cada columna un campo. Este modelo, propuesto por Edgar Codd en 1970, revolucionó la gestión de datos al proporcionar un marco matemáticamente riguroso basado en la teoría de conjuntos y en el álgebra relacional. Para trabajar con bases de datos relacionales se utiliza un lenguaje estándar llamado SQL, por sus siglas en inglés (Structured Query Language), que permite crear tablas, insertar y modificar datos, definir restricciones y realizar consultas complejas combinando información de varias tablas. Las relaciones entre tablas se establecen mediante claves: la clave primaria identifica de manera única cada registro de una tabla, y las claves foráneas vinculan filas de una tabla con filas de otra. Los sistemas de gestión de bases de datos relacionales, como MySQL, PostgreSQL, Oracle o Microsoft SQL Server, garantizan la integridad y la consistencia de los datos mediante propiedades conocidas como ACID (atomicidad, consistencia, aislamiento y durabilidad). Las bases de datos relacionales son la base de una enorme cantidad de aplicaciones, desde sistemas bancarios hasta comercios electrónicos, pasando por aplicaciones empresariales y plataformas sociales. A pesar de la aparición de bases de datos NoSQL, las relacionales siguen siendo la elección dominante en muchos sectores gracias a su madurez y fiabilidad.', '[{"pregunta":"¿Quién propuso el modelo relacional?","opciones":["Turing","Codd","Dijkstra","Knuth"],"correcta":1},{"pregunta":"¿Qué lenguaje se usa para consultarlas?","opciones":["Python","SQL","HTML","Bash"],"correcta":1},{"pregunta":"¿Qué identifica unívocamente una fila?","opciones":["Clave foránea","Clave primaria","Índice secundario","Comentario"],"correcta":1},{"pregunta":"¿Qué significa la A de ACID?","opciones":["Atomicidad","Automatización","Accesibilidad","Archivo"],"correcta":0}]'::jsonb),

('programacion', 'bachillerato', '{1}', 'El desarrollo web: front-end y back-end', 'El desarrollo web es una de las áreas más activas y demandadas dentro de la informática. Consiste en crear sitios y aplicaciones que funcionan en la web, es decir, accesibles desde un navegador. Se divide tradicionalmente en dos grandes partes: el front-end y el back-end. El front-end es la parte con la que interactúa directamente el usuario. Incluye el diseño visual, la disposición de los elementos, las animaciones y la interactividad. Se basa en tres tecnologías fundamentales: HTML, que define la estructura; CSS, que se encarga del estilo y la presentación; y JavaScript, el lenguaje que aporta interactividad y lógica del lado del cliente. Para desarrollar interfaces más complejas se utilizan frameworks y bibliotecas como React, Angular o Vue. El back-end, por su parte, es la parte que funciona en los servidores y se ocupa de gestionar los datos, la lógica de negocio, la seguridad y la comunicación con las bases de datos. En el back-end se usan lenguajes como Python, Node.js, Java, C#, Ruby o PHP, además de frameworks como Django, Express, Spring o Laravel. El intercambio de información entre front-end y back-end se realiza normalmente a través de APIs, a menudo en formato JSON. Un desarrollador web puede especializarse en front-end, en back-end o ser full-stack, si domina ambas partes. El desarrollo web evoluciona rápidamente y requiere aprendizaje continuo.', '[{"pregunta":"¿Qué hace el front-end?","opciones":["Gestión de servidores","Interacción con el usuario","Copia de seguridad","Administración de redes"],"correcta":1},{"pregunta":"¿Qué lenguaje estructura una página web?","opciones":["CSS","HTML","Python","SQL"],"correcta":1},{"pregunta":"¿Qué formato de datos es habitual entre front y back?","opciones":["JSON","PDF","JPG","EXE"],"correcta":0},{"pregunta":"¿Cómo se llama quien domina ambas partes?","opciones":["Front-end","Back-end","Full-stack","Mid-stack"],"correcta":2}]'::jsonb),

('programacion', 'bachillerato', '{1}', 'La importancia del control de versiones', 'El control de versiones es una práctica esencial en el desarrollo de software moderno. Consiste en llevar un registro sistemático de los cambios realizados en los archivos de un proyecto, de manera que se pueda consultar su historial, volver a versiones anteriores o trabajar en paralelo con otras personas sin interferencias. El sistema de control de versiones más popular en la actualidad es Git, creado en 2005 por Linus Torvalds, el mismo programador del núcleo Linux. Git permite a los desarrolladores crear ramas (branches), trabajar en ellas de manera independiente y luego unirlas (merge) cuando el trabajo está listo para integrarse. Plataformas como GitHub, GitLab o Bitbucket añaden a Git funcionalidades de colaboración en línea, como la gestión de incidencias, la revisión de código (pull requests) o la integración continua. Un flujo de trabajo habitual incluye clonar un repositorio remoto, crear una rama para una nueva funcionalidad o corrección, realizar cambios locales, confirmarlos (commit), subirlos al servidor (push) y solicitar su incorporación al código principal. El control de versiones no solo es útil en proyectos grandes y colaborativos: también aporta seguridad y claridad al trabajo individual, pues permite experimentar sin miedo y volver atrás si algo sale mal. Dominar Git se considera hoy una habilidad básica para cualquier programador profesional y muchas empresas lo exigen desde el primer momento.', '[{"pregunta":"¿Quién creó Git?","opciones":["Bill Gates","Linus Torvalds","Mark Zuckerberg","Steve Jobs"],"correcta":1},{"pregunta":"¿Qué permite una rama?","opciones":["Eliminar el proyecto","Trabajar en paralelo de forma independiente","Copiar vídeos","Cerrar el ordenador"],"correcta":1},{"pregunta":"¿Qué plataforma usa Git?","opciones":["Instagram","GitHub","Facebook","YouTube"],"correcta":1},{"pregunta":"¿Qué ventaja aporta el control de versiones?","opciones":["Permite experimentar y volver atrás","Borra datos","Impide el trabajo","Aumenta el tamaño del disco inútilmente"],"correcta":0}]'::jsonb),

('programacion', 'bachillerato', '{1}', 'Las estructuras de datos fundamentales', 'Las estructuras de datos son formas organizadas de almacenar y gestionar información para que las operaciones puedan realizarse de manera eficiente. Su elección adecuada es crucial para el rendimiento de un programa. Entre las estructuras más fundamentales destacan los arrays o vectores, que almacenan elementos en posiciones consecutivas y permiten acceder a ellos mediante un índice; las listas enlazadas, donde cada elemento contiene una referencia al siguiente, facilitando inserciones y borrados en medio de la lista pero dificultando el acceso aleatorio; las pilas, que siguen el principio LIFO (último en entrar, primero en salir), como una pila de platos; y las colas, que siguen el principio FIFO (primero en entrar, primero en salir), como una fila en una cafetería. Otras estructuras más avanzadas son los árboles, que organizan jerárquicamente la información y permiten búsquedas rápidas, especialmente los árboles binarios de búsqueda, los árboles AVL o los rojo-negro; los grafos, que representan relaciones entre entidades y se utilizan para modelar redes sociales, caminos o dependencias; y las tablas hash, que asocian claves con valores permitiendo búsquedas en tiempo prácticamente constante. Cada estructura tiene ventajas e inconvenientes en términos de memoria, velocidad de acceso, inserción o eliminación. Un buen programador debe conocer las características principales de cada una para poder elegir la más adecuada en función del problema concreto y del comportamiento esperado del programa.', '[{"pregunta":"¿Qué principio sigue una pila?","opciones":["FIFO","LIFO","Aleatorio","Alfabético"],"correcta":1},{"pregunta":"¿Cómo accede un array?","opciones":["Por puntero","Por índice","Por nombre","Por fecha"],"correcta":1},{"pregunta":"¿Qué estructura es ideal para búsquedas rápidas por clave?","opciones":["Lista enlazada","Pila","Tabla hash","Cola"],"correcta":2},{"pregunta":"¿Qué usan para modelar relaciones?","opciones":["Árboles","Grafos","Pilas","Arrays"],"correcta":1}]'::jsonb),

('programacion', 'bachillerato', '{1}', 'La depuración de programas', 'La depuración (debugging en inglés) es el proceso de localizar y corregir errores en un programa informático. Por experiencia, se sabe que todos los programas contienen fallos (bugs) y que parte esencial del trabajo de un desarrollador consiste en encontrarlos y arreglarlos. La expresión bug se atribuye popularmente a la ingeniera Grace Hopper, quien en 1947 encontró una polilla real dentro de una máquina, causando un fallo, aunque el término ya se usaba antes en ingeniería. Los errores pueden ser de distintos tipos: sintácticos, si incumplen las reglas del lenguaje y son detectados por el compilador o el intérprete; de ejecución, que ocurren solo al correr el programa; y lógicos, los más difíciles, cuando el programa funciona pero produce resultados incorrectos. Para depurar existen diversas técnicas y herramientas. Los mensajes impresos en la consola permiten rastrear el valor de las variables en puntos concretos. Los depuradores (debuggers) integrados en los entornos de desarrollo permiten detener la ejecución, examinar el estado del programa, avanzar instrucción por instrucción o establecer puntos de interrupción. Otras técnicas incluyen las pruebas unitarias, que comprueban automáticamente que cada función produce el resultado esperado, y la revisión por pares, en la que otros programadores inspeccionan el código en busca de problemas. Una actitud metódica y paciente es fundamental: la depuración es tanto una habilidad técnica como una disciplina mental.', '[{"pregunta":"¿A quién se atribuye la palabra bug?","opciones":["Alan Turing","Grace Hopper","Linus Torvalds","Ada Lovelace"],"correcta":1},{"pregunta":"¿Qué tipo de error es el más difícil?","opciones":["Sintáctico","De ejecución","Lógico","Tipográfico"],"correcta":2},{"pregunta":"¿Qué hace un debugger?","opciones":["Imprime documentos","Permite examinar la ejecución paso a paso","Apaga el ordenador","Diseña gráficos"],"correcta":1},{"pregunta":"¿Qué son las pruebas unitarias?","opciones":["Entrevistas","Comprobaciones automáticas de funciones","Revisiones de diseño","Diagramas de flujo"],"correcta":1}]'::jsonb),

('programacion', 'bachillerato', '{1}', 'La ciberseguridad y la protección de datos', 'La ciberseguridad es el conjunto de prácticas, tecnologías y procesos destinados a proteger sistemas informáticos, redes, dispositivos y datos frente a accesos no autorizados, ataques y daños. En un mundo cada vez más digital, la seguridad informática es una preocupación crítica tanto para las empresas como para los gobiernos y los ciudadanos. Los ataques más comunes incluyen los virus, los gusanos, los troyanos y el ransomware, que secuestra archivos y pide un rescate; las campañas de phishing, que engañan a las víctimas para que entreguen sus contraseñas; los ataques de denegación de servicio (DDoS), que saturan un servicio con peticiones; y las explotaciones de vulnerabilidades en el software. Para defenderse, las organizaciones utilizan firewalls, antivirus, sistemas de detección de intrusiones, cifrado de datos, autenticación multifactor y políticas estrictas de acceso y copias de seguridad. El usuario final también desempeña un papel fundamental: contraseñas robustas, actualizaciones regulares, prudencia ante enlaces sospechosos y respaldos periódicos reducen enormemente los riesgos. A nivel jurídico, normativas como el Reglamento General de Protección de Datos (RGPD) de la Unión Europea exigen a las empresas una gestión responsable de los datos personales y prevén sanciones importantes en caso de incumplimiento. La ciberseguridad es una disciplina en constante evolución, pues los atacantes y los defensores se adaptan continuamente a nuevas tecnologías y amenazas.', '[{"pregunta":"¿Qué tipo de ataque engaña al usuario?","opciones":["DDoS","Phishing","Firewall","Backup"],"correcta":1},{"pregunta":"¿Qué norma europea protege datos personales?","opciones":["LOPD","RGPD","CEPI","DMCA"],"correcta":1},{"pregunta":"¿Qué es el ransomware?","opciones":["Un antivirus","Malware que secuestra archivos","Una red","Un cortafuegos"],"correcta":1},{"pregunta":"¿Qué recomendación es básica para el usuario?","opciones":["Contraseñas débiles","Contraseñas robustas y actualizaciones","Compartir claves","No hacer copias"],"correcta":1}]'::jsonb),

('programacion', 'bachillerato', '{1}', 'La programación funcional', 'La programación funcional es un paradigma en el que los programas se construyen aplicando y componiendo funciones, tratándolas como ciudadanos de primera clase. A diferencia de la programación imperativa, que describe cómo resolver un problema mediante instrucciones paso a paso, la programación funcional pone el énfasis en qué se quiere calcular, usando expresiones y funciones matemáticas. Las ideas centrales son la inmutabilidad de los datos (una vez creada una estructura, no se modifica), las funciones puras (producen siempre el mismo resultado para los mismos argumentos y no tienen efectos colaterales) y las funciones de orden superior (funciones que pueden recibir o devolver otras funciones). Lenguajes como Haskell, Clojure, Erlang o F# están construidos alrededor de este paradigma, pero muchos lenguajes modernos como JavaScript, Python, Scala o Kotlin incorporan también muchas de sus ideas. Conceptos como map, filter y reduce, muy utilizados para procesar listas, provienen de este mundo y permiten escribir código conciso y expresivo. La programación funcional facilita el razonamiento formal sobre los programas, la paralelización y la construcción de software robusto y libre de ciertos tipos de errores. No es, sin embargo, una panacea: requiere un esfuerzo de cambio de mentalidad y puede ser menos intuitiva para quienes se han formado con enfoques imperativos. Muchos proyectos modernos combinan estilos funcionales y orientados a objetos para aprovechar las ventajas de cada paradigma.', '[{"pregunta":"¿Qué caracteriza a una función pura?","opciones":["Tiene efectos secundarios","Produce el mismo resultado sin efectos colaterales","Imprime siempre","Nunca termina"],"correcta":1},{"pregunta":"¿Qué significa inmutabilidad?","opciones":["Los datos cambian","Los datos no se modifican","Es un lenguaje","Es un error"],"correcta":1},{"pregunta":"¿Qué lenguaje es principalmente funcional?","opciones":["Haskell","C","Ensamblador","COBOL"],"correcta":0},{"pregunta":"¿Qué funciones manejan listas de forma funcional?","opciones":["map, filter, reduce","compile, link, run","init, start, stop","open, read, close"],"correcta":0}]'::jsonb),

('programacion', 'bachillerato', '{1}', 'Las APIs y la integración de sistemas', 'Una API, del inglés Application Programming Interface, es un conjunto de reglas y definiciones que permite que distintos programas se comuniquen entre sí. Las APIs actúan como intermediarios que exponen funcionalidades o datos de un sistema para que otros puedan utilizarlos sin conocer los detalles internos. Por ejemplo, cuando una aplicación móvil obtiene el pronóstico del tiempo, está consultando una API que proporciona los datos meteorológicos en formato estructurado, normalmente JSON o XML. Las APIs modernas siguen muchas veces el estilo REST, que organiza los recursos en URLs y los manipula mediante verbos HTTP como GET (para obtener datos), POST (para crear), PUT (para actualizar) y DELETE (para eliminar). También está ganando popularidad el enfoque GraphQL, que permite al cliente pedir exactamente los datos que necesita. Las APIs bien diseñadas ofrecen ventajas enormes: permiten reutilizar servicios existentes, facilitan la integración entre aplicaciones, aceleran el desarrollo y fomentan la creación de ecosistemas donde diferentes actores pueden colaborar. En cambio, unas APIs mal diseñadas o mal documentadas pueden ser una fuente de frustración y errores. La documentación clara, el versionado, la seguridad y el control de acceso son aspectos críticos. Hoy en día prácticamente todos los servicios importantes, desde redes sociales hasta plataformas de pago, exponen APIs públicas que los desarrolladores utilizan para crear aplicaciones innovadoras.', '[{"pregunta":"¿Qué significan las siglas API?","opciones":["Application Programming Interface","Advanced Protocol Integration","Automated Process Identification","App Public Info"],"correcta":0},{"pregunta":"¿Qué formato es habitual en APIs?","opciones":["MP3","JSON","EXE","DOC"],"correcta":1},{"pregunta":"¿Qué verbo HTTP obtiene datos?","opciones":["DELETE","POST","GET","PUT"],"correcta":2},{"pregunta":"¿Qué ventaja tienen las APIs?","opciones":["Reutilizar servicios y facilitar la integración","Aumentar costes","Impedir la colaboración","Ocultar los datos siempre"],"correcta":0}]'::jsonb),

('programacion', 'bachillerato', '{1}', 'La inteligencia artificial y el aprendizaje automático', 'La inteligencia artificial (IA) es la rama de la informática que pretende crear máquinas capaces de realizar tareas que habitualmente requieren inteligencia humana. Dentro de la IA, el aprendizaje automático o machine learning ha cobrado especial relevancia en las últimas décadas. Su idea central es que, en lugar de programar explícitamente a un ordenador para cada tarea, se le pueden suministrar grandes cantidades de datos y dejar que aprenda por sí mismo los patrones que los caracterizan. El aprendizaje automático se clasifica habitualmente en tres categorías: supervisado, cuando el sistema aprende a partir de ejemplos etiquetados con la respuesta correcta; no supervisado, cuando debe encontrar estructuras en datos sin etiquetas; y por refuerzo, cuando aprende a través de prueba y error en interacción con un entorno. Un tipo especial de modelos, las redes neuronales profundas, han revolucionado campos como la visión por ordenador, el reconocimiento de voz, la traducción automática y los asistentes conversacionales. La IA plantea desafíos técnicos importantes, como la calidad de los datos o la capacidad computacional, pero también profundas cuestiones éticas: sesgo en las decisiones, protección de la privacidad, responsabilidad ante errores o el futuro del empleo en muchos sectores. Desarrollar sistemas de IA responsables y transparentes es uno de los retos más importantes de la informática contemporánea.', '[{"pregunta":"¿Qué hace el aprendizaje automático?","opciones":["Programar cada tarea manualmente","Aprender patrones de los datos","Copiar archivos","Imprimir documentos"],"correcta":1},{"pregunta":"¿Cuántas categorías principales de ML existen?","opciones":["Dos","Tres","Cuatro","Cinco"],"correcta":1},{"pregunta":"¿Qué tipo de red es clave en IA moderna?","opciones":["Red neuronal profunda","Red eléctrica","Red de pesca","Red social"],"correcta":0},{"pregunta":"¿Qué reto ético menciona el texto?","opciones":["El color de los cables","El sesgo en decisiones","El tamaño del disco","El brillo de la pantalla"],"correcta":1}]'::jsonb),

('programacion', 'bachillerato', '{1}', 'El software libre y el código abierto', 'El software libre es aquel cuyo código fuente puede ser usado, estudiado, modificado y distribuido libremente por cualquier persona, siempre respetando las condiciones de su licencia. El movimiento del software libre fue iniciado a mediados de los años ochenta por Richard Stallman, quien fundó el proyecto GNU y la Free Software Foundation. El software libre no es necesariamente gratuito: la libertad se refiere a los derechos de los usuarios sobre el programa, no al precio. Años más tarde apareció el término software de código abierto, promovido por la Open Source Initiative, que pone el acento en los beneficios prácticos de compartir el código, como la transparencia, la fiabilidad y la colaboración. Ambos movimientos se solapan en gran medida, aunque sus filosofías tienen matices diferentes. Entre los proyectos más famosos se encuentran el sistema operativo Linux, los servidores web Apache y Nginx, los lenguajes Python y Ruby, el navegador Firefox, el paquete ofimático LibreOffice o la base de datos MySQL. Muchas empresas utilizan software libre y también contribuyen a su desarrollo. Las licencias libres, como la GPL, la MIT o la Apache, regulan los derechos y obligaciones de quienes utilizan o distribuyen el software. El ecosistema del software libre ha transformado la industria informática, abaratando el acceso a herramientas potentes, fomentando la educación y contribuyendo a un conocimiento compartido a nivel mundial.', '[{"pregunta":"¿Quién inició el movimiento del software libre?","opciones":["Linus Torvalds","Richard Stallman","Bill Gates","Mark Shuttleworth"],"correcta":1},{"pregunta":"¿El software libre siempre es gratuito?","opciones":["Sí","No, la libertad no es el precio","Solo para estudiantes","Solo para empresas"],"correcta":1},{"pregunta":"¿Qué sistema operativo es libre?","opciones":["Windows","macOS","Linux","iOS"],"correcta":2},{"pregunta":"¿Qué licencia NO es libre?","opciones":["GPL","MIT","Apache","Licencia propietaria cerrada"],"correcta":3}]'::jsonb),

('programacion', 'bachillerato', '{1}', 'La computación en la nube', 'La computación en la nube, o cloud computing, es un modelo de prestación de servicios informáticos a través de internet. En lugar de ejecutar aplicaciones en ordenadores propios y almacenar los datos en discos locales, los usuarios y las empresas pueden alquilar recursos de computación, almacenamiento y software que se ejecutan en centros de datos remotos gestionados por empresas proveedoras. Los tres grandes modelos de servicios en la nube son: Infraestructura como servicio (IaaS), que ofrece máquinas virtuales, redes y almacenamiento; Plataforma como servicio (PaaS), que proporciona entornos para desarrollar y ejecutar aplicaciones sin preocuparse por el hardware; y Software como servicio (SaaS), que ofrece aplicaciones listas para usar, como el correo electrónico o las suites ofimáticas web. Los principales proveedores son Amazon Web Services, Microsoft Azure y Google Cloud. La nube ofrece ventajas como el escalado flexible según la demanda, la reducción de costes iniciales, la accesibilidad desde cualquier lugar y la delegación del mantenimiento al proveedor. Sin embargo, también plantea desafíos: dependencia del proveedor, cuestiones de privacidad y seguridad de los datos, posibles costes imprevistos y necesidad de buena conexión a internet. La nube ha transformado profundamente el desarrollo y la operación del software, facilitando la creación rápida de servicios a escala global y permitiendo a pequeñas empresas competir con grandes corporaciones al disponer de infraestructura que antes estaba fuera de su alcance.', '[{"pregunta":"¿Qué es SaaS?","opciones":["Software as a Service","Space and Storage","Secure Access Service","Simple Application Server"],"correcta":0},{"pregunta":"¿Quién NO es un proveedor mayor de nube?","opciones":["AWS","Azure","Google Cloud","Blender"],"correcta":3},{"pregunta":"¿Qué ventaja ofrece la nube?","opciones":["Escalado flexible","Discos físicos","Falta de servicios","Imposibilidad de acceso"],"correcta":0},{"pregunta":"¿Qué desafío plantea?","opciones":["Independencia total","Dependencia del proveedor y privacidad","Costes siempre fijos","Sin conexión"],"correcta":1}]'::jsonb),

('programacion', 'bachillerato', '{1}', 'Las buenas prácticas de programación', 'Escribir código que funcione no basta: el código debe ser legible, mantenible y fácil de ampliar. Las buenas prácticas de programación son un conjunto de reglas y hábitos que los desarrolladores profesionales aplican para conseguirlo. Entre las más importantes destacan: elegir nombres claros y descriptivos para variables, funciones y clases; mantener funciones y métodos cortos y con una sola responsabilidad; comentar el código solo cuando sea necesario y con información útil, evitando explicar lo obvio; evitar la duplicación de código mediante la reutilización adecuada; y seguir una guía de estilo coherente. Otro principio clave es el llamado KISS (Keep It Simple, Stupid), que recomienda evitar soluciones innecesariamente complicadas, y el DRY (Do not Repeat Yourself), que insta a no repetir la misma lógica en varios lugares. También resulta fundamental separar las responsabilidades de cada parte del sistema, aplicar patrones de diseño cuando sean adecuados, escribir pruebas automáticas para validar el código y utilizar herramientas de análisis estático y linters que detectan errores comunes. La revisión de código por parte de otros desarrolladores y el trabajo en equipo con herramientas de control de versiones contribuyen enormemente a la calidad del software. Aplicar estas buenas prácticas exige disciplina, experiencia y voluntad de aprender continuamente, pero sus beneficios son enormes en proyectos reales, donde el código debe mantenerse y modificarse durante años por equipos cambiantes.', '[{"pregunta":"¿Qué significa DRY?","opciones":["Do not Repeat Yourself","Do Run You","Dry Run Yes","Deep Recursive Yield"],"correcta":0},{"pregunta":"¿Qué recomienda el principio KISS?","opciones":["Abandonar proyectos","Mantenerlo simple","Añadir complejidad","Crear muchas clases"],"correcta":1},{"pregunta":"¿Qué herramienta detecta errores comunes automáticamente?","opciones":["Linter","Compilador solamente","Servidor DNS","Router"],"correcta":0},{"pregunta":"¿Qué debe hacer una función ideal?","opciones":["Tener muchas responsabilidades","Ser corta y con una sola responsabilidad","No retornar valores","No tener nombre"],"correcta":1}]'::jsonb);

