INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('tecnologia', 'bachillerato', '{1}', 'La evolución de los materiales', 'A lo largo de la historia, los materiales disponibles han determinado en gran medida el nivel tecnológico de cada sociedad. Las primeras civilizaciones utilizaban materiales naturales como la piedra, la madera, el hueso, el barro o las fibras vegetales. Más tarde, con la metalurgia, llegaron las edades del cobre, del bronce y del hierro, que dieron nombre a épocas enteras. Durante los últimos siglos se han desarrollado numerosos materiales nuevos, muchos de los cuales han transformado por completo la industria, los transportes, la construcción y la vida cotidiana. Los metales continúan siendo imprescindibles: el hierro y el acero son la base de las estructuras modernas; el aluminio se utiliza ampliamente en la aeronáutica y el envasado por su ligereza; el cobre es esencial en la electricidad. Junto a ellos, los polímeros o plásticos, desarrollados en el siglo XX, aportan flexibilidad, ligereza y bajo coste, pero plantean serios problemas medioambientales debido a su difícil degradación. Los materiales cerámicos modernos son resistentes a altas temperaturas y se utilizan en turbinas o prótesis dentales. Los materiales compuestos, como la fibra de carbono, combinan propiedades de distintos materiales y son fundamentales en deportes de competición, automovilismo y aviación. Hoy, la investigación avanza en nanomateriales, materiales inteligentes y biomateriales, abriendo posibilidades que hace pocos años parecían imposibles en campos como la medicina o la sostenibilidad.', '[{"pregunta":"¿Qué edad histórica NO está ligada a un metal?","opciones":["Edad del cobre","Edad del bronce","Edad del hierro","Edad del carbón"],"correcta":3},{"pregunta":"¿Qué metal se usa por su ligereza en aeronáutica?","opciones":["Hierro","Aluminio","Plomo","Cobre"],"correcta":1},{"pregunta":"¿Qué problema plantean los plásticos?","opciones":["Alto coste","Difícil degradación","Demasiada rigidez","Escasa disponibilidad"],"correcta":1},{"pregunta":"¿Qué son los materiales compuestos?","opciones":["Mezclas de metales","Combinan propiedades de distintos materiales","Solo plásticos","Líquidos viscosos"],"correcta":1}]'::jsonb),

('tecnologia', 'bachillerato', '{1}', 'La electricidad como fuente de energía', 'La electricidad es una de las formas de energía más versátiles y limpias en su punto de uso, lo que la ha convertido en pilar fundamental de la vida moderna. Su generación, sin embargo, puede realizarse a partir de fuentes muy diversas. Las centrales térmicas convencionales queman combustibles fósiles como el carbón, el gas natural o el fueloil para producir vapor que mueve turbinas acopladas a generadores. Las centrales nucleares utilizan la fisión del uranio para calentar el agua y obtener el mismo efecto. Entre las fuentes renovables destacan la hidroeléctrica, que aprovecha la energía del agua en movimiento; la eólica, basada en grandes aerogeneradores que captan la energía del viento; la solar fotovoltaica, que convierte directamente la luz en electricidad mediante paneles; la solar térmica de concentración; la geotérmica, que explota el calor del subsuelo; y la biomasa, procedente de residuos orgánicos. La electricidad producida en estas centrales llega a los hogares y las fábricas a través de la red eléctrica, que utiliza transformadores, líneas de alta tensión y subestaciones para adaptar la tensión a cada tramo. Uno de los grandes retos actuales consiste en integrar en la red las energías renovables intermitentes, como la solar y la eólica, mediante sistemas de almacenamiento eficientes, redes inteligentes y políticas adecuadas. La transición energética es esencial para reducir las emisiones contaminantes y luchar contra el cambio climático.', '[{"pregunta":"¿Qué central usa uranio?","opciones":["Hidroeléctrica","Térmica de carbón","Nuclear","Eólica"],"correcta":2},{"pregunta":"¿Qué tipo de energía aprovecha el viento?","opciones":["Solar","Eólica","Geotérmica","Biomasa"],"correcta":1},{"pregunta":"¿Qué papel tienen los transformadores?","opciones":["Almacenan luz","Adaptan la tensión en la red","Generan uranio","Calientan agua"],"correcta":1},{"pregunta":"¿Qué reto plantean solar y eólica?","opciones":["Su intermitencia","Que no existen","Que son caras siempre","Que contaminan mucho"],"correcta":0}]'::jsonb),

('tecnologia', 'bachillerato', '{1}', 'La electrónica analógica y digital', 'La electrónica es la rama de la tecnología que se ocupa del diseño y el uso de circuitos eléctricos que manipulan señales para realizar funciones útiles, como amplificar sonidos, procesar información o controlar máquinas. Se distinguen dos grandes ramas: la electrónica analógica y la digital. La electrónica analógica trabaja con señales continuas, que pueden tomar cualquier valor dentro de un rango; es la utilizada, por ejemplo, para amplificar una voz en un micrófono o para captar la señal de una antena. La electrónica digital, por su parte, se basa en señales que solo pueden tomar dos valores discretos, representados habitualmente como cero y uno. Esta representación binaria permite codificar información de manera robusta y es la base de todos los ordenadores, teléfonos móviles y dispositivos digitales modernos. Los componentes clave de la electrónica son las resistencias, los condensadores, las bobinas, los diodos y los transistores. El transistor, inventado en 1947, supuso una revolución: más pequeño, rápido y económico que las válvulas de vacío anteriores, permitió la miniaturización y el desarrollo de los circuitos integrados con millones de componentes en un solo chip. Hoy, la microelectrónica y la nanoelectrónica siguen avanzando hacia dispositivos cada vez más potentes y eficientes, al tiempo que se investigan nuevas tecnologías como la computación cuántica, que promete revolucionar el procesamiento de información en las próximas décadas.', '[{"pregunta":"¿Cuántos valores usa una señal digital?","opciones":["Dos (0 y 1)","Tres","Continuos","Diez"],"correcta":0},{"pregunta":"¿Cuándo se inventó el transistor?","opciones":["1900","1947","1975","2000"],"correcta":1},{"pregunta":"¿Qué permite el circuito integrado?","opciones":["Combinar millones de componentes en un chip","Eliminar la electrónica","Ver la luz","Aumentar la resistencia"],"correcta":0},{"pregunta":"¿Qué rama manipula señales continuas?","opciones":["Digital","Analógica","Cuántica","Óptica"],"correcta":1}]'::jsonb),

('tecnologia', 'bachillerato', '{1}', 'Los sistemas de control automático', 'Un sistema de control automático es un conjunto de dispositivos que gestionan una máquina o un proceso sin necesidad de intervención humana directa, siguiendo unas reglas o una señal de referencia. Estos sistemas son fundamentales en la industria moderna, en los electrodomésticos, en los vehículos y en innumerables dispositivos cotidianos. Se distinguen dos tipos principales: los sistemas en bucle abierto, en los que la salida no se mide para corregir la entrada, y los sistemas en bucle cerrado o retroalimentados, en los que un sensor mide la salida y la compara con la referencia para ajustar la acción. Un ejemplo clásico de bucle cerrado es el termostato de una calefacción: el sensor mide la temperatura de la habitación y activa o desactiva el sistema para mantenerla dentro del valor deseado. Los elementos básicos de un sistema de control son los sensores, que detectan magnitudes físicas; los actuadores, que ejecutan las acciones; y los controladores, que interpretan las señales y toman decisiones. Cada vez más a menudo, los controladores son dispositivos programables o microcontroladores que ejecutan algoritmos sofisticados. Los sistemas de control permiten ajustes más precisos, mejor eficiencia energética, mayor seguridad y automatización de tareas repetitivas. La robótica, la domótica y la automatización industrial se basan en los principios del control automático, cuya importancia solo crece en la medida en que aumenta la complejidad de los sistemas técnicos.', '[{"pregunta":"¿Qué tipo de sistema mide la salida para corregirla?","opciones":["Bucle abierto","Bucle cerrado","Sin control","Manual"],"correcta":1},{"pregunta":"¿Qué ejemplo clásico ilustra el bucle cerrado?","opciones":["Un interruptor manual","Un termostato","Una linterna","Un martillo"],"correcta":1},{"pregunta":"¿Qué elemento detecta magnitudes?","opciones":["Actuador","Sensor","Controlador","Resistencia"],"correcta":1},{"pregunta":"¿Qué disciplina se basa en el control automático?","opciones":["Historia del arte","Robótica","Música clásica","Literatura"],"correcta":1}]'::jsonb),

('tecnologia', 'bachillerato', '{1}', 'Las estructuras en ingeniería', 'Las estructuras son conjuntos de elementos unidos entre sí que soportan cargas sin deformarse ni romperse. Estudiar las estructuras es fundamental en la ingeniería civil, la arquitectura y muchos otros campos. Una estructura debe cumplir dos objetivos básicos: soportar las fuerzas que actúan sobre ella y transmitir esas fuerzas al terreno o a otros soportes sin fallar. Los esfuerzos principales que sufren los elementos de una estructura son la tracción, cuando se tira de ellos; la compresión, cuando se empujan; la flexión, cuando se doblan; la torsión, cuando se retuercen; y el cortante, cuando se corta transversalmente. La capacidad de un material para resistir estos esfuerzos depende de sus propiedades mecánicas, como la resistencia a la tracción, la elasticidad o la dureza. Los elementos más comunes son los pilares, que transmiten cargas verticales; las vigas, que las soportan horizontalmente y las transmiten a los pilares; los tirantes, que trabajan a tracción; y los arcos, que convierten la carga en esfuerzo de compresión. La historia de la arquitectura muestra cómo los materiales disponibles han condicionado las formas estructurales: los romanos dominaron el arco de piedra, los góticos desarrollaron bóvedas con arbotantes, y el acero y el hormigón armado permitieron construir rascacielos y grandes puentes modernos. Hoy, los ingenieros diseñan estructuras cada vez más eficientes ayudados por programas de cálculo capaces de simular su comportamiento.', '[{"pregunta":"¿Qué esfuerzo se produce al tirar de un elemento?","opciones":["Compresión","Tracción","Torsión","Flexión"],"correcta":1},{"pregunta":"¿Qué elemento soporta cargas verticales?","opciones":["Viga","Pilar","Arco","Tirante"],"correcta":1},{"pregunta":"¿Qué dominio arquitectónico destaca en los romanos?","opciones":["El arco","El rascacielos","El hormigón","La grúa"],"correcta":0},{"pregunta":"¿Qué materiales permitieron rascacielos?","opciones":["Piedra y madera","Acero y hormigón","Barro y paja","Vidrio y cerámica"],"correcta":1}]'::jsonb),

('tecnologia', 'bachillerato', '{1}', 'Las máquinas y los mecanismos', 'Una máquina es un dispositivo que transforma energía o movimiento para realizar un trabajo útil, ya sea mover objetos, cortar materiales, generar electricidad o procesar información. Cualquier máquina puede descomponerse en mecanismos, conjuntos de piezas que transmiten o transforman movimientos. Los mecanismos más básicos se conocen desde la Antigüedad: la palanca, el torno, la polea, el plano inclinado, la cuña y el tornillo. Estas máquinas simples permiten multiplicar la fuerza, cambiar su dirección o desplazar cargas pesadas con un esfuerzo menor, aunque siempre a costa de incrementar el recorrido o el tiempo. Las máquinas compuestas combinan varias de estas ideas. Entre los mecanismos más importantes destacan los engranajes, que transmiten movimiento rotatorio entre ejes y permiten aumentar o reducir la velocidad de giro; las correas, los piñones y cadenas; los levas, que convierten rotación en movimiento alterno; los sistemas biela-manivela, que transforman el giro en movimiento rectilíneo; y los trinquetes, que permiten el giro en un solo sentido. El estudio de los mecanismos es fundamental en la ingeniería mecánica, el diseño de automóviles, la robótica y la electrónica. Comprender cómo se combinan los elementos básicos para producir movimientos complejos permite crear desde un simple juguete hasta los sistemas de transmisión de un vehículo o un satélite, y supone uno de los pilares del conocimiento tecnológico.', '[{"pregunta":"¿Qué mecanismo simple NO aparece en el texto?","opciones":["Palanca","Polea","Pistón","Tornillo"],"correcta":2},{"pregunta":"¿Qué convierte rotación en alterno?","opciones":["Engranaje","Leva","Polea","Tornillo"],"correcta":1},{"pregunta":"¿Qué mecanismo transmite entre ejes rotatorios?","opciones":["Biela","Engranajes","Leva","Trinquete"],"correcta":1},{"pregunta":"¿Qué siempre incrementa una palanca al reducir la fuerza?","opciones":["El recorrido","El color","El peso del suelo","La temperatura"],"correcta":0}]'::jsonb),

('tecnologia', 'bachillerato', '{1}', 'Los microcontroladores y Arduino', 'Un microcontrolador es un pequeño ordenador integrado en un único chip, diseñado para ejecutar tareas específicas en dispositivos electrónicos. A diferencia de los ordenadores de propósito general, los microcontroladores tienen recursos limitados de memoria y velocidad, pero a cambio son baratos, consumen poca energía y están especialmente pensados para interactuar con el mundo físico mediante sensores y actuadores. Se encuentran en la mayoría de los aparatos domésticos: desde un microondas o una lavadora hasta un coche, un juguete electrónico o un electrodoméstico inteligente. En los últimos años, plataformas abiertas como Arduino han puesto la electrónica al alcance de estudiantes, aficionados e inventores. Arduino es una pequeña placa con un microcontrolador que puede programarse fácilmente con un lenguaje sencillo derivado de C. A ella pueden conectarse numerosos componentes, como sensores de temperatura, de distancia, de luz, pantallas LCD, motores o LEDs, y construir todo tipo de proyectos: desde una regadera automática hasta un robot que evita obstáculos. Gracias a su carácter abierto, Arduino dispone de una enorme comunidad internacional de usuarios que comparten proyectos, esquemas y código. Aprender a trabajar con microcontroladores proporciona una visión muy completa de cómo interactúan el hardware y el software en los sistemas embebidos, y prepara a los estudiantes para campos profesionales en crecimiento como la domótica, el internet de las cosas y la robótica educativa.', '[{"pregunta":"¿Qué es un microcontrolador?","opciones":["Un gran servidor","Un pequeño ordenador integrado en un chip","Una pantalla táctil","Un disco duro grande"],"correcta":1},{"pregunta":"¿Qué lenguaje usa Arduino?","opciones":["Derivado de C","Solo Python","Ensamblador","SQL"],"correcta":0},{"pregunta":"¿Qué componente NO se conecta típicamente a Arduino?","opciones":["Sensor","Motor","Central nuclear","LED"],"correcta":2},{"pregunta":"¿A qué campo profesional prepara?","opciones":["Arqueología","Domótica y robótica","Literatura","Historia del arte"],"correcta":1}]'::jsonb),

('tecnologia', 'bachillerato', '{1}', 'La fabricación aditiva y la impresión 3D', 'La fabricación aditiva, conocida popularmente como impresión 3D, es una técnica que permite crear objetos físicos a partir de un modelo digital añadiendo material capa por capa. A diferencia de los métodos tradicionales, que parten de un bloque de material y retiran lo sobrante mediante corte, fresado o torneado, la impresión 3D construye el objeto progresivamente, lo que reduce desperdicios y permite geometrías imposibles por otros medios. Existen varias tecnologías de impresión 3D. La más popular entre aficionados es la FDM, que funde un filamento de plástico, generalmente PLA o ABS, y lo deposita capa a capa a través de una boquilla caliente. Otras técnicas incluyen la estereolitografía, que solidifica resinas líquidas mediante luz ultravioleta; la sinterización láser selectiva, que funde polvos metálicos o plásticos; y las impresoras industriales que pueden trabajar con metales de uso aeronáutico o incluso con materiales biocompatibles para medicina. La impresión 3D se utiliza en la fabricación rápida de prototipos, en la producción personalizada de piezas de repuesto, en joyería, en prótesis médicas, en arquitectura y en la industria aeroespacial. Los retos actuales incluyen aumentar la velocidad, mejorar la calidad de acabado y ampliar la variedad de materiales disponibles. A largo plazo, esta tecnología promete transformar buena parte de la cadena de producción industrial, acercando la fabricación a los propios usuarios y fomentando la creatividad y la innovación distribuida.', '[{"pregunta":"¿Cómo construye el objeto la impresión 3D?","opciones":["Quitando material","Añadiendo material capa a capa","Quemando plástico","Soldando metal"],"correcta":1},{"pregunta":"¿Qué tecnología usa filamento fundido?","opciones":["FDM","SLA","SLS","DMLS"],"correcta":0},{"pregunta":"¿Qué ventaja tiene frente a la fabricación tradicional?","opciones":["Geometrías imposibles y menor desperdicio","Es más ruidosa","Elimina todo el software","Usa menos electricidad siempre"],"correcta":0},{"pregunta":"¿En qué ámbito NO es habitual su uso?","opciones":["Prototipos","Joyería","Prótesis médicas","Minería masiva"],"correcta":3}]'::jsonb),

('tecnologia', 'bachillerato', '{1}', 'Las redes de ordenadores e internet', 'Una red de ordenadores es un conjunto de dispositivos conectados entre sí que pueden intercambiar datos, compartir recursos y colaborar en la ejecución de tareas. Las redes pueden ser de muy distinta escala: las LAN (redes de área local) cubren una oficina o un edificio, las MAN abarcan una ciudad, y las WAN pueden extenderse por todo un continente o el mundo entero, como ocurre con internet. Internet es la red global por excelencia, una red de redes que conecta miles de millones de dispositivos mediante el conjunto de protocolos TCP/IP. Cada dispositivo conectado tiene una dirección IP única, y la información se transmite dividida en paquetes que viajan por caminos distintos y se reensamblan en el destino. La arquitectura de internet se organiza en capas, lo que facilita el diseño y la gestión. En la parte más visible para los usuarios están las aplicaciones: la web (HTTP/HTTPS), el correo electrónico, la mensajería, los juegos en línea, las videollamadas. Las páginas web están identificadas por URLs y se obtienen mediante servidores que responden a las peticiones de los clientes. Internet ha transformado la economía, la cultura, la educación y la vida cotidiana de miles de millones de personas en pocas décadas. También ha planteado retos como la privacidad, la seguridad, la brecha digital o la desinformación, que requieren respuestas técnicas, sociales y políticas cada vez más sofisticadas.', '[{"pregunta":"¿Qué es una LAN?","opciones":["Red global","Red de área local","Tipo de ordenador","Lenguaje de programación"],"correcta":1},{"pregunta":"¿Qué protocolo es la base de internet?","opciones":["TCP/IP","HTTP únicamente","FTP únicamente","PDF"],"correcta":0},{"pregunta":"¿Cómo se divide la información al transmitirse?","opciones":["En colores","En paquetes","En letras","En fotos"],"correcta":1},{"pregunta":"¿Qué reto NO plantea internet?","opciones":["Privacidad","Seguridad","Brecha digital","Gravedad terrestre"],"correcta":3}]'::jsonb),

('tecnologia', 'bachillerato', '{1}', 'Los sensores y su aplicación', 'Los sensores son dispositivos capaces de detectar magnitudes físicas del entorno y transformarlas en señales eléctricas que pueden ser procesadas por un circuito electrónico. Son los ojos, oídos y manos de los sistemas electrónicos y juegan un papel fundamental en la automatización, la robótica, la domótica y el internet de las cosas. Existen muchos tipos de sensores según la magnitud que miden: sensores de temperatura, como las termistencias o los termopares; sensores de luz, como las fotorresistencias o los fotodiodos; sensores de proximidad, que detectan la cercanía de un objeto; sensores de presión, que miden la fuerza por unidad de superficie; sensores de humedad, de fuerza, de aceleración (acelerómetros), de posición angular (giroscopios), de campo magnético, de presencia, de gases, de corriente eléctrica, entre muchos otros. Los sensores modernos están cada vez más integrados y son capaces de enviar directamente datos digitales a través de buses como I2C o SPI. Se utilizan en aplicaciones tan diversas como los sistemas de seguridad domiciliarios, los termostatos inteligentes, los vehículos autónomos, los smartphones, la medicina o la agricultura de precisión. Junto a los actuadores, los sensores permiten que los sistemas electrónicos interactúen con su entorno de manera inteligente, abriendo la puerta a infinitas aplicaciones en el presente y en el futuro próximo de la tecnología.', '[{"pregunta":"¿Qué hace un sensor?","opciones":["Produce energía","Convierte magnitudes físicas en señales eléctricas","Solo almacena","Borra datos"],"correcta":1},{"pregunta":"¿Qué sensor mide rotación?","opciones":["Termistor","Acelerómetro","Giroscopio","Fotorresistencia"],"correcta":2},{"pregunta":"¿Qué bus digital NO es habitual?","opciones":["I2C","SPI","USB","FUEL"],"correcta":3},{"pregunta":"¿Dónde se aplican los sensores?","opciones":["Solo en ciencia","En domótica, medicina y vehículos","Solo en cocina","En ningún lugar"],"correcta":1}]'::jsonb),

('tecnologia', 'bachillerato', '{1}', 'La domótica y los hogares inteligentes', 'La domótica es el conjunto de tecnologías que permiten automatizar y gestionar remotamente las funciones de un hogar o un edificio, con el objetivo de mejorar la comodidad, la seguridad, la eficiencia energética y la accesibilidad de sus ocupantes. Un hogar domótico puede controlar automáticamente la iluminación, la climatización, las persianas, los sistemas de seguridad, el riego del jardín o incluso los electrodomésticos, en función de la hora, la presencia de personas, la temperatura o cualquier otra variable. En los sistemas más avanzados, todo se gestiona desde una aplicación para móvil, un panel central o mediante asistentes de voz. La domótica se apoya en tres elementos básicos: los sensores, que recogen información del entorno; los actuadores, que ejecutan las acciones; y un sistema de control que interpreta los datos y toma decisiones, ya sea localmente o conectado a la nube. Los estándares y protocolos, como Zigbee, Z-Wave, Matter o Wi-Fi, permiten que dispositivos de distintos fabricantes interactúen entre sí. Las ventajas de la domótica incluyen el ahorro energético, la mejora de la seguridad con alarmas y cámaras inteligentes, el incremento del confort y una mayor independencia para personas mayores o con movilidad reducida. Entre los retos destacan el coste inicial, la complejidad de instalación, los posibles problemas de privacidad y la necesidad de que los dispositivos sigan funcionando cuando no hay conexión a internet o el fabricante deja de dar soporte.', '[{"pregunta":"¿Qué automatiza la domótica?","opciones":["Solo la cocina","Funciones del hogar en general","Vehículos","Aeropuertos"],"correcta":1},{"pregunta":"¿Qué elementos básicos usa?","opciones":["Sensores, actuadores y control","Solo sensores","Solo bombillas","Pantallas y papel"],"correcta":0},{"pregunta":"¿Cuál NO es un estándar domótico?","opciones":["Zigbee","Z-Wave","Matter","MP3"],"correcta":3},{"pregunta":"¿Qué beneficio social aporta?","opciones":["Solo lujo","Mayor independencia para personas mayores","Más complicaciones","Más ruido"],"correcta":1}]'::jsonb),

('tecnologia', 'bachillerato', '{1}', 'Las energías renovables en el futuro', 'Las energías renovables son aquellas que provienen de fuentes prácticamente inagotables a escala humana, como el sol, el viento, el agua, la biomasa o el calor terrestre. A diferencia de los combustibles fósiles, su uso no genera gases de efecto invernadero ni residuos radiactivos persistentes, lo que las convierte en una de las claves para la transición hacia un modelo energético sostenible. En las últimas décadas, su desarrollo ha sido espectacular. La energía solar fotovoltaica ha reducido sus costes de forma drástica y es hoy una de las fuentes más competitivas en muchos lugares del mundo. La energía eólica ha multiplicado su capacidad y se ha extendido con parques en tierra y en el mar. Las mini hidroeléctricas, la geotermia y la biomasa complementan el mix energético renovable. Sin embargo, la transición energética no es sencilla. Algunas fuentes son intermitentes, lo que obliga a contar con sistemas de almacenamiento eficaces, como baterías, bombeo hidráulico o hidrógeno verde. Otras plantean retos medioambientales o sociales en la instalación de las infraestructuras. A nivel político, se requieren acuerdos internacionales, regulaciones justas y ayudas para que la transición sea equitativa y no perjudique a los más vulnerables. Pese a los obstáculos, las energías renovables tienen un papel central en cualquier estrategia seria contra el cambio climático y son, cada vez más, una gran oportunidad para crear empleo, desarrollar tecnología local y fortalecer la soberanía energética de los países.', '[{"pregunta":"¿Qué caracteriza a una renovable?","opciones":["Se agota pronto","Prácticamente inagotable a escala humana","Contamina mucho","Es siempre fósil"],"correcta":1},{"pregunta":"¿Qué energía ha bajado mucho sus costes?","opciones":["Fósil","Solar fotovoltaica","Carbón","Nuclear"],"correcta":1},{"pregunta":"¿Qué soluciona la intermitencia?","opciones":["Más contaminación","Sistemas de almacenamiento","Menos sensores","Menos ingeniería"],"correcta":1},{"pregunta":"¿Qué beneficio extra aportan?","opciones":["Crean empleo y soberanía energética","Aumentan emisiones","Reducen diversidad","Eliminan viento"],"correcta":0}]'::jsonb),

('tecnologia', 'bachillerato', '{1}', 'El diseño CAD y la ingeniería asistida', 'El diseño asistido por ordenador (CAD, del inglés Computer-Aided Design) es el uso de software especializado para elaborar planos y modelos técnicos en dos o tres dimensiones. Desde los años setenta, el CAD ha ido sustituyendo progresivamente al dibujo manual en los despachos de ingeniería, arquitectura y diseño industrial, gracias a su precisión, rapidez y facilidad para modificar propuestas. Los programas modernos permiten construir modelos paramétricos, en los que cada cota, ángulo o relación geométrica se asocia a una variable que puede cambiarse con facilidad, recalculando automáticamente el resto del diseño. También pueden generar automáticamente las vistas normalizadas, los despieces, las listas de materiales y los renderizados fotorrealistas para presentaciones. Junto al CAD, existen otras siglas importantes: CAM (Computer-Aided Manufacturing) designa el software que controla las máquinas de fabricación, como las fresadoras CNC o las impresoras 3D; CAE (Computer-Aided Engineering) incluye las herramientas de simulación para analizar esfuerzos, flujos de fluidos, vibraciones o comportamientos térmicos antes de fabricar físicamente un prototipo. Todas estas disciplinas se integran en un flujo de trabajo digital que va desde la idea hasta la producción en serie. Dominarlas es imprescindible para los ingenieros y diseñadores contemporáneos, y existen programas tanto comerciales, como SolidWorks, AutoCAD, CATIA o Fusion 360, como de código abierto, como FreeCAD, que permiten aprender y trabajar sin licencias costosas.', '[{"pregunta":"¿Qué significa CAD?","opciones":["Computer-Aided Design","Cad Automatic Drawer","Control Active Device","Centro Automatizado Digital"],"correcta":0},{"pregunta":"¿Qué permite el modelo paramétrico?","opciones":["Cambiar variables y recalcular","Pintar manualmente","Imprimir solo texto","Nada especial"],"correcta":0},{"pregunta":"¿Qué sigla se refiere a la fabricación?","opciones":["CAD","CAM","CAE","RAM"],"correcta":1},{"pregunta":"¿Qué programa NO es habitual en CAD?","opciones":["SolidWorks","AutoCAD","CATIA","Photoshop"],"correcta":3}]'::jsonb),

('tecnologia', 'bachillerato', '{1}', 'La ética de la tecnología', 'La tecnología transforma nuestras vidas de maneras cada vez más profundas y rápidas, y plantea dilemas éticos que exigen reflexión. Los avances en inteligencia artificial, biotecnología, vigilancia o redes sociales, por mencionar algunos ejemplos, generan beneficios y oportunidades, pero también riesgos e injusticias. La ética de la tecnología es el campo que se ocupa de analizar estos problemas y proponer principios y prácticas para afrontarlos. Algunas de las preguntas más importantes son: ¿qué derechos tienen los usuarios sobre sus propios datos personales?, ¿cómo evitar que los algoritmos reproduzcan o amplifiquen discriminaciones?, ¿quién es responsable cuando un vehículo autónomo provoca un accidente?, ¿cómo garantizar que las nuevas tecnologías sean accesibles para todos y no agraven las desigualdades?, ¿cómo proteger la democracia frente a la desinformación masiva en internet? La ética tecnológica no consiste en rechazar los avances, sino en orientarlos hacia el bien común. Exige la participación de ingenieros, científicos, legisladores, filósofos, usuarios y políticas públicas capaces de establecer marcos legales adecuados, como los que regulan la protección de datos o la experimentación con humanos. Fomentar la formación ética en las carreras técnicas y científicas es esencial para que los profesionales sean conscientes del impacto de su trabajo. La sociedad en su conjunto debe participar en el debate sobre qué tipo de tecnologías queremos desarrollar y cómo queremos que influyan en nuestro futuro común.', '[{"pregunta":"¿Qué estudia la ética de la tecnología?","opciones":["Solo el hardware","Los problemas morales de los avances técnicos","Solo algoritmos","Solo historia"],"correcta":1},{"pregunta":"¿Qué pregunta NO es ética?","opciones":["Quién responde de un coche autónomo","Cómo evitar discriminación algorítmica","Qué color tiene el cable","Cómo proteger datos"],"correcta":2},{"pregunta":"¿Qué supone una buena ética tecnológica?","opciones":["Rechazar todo progreso","Orientar los avances al bien común","Ignorar al usuario","Limitar el acceso"],"correcta":1},{"pregunta":"¿Quiénes deben participar en el debate?","opciones":["Solo ingenieros","Ingenieros, filósofos, políticas públicas y sociedad","Solo filósofos","Solo empresas"],"correcta":1}]'::jsonb),

('tecnologia', 'bachillerato', '{1}', 'Los vehículos eléctricos y el transporte sostenible', 'Los vehículos eléctricos son automóviles que utilizan motores eléctricos alimentados por baterías recargables en lugar de motores de combustión interna. A diferencia de los coches tradicionales, no emiten gases contaminantes durante su uso, lo que los convierte en una herramienta importante para reducir la contaminación en las ciudades y combatir el cambio climático. En los últimos años, su tecnología ha mejorado notablemente: las baterías son más eficientes, ofrecen mayor autonomía, los precios han ido bajando y la red de puntos de recarga se ha ampliado en muchos países. Aunque los vehículos eléctricos solo representan todavía una fracción de las ventas globales, su crecimiento es constante y numerosos gobiernos están planificando el fin progresivo de los motores de combustión. Existen también vehículos híbridos, que combinan un motor térmico con uno eléctrico, reduciendo el consumo y las emisiones sin depender totalmente de una infraestructura de recarga. Además del automóvil privado, la electrificación afecta al transporte público, con autobuses eléctricos o trenes, y a los vehículos ligeros, como bicicletas y patinetes eléctricos, que están revolucionando la movilidad urbana. El transporte sostenible no se limita sin embargo a sustituir motores: incluye también la apuesta por el transporte público, la bicicleta, los desplazamientos a pie y un diseño urbano que reduzca la necesidad de grandes desplazamientos. Combinar todas estas estrategias es esencial para construir ciudades más limpias, saludables y habitables en el futuro próximo.', '[{"pregunta":"¿Qué ventaja ambiental tienen los eléctricos?","opciones":["No emiten gases en uso","Son más baratos siempre","Son más ruidosos","No necesitan energía"],"correcta":0},{"pregunta":"¿Qué es un vehículo híbrido?","opciones":["Solo eléctrico","Combina motor térmico y eléctrico","Solo de hidrógeno","Solo solar"],"correcta":1},{"pregunta":"¿Qué mejora ha permitido su expansión?","opciones":["Baterías más eficientes","Menos ruedas","Menos seguridad","Menor autonomía"],"correcta":0},{"pregunta":"¿Qué NO es parte del transporte sostenible?","opciones":["Bicicletas","Transporte público","Caminar","Aumentar autopistas"],"correcta":3}]'::jsonb),

('tecnologia', 'bachillerato', '{1}', 'El internet de las cosas', 'El internet de las cosas, abreviado como IoT por sus siglas en inglés, designa la red creciente de objetos cotidianos conectados a internet y capaces de enviar y recibir datos. Desde un termostato inteligente hasta una pulsera que mide la actividad física, pasando por neveras, lámparas, cerraduras o sensores medioambientales, los dispositivos IoT comparten la idea de transformar objetos físicos en fuentes de información y en puntos de control remoto. Cada dispositivo dispone generalmente de uno o más sensores, una pequeña unidad de procesamiento y un módulo de comunicación inalámbrica, y se conecta a servidores en la nube donde los datos se almacenan y se analizan. Entre las tecnologías de comunicación más utilizadas se encuentran el Wi-Fi, el Bluetooth, LoRa, Zigbee y las redes móviles. Las aplicaciones del IoT son enormes: en la agricultura, sensores de humedad y temperatura permiten optimizar el riego; en las ciudades, el alumbrado inteligente ahorra energía; en la industria, máquinas conectadas ayudan a anticipar averías y a optimizar la producción; en la salud, los dispositivos portátiles permiten monitorizar a distancia a pacientes crónicos. Sin embargo, la expansión del IoT plantea importantes retos de seguridad y privacidad, pues cada dispositivo conectado es un posible punto de ataque y produce datos sensibles. Diseñar sistemas seguros y respetuosos con la privacidad es uno de los grandes desafíos del futuro tecnológico.', '[{"pregunta":"¿Qué significa IoT?","opciones":["Internet of Things","Input Output Terminal","Internal Object Technique","Interconnected Open Tools"],"correcta":0},{"pregunta":"¿Qué NO suele tener un dispositivo IoT?","opciones":["Sensor","Unidad de procesamiento","Conexión inalámbrica","Motor de explosión"],"correcta":3},{"pregunta":"¿Qué aplicación es típica del IoT?","opciones":["Riego agrícola inteligente","Pintura al óleo","Escribir a máquina","Silbatos manuales"],"correcta":0},{"pregunta":"¿Qué reto importante plantea?","opciones":["Seguridad y privacidad","Color de carcasa","Peso excesivo","Idioma del manual"],"correcta":0}]'::jsonb),

('tecnologia', 'bachillerato', '{1}', 'La robótica y sus aplicaciones', 'La robótica es el campo multidisciplinar que se ocupa del diseño, la construcción y el uso de robots, máquinas capaces de ejecutar tareas de manera autónoma o semiautónoma. Los robots combinan elementos mecánicos, electrónicos y de programación, y pueden adoptar formas y tamaños muy variados, desde los brazos robóticos que ensamblan coches en las fábricas hasta los pequeños robots educativos que aprenden los estudiantes, los drones que sobrevuelan zonas difíciles o los robots humanoides que se desarrollan en laboratorios de investigación. Las aplicaciones de la robótica son cada vez más numerosas. En la industria, la automatización mediante robots aumenta la productividad, mejora la calidad y libera a los trabajadores de tareas repetitivas o peligrosas. En la medicina, los robots quirúrgicos permiten operaciones de alta precisión, mientras que otros ayudan en la rehabilitación o en la asistencia a personas mayores. En la exploración, los robots llegan allí donde el ser humano no puede ir, como el fondo del océano o la superficie de Marte. En la agricultura, están empezando a realizar tareas de recolección, supervisión o siembra de precisión. En el ámbito doméstico, los robots aspiradores son ya comunes y se investigan robots de servicio más complejos. La robótica educativa se ha convertido en una herramienta muy útil para fomentar en los jóvenes el interés por la ciencia, la tecnología y la resolución de problemas, combinando creatividad y razonamiento lógico.', '[{"pregunta":"¿Qué combina un robot?","opciones":["Solo mecánica","Mecánica, electrónica y programación","Solo software","Solo hardware"],"correcta":1},{"pregunta":"¿Qué aplicación NO es médica?","opciones":["Cirugía robótica","Rehabilitación","Asistencia a mayores","Ensamblar coches"],"correcta":3},{"pregunta":"¿Dónde han explorado robots?","opciones":["Solo en la Tierra","Océano y Marte","Solo en casas","En ningún sitio"],"correcta":1},{"pregunta":"¿Qué fomenta la robótica educativa?","opciones":["Desinterés","Interés por la ciencia y la lógica","Aburrimiento","Solo memoria"],"correcta":1}]'::jsonb);

