INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('valenciano', 'bachillerato', '{1}', 'Ausiàs March, poeta del segle XV', 'Ausiàs March (1400-1459) és considerat un dels poetes més importants de la literatura europea del segle XV i un dels grans renovadors de la poesia en llengua catalana. Nascut a Gandia, membre d''una família noble valenciana, va ser senyor de Beniarjó i va participar en campanyes militars al servei del rei Alfons el Magnànim. La seua obra, composta per prop de cent trenta poemes, marca un trencament profund amb la tradició trobadoresca anterior. Fins llavors, els poetes catalans imitaven els models provençals i escrivien en una llengua artificial que barrejava el català amb l''occità. March, en canvi, decideix escriure en català pur, sense intermediaris, i explorar temes amorosos, morals i espirituals amb una intensitat i una sinceritat noves. La seua poesia amorosa no idealitza l''estimada com feia la tradició cortesana, sinó que analitza els sentiments amb gran detall psicològic i reflecteix el conflicte entre el desig físic i l''aspiració espiritual. Els seus cants de mort i els seus cants espirituals mostren una visió pessimista però lúcida de la condició humana. March és també conegut per l''ús d''imatges sorprenents i d''un llenguatge dens i culte. La seua obra va influir notablement en poetes posteriors tant en llengua catalana com en llengua castellana, especialment a partir del segle XVI, quan va ser traduït al castellà per autors del Renaixement.', '[{"pregunta":"On va néixer Ausiàs March?","opciones":["València","Gandia","Barcelona","Palma"],"correcta":1},{"pregunta":"Per què March és rellevant?","opciones":["Va escriure en llatí","Va renovar la poesia catalana","Va imitar els trobadors","Va escriure novel·les"],"correcta":1},{"pregunta":"Quina llengua abandona?","opciones":["El castellà","La barreja català-occitana","El francés","L''italià"],"correcta":1},{"pregunta":"Quin tema domina la seua poesia?","opciones":["La pesca","L''anàlisi dels sentiments","La botànica","L''astronomia"],"correcta":1}]'::jsonb),

('valenciano', 'bachillerato', '{1}', 'La Crònica de Jaume I', 'El Llibre dels fets, conegut també com a Crònica de Jaume I, és una de les obres més importants de la prosa catalana medieval i una peça clau per a la història de la Corona d''Aragó. Es tracta d''una autobiografia històrica atribuïda al mateix rei Jaume I el Conqueridor (1208-1276), que hi narra en primera persona els esdeveniments més rellevants de la seua vida i del seu regnat: les conquestes de Mallorca i València, les campanyes militars, els tractats amb altres reis, els conflictes amb la noblesa i fins i tot reflexions personals sobre la seua infància i les dificultats del govern. Una de les característiques més notables de l''obra és que, tot i tractar-se d''una crònica reial, conté un estil planer, vívid i proper al parlar del moment, amb episodis narrats amb gran emoció i lucidesa. El llibre ofereix una mirada privilegiada sobre la mentalitat medieval, les relacions entre monarquia, Església i noblesa, i la societat cristiana, musulmana i jueva que convivia als territoris conquerits. Per als lectors actuals, és també un testimoni fonamental per entendre el naixement del Regne de València i la formació d''una identitat cultural pròpia, amb la llengua catalana com a vehicle principal de comunicació. La Crònica de Jaume I, juntament amb altres cròniques posteriors, constitueix un dels monuments més importants de la literatura medieval a Europa.', '[{"pregunta":"Com es coneix també el Llibre dels fets?","opciones":["Crònica de Ramon Muntaner","Crònica de Pere el Cerimoniós","Crònica de Jaume I","Llibre del repartiment"],"correcta":2},{"pregunta":"En quina persona està narrat?","opciones":["Primera persona","Tercera persona","Plural","Mixta"],"correcta":0},{"pregunta":"Quina ciutat important va conquerir Jaume I?","opciones":["Granada","València","Barcelona","Toledo"],"correcta":1},{"pregunta":"Com és l''estil de l''obra?","opciones":["Molt culte i artificial","Planer i vívid","Hermètic","Científic"],"correcta":1}]'::jsonb),

('valenciano', 'bachillerato', '{1}', 'Joanot Martorell i el Tirant lo Blanc', 'Joanot Martorell, cavaller valencià del segle XV, és l''autor del Tirant lo Blanc, una de les grans novel·les cavalleresques de la literatura europea. L''obra, escrita en català entre 1460 i 1464 i publicada per primera vegada en 1490, ha estat admirada per autors com Miguel de Cervantes, que en el Quixot la qualifica de millor llibre del món. A diferència de les novel·les cavalleresques habituals de l''època, plenes de gegants, dragons i elements fantàstics, el Tirant lo Blanc presenta un món més realista i humà. El seu protagonista, Tirant, és un cavaller bretó que viatja per mig Europa i arriba a l''Imperi bizantí, on combat els turcs i viu una intensa història d''amor amb la princesa Carmesina. L''obra combina batalles, escenes cortesanes, episodis humorístics i passatges d''anàlisi psicològica molt moderna per a la seua època. Tirant és un heroi creïble, amb debilitats i dubtes, i la princesa es mostra com una dona intel·ligent i activa. El llenguatge del Tirant lo Blanc és molt ric i variat, capaç d''adaptar-se tant als discursos solemnes com a les converses més íntimes. L''obra reflecteix la cultura cavalleresca tardomedieval i al mateix temps anuncia el Renaixement, amb la seua atenció als sentiments humans i a la realitat concreta. Tirant lo Blanc continua essent una lectura essencial per entendre la literatura europea medieval i moderna.', '[{"pregunta":"Qui és l''autor del Tirant?","opciones":["Ausiàs March","Joanot Martorell","Roís de Corella","Sor Isabel de Villena"],"correcta":1},{"pregunta":"En quin any es va publicar per primera vegada?","opciones":["1400","1460","1490","1550"],"correcta":2},{"pregunta":"Qui elogia l''obra al Quixot?","opciones":["Quevedo","Cervantes","Góngora","Lope"],"correcta":1},{"pregunta":"Com és el món del Tirant?","opciones":["Ple de gegants i dragons","Més realista i humà","Només fantàstic","Solament religiós"],"correcta":1}]'::jsonb),

('valenciano', 'bachillerato', '{1}', 'Sor Isabel de Villena i la literatura religiosa', 'Sor Isabel de Villena (1430-1490) és una de les veus més singulars de la literatura valenciana medieval. Filla il·legítima del marqués de Villena i criada a la cort de la reina Maria, va ingressar molt jove al convent de la Trinitat de València, del qual va arribar a ser abadessa. Allà va escriure una obra notable, la Vita Christi, un llarg relat en prosa que narra la vida de Jesucrist amb un estil extraordinàriament viu i humà, basat en els evangelis però amb nombroses aportacions pròpies. El més sorprenent de la seua obra és la importància que dóna als personatges femenins que envolten Crist, especialment a la Mare de Déu, que apareix com una figura activa, sàvia i protagonista principal de molts episodis. Isabel de Villena recrea amb imaginació i delicadesa escenes quotidianes, converses imaginàries, sentiments íntims i reflexions religioses, oferint una visió profundament femenina de la història sagrada en una època en què poques dones podien escriure. La seua prosa és clara, dolça, emotiva i tècnicament impecable, i fa servir tota la riquesa de la llengua catalana del seu temps. Tot i que la seua obra va quedar en l''ombra durant segles, en els darrers decennis ha estat recuperada pels estudiosos i es considera una fita fonamental de la literatura religiosa europea i una veu imprescindible dins del cànon valencià.', '[{"pregunta":"De quin convent va ser abadessa?","opciones":["Sant Francesc","La Trinitat de València","Poblet","Montserrat"],"correcta":1},{"pregunta":"Quina obra principal va escriure?","opciones":["Tirant lo Blanc","Vita Christi","Espill","Curial e Güelfa"],"correcta":1},{"pregunta":"Quina figura femenina destaca especialment?","opciones":["Santa Bàrbara","La Mare de Déu","Santa Teresa","Maria Magdalena només"],"correcta":1},{"pregunta":"Com és la seua prosa?","opciones":["Tècnica i freda","Clara, dolça i emotiva","Dura i militar","Només en llatí"],"correcta":1}]'::jsonb),

('valenciano', 'bachillerato', '{1}', 'Jaume Roig i l''Espill', 'Jaume Roig (v. 1400-1478) va ser un metge i escriptor valencià autor de l''Espill, també conegut com a Llibre de les dones, una obra singular del segle XV que combina la literatura satírica amb la reflexió moral. Escrita en versos molt curts, l''Espill narra les aventures d''un home que, al llarg de la vida, coneix diverses dones i experimenta amb elles tota classe de decepcions i desgràcies. A partir d''aquestes vivències, el narrador adreça consells al jove Baltasar sobre com conduir-se davant del món femení. L''obra té un to clarament misògin, característic de molts textos medievals, i ha generat moltes lectures crítiques al llarg dels segles, especialment en la cultura actual. Tanmateix, més enllà del seu contingut problemàtic, l''Espill és interessant com a document que reflecteix la vida quotidiana de la València del segle XV, amb referències a metges, mercaders, frares, prostitutes, advocats i gent comuna. El llenguatge és molt vigorós i realista, amb abundància d''expressions col·loquials, jocs de paraules, comparacions i detalls del dia a dia. Jaume Roig escriu en una llengua popular rica, plena de refranys i de girs característics de la parla valenciana del moment. L''Espill ocupa un lloc particular dins la literatura valenciana medieval, tant per la seua forma com per la seua capacitat per recollir el pols d''una societat urbana mediterrània en plena efervescència cultural i econòmica.', '[{"pregunta":"Com es coneix també l''Espill?","opciones":["Llibre dels fets","Llibre de les dones","Tirant lo Blanc","Vita Christi"],"correcta":1},{"pregunta":"A qui adreça consells el narrador?","opciones":["Al rei","Al jove Baltasar","A un bisbe","A un soldat"],"correcta":1},{"pregunta":"Quin to domina l''obra?","opciones":["Feminista","Clarament misògin","Religiós estricte","Poèticament amorós"],"correcta":1},{"pregunta":"Quin valor té avui l''Espill?","opciones":["Reflex de la vida quotidiana del segle XV","Manual de medicina","Llibre d''astronomia","Tractat filosòfic"],"correcta":0}]'::jsonb),

('valenciano', 'bachillerato', '{1}', 'Joan Roís de Corella i la prosa elegant', 'Joan Roís de Corella (1435-1497) és un dels grans escriptors del Segle d''Or valencià, considerat un dels prosistes més cultes de la literatura catalana medieval. Format en ambients culturals refinats, coneixia perfectament la tradició clàssica llatina i els models italians renaixentistes, que va saber incorporar a una prosa catalana d''una elegància poc comuna. Roís de Corella va cultivar gèneres molt diversos: obres religioses, com la Vita Christi en vers; narracions de tema mitològic inspirades en autors com Ovidi, com la Tragèdia de Caldesa o la Istòria de Biblis; epístoles; tractats i poesia amorosa. El seu estil, conegut com a valenciana prosa, es caracteritza per un llenguatge culte, ple de llatinismes, oracions llargues i harmonioses, i un to sovint solemne, ben adequat per narrar passions intenses i reflexions morals. La Tragèdia de Caldesa és especialment famosa perquè combina autobiografia i ficció literària en l''anàlisi d''un desengany amorós, convertint un fet personal en una peça literària de gran força. Tot i que la seua obra no va ser tan coneguda en el seu moment com la de Martorell, Roís de Corella és considerat avui un autor imprescindible per a comprendre el final del segle XV valencià i per a valorar fins a quin punt el català medieval va arribar a un nivell estilístic molt alt, comparable al de les millors literatures europees de l''època.', '[{"pregunta":"Com s''anomena el seu estil?","opciones":["Barroc valencià","Valenciana prosa","Cavalleresc","Col·loquial"],"correcta":1},{"pregunta":"Quina obra autobiogràfica amorosa escriví?","opciones":["Tragèdia de Caldesa","Espill","Tirant lo Blanc","Vita Christi"],"correcta":0},{"pregunta":"A quins autors clàssics s''inspirà?","opciones":["Ovidi i llatins","Només en jueus","Autors xinesos","Pitàgores"],"correcta":0},{"pregunta":"Com és el seu llenguatge?","opciones":["Culte i solemne","Molt col·loquial","Només oral","Amb arcaismes del segle XII"],"correcta":0}]'::jsonb),

('valenciano', 'bachillerato', '{1}', 'La Decadència de la literatura catalana', 'Després del brillant Segle d''Or literari valencià, amb figures com Ausiàs March, Joanot Martorell o Roís de Corella, la literatura en llengua catalana va viure un període conegut tradicionalment com a Decadència, que s''estén entre els segles XVI i XVIII. Les causes d''aquesta davallada són múltiples. L''ascens del castellà com a llengua de prestigi de la Corona, el trasllat de la cort a Madrid, l''aparició de la impremta que va afavorir les llengües dominants i el canvi de les elits culturals cap a models castellans, van reduir l''ús del català en els àmbits de cultura escrita. Els Decrets de Nova Planta del segle XVIII, dictats pels Borbons després de la Guerra de Successió, van fer encara més difícil la situació, imposant el castellà com a llengua oficial en l''administració i limitant l''ús del català en l''ensenyament i els tribunals. Tot i això, el català no va desaparèixer: va continuar essent la llengua parlada per la major part del poble valencià i català, i van produir-se algunes obres literàries, sobretot de caràcter popular, religiós o teatral, que han anat sent rescatades pels estudiosos actuals. La mateixa denominació de Decadència ha estat discutida, perquè, encara que la literatura culta sí que va patir una clara recessió, la vida lingüística col·loquial va mantenir una vitalitat notable. La recuperació literària arribaria al segle XIX amb la Renaixença.', '[{"pregunta":"Entre quins segles se situa la Decadència?","opciones":["XII-XIII","XVI-XVIII","XIX-XX","XX-XXI"],"correcta":1},{"pregunta":"Quins decrets del XVIII van perjudicar el català?","opciones":["Decrets de Nova Planta","Decrets del Consell","Decrets reials pacífics","Decrets foraesters"],"correcta":0},{"pregunta":"Què es va imposar com a llengua oficial?","opciones":["Francés","Castellà","Llatí","Àrab"],"correcta":1},{"pregunta":"Què va passar al segle XIX?","opciones":["Decadència","Renaixença","Prohibició total","Indiferència"],"correcta":1}]'::jsonb),

('valenciano', 'bachillerato', '{1}', 'La Renaixença al País Valencià', 'La Renaixença és el moviment cultural i literari que va propiciar la recuperació de la llengua i la literatura en català al llarg del segle XIX, després del llarg període de Decadència. Al País Valencià, la Renaixença va tenir característiques pròpies i un ritme diferent al de Catalunya. Els primers noms destacats foren Teodor Llorente i Constantí Llombart, dues figures que representen dues tendències complementàries dins del moviment. Teodor Llorente (1836-1911) va ser un poeta elegant i conservador, director del diari Las Provincias, que va escriure una obra poètica inspirada en els paisatges i les tradicions valencianes, reivindicant la bellesa de la llengua culta. Constantí Llombart (1848-1893), en canvi, va tenir un caràcter més popular i combatiu, va fundar l''entitat Lo Rat Penat en 1878 i defensava un ús més social i democràtic del valencià. A partir dels anys finals del segle XIX i especialment al primer terç del segle XX, van aparèixer nous escriptors que anaren consolidant una literatura valenciana moderna, capaç de competir amb les grans tradicions europees. La Renaixença va ser, doncs, un procés essencial per recuperar el prestigi de la llengua i la consciència de formar part d''una cultura pròpia. El seu llegat és encara visible avui en la vitalitat cultural, educativa i acadèmica del valencià, tot i els canvis profunds de la societat contemporània.', '[{"pregunta":"Quin segle correspon a la Renaixença?","opciones":["XVII","XVIII","XIX","XX"],"correcta":2},{"pregunta":"Qui va ser el director de Las Provincias?","opciones":["Llorente","Llombart","March","Corella"],"correcta":0},{"pregunta":"Quina entitat va fundar Llombart?","opciones":["Lo Rat Penat","L''Acadèmia","La Societat Coral","El Valencià Unit"],"correcta":0},{"pregunta":"Què va intentar recuperar el moviment?","opciones":["Prestigi de la llengua catalana","Llatí clàssic","Àrab medieval","Grec antic"],"correcta":0}]'::jsonb),

('valenciano', 'bachillerato', '{1}', 'Vicent Andrés Estellés, poeta del poble', 'Vicent Andrés Estellés (1924-1993) és un dels poetes valencians més importants del segle XX. Nascut a Burjassot, provenia d''una família humil, filla de forners, fet que va marcar profundament la seua sensibilitat literària i el seu compromís amb la gent del carrer. Va treballar durant dècades com a periodista al diari Las Provincias, i va escriure una obra poètica immensa, de més d''una trentena de llibres, en una època en què publicar en valencià presentava moltes dificultats pel context cultural i polític del franquisme. La seua poesia combina diversos registres: el tendre, el sensual, l''elegíac, el social, l''irònic, l''íntim. Un dels aspectes més destacats de la seua obra és la celebració dels petits detalls de la vida quotidiana, dels afectes familiars, del treball, dels aliments, dels costums valencians, sempre amb un llenguatge proper a la parla col·loquial i enriquit amb referències cultes. Llibres com La nit, Llibre de meravelles, Mural del País Valencià i altres l''han convertit en una veu imprescindible de la literatura catalana del segle XX. Estellés reivindica la dignitat del poble valencià, la bellesa de la seua llengua i la memòria de les persones senzilles. La seua figura va ser essencial per a connectar la poesia culta amb l''experiència col·lectiva i el seu llegat inspira encara poetes i cantants de generacions posteriors, que continuen musicant i citant els seus versos en actes culturals i reivindicacions socials.', '[{"pregunta":"On va nàixer Estellés?","opciones":["València","Burjassot","Alcoi","Castelló"],"correcta":1},{"pregunta":"Quin context polític marcà la seua obra?","opciones":["La República","El franquisme","La transició","La democràcia actual"],"correcta":1},{"pregunta":"Quina temàtica és central?","opciones":["Celebració de la vida quotidiana","Mitologia grega","Novel·la negra","Economia"],"correcta":0},{"pregunta":"Com és el seu llenguatge?","opciones":["Proper al col·loquial enriquit amb cultes","Molt arcaic","Llatí","Només hermètic"],"correcta":0}]'::jsonb),

('valenciano', 'bachillerato', '{1}', 'Joan Fuster i l''assaig modern', 'Joan Fuster (1922-1992) és considerat un dels assagistes més importants de la literatura catalana contemporània i una figura fonamental del pensament valencià del segle XX. Nascut a Sueca, va passar bona part de la seua vida al seu poble natal, tot i mantindré una activitat literària i intel·lectual molt intensa. La seua obra abasta més d''un centenar de llibres dedicats a temes molt diversos: història, política, llengua, literatura, costums, reflexions personals. El llibre més influent és sens dubte Nosaltres, els valencians, publicat el 1962, en el qual Fuster analitza amb rigor la identitat dels valencians i proposa una interpretació del seu passat i del seu futur vinculada als Països Catalans. L''obra va provocar un gran impacte, tant entre els seus defensors com entre els seus detractors, i va convertir Fuster en un referent del valencianisme cultural. L''estil de Fuster és lúcid, irònic, precís i sovint provocador. Defensa un ús culte i normatiu del valencià, basat en la unitat de la llengua catalana. Les seues reflexions sobre la literatura, l''Església, el poder, la vida quotidiana o el paper dels intel·lectuals continuen sent d''una actualitat sorprenent. Al llarg de la seua vida va rebre importants reconeixements i premis, i la seua influència en l''assaig, la crítica i la política cultural valenciana va ser, i continua sent, molt profunda.', '[{"pregunta":"On va viure Fuster?","opciones":["València","Sueca","Alacant","Alcoi"],"correcta":1},{"pregunta":"Quin llibre publicat en 1962 és fonamental?","opciones":["Nosaltres, els valencians","La pell de brau","Obra completa","El desterrat"],"correcta":0},{"pregunta":"Com és el seu estil?","opciones":["Lúcid, irònic i provocador","Èpic i solemne","Místic i religiós","Només sentimental"],"correcta":0},{"pregunta":"Què defensa sobre la llengua?","opciones":["Unitat de la llengua catalana","Ús només oral","Retorn al llatí","Abandó del valencià"],"correcta":0}]'::jsonb),

('valenciano', 'bachillerato', '{1}', 'Les varietats del valencià', 'El valencià és la denominació tradicional que rep al País Valencià la llengua catalana, una de les llengües romàniques nascudes del llatí que es parla també a Catalunya, les Illes Balears, la Franja d''Aragó, Andorra, la Catalunya del Nord (estat francés) i la ciutat sarda de l''Alguer. Tot i que la llengua és bàsicament la mateixa, presenta certes varietats dialectals que reflecteixen la seua història i la geografia. Dins del valencià se solen distingir diverses subvarietats principals: el valencià septentrional, parlat al nord de Castelló; el valencià central, al voltant de València i les comarques pròximes; el valencià meridional, a les comarques del sud; el valencià alacantí, amb característiques particulars a les zones més meridionals; i el parlar tortosí en algunes zones de transició. Cadascun d''aquests parlars té peculiaritats de pronunciació, de vocabulari i, a vegades, de morfologia, però totes formen part del mateix sistema lingüístic i són plenament comprensibles entre si. La normativa lingüística del valencià s''estableix a través de l''Acadèmia Valenciana de la Llengua, que elabora gramàtiques, diccionaris i recomanacions per tal de fomentar un ús culte i coherent amb la tradició del català. Estudiar les varietats no és només un exercici acadèmic: ajuda a valorar la riquesa de la llengua, el sentit d''identitat de cada comarca i el patrimoni comú que compartim amb la resta de territoris de parla catalana.', '[{"pregunta":"De quina llengua prové el valencià?","opciones":["Grec","Llatí","Àrab","Germànic"],"correcta":1},{"pregunta":"Quina institució fa la normativa del valencià?","opciones":["RAE","AVL","Institut d''Estudis Catalans sol","UNESCO"],"correcta":1},{"pregunta":"Les varietats són intercomprensibles?","opciones":["Sí","No","Només algunes","No pertanyen a la mateixa llengua"],"correcta":0},{"pregunta":"Quin parlar és pròxim a l''Ebre?","opciones":["Tortosí","Alacantí","Algueresa","Balear"],"correcta":0}]'::jsonb),

('valenciano', 'bachillerato', '{1}', 'Les Falles de València', 'Les Falles són una de les festes més conegudes i representatives del País Valencià, declarades Patrimoni Cultural Immaterial de la Humanitat per la UNESCO en 2016. Se celebren del 15 al 19 de març en moltes localitats valencianes, i especialment a la ciutat de València, on atrauen cada any milions de visitants. La festa té els seus orígens en l''antiga tradició dels fusters, que la nit del 19 de març, dia de Sant Josep, cremaven les restes de fusta i els estris que no els feien falta per l''arribada de la primavera. Amb el temps, la festa va anar creixent i les cremades es van transformar en autèntiques escultures fetes de fusta, cartó i altres materials, que representen escenes crítiques, satíriques o humorístiques de l''actualitat social i política. Cada comissió fallera prepara durant mesos el seu monument i el col·loca al carrer, i la nit de Sant Josep, coneguda com la cremà, totes les falles es cremen simultàniament en un espectacle únic. Les Falles inclouen també altres actes molt populars, com la mascletà de cada dia, les ofrenes florals a la Mare de Déu dels Desemparats, els desfilades amb vestits tradicionals, la música i els focs artificials. Més enllà del vessant lúdic, les Falles reflecteixen la creativitat del poble valencià, el sentit crític, la vinculació al territori i la manera de viure la festa en comunitat, i són avui un símbol fonamental de la identitat valenciana.', '[{"pregunta":"Quan se celebren les Falles?","opciones":["Març","Maig","Juliol","Desembre"],"correcta":0},{"pregunta":"Quan es van declarar Patrimoni de la Humanitat?","opciones":["2000","2010","2016","2020"],"correcta":2},{"pregunta":"Com s''anomena la nit de la crema?","opciones":["La mascletà","La cremà","La despertà","L''ofrena"],"correcta":1},{"pregunta":"Què representen els monuments?","opciones":["Només animals","Escenes crítiques i satíriques","Paisatges abstractes","Mapes"],"correcta":1}]'::jsonb),

('valenciano', 'bachillerato', '{1}', 'L''horta valenciana i el Tribunal de les Aigües', 'L''horta valenciana és un paisatge agrícola únic al món, situat al voltant de la ciutat de València, i està considerada una de les hortes més antigues i productives d''Europa. Els seus orígens es remunten als musulmans, que al segle VIII van introduir tècniques de regadiu molt sofisticades, amb séquies, aqüeductes i sistemes de distribució de l''aigua. Aquests sistemes es conserven en gran part fins a l''actualitat i permeten mantenir un paisatge de camps, horts, alqueries i barraques tradicionals. Un dels elements més emblemàtics i curiosos de la cultura de l''horta és el Tribunal de les Aigües, una institució jurídica mil·lenària que es reuneix cada dijous a les dotze del migdia a la porta de la catedral de València. Els seus membres, elegits pels regants de les vuit séquies històriques, jutgen de manera oral, pública i sense paperassa els conflictes sobre l''ús de l''aigua, seguint una tradició que es remunta a l''època de Jaume I i probablement anterior. El Tribunal de les Aigües ha estat declarat Patrimoni Cultural Immaterial de la Humanitat per la UNESCO, pel seu interès històric i per ser un exemple de justícia de proximitat excepcional. L''horta, amenaçada per la urbanització i els canvis en l''agricultura, és avui protegida per diverses normatives i moviments ciutadans que valoren el seu patrimoni natural, cultural i gastronòmic com un tresor irrenunciable del País Valencià.', '[{"pregunta":"Qui va introduir el sistema de regadiu?","opciones":["Romans","Musulmans","Grecs","Visigots"],"correcta":1},{"pregunta":"Quan es reuneix el Tribunal de les Aigües?","opciones":["Cada dilluns","Cada dijous a les 12","Cada diumenge","Un cop al mes"],"correcta":1},{"pregunta":"On es reuneix?","opciones":["A la Llotja","A la porta de la catedral","A l''Ajuntament","A l''horta mateixa"],"correcta":1},{"pregunta":"Què amenaça l''horta avui?","opciones":["Urbanització i canvis agrícoles","Excés de pluja","Plagues úniques","Cosmos"],"correcta":0}]'::jsonb),

('valenciano', 'bachillerato', '{1}', 'La gastronomia valenciana i la paella', 'La gastronomia valenciana és una de les cuines més reconegudes de la península Ibèrica i del Mediterrani. Es basa en productes de proximitat com l''arròs, les verdures, les hortalisses, els llegums, el peix fresc, els embotits, les fruites i l''oli d''oliva. El plat més famós és, sens dubte, la paella, nascut a l''horta valenciana com a menjar camperol que es preparava al foc amb una gran paella de ferro i els ingredients que es tenien a mà. La paella valenciana tradicional conté arròs, pollastre, conill, garrofó, ferradura, tavella, tomaca, oli, aigua, sal, safrà i, a vegades, caragols o romer. Sol cuinar-se a l''aire lliure, amb llenya de taronger, en una pràctica que és tant culinària com social i familiar. Existeixen moltes altres variants d''arròs, com l''arròs al forn, l''arròs a banda, l''arròs caldós amb bogavant o la fideuà. Més enllà de l''arròs, són característics plats com la titaina, la coca de tomaca, el puchero valencià, la coca cristina, l''all i pebre d''anguila de l''Albufera o els dolços tradicionals, com les monetes, les pastissetes o els bunyols, especialment populars en festes com les Falles. L''horxata, beguda feta amb xufes, és un emblema valencià conegut arreu del món. La cuina valenciana reflecteix la riquesa del seu territori i conserva tradicions que es transmeten de generació en generació.', '[{"pregunta":"D''on prové la paella?","opciones":["De les muntanyes","De l''horta valenciana","Del mar","De la ciutat"],"correcta":1},{"pregunta":"Quin ingredient NO és tradicional de la paella?","opciones":["Pollastre","Garrofó","Calamar","Conill"],"correcta":2},{"pregunta":"Amb què es fa habitualment l''horxata?","opciones":["Arròs","Xufes","Ametles","Avellanes"],"correcta":1},{"pregunta":"Quin plat de peix característic hi ha?","opciones":["All i pebre d''anguila","Pizza","Sushi","Hamburguesa"],"correcta":0}]'::jsonb),

('valenciano', 'bachillerato', '{1}', 'La literatura infantil i juvenil en valencià', 'La literatura infantil i juvenil en valencià ha experimentat un creixement notable en les darreres dècades, gràcies a la consolidació del sistema educatiu, a l''aparició d''editorials especialitzades i al treball de molts autors i il·lustradors compromesos amb la llengua. Després de segles de dificultats per publicar en català, les escoles valencianes van començar a incorporar el valencià a partir dels anys vuitanta, fet que va generar una demanda creixent de llibres adaptats a les diferents edats dels lectors. A la capçalera d''aquesta renovació cal destacar escriptors com Enric Valor, autor de les famoses Rondalles valencianes, que ha acostat a diverses generacions el patrimoni de contes tradicionals. Autores contemporànies com Rosa Serrano, Anna Ballester o Maria Jesús Bolta han publicat històries per a joves que combinen humor, aventura i reflexió. Les editorials dedicades a la literatura infantil i juvenil en valencià ofereixen àlbums il·lustrats, novel·les juvenils, contes clàssics, llibres informatius i adaptacions d''obres universals. Aquest sector és essencial no solament per a l''entreteniment, sinó també per a la transmissió de la llengua, la creació de nous lectors i el foment d''una cultura literària pròpia. Les biblioteques escolars i públiques, els certàmens literaris i les fires del llibre contribueixen a donar visibilitat a aquestes obres. Tot i els reptes actuals, com el descens dels hàbits lectors o la competència amb continguts digitals, la literatura infantil en valencià continua creixent en varietat i qualitat.', '[{"pregunta":"Qui és un autor clàssic de rondalles valencianes?","opciones":["Enric Valor","Joan Fuster","Estellés","Corella"],"correcta":0},{"pregunta":"Quan es va incorporar el valencià a l''escola?","opciones":["Anys 20","Anys 50","Anys 80","Anys 2000"],"correcta":2},{"pregunta":"Per què és important aquesta literatura?","opciones":["Només per diversió","Transmissió de llengua i cultura","Només comercial","Només escolar"],"correcta":1},{"pregunta":"Què pot afectar negativament el sector?","opciones":["Més fires del llibre","Descens dels hàbits lectors","Més biblioteques","Més autores"],"correcta":1}]'::jsonb),

('valenciano', 'bachillerato', '{1}', 'La música popular valenciana', 'La música popular valenciana té una llarga tradició i forma part essencial de la identitat cultural del País Valencià. Les societats musicals, els grups de dolçainers i tabaleters, els cors i les bandes de música són presents en pràcticament tots els pobles, i les festes majors sovint giren al voltant de l''activitat musical. Les bandes de música valencianes destaquen per la seua gran qualitat i quantitat: es calcula que el País Valencià compta amb centenars d''agrupacions que reuneixen milers de músics aficionats i professionals. Aquesta xarxa d''associacions musicals ha estat declarada Manifestació Representativa del Patrimoni Cultural Immaterial per la UNESCO en 2018, un reconeixement que subratlla la importància social, educativa i artística d''aquesta tradició. Al costat de la música instrumental, la cançó popular valenciana ha conegut un renaixement des dels anys seixanta amb la Nova Cançó, en què artistes com Raimon, Ovidi Montllor, Paco Muñoz i el grup Al Tall van reivindicar l''ús del valencià i temes propis, combinant tradició i modernitat. Més recentment, grups com Obrint Pas, La Gossa Sorda, Aspencat, Zoo o La Fúmiga han renovat la música popular valenciana amb estils com el rock, el ska, el rap o la fusió amb ritmes llatins, arribant a públics joves i connectant la llengua amb l''expressió artística del segle XXI. La música és així un vehicle fonamental de transmissió de la llengua, les emocions i la identitat valenciana actual.', '[{"pregunta":"Què ha estat declarat Patrimoni UNESCO en 2018?","opciones":["La paella","Les societats musicals valencianes","Les Falles","El Tribunal de les Aigües"],"correcta":1},{"pregunta":"Quin moviment cançonístic apareix als anys 60?","opciones":["Nova Cançó","Rock dur","Electro","Cant gregorià"],"correcta":0},{"pregunta":"Quin cantautor és representatiu?","opciones":["Raimon","Enric Valor","Estellés","Fuster"],"correcta":0},{"pregunta":"Quin grup modern NO és esmentat?","opciones":["Obrint Pas","Zoo","La Fúmiga","Los Beatles"],"correcta":3}]'::jsonb),

('valenciano', 'bachillerato', '{1}', 'La cultura popular: Moros i Cristians', 'Les festes de Moros i Cristians són una de les manifestacions culturals més espectaculars i característiques del País Valencià, especialment a les comarques del sud i del centre. Aquestes festes commemoren, en clau dramàtica i festiva, els episodis històrics de la Reconquesta, és a dir, les lluites entre cristians i musulmans durant l''edat mitjana que van culminar amb la conquesta de bona part del territori per Jaume I. Les celebracions es remunten, en molts casos, a diversos segles, i s''han anat adaptant al llarg del temps. Cada poble que celebra Moros i Cristians té les seues pròpies tradicions, vestits, balls i actes, però en general les festes inclouen les entrades, desfilades multitudinàries on les comparses, dividides entre els bàndols moro i cristià, es presenten amb espectaculars vestits tradicionals; les ambaixades, en què s''escenifiquen diàlegs entre els dos bàndols; i les batalles simulades, amb trons i pólvora. Un dels casos més coneguts és el d''Alcoi, on la festa se celebra a finals d''abril al voltant de Sant Jordi i compta amb una enorme participació popular. Més enllà del vessant lúdic, les festes de Moros i Cristians són una expressió de la convivència històrica de cultures al nostre territori i un exemple de com el passat pot transformar-se en un patrimoni cultural viu que uneix les generacions presents, reforça els lligams de la comunitat i projecta una imatge rica i festiva de la societat valenciana actual.', '[{"pregunta":"Quin fet històric commemoren?","opciones":["Les Falles","Les lluites entre cristians i musulmans","La guerra civil","Els Jocs Olímpics"],"correcta":1},{"pregunta":"A quin poble és especialment famosa la festa?","opciones":["Alcoi","Gandia","Calp","Sagunt"],"correcta":0},{"pregunta":"Què són les entrades?","opciones":["Àpats","Desfilades amb vestits tradicionals","Balls en cercle","Concerts de rock"],"correcta":1},{"pregunta":"Què reforça la festa en la comunitat?","opciones":["Els lligams i el patrimoni cultural","L''aïllament","La indiferència","L''oblit"],"correcta":0}]'::jsonb);

